    updated_at = now();

INSERT INTO services (slug, icon, tags, published, sort_order, translations)
VALUES ('mobile', '◈', ARRAY['Flutter', 'Swift', 'iOS', 'Android'], true, 2, $row_2${"en":{"body":"In a world that is increasingly mobile-centric, a robust and user-friendly mobile app is a prerequisite for growth. Piplos Media specialises in mobile app development for iOS and Android: cross-platform with Flutter and native with Swift. A consumer-facing service, an enterprise solution or anything in between — we build high-performance, engaging, feature-rich apps that meet user expectations and drive business growth.\n\n![Mobile app development — Piplos Media](/uploads/services/mobile.png)\n\n## What we do\n\n- **Cross-platform development with Flutter** — iOS and Android from a single codebase: faster and cheaper than two native teams;\n- **Native iOS with Swift** — when maximum performance and platform capabilities matter;\n- **Store publishing** — preparation, review and release on the App Store and Google Play;\n- **Redesign and growth** — refreshing the design and features of existing apps;\n- **Server side** — APIs, authentication and push notifications by our [backend team](/en/services/backend).\n\n## Our approach\n\nPerformance from the first screen: fast cold start, smooth animations, battery efficiency. We design offline-ready flows so the app stays useful without a connection. Every release is tested on real devices of different generations, not just in an emulator.\n\n## Selected projects\n\n- [AiFront — mobile app for the AI visualiser](/en/portfolio/aifront-app);\n- [Unistar — radio station app for Android and iOS](/en/portfolio/unistar);\n- [Autoradio — mobile app](/en/portfolio/avtoradio-app);\n- [Local Market — Android marketplace app](/en/portfolio/localmarket).\n\n## FAQ\n\n### Flutter or native — which should I choose?\n\nFor most products Flutter wins: one team, one codebase, feature parity on iOS and Android. Native Swift makes sense when you need deep platform integrations or maximum performance. On the first call we will honestly recommend the option that fits your case.\n\n### How much does a mobile app cost?\n\nIt depends on scope: a Flutter MVP takes from 2–3 months of work, a full product with a backend takes longer. [Describe your idea](/en/order) — we will prepare an estimate with a budget range within 2–3 days.\n\n### Do you help with App Store and Google Play publishing?\n\nYes, we handle the whole process: developer accounts, builds, screenshots, store review and responses to reviewer feedback — all the way to the public release.\n\n### Who maintains the app after release?\n\nWe do: monitoring, bug fixes, updates for new iOS and Android versions, feature development. See our [maintenance and support service](/en/services/devops) for details.","title":"Mobile Apps","description":"Cross-platform apps with Flutter and native iOS with Swift. Performance-first UX, offline-ready flows and full App Store deployment."},"ru":{"body":"В мире, который всё больше ориентируется на мобильные устройства, надёжное и удобное мобильное приложение — обязательное условие роста. Piplos Media специализируется на разработке мобильных приложений для iOS и Android: кроссплатформенных на Flutter и нативных на Swift. Потребительский сервис, корпоративное решение или что-то среднее — мы создаём производительные, увлекательные и многофункциональные приложения, которые не только отвечают ожиданиям пользователей, но и работают на рост бизнеса.\n\n![Разработка мобильных приложений — Piplos Media](/uploads/services/mobile.png)\n\n## Что мы делаем\n\n- **Кроссплатформенная разработка на Flutter** — iOS и Android из одной кодовой базы: быстрее и дешевле двух нативных команд;\n- **Нативный iOS на Swift** — когда важна максимальная производительность и платформенные возможности;\n- **Публикация в сторах** — подготовка, ревью и выпуск в App Store и Google Play;\n- **Редизайн и развитие** — обновление дизайна и функциональности существующих приложений;\n- **Серверная часть** — API, авторизация и пуш-уведомления силами нашей [бэкенд-команды](/ru/services/backend).\n\n## Наш подход\n\nПроизводительность — с первого экрана: холодный старт, плавные анимации, экономия батареи. Продумываем офлайн-сценарии — приложение остаётся полезным без сети. Каждый релиз тестируем на реальных устройствах разных поколений, а не только в эмуляторе.\n\n## Примеры проектов\n\n- [AiFront — мобильное приложение AI-визуализатора](/ru/portfolio/aifront-app);\n- [Unistar — приложение радиостанции для Android и iOS](/ru/portfolio/unistar);\n- [«Авторадио» — мобильное приложение](/ru/portfolio/avtoradio-app);\n- [«Местный Рынок» — Android-приложение маркетплейса](/ru/portfolio/localmarket).\n\n## Частые вопросы\n\n### Flutter или нативная разработка — что выбрать?\n\nДля большинства продуктов Flutter выгоднее: одна команда, одна кодовая база, паритет функций на iOS и Android. Нативный Swift оправдан, когда нужны глубокие платформенные интеграции или максимальная производительность. На первом созвоне честно порекомендуем вариант под вашу задачу.\n\n### Сколько стоит разработка мобильного приложения?\n\nЗависит от функциональности: MVP на Flutter — от 2–3 месяцев работы, полноценный продукт с бэкендом — больше. [Опишите идею](/ru/order) — подготовим оценку с вилкой бюджета за 2–3 дня.\n\n### Поможете с публикацией в App Store и Google Play?\n\nДа, берём на себя весь процесс: аккаунты разработчика, сборки, скриншоты, прохождение ревью и ответы на замечания сторов — вплоть до выхода приложения в свет.\n\n### Кто поддерживает приложение после релиза?\n\nМы: мониторинг, исправление ошибок, обновления под новые версии iOS и Android, развитие функциональности. Подробнее — в услуге [«Поддержка и сопровождение»](/ru/services/devops).","title":"Мобильные приложения","description":"Кроссплатформенные приложения на Flutter и нативный iOS на Swift. Производительный UX, офлайн-сценарии и полный деплой в App Store."}}$row_2$::jsonb)
