INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('sportevent', 'web', ARRAY['web'], ARRAY['React', 'TypeScript', 'PHP', 'Symfony', 'MySQL', 'HTML/CSS'], 2025, false, true, 9, '/uploads/projects/sportevent/3924690-12590-1.png', $row_9${"en":{"title":"Sports Event Landing Page","result":"The project was successfully delivered to the client. The work was completed in 2025.","solution":"## Project: a modern web application for organising and promoting an international sports championship.\n\n![Sports event landing page — 1](/uploads/projects/sportevent/macbook-mockup-front-view-uv.jpeg)\n\n## Delivered functionality\n\nPublic website\n- Hero section — a banner with event information and registration buttons.\n- About the event — a section describing the championship, disciplines, number of participants and contacts.\n- Athletes — interactive cards with photos, achievements and countries.\n- Schedule — tabs by day, showing events, times and venues.\n- Sponsors — a grid of partner logos and a call for cooperation.\n- FAQ — a dynamic accordion with frequently asked questions.\n- Registration — a form for participants and guests.\n- Footer — contacts and social media links.\n\nAdmin panel\n- Authentication and access protection (JWT tokens, Symfony Security).\n- General settings: editing event information, contact details and the banner.\n- Athletes: adding, editing and deleting entries, uploading photos and achievements.\n- Schedule: flexible management of days and events.\n- Sponsors: uploading logos, configuring display order.\n- FAQ: CRUD operations for questions and answers.\n- Publishing: domain, SSL, caching and compression configuration.\n\n![MacBook Mockup, Floating.jpeg](/uploads/projects/sportevent/mac-book-mockup-floating.jpeg)\n\n## Technology stack\n\nFrontend:\n- React 18 (UI)\n- TypeScript 5.7\n- Vite 6 (fast builds)\n- Tailwind CSS + HeroUI (interface)\n- Framer Motion (animations)\n\nBackend:\n- PHP 8.1+ (Symfony 6)\n- API Platform (REST API)\n- Doctrine ORM\n- Symfony Security / Validator / Serializer\n\nDatabase:\n- MySQL 8.0\n\nInfrastructure and tools:\n- PostCSS / ESLint / Babel\n- Composer / Symfony CLI\n\n## Architecture highlights\n\n- Component-based React UI with reusable blocks.\n- Automatic REST API generation with API Platform.\n- Frontend-backend integration through secured CORS requests.\n- Data validation and JWT authentication.\n- Doctrine ORM — safe database access and migrations.\n- Tailwind — responsive, utility-first styling.\n\n![Mobile App Screen Mockup, Mosaic.jpeg](/uploads/projects/sportevent/mobile-app-screen-mockup-mosaic.jpeg)\n\n## Development stages\n\n**Week 1 — Analysis and design**\n- Architecture and interface prototype.\n- Environment setup and project structure.\n\n**Week 2 — Landing page and API development**\n- Frontend implementation in React.\n- REST API built with Symfony.\n- Entity setup: athletes, schedule, FAQ, sponsors.\n\n**Week 3 — Integration and launch**\n- Connecting the frontend to the API.\n- Testing and performance optimisation.\n- Deployment to the production server.\n\nTotal duration: 3 weeks.\n\n## Project team\n\n- Project manager: 1\n- Frontend developer: 1\n- Backend developer: 1","subtitle":"Web · Landing page","challenge":"The project delivers a digital platform for announcing, managing and covering a major sports event. The client's key goals: build an attractive, responsive landing page with a strong focus on visuals and usability; create an admin panel for managing content (athletes, schedule, sponsors, FAQ, general settings); connect the frontend and backend through an API for flexibility and scalability.","description":"Case study: developing a landing page and admin panel for the SPORTFEST 2024 sports event","stack_detail":"React, TypeScript, PHP, Symfony, MySQL, HTML/CSS"},"ru":{"title":"Лендинг Спортивного События","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2025 году.","solution":"## Проект: Создание современного веб-приложения для организации и продвижения международного спортивного чемпионата.\n\n![Лендинг Спортивного События — 1](/uploads/projects/sportevent/macbook-mockup-front-view-uv.jpeg)\n\n## Реализованный функционал\n\nПубличная часть сайта\n- Главный экран (Hero Section) — баннер с информацией о событии и кнопками регистрации.\n- О событии — блок с описанием чемпионата, направлениями, числом участников и контактами.\n- Спортсмены — интерактивные карточки с фотографиями, достижениями и странами.\n- Расписание — табы по дням, отображение событий, времени и площадок.\n- Спонсоры — сетка логотипов партнёров и приглашение к сотрудничеству.\n- FAQ — динамический аккордеон с часто задаваемыми вопросами.\n- Регистрация — форма для участников и гостей.\n- Footer — контакты и ссылки на социальные сети.\n\nАдмин-панель\n- Аутентификация и защита доступа (JWT-токены, Symfony Security).\n- Общие настройки: редактирование информации о событии, контактных данных, баннера.\n- Спортсмены: добавление, редактирование и удаление, загрузка фото и достижений.\n- Расписание: гибкое управление днями и событиями.\n- Спонсоры: загрузка логотипов, настройка порядка отображения.\n- FAQ: CRUD-операции с вопросами и ответами.\n- Публикация: конфигурация домена, SSL, кэширования и сжатия.\n\n![MacBook Mockup, Floating.jpeg](/uploads/projects/sportevent/mac-book-mockup-floating.jpeg)\n\n## Технологический стек\n\nFrontend:\n- React 18 (UI)\n- TypeScript 5.7\n- Vite 6 (быстрая сборка)\n- Tailwind CSS + HeroUI (интерфейс)\n- Framer Motion (анимации)\n\nBackend:\n- PHP 8.1+ (Symfony 6)\n- API Platform (REST API)\n- Doctrine ORM\n- Symfony Security / Validator / Serializer\n\nБаза данных:\n- MySQL 8.0\n\nИнфраструктура и инструменты:\n- PostCSS / ESLint / Babel\n- Composer / Symfony CLI\n\n## Особенности архитектуры\n\n- Компонентный React UI с переиспользуемыми блоками.\n- Автоматическая генерация REST API на базе API Platform.\n- Интеграция frontend и backend через защищённые CORS-запросы.\n- Валидация данных и JWT-аутентификация.\n- Doctrine ORM — безопасная работа с БД и миграции.\n- Tailwind — адаптивная стилизация с utility-first подходом.\n\n![Mobile App Screen Mockup, Mosaic.jpeg](/uploads/projects/sportevent/mobile-app-screen-mockup-mosaic.jpeg)\n\n## Этапы разработки\n\n**Неделя 1 — Анализ и проектирование**\n- Подготовка архитектуры и прототипа интерфейса.\n- Настройка окружения и структуры проекта.\n\n**Неделя 2 — Разработка лендинга и API**\n- Реализация фронтенда на React.\n- Создание REST API на Symfony.\n- Настройка сущностей: спортсмены, расписание, FAQ, спонсоры.\n\n**Неделя 3 — Интеграция и запуск**\n- Соединение фронтенда с API.\n- Тестирование и оптимизация производительности.\n- Развёртывание проекта на продакшн-сервере.\n\nОбщий срок: 3 недели.\n\n## Команда проекта\n\n- Руководитель проекта: 1\n- Frontend-разработчик: 1\n- Backend-разработчик: 1","subtitle":"Веб · Лендинг","challenge":"Проект направлен на создание цифровой платформы для анонса, управления и освещения крупного спортивного события. Основные задачи, поставленные заказчиком: Разработать привлекательный, адаптивный лендинг с акцентом на визуальную составляющую и удобство пользователей. Создать админ-панель для управления контентом (спортсмены, расписание, спонсоры, FAQ, общие настройки). Обеспечить интеграцию frontend и backend через API для гибкости и масштабируемости.","description":"Кейс. Разработка лендинга и админ-панели для спортивного мероприятия «СПОРТФЕСТ 2024»","stack_detail":"React, TypeScript, PHP, Symfony, MySQL, HTML/CSS"}}$row_9$::jsonb)
