INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('gypsy', 'web', ARRAY['web'], ARRAY['PHP', 'Symfony', 'PostgreSQL', 'Docker', 'JavaScript', 'HTML/CSS'], 2025, false, true, 15, '/uploads/projects/gypsy/frame-39.jpg', $row_15${"en":{"title":"Landing and Chat Bot Event","result":"Reduced application moderation time due to statuses and templates. Increased lending conversion rate due to block structure and SEO framework. Stability under peak loads, predictable uptime. Unified analytics on the funnel site → bot → confirmation.","solution":"We developed a comprehensive solution for the event: a conversion-based landing page and a Telegram bot integrated with it for registration, moderation and communication with participants. The project is deployed in a Docker environment, data is stored in PostgreSQL, advanced integrations (Spotify API) and video content uploading are implemented.\n\n## About the client and the task\n\n- It was necessary to launch a single digital flow: attraction on the website → collection and moderation of requests → mailings and notifications in Telegram.\n- Speed of launch, stability under peak loads and transparent analytics throughout the funnel were important.\n\n## Business goals\n\n- Increase the number of quality applications and speed up their processing.\n- Reduce manual moderation and human error.\n- Ensure stable mailings and communication with participants.\n- Give marketing transparent metrics along the funnel (site → bot → confirmation).\n\n**Implementation phases**\n\n![Landing and Chat Bot Event — 1](/uploads/projects/gypsy/card-3.png)\n\n## What's been done\n\n- Telegram bot: 3-step registration, application statuses, moderator roles, segmented mailings.\n- Landing: clear offer, programme/speakers, social proof, FAQ, application forms.\n- Cross-cutting analytics: site and bot events, tracking key conversions.\n- Infrastructure: Docker environment for local development and production deployment, logging and monitoring.\n\n![Landing and Chat Bot Event — 2](/uploads/projects/gypsy/card-1-2.png)\n\n## Telegram bot functionality\n\n- Participant registration: step-by-step questions, data validation, confirmation.\n- Moderation and statuses: new → under review → approved/rejected; reasons for rejection.\n- Newsletters: segmentation by statuses and events, message templates, delayed sending.\n- Messages: ability to write to support.\n- Reliability: centralised logging, error handling, failure alerts.\n\n![Landing and Chat Bot Event — 3](/uploads/projects/gypsy/card-2-2.png)\n\n## Technology stack\n\n- Backend: PHP (Symfony), Telegram Bot API, Spotify Web API.\n- Frontend: JavaScript, HTML, CSS.\n- Database: PostgreSQL.\n- Environment and deployment: Docker, docker-compose, CI/CD.\n- Logging and monitoring: centralised logging, alerts.\n\n![Landing and Chat Bot Event — 4](/uploads/projects/gypsy/about-me4.png)\n\n## Total\n\nWe created a scalable bundle of website + Telegram bot with a single database and reliable infrastructure. In the course of work, we prepared separate TORs (for both the website and the bot), quickly developed additional sections on the website, integrated Spotify API and implemented video uploading. The solution speeds up the engagement and registration cycle, reduces manual operations and provides transparent metrics for marketing.","subtitle":"Web · Website","challenge":"We developed a comprehensive solution for the event: a conversion-based landing page and a Telegram bot integrated with it for registration, moderation and communication with participants. The project is deployed in a Docker environment, data is stored in PostgreSQL, advanced integrations (Spotify API) and video content uploading are implemented.","description":"Case: Website and Telegram-bot for events | Gypsy Event","stack_detail":"PHP, Symfony, PostgreSQL, Docker, JavaScript, HTML/CSS"},"ru":{"title":"Лендинг и Чат Бот Ивента","result":"Сокращено время модерации заявки за счет статусов и шаблонов. Рост конверсии лендинга благодаря структуре блоков и SEO‑базе. Стабильность под пиковые нагрузки, предсказуемый аптайм. Единая аналитика по воронке сайт → бот → подтверждение. Мы создали масштабируемую связку лендинг + Telegram‑бот с единой базой данных и надежной инфраструктурой. В процессе работ оформили раздельные ТЗ (по лендингу и по боту), оперативно доработали дополнительные разделы на сайте, интегрировали Spotify API и реализовали загрузку видео.","solution":"Мы разработали комплексное решение для мероприятия: конверсионный лендинг и интегрированный с ним Telegram‑бот для регистрации, модерации и коммуникаций с участниками. Проект развернут в Docker‑окружении, данные хранятся в PostgreSQL, реализованы расширенные интеграции (Spotify API) и загрузка видео‑контента.\n\n## Бизнес-цели\n\n- Увеличить число качественных заявок и ускорить их обработку.\n- Снизить ручную модерацию и человеческие ошибки.\n- Обеспечить стабильные рассылки и коммуникации с участниками.\n- Дать маркетингу прозрачные метрики по воронке (сайт → бот → подтверждение).\n\n![Лендинг и Чат Бот Ивента — 1](/uploads/projects/gypsy/card.png)\n\n## Что сделано\n\n- Telegram‑бот: регистрация в 3 шага, статусы заявок, роли модераторов, сегментированные рассылки.\n- Лендинг: четкий оффер, программа/спикеры, социальные доказательства, FAQ, формы заявок.\n- Сквозная аналитика: события на сайте и в боте, отслеживание ключевых конверсий.\n- Инфраструктура: Docker‑окружение для локальной разработки и продакшн‑деплоя, логирование и мониторинг.\n\n![Лендинг и Чат Бот Ивента — 2](/uploads/projects/gypsy/card-1.png)\n\n## Функциональность Telegram‑бота\n\n- Регистрация участников: пошаговые вопросы, валидация данных, подтверждение.\n- Модерация и статусы: новая → на проверке → одобрена/отклонена; причины отклонения.\n- Рассылки: сегментация по статусам и событиям, шаблоны сообщений, отложенные отправки.\n-Сообщения: возможность написать в поддержку.\n- Надежность: централизованное логирование, обработка ошибок, алерты при сбоях.\n\n![Лендинг и Чат Бот Ивента — 3](/uploads/projects/gypsy/card-2.png)\n\n## Технологический стек\n\n- Backend: PHP (Symfony), Telegram Bot API, Spotify Web API.\n- Frontend: JavaScript, HTML, CSS.\n- База данных: PostgreSQL.\n- Окружение и деплой: Docker, docker‑compose, CI/CD.\n- Логи и мониторинг: централизованное логирование, оповещения.\n\n![Лендинг и Чат Бот Ивента — 4](/uploads/projects/gypsy/about-me.png)","subtitle":"Веб · Сайт","challenge":"Требовалось запустить единый цифровой поток: привлечение на лендинге → сбор и модерация заявок → рассылки и уведомления в Telegram. Важны скорость запуска, стабильность под пиковые нагрузки и прозрачная аналитика по всей воронке.","description":"Кейс: лендинг и Telegram-бот для мероприятий | Gypsy Event","stack_detail":"PHP, Symfony, PostgreSQL, Docker, JavaScript, HTML/CSS"}}$row_15$::jsonb)
