INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('belint-new', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2023, false, true, 36, '/uploads/projects/belint-new/placeholder-mobile.png', $row_36${"en":{"title":"Redesign of the Belitertrans","result":"As a result of the redesign of the Belitertrans homepage, users are able to find the information they need faster and easier, which has a positive impact on the usability of the site and on customer satisfaction.","solution":"The new design of Belitertrans' home page was designed to make it as easy and straightforward for users to interact with the company as possible. The page now features clearer and brighter sections such as services, trucking and contacts, which instantly grab users' attention and allow them to quickly find the information they need.\n\n![Redesign of the Belitertrans — 1](/uploads/projects/belint-new/1.png)\n\nParticular attention was paid to the usability of the site on mobile devices. The redesign took into account the growing trend to use mobile devices for searching and booking logistics services. Now Belitertrans's home page is adapted to different screens of mobile devices to ensure a more comfortable and convenient interaction with the company for users using mobile devices.\n\nOverall, the redesign of Belitertrans' home page has improved the user experience and provided a simpler and more informative interface. The company continues to work on improving its services and facilities in order to provide its customers with better logistics solutions.\n\n![Redesign of the Belitertrans — 2](/uploads/projects/belint-new/2.png)\n\nThe Figma tool was used for the redesign of the Belitertrans Logistics Company's homepage. Figma is a handy and functional tool to design layouts for websites and mobile applications.\n\nDuring the development process a new design concept was created which took into account current trends in web design and user needs. One of the main goals was to simplify navigation and improve the visual component of the website.\n\n![Redesign of the Belitertrans — 3](/uploads/projects/belint-new/1440.png)\n\nWork was done to analyze user behavior in order to determine which sections of the site were the most popular and which design elements were the most challenging. Based on this data, new layouts have been developed that are more user-friendly and make it easier to find the necessary information.\n\nGraphic elements and animations were also improved to make the site more appealing to visitors. The new design was tested on a group of users and after receiving positive results, it was implemented on the site.\n\n![Redesign of the Belitertrans — 4](/uploads/projects/belint-new/3.png)\n\n**Project website:** [belint.by](https://belint.by/)","subtitle":"Web · Website","challenge":"Belitertrans is one of the leading logistics companies in Belarus, which provides cargo transportation services of various weights and volumes. The company has recently redesigned its website, including the home page, to provide its customers with a more convenient and informative interface.","description":"Redesign of the Belitertrans homepage: a new look at logistics","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Редизайн Belitertrans","result":"В результате редизайна Главной страницы сайта Belitertrans пользователи могут быстрее и проще находить нужную информацию, что положительно сказывается на удобстве использования сайта и на уровне удовлетворенности клиентов.","solution":"Новый дизайн главной страницы сайта Belitertrans был разработан, чтобы обеспечить максимально простое и понятное взаимодействие пользователей с компанией. На странице теперь представлены более четкие и яркие разделы, такие как услуги, грузоперевозки и контакты, которые мгновенно привлекают внимание пользователей и позволяют им быстро найти нужную информацию.\n\n![Редизайн Belitertrans — 1](/uploads/projects/belint-new/1.png)\n\nОсобое внимание было уделено удобству использования сайта на мобильных устройствах. При редизайне был учтен растущий тренд использования мобильных устройств для поиска и бронирования логистических услуг. Теперь главная страница сайта Belitertrans адаптирована под разные экраны мобильных устройств, что обеспечивает более комфортное и удобное взаимодействие с компанией для пользователей, использующих мобильные устройства.\n\nВ целом, редизайн главной страницы сайта Belitertrans позволил улучшить пользовательский опыт и обеспечить более простой и информативный интерфейс. Компания продолжает работать над улучшением своих сервисов и услуг, чтобы обеспечить своих клиентов лучшими решениями в области логистики.\n\n![Редизайн Belitertrans — 2](/uploads/projects/belint-new/2.png)\n\nДля редизайна Главной страницы сайта Логистической компании Belitertrans был использован инструмент Figma. Figma - это удобный и функциональный инструмент для разработки макетов веб-сайтов и мобильных приложений.\n\nВ процессе разработки была создана новая концепция дизайна, учитывающая современные тенденции веб-дизайна и потребности пользователей. Одной из главных задач было упрощение навигации и улучшение визуальной составляющей сайта.\n\n![Редизайн Belitertrans — 3](/uploads/projects/belint-new/1440.png)\n\nБыла проведена работа по анализу пользовательского поведения, чтобы узнать, какие разделы сайта наиболее популярны и какие элементы дизайна вызывают затруднения. На основе этих данных были разработаны новые макеты, которые удобнее для пользователей и позволяют легко находить необходимую информацию.\n\nТакже были улучшены графические элементы и анимации, чтобы сделать сайт более привлекательным для посетителей. Новый дизайн был протестирован на группе пользователей, и после получения положительных результатов, он был внедрен на сайт.\n\n![Редизайн Belitertrans — 4](/uploads/projects/belint-new/3.png)\n\n**Сайт проекта:** [belint.by](https://belint.by/)","subtitle":"Веб · Сайт","challenge":"Belitertrans - одна из ведущих логистических компаний в Беларуси, которая оказывает услуги по перевозке грузов различного веса и объема. Недавно компания провела редизайн своего сайта, в том числе и главной страницы, чтобы предоставить своим клиентам более удобный и информативный интерфейс.","description":"Редизайн главной страницы сайта Belitertrans: новый взгляд на логистику","stack_detail":"UI/UX, Figma, Photoshop"}}$row_36$::jsonb)
