INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('rating', 'web', ARRAY['web'], ARRAY['Symfony'], 2022, false, true, 38, '/uploads/projects/rating/image-38.png', $row_38${"en":{"title":"RateMeUp","result":"The project was successfully delivered to the client. The work was completed in 2022.","solution":"We love interesting and non-standard tasks and projects! And this time we were approached by a customer with a task that is difficult to name a typical one.\nThe main idea of the project is to form a rating of companies from different business segments. The companies are segmented in a list and analyzed the various terms of these organizations, forming a rating for each of them.\n\nThe project started with the development of technical documentation. Taking into consideration the specific functionality of the project and the program code it is a necessary step to achieve the goals set by the customer. And they were as follows:\n1. Creation of convenient and well-thought-out structure of the site with information about ratings of companies for users. \n2. Providing a list of companies and information about them.\n3. Forming a rating of companies based on user feedback.\n\n![RateMeUp — 1](/uploads/projects/rating/1-sajt.png)\n\nOf course, the Technical Documentation should be present in each project for its successful implementation, but in this case, it is worth highlighting it, especially considering the structure of the project, the number of types of users and their capabilities, the system of project administration, the system of moderation of registered companies/users and feedbacks, as well as individual settings of companies, which are in the top.\n\n![RateMeUp — 2](/uploads/projects/rating/2-shablon.png)\n\nThe documentation included a complete list of requirements for the site to be developed, including a description of the following:\n1. The complete structure of the site.\n2. requirements for functional characteristics\n3. Operating conditions 4.\nDescription of the navigation system of the site (main and additional means of navigation) 5.\n5. Description of components and modules: data structure (list of all fields of the section), description of the appearance of pages of each section.\n6. Description of the structure, capabilities and display parameters of the Symfony modules and components involved in this project.\n\nThe project was developed based on the Symfony framework, which allowed to implementation of all the necessary technical features requested by the customer. In particular, this way of coding allowed setting administration system in such a way that the site administrator could manage all the necessary elements of the site with minimum gestures.\n\n![RateMeUp — 3](/uploads/projects/rating/3-dop-makety.png)\n\nBased on the Symfony framework, automatic verification by registered users has been developed, including the automation of moderation of reviews with the possibility of manual control.\n\nThe project has implemented an algorithm for banner advertising with the possibility of manual control through the site administration system, which allows you to set certain parameters for its display in the necessary sections of the site.\n\n![RateMeUp — 4](/uploads/projects/rating/4-telefon.png)","subtitle":"Web · Website","challenge":"The project started with the development of technical documentation. Taking into consideration the specific functionality of the project and the program code it is a necessary step to achieve the goals set by the customer. And they were as follows: Creation of convenient and well-thought-out structure of the site with information about ratings of companies for users. Providing a list of companies and information about them. Forming a rating of companies based on user feedback.","description":"RateMeUp - Software and Website Development for Company Rankings","stack_detail":"Symfony"},"ru":{"title":"Рейтинг Репутаций","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2022 году.","solution":"Проект стартовал с разработки Технического Документации. С учетом специфики функциональных возможностей проекта и программного кода это необходимая мера для достижения поставленных задач Заказчиком. А они были таковыми:\n1. Создание удобной и продуманной структуры сайта с информацией по рейтингам компаний для пользователей. \n2. Предоставление списка компаний и информации о них.\n3. Формирование рейтинга компаний на основании отзывов пользователей.\n\n![Рейтинг Репутаций — 1](/uploads/projects/rating/1-sajt.png)\n\nКонечно же Техническая Документация должна присутствовать в каждом проекте для успешной его реализации, но в данном случае ее стоит выделить особенно с учетом структуры проекта, кол-ва типов пользователей и их возможностей, системы администрирования проектом, системы модерации зарегистрированными компаниями/пользователями и отзывами, а также индивидуальными настройками компаний, которые в ходят в ТОП.\n\n![Рейтинг Репутаций — 2](/uploads/projects/rating/2-shablon.png)\n\nДокументация включала в себя полный перечень требований к разрабатываемому сайту, включая описание следующих его параметров:\n1. Полная структура сайта.\n2. Требования к функциональным характеристикам\n3. Условия эксплуатации\n4. Описание системы навигации по сайту (основных и дополнительных средств навигации)\n5. Описание компонентов и модулей: структура данных (список всех полей раздела), описание внешнего вида страниц каждого раздела.\n6. Описание структуры, возможностей и параметров отображения модулей и компонентов Symfony, задействованных в данном проекте.\n\nПроект разработан на базе Фреймворка Symfony, что позволило реализовать все необходимые технические возможности запрашиваемые Заказчиком. В том числе, такой вариант разработки программного кода, позволил настроить систему администрирования таким образом, чтобы администратор сайта, мог управлять всеми необходимыми для него элементами сайта с минимальными телодвижениями.\n\n![Рейтинг Репутаций — 3](/uploads/projects/rating/3-dop-makety.png)\n\nНа базе Фреймворка Symfony, была разработана автоматическая верификация зарегистрированными пользователями, в том числе, автоматизация процессов модерации отзывов с возможностью ручного управления.\n\nВ проекте реализован алгоритм баннерной рекламы с возможностью ручного управления через систему администрирования сайтом, которая позволяет задавать определенные параметры ее отображения в нужных разделах сайта.\n\n![Рейтинг Репутаций — 4](/uploads/projects/rating/4-telefon.png)","subtitle":"Веб · Сайт","challenge":"Мы любим интересные и нестандартные задачи и проекты! Вот и в этот раз к нам обратился Заказчик с задачей, которую сложно назвать типовой. Основная идея проекта заключается в формировании рейтинга компаний из различных сегментов вида деятельности. Компании сегментируются списком и анализируя различные критерии этих организаций формируя рейтинг каждой из них.","description":"RateMeUp - разработка программного обеспечения и веб-сайтов для рейтинга компаний","stack_detail":"Symfony"}}$row_38$::jsonb)
