INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('alcohol-mockup', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2022, false, true, 39, '/uploads/projects/alcohol-mockup/image-39.png', $row_39${"en":{"title":"Alcohol website concept idea","result":"The project was successfully delivered to the client. The work was completed in 2022.","solution":"The website structure was optimised, so that all sections of the site, including the alcohol catalogue, could be accessed more easily.\n\nThis concept was developed through Figma technologies. The home page of the possible factory website was presented, with its individual blocks highlighted.\n\n![Alcohol website concept idea — 1](/uploads/projects/alcohol-mockup/13.jpg)\n\n![Alcohol website concept idea — 2](/uploads/projects/alcohol-mockup/15.jpg)\n\n![Alcohol website concept idea — 3](/uploads/projects/alcohol-mockup/8.jpg)\n\n![Alcohol website concept idea — 4](/uploads/projects/alcohol-mockup/9.jpg)\n\n![Alcohol website concept idea — 5](/uploads/projects/alcohol-mockup/10.jpg)\n\n![Alcohol website concept idea — 6](/uploads/projects/alcohol-mockup/16.jpg)\n\n![Alcohol website concept idea — 7](/uploads/projects/alcohol-mockup/17.jpg)\n\n![Alcohol website concept idea — 8](/uploads/projects/alcohol-mockup/11.jpg)","subtitle":"Web · Website","challenge":"This concept was developed for a factory for the production and sale of alcoholic products. Our task was to create a completely new visualisation of the website and to present the factory as a producer and distributor.","description":"Development of a website design concept for an alcohol production and sale factory","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Концепт-идея сайта алкогольной продукции","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2022 году.","solution":"Была оптимизирована структура веб-сайта, для более простого доступа ко всем разделам сайта, в том числе к алкогольному каталогу.\n\nДанная концепция разрабатывалась через технологии Figma. Была представлена Главная страница возможного сайта завода с выделением отдельных ее блоков.\n\n![Концепт-идея сайта алкогольной продукции — 1](/uploads/projects/alcohol-mockup/13.jpg)\n\n![Концепт-идея сайта алкогольной продукции — 2](/uploads/projects/alcohol-mockup/15.jpg)\n\n![Концепт-идея сайта алкогольной продукции — 3](/uploads/projects/alcohol-mockup/8.jpg)\n\n![Концепт-идея сайта алкогольной продукции — 4](/uploads/projects/alcohol-mockup/9.jpg)\n\n![Концепт-идея сайта алкогольной продукции — 5](/uploads/projects/alcohol-mockup/10.jpg)\n\n![Концепт-идея сайта алкогольной продукции — 6](/uploads/projects/alcohol-mockup/16.jpg)\n\n![Концепт-идея сайта алкогольной продукции — 7](/uploads/projects/alcohol-mockup/17.jpg)\n\n![Концепт-идея сайта алкогольной продукции — 8](/uploads/projects/alcohol-mockup/11.jpg)","subtitle":"Веб · Сайт","challenge":"Данный концепт разрабатывался для Завода по производству и продаже алкогольной продукции. наша задача состояла в создании абсолютно новой визуализации сайта и представления Завода как производителя так и дистрибутора.","description":"Разработка концепт дизайна сайта для Завода о производству и продаже алкоголя","stack_detail":"UI/UX, Figma, Photoshop"}}$row_39$::jsonb)
