INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('unitess', 'web', ARRAY['web'], ARRAY['PHP', 'Symfony', 'Figma', 'HTML/CSS'], 2022, false, true, 41, '/uploads/projects/unitess/dlya-kompika.jpg', $row_41${"en":{"title":"UNITESS Website Development","result":"The project was successfully launched and is available at unitessambient.com. The work was completed in 2022.","solution":"A classic project for our customer UNITESS, which in turn is engaged in a completely non-standard production - the development of automated workstations and hardware and software systems for testing, verification and calibration laboratories.\n\n![UNITESS Website Development — 1](/uploads/projects/unitess/1.jpg)\n\nThe Customer approached us with the task of developing a new website unitessambient.com. After a detailed briefing we set the following stages of the project development:\n\n1. Development of Technical Documentation according to the project budget\n2. Agreeing on the final estimate based on the agreed documentation\n3. Development of a prototype design\n4. Site design development including adaptation for mobile devices. There were chosen 3 resolutions for adaptive design. \n5. Front-end development.\n6. Back-end development. Creation of project administration system based on Symfony framework, with the ability to manage all the elements of the site.\n\n![UNITESS Website Development — 2](/uploads/projects/unitess/2.jpg)\n\n![UNITESS Website Development — 3](/uploads/projects/unitess/4.jpg)\n\nThe process of creating this project was thoroughly checked by the customer and coordination with various departments of the company.\n\n![UNITESS Website Development — 4](/uploads/projects/unitess/5.jpg)\n\nThe methodology for the introduction of the project was determined by Kanban. It allowed an even distribution of tasks between the team, which in turn made the whole development process transparent to both team members and the responsible person of the customer.\n\nTechnology stack which was involved in this project is not great (figma, HTML, JS, Symfony, PHP, CSS), but it was more than enough for the successful launch of the site.\n\n![UNITESS Website Development — 5](/uploads/projects/unitess/6.jpg)\n\n**Project website:** [unitessambient.com](https://unitessambient.com/)","subtitle":"Web · Website","challenge":"The Customer approached us with the task of developing a new website unitessambient.com. After a detailed briefing we set the following stages of the project development:","description":"Development of a corporate catalog for UNITESS","stack_detail":"PHP, Symfony, Figma, HTML/CSS"},"ru":{"title":"Разработка Сайта UNITESS","result":"Проект успешно запущен и доступен по адресу unitessambient.com. Работы выполнены в 2022 году.","solution":"Классический проект для нашего Заказчика UNITESS, который в свою очередь занимается совершенно не стандартным производством - разработкой автоматизированных рабочих мест и аппаратно-программных комплексов для испытательных, поверочных и калибровочных лабораторий.\n\n![Разработка Сайта UNITESS — 1](/uploads/projects/unitess/1.jpg)\n\nА к нам Заказчик обратился с задачей по разработке нового сайта unitessambient.com. После детального Брифинга мы установили следующие этапы разработки проекта:\n\n1. Разработка Технического Задания согласно бюджета проекта\n2. Согласование финальной оценки исходя из согласованной документации\n3. Разработка прототипа дизайна сайта\n4. Разработка дизайна сайта в том числе адаптация его под мобильные устройства. Было выбрано 3 разрешения для адаптивного дизайна. \n5. Верстка дизайна сайта.\n6. Программирование сайта. Создание системы администрирования проекта на базе фреймворка Symfony, с возможностью управления всеми элементами сайта.\n\n![Разработка Сайта UNITESS — 2](/uploads/projects/unitess/2.jpg)\n\n![Разработка Сайта UNITESS — 3](/uploads/projects/unitess/4.jpg)\n\nПроцесс создания данного проекта, проходил тщательную проверку Заказчиком и согласования с различными отделами компании.\n\n![Разработка Сайта UNITESS — 4](/uploads/projects/unitess/5.jpg)\n\nМетодология введения данного проекта была определена Kanban. Это позволило равномерно распределить задачи между командой, что в свою очередь сделало весь процесс разработки прозрачным как для членов команды, так и для ответственного лица Заказчика.\n\nСтек технологий который был задействован на данном проекте не велик (figma, HTML, JS, Symfony, PHP, CSS), но его было больше чем достаточно для успешного запуска сайта.\n\n![Разработка Сайта UNITESS — 5](/uploads/projects/unitess/6.jpg)\n\n**Сайт проекта:** [unitessambient.com](https://unitessambient.com/)","subtitle":"Веб · Сайт","challenge":"А к нам Заказчик обратился с задачей по разработке нового сайта unitessambient.com. После детального Брифинга мы установили следующие этапы разработки проекта:","description":"Разработка корпоративного каталога для UNITESS","stack_detail":"PHP, Symfony, Figma, HTML/CSS"}}$row_41$::jsonb)
