INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('fdc', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2021, false, true, 42, '/uploads/projects/fdc/dlya-kompika.jpg', $row_42${"en":{"title":"Football Development Center","result":"The project was successfully launched and is available at fdc.by. The work was completed in 2021.","solution":"We love to work on sports projects! Especially related to the development of the younger generation.\n\nAnother football project is leaving for our partners in the city of Brest. The project is aimed at developing young football talents throughout the Republic of Belarus.\n\n![Football Development Center — 1](/uploads/projects/fdc/1.jpg)\n\nTo attract the attention and development of this Center, the task was to develop a one-page website with basic information about the Center itself, its events and contacts.\n\n![Football Development Center — 2](/uploads/projects/fdc/2.jpg)\n\nThe moment of the teams' results in various tournaments was not ignored either.\n\nSite content management is carried out entirely in manual mode through the site administration system.\n\n![Football Development Center — 3](/uploads/projects/fdc/3.jpg)\n\n**Project website:** [fdc.by](https://fdc.by/)","subtitle":"Web · Landing page","challenge":"To attract the attention and development of this Center, the task was to develop a one-page website with basic information about the Center itself, its events and contacts.","description":"Development of a landing page for the Football Development Center to attract and train the best young players in Belarus.","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Центр развития футбола","result":"Проект успешно запущен и доступен по адресу fdc.by. Работы выполнены в 2021 году.","solution":"Любим мы работать над спортивными проектами! Особенно связанными с развитием юного поколения.\n\nОчередной проект футбольной тематики уезжает к нашим партнёрам в город Брест. Проект нацелен на развитие юных футбольных дарований по всей Республики Беларусь.\n\n![Центр развития футбола — 1](/uploads/projects/fdc/1.jpg)\n\nДля привлечения внимания и развития данного Центра был поставлена задача разработки одностраничного сайта с базовой информацией о самом Центре, его событиях и контактах.\n\n![Центр развития футбола — 2](/uploads/projects/fdc/2.jpg)\n\nНе обошло внимание и момент результатов команд в различных турнирах.\n\nУправление содержимым сайта осуществляться полностью в ручном режиме через систему администрирования сайтом.\n\n![Центр развития футбола — 3](/uploads/projects/fdc/3.jpg)\n\n**Сайт проекта:** [fdc.by](https://fdc.by/)","subtitle":"Веб · Лендинг","challenge":"Для привлечения внимания и развития данного Центра был поставлена задача разработки одностраничного сайта с базовой информацией о самом Центре, его событиях и контактах.","description":"Разработка лендинга для Центра Развития Футбола для привлечения и обучения лучших молодых игроков Беларуси.","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_42$::jsonb)
