INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('theview-lending', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2020, false, true, 48, '/uploads/projects/theview-lending/0cfa32d07f4b4ff59943475a896205de.jpg', $row_48${"en":{"title":"Landing page for 3D Player","result":"The project was successfully launched and is available at theviewvr.com. The work was completed in 2020.","solution":"Our team analyzed the activities of the Customer's company (3D tours), the market segment (developers in the USA) and competitors in this segment, and was able to form the missing information.\n\n![Landing page for 3D Player — 1](/uploads/projects/theview-lending/364673ed07914973af5c03c8cc4a3556.png)\n\nThe structure was developed by prototyping. After approval, the design team developed the visual component of this project.\n\nInteresting moments of this project are the integration of the iframe 3D player, as well as the insertion of gif images into separate blocks of the landing page.\n\n![Landing page for 3D Player — 2](/uploads/projects/theview-lending/e9a95cba493341808a3a80b95e42a11a.png)\n\n![Landing page for 3D Player — 3](/uploads/projects/theview-lending/12135fc1e990445d8bcda6292794983e.png)\n\n**Project website:** [theviewvr.com](https://theviewvr.com)","subtitle":"Web · Landing page","challenge":"We started developing this project with a special approach. The Customer had an idea only about the Goals of this project, and what Tasks and how the landing page should solve them - no.","description":"Landing page development for The View company","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Лендинг для 3D Плеера","result":"Проект успешно запущен и доступен по адресу theviewvr.com. Работы выполнены в 2020 году.","solution":"Наша команда проанализировав деятельность компании Заказчика (3D туры), сегмент рынка (застройщики в США) и конкурентов на данном сегменте, смогла сформировать недостающие пазлы.\n\n![Лендинг для 3D Плеера — 1](/uploads/projects/theview-lending/81c6a8e9f60a4074b908d4778977b04b.png)\n\nИсходя из полученных данных, была сформирована структура лендинга и его функциональная составляющая. \nСтруктура разрабатывалась методом прототипирования. После согласования команда дизайнеров разработала визуальную составляющую данного проекта.\n\nК фишкам данного проекта можно отнести интеграцию iframe 3D плеера, а так же вставку gif изображений в отдельные блоки лендинга.\n\n![Лендинг для 3D Плеера — 2](/uploads/projects/theview-lending/01ac60fd65e24192adbf47b652f27416.png)\n\n![Лендинг для 3D Плеера — 3](/uploads/projects/theview-lending/e4733605eea4413f820677fc98e65479.png)\n\n**Сайт проекта:** [theviewvr.com](https://theviewvr.com)","subtitle":"Веб · Лендинг","challenge":"Разработкой данного проекта мы принялись с особым подходом. Дело в том, что у Заказчика было представление только о Цели данного проекта, а какие Задачи и каким образом должен решать данный проект - нет.","description":"Разработка Лендинга для компании The View","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_48$::jsonb)
