INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('rsm', 'web', ARRAY['web'], ARRAY['HTML/CSS'], 2020, false, true, 49, '/uploads/projects/rsm/1b3ec941628241f885a1aa60efb1038f.jpg', $row_49${"en":{"title":"Marketing Agency Website","result":"The project was successfully launched and is available at rsmpro.by. The work was completed in 2020.","solution":"We were contacted by the marketing agency RSM. The task they set us was not new - the creation of a new website for the company. A site where you can post their creative projects, where you can show your work and achievements.\n\n![Marketing Agency Website — 1](/uploads/projects/rsm/dcae3dbbf73048179fe73b14d82b108a.png)\n\n![Marketing Agency Website — 2](/uploads/projects/rsm/c99ec5c34bf14ba984bf5a5029e1270f.png)\n\nSince the project of our Customer has creativity, the very implementation of such a site should not be inferior.\n\nHaving disassembled all the details of the project into its components, our development team prepared a detailed plan of all possible nuances awaiting us in this project and how they can be solved.\n\nThe Customer's reaction was not long in coming and we started to create this project.\n\nThe main stages of this project:\n1. Creation of Technical Documentation\n2. Designation of break points of the fron-end\n3. Development of software\n4. Testing the project\n\n![Marketing Agency Website — 3](/uploads/projects/rsm/42a09469992f4719abf065404e08dcea.png)\n\nEach stage includes various sub-stages that are worked out by the entire team working on the project.\n\nIn the development of a new site for the marketing agency RSM, special animation effects of the site's navigation menu were developed.\nIn general, the product version of the site fully reflects the essence of the agency itself. And the most important thing is the positive emotions of the Customer.\n\n![Marketing Agency Website — 4](/uploads/projects/rsm/a627dcad63c6493d8c46956d4afe43ba.png)\n\n**Project website:** [rsmpro.by](https://rsmpro.by)","subtitle":"Web · Website","challenge":"Our company is very fond of helping other creative agencies with various interesting tasks. So the new project has become such.","description":"Development of a portfolio website for the RSM marketing agency","stack_detail":"HTML/CSS"},"ru":{"title":"Сайт Маркетингового Агентства","result":"Проект успешно запущен и доступен по адресу rsmpro.by. Работы выполнены в 2020 году.","solution":"К нам обратилось маркетинговое агентство RSM. Задача которую они нам поставили была не нова - создание нового сайта компании. Сайта на котором можно будет разместить их креативные проекты, где можно показать свои работы и наработки.\n\n![Сайт Маркетингового Агентства — 1](/uploads/projects/rsm/6469e3aa6c9f480d8b0023f810dbc057.png)\n\n![Сайт Маркетингового Агентства — 2](/uploads/projects/rsm/409ffde8da6344f4abd181cc2196bdb1.png)\n\nТак как проекту у нашего Заказчика обладают креативом сам подход к реализации и сама реализация такого сайта не должны уступать.\n\nРазобрав все детали проекта на составляющие наша команда разработчиков подготовила подробный план всех возможных подводных камней ожидающих нас в данном проекте и как их можно решить.\n\nРеакция Заказчика не заставила себя ждать и мы приступили к созданию данного проекта.\n\nОсновные стадии данного проекта:\n1. Создание Технической документации\n2. Обозначение точек излома верстки\n3. Разработка программной части\n4. Тестирование проекта\n\n![Сайт Маркетингового Агентства — 3](/uploads/projects/rsm/118251c52a914f1981e80d969df21931.png)\n\nКаждый этап включает в себя различные под этапы которые прорабатывается всей командой работающей над проектом.\n\nВ разработке нового сайта для маркетингового агентства RSM были разработаны специальные анимационные эффекты работы навигационного меню сайта.\n\nВ целом, продакт версия сайта, полностью отражает сущность самого агентства. Ну и самое главное - это положительные эмоции Заказчика.\n\n![Сайт Маркетингового Агентства — 4](/uploads/projects/rsm/27b61a936a994f1d85b03d9bce4389d1.png)\n\n**Сайт проекта:** [rsmpro.by](https://rsmpro.by)","subtitle":"Веб · Сайт","challenge":"Наша компания очень любит помогать другим креативным агентствам с различными интересными задачами. Вот и новый проект стал таковым.","description":"Разработка сайта-портфолио для маркетингового агентства RSM","stack_detail":"HTML/CSS"}}$row_49$::jsonb)
