INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('polimaster-new', 'web', ARRAY['web'], ARRAY['HTML/CSS'], 2020, false, true, 50, '/uploads/projects/polimaster-new/26f42d7975b54102b58716796e61e8dd.jpg', $row_50${"en":{"title":"New version of Polimaster website","result":"The project was successfully launched and is available at dev.polimaster.eu. The work was completed in 2020.","solution":"As part of such a service for OJSC \"Polimaster\" we decided to offer our Customer to update the design of the polimaster.com website.\n\n![New version of Polimaster website — 1](/uploads/projects/polimaster-new/dcdf54155f9941ecaf34f0875656e266.png)\n\nTaking into account the specifics of the work of the company Polimaster, it was decided to start a systematic change in the visualization of this project. And we decided to start from the Home page.\n\nThrough the joint efforts of our design team and the responsible persons from Polimaster, we have concentrated on the idea of implementing the visual part of the main page using separate Blocks with parallax.\n\n![New version of Polimaster website — 2](/uploads/projects/polimaster-new/1b3a4ce3d774409baac3170dfeba2df9.png)\n\nThis visualization style will have to be pursued on all elements of the site in the internal sections in the future.\n\n![New version of Polimaster website — 3](/uploads/projects/polimaster-new/ab25a93e30c44fb7adf957befd982c6c.png)\n\n**Project website:** [dev.polimaster.eu](https://dev.polimaster.eu)","subtitle":"Web · Website","challenge":"Having in stock such services as Website Support, we can provide a wide range of services for the maintenance and modernization of websites.","description":"Redesign of the main page of the Polimaster website","stack_detail":"HTML/CSS"},"ru":{"title":"Новая версия сайта Polimaster","result":"Проект успешно запущен и доступен по адресу dev.polimaster.eu. Работы выполнены в 2020 году.","solution":"В рамках такой услуги для ОАО \"Полимастер\" мы решили предложить нашему Заказчику обновить дизайн сайта polimaster.com.\n\n![Новая версия сайта Polimaster — 1](/uploads/projects/polimaster-new/fd45825ac9674b1aae41a948d5ad021c.png)\n\nС учетом специфики работы компании Полимастер,было принято решение начать планомерное изменение визуализации данного проекта. И мы решили начат с Главной страницы.\n\nОбщими усилиями нашей команды дизайнеров и ответственными лицами со стороны Полимастер, мы сконцентрировались на идеи реализации визуальной части главной страницы по средством отдельных Блоков с параллакс версткой.\n\n![Новая версия сайта Polimaster — 2](/uploads/projects/polimaster-new/5e190318f5864490a457c75669dcdc26.png)\n\nДанный стиль визуализации должен будет преследоваться на всех элементах сайта во внутренних разделов в будущем.\n\n![Новая версия сайта Polimaster — 3](/uploads/projects/polimaster-new/b9e8786eb2af4b16a40e7ff9efae15f7.png)\n\n**Сайт проекта:** [dev.polimaster.eu](https://dev.polimaster.eu)","subtitle":"Веб · Сайт","challenge":"Имея в запасе такие услуги как Поддержка сайтов, мы можем оказывать широкий спектр услуг по обслуживанию и модернизации сайтов.","description":"Редизайн главной страницы сайта Полимастер","stack_detail":"HTML/CSS"}}$row_50$::jsonb)
