INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('abff-comet', 'backend', ARRAY['backend'], ARRAY['PHP', 'MySQL', 'JavaScript'], 2019, false, true, 54, '/uploads/projects/abff-comet/bez-imeni-2.png', $row_54${"en":{"title":"Integration with COMET","result":"The project was successfully launched and is available at championship.abff.by. The work was completed in 2019.","solution":"When it comes to managing sporting events, keeping match records and counting player statistics are critical tasks. The National Championship of the Republic of Belarus was also faced with these challenges. We have implemented integration between the Championship website and the COMET system to automate match report entry and statistical calculations.\n\n![Integration with COMET — 1](/uploads/projects/abff-comet/bez-imeni.png)\n\nCOMET is a match management system which allows referees and club representatives to enter match protocols and statistics for all games, players, clubs, coaches, etc. This system can now be integrated with the RB championship website.\n\nThe integration process has started with creation of an API for communication between the championship site and the COMET system. After that we have developed an interface that allows referees and clubs' representatives to input match records and statistics into the COMET system. All the data entered into the COMET system is automatically updated on the championship website by means of an API.\n\n![Integration with COMET — 2](/uploads/projects/abff-comet/untitled-mockup.png)\n\nThe website of National Championship RB now shows all data entered in the COMET system. The match records, player, club and coach statistics are automatically updated on the website. The website also enables viewing of statistics for the entire championship as a whole as well as for each individual player.\n\nThe integration of the Championship RB website with the COMET system has greatly simplified the process of recording matches and tallying statistics, saving time and money on administration and management of competitions.\n\n![Integration with COMET — 3](/uploads/projects/abff-comet/untitled-mockup-1.png)\n\n**Project website:** [championship.abff.by](https://championship.abff.by)","subtitle":"Backend · Platform","challenge":"Integration of a football federation website with COMET: automating the process of entering match protocols and statistics","description":"Football federation website integration with COMET: automating the process of entering match protocols and statistics","stack_detail":"PHP, MySQL, JavaScript"},"ru":{"title":"Интеграция с COMET","result":"Проект успешно запущен и доступен по адресу championship.abff.by. Работы выполнены в 2019 году.","solution":"Интеграция сайта футбольной федерации с COMET: автоматизация процессов введения протоколов матчей и статистики\n\nКогда дело доходит до управления спортивными соревнованиями, ведение протоколов матчей и подсчет статистики игроков являются критически важными задачами. Национальное Первенство по футболу Республики Беларусь также столкнулось с этими вызовами. Для автоматизации процессов ввода протоколов матчей и подсчета статистики мы реализовали интеграцию между сайтом чемпионата и системой COMET.\n\n![Интеграция с COMET — 1](/uploads/projects/abff-comet/2704f5aa4a374e5784e3786511c58a48.jpg)\n\nCOMET - это система управления футбольными матчами, которая позволяет судьям и представителям клубов вводить протоколы матчей и статистику по всем играм, игрокам, клубам, тренерам и т.д. Теперь эта система может быть интегрирована с сайтом чемпионата РБ.\n\nПроцесс интеграции начался с создания API для взаимодействия между сайтом чемпионата и системой COMET. После этого мы разработали интерфейс, который позволяет судьям и представителям клубов вводить протоколы матчей и статистику в систему COMET. Все данные, введенные в систему COMET, автоматически обновляются на сайте чемпионата по средством API.\n\n![Интеграция с COMET — 2](/uploads/projects/abff-comet/2e1c985c6b704656846871ea044f5f9a.png)\n\nСайт чемпионата РБ теперь отображает все данные, вводимые в систему COMET. Протоколы матчей, статистика по игрокам, клубам и тренерам автоматически обновляются на сайте. Сайт также позволяет просматривать статистику как для всего чемпионата в целом, так и для каждого отдельного игрока.\n\nИнтеграция сайта чемпионата РБ с системой COMET значительно упростила процесс ведения протоколов матчей и подсчета статистики, сэкономив время и средства на администрирование и управление соревнованиями.\n\n![Интеграция с COMET — 3](/uploads/projects/abff-comet/untitled-mockup-1.png)\n\n**Сайт проекта:** [championship.abff.by](https://championship.abff.by)","subtitle":"Бэкенд · Платформа","challenge":"Когда дело доходит до управления спортивными соревнованиями, ведение протоколов матчей и подсчет статистики игроков являются критически важными задачами. Национальное Первенство по футболу Республики Беларусь также столкнулось с этими вызовами. Для автоматизации процессов ввода протоколов матчей и подсчета статистики мы реализовали интеграцию между сайтом чемпионата и системой COMET.","description":"Интеграция сайта футбольной федерации с COMET: автоматизация процессов введения протоколов матчей и статистики","stack_detail":"PHP, MySQL, JavaScript"}}$row_54$::jsonb)
