INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('polimaster-promo', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2019, false, true, 55, '/uploads/projects/polimaster-promo/4010fbf8241949e1a340923cb00ed52d.jpg', $row_55${"en":{"title":"Promo Sites for Polimaster","result":"The project was successfully launched and is available at pm2012mb.polimaster.com. The work was completed in 2019.","solution":"Also, the development of five clones of this landing for five other individual products of the company.\n\n![Promo Sites for Polimaster — 1](/uploads/projects/polimaster-promo/608c8e60554d4b01a2ab59b28daa17cb-2.png)\n\nThe information on these one-page websites displays all the characteristics of the already complex devices manufactured by Polimaster.\n\n![Promo Sites for Polimaster — 2](/uploads/projects/polimaster-promo/bac568d4bfa14dcdbf031bf35aa83a58-2.png)\n\nThis project was developed using corporate colors of the company, as well as with an adaptive design for all possible resolutions of mobile devices.\n\nThe project was developed for a target audience from South America. The main language of these landing pages is Spanish.\n![Promo Sites for Polimaster — 3](/uploads/projects/polimaster-promo/10229f3f07864c4f896c385f42546eb7-2.png)\n\n**Project website:** [pm2012mb.polimaster.com](https://pm2012mb.polimaster.com)","subtitle":"Web · Landing page","challenge":"The task is to create a landing page for a separate company product with the goal of advertising it in individual regions.","description":"Development of 5 landing pages, for individual product lines manufactured by Polimaster","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Промо-сайты для Polimaster","result":"Проект успешно запущен и доступен по адресу pm2012mb.polimaster.com. Работы выполнены в 2019 году.","solution":"Так же, необходимо была реализация 5-ти клонов данного лендинга, для 5-ти других отдельно взятых продуктов компании.\n\n![Промо-сайты для Polimaster — 1](/uploads/projects/polimaster-promo/608c8e60554d4b01a2ab59b28daa17cb.png)\n\nИнформация на данных одностраничных сайтах, должна максимально отражать все характеристики и без того сложных приборов производимых в компании Polimaster.\n\n![Промо-сайты для Polimaster — 2](/uploads/projects/polimaster-promo/bac568d4bfa14dcdbf031bf35aa83a58.png)\n\nДанный проект создавался с использованием фирменных цветов компании, а так же с адаптивным дизайном под все возможные разрешения мобильных устройств.\n\nПроект создавался для целевой аудитории из Южной Америки. основной язык данных лендингов - Испанский. \n![Промо-сайты для Polimaster — 3](/uploads/projects/polimaster-promo/10229f3f07864c4f896c385f42546eb7.png)\n\n**Сайт проекта:** [pm2012mb.polimaster.com](https://pm2012mb.polimaster.com)","subtitle":"Веб · Лендинг","challenge":"Нам была поставлена следующая задача - Создания лендинга, для отдельного продукта компании с целью рекламирования его в отдельно взятых регионах.","description":"Разработка 5-ти лендингов, под отдельные направления продукции, производимых компанией Polimaster","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_55$::jsonb)
