INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('gdrive', 'web', ARRAY['web'], ARRAY['Symfony'], 2019, false, true, 57, '/uploads/projects/gdrive/group-24.png', $row_57${"en":{"title":"Development of the G-Drive promotional website","result":"The project was successfully delivered to the client. The work was completed in 2019.","solution":"Project represents landing page for users registration/authorization, information tracking about winning codes and numbers.\n\nThe site is developed on tha basis of framwork Simfony with automatic code loding, which are given to each user by their loyalty card numbers.\n\n![Development of the G-Drive promotional website — 1](/uploads/projects/gdrive/09c7c068529c4384bb4232cb203e9c23-2.png)\n\nAlso we developed own email system with the possebility to track the status of sending and re-sending letters.\n\n![Development of the G-Drive promotional website — 2](/uploads/projects/gdrive/ef90cbefcac94de1a9aeecc700acfa80-2.png)\n\nEach second code assigned to the user is credited with a number that participates in the MAIN PRIZE draw - A trip for two to the Grand Prix race in Sochiи.\n\nThe project was completed in the corporate colors of the Gdrive fuel brand. The site is developed responsive for all devices.\"\n\n![Development of the G-Drive promotional website — 3](/uploads/projects/gdrive/71001c16009d4df082233827af1615fe-2.png)","subtitle":"Web · Landing page","challenge":"Is was neccessary to develop and launch promo site for user registration taking part in advertising game of FLLS \"\"Gazpromneft-Belnefteproduct\"\" compony.","description":"Promotional website development for an oil and gas enterprise: code tracking and prize draw","stack_detail":"Symfony"},"ru":{"title":"Разработка промо сайта G-Drive","result":"В результате наша команда успешно разработала промо сайт для нефтегазового предприятия, который позволяет клиентам легко регистрироваться и отслеживать свои выигрыши, а также участвовать в розыгрыше призов .","solution":"Нефтегазовые предприятия всегда стремятся к увеличению лояльности своих клиентов и расширению своей аудитории. Использование промо сайта с розыгрышем призов - один из наиболее эффективных инструментов в этой сфере. В данной статье мы рассмотрим процесс разработки промо сайта для нефтегазового предприятия, который позволяет отслеживать коды и проводить розыгрыш призов.\n\nДля начала, наша команда разработчиков в Piplos Media провела анализ требований клиента и выявила основные задачи, которые должен решать сайт: регистрация/авторизация пользователей, отслеживание информации о выигравших кодах и номерах, розыгрыш призов.\n\n![Разработка промо сайта G-Drive — 1](/uploads/projects/gdrive/09c7c068529c4384bb4232cb203e9c23.png)\n\nМы использовали фреймворк Symfony для разработки сайта, который обеспечивает быструю и эффективную работу сайта. Также была разработана собственная система email-рассылки с возможностью отслеживания статусов отправки писем и повторной отправки, чтобы убедиться, что все зарегистрированные пользователи получили необходимую информацию о розыгрыше призов.\n\nКоды были присвоены каждому пользователю по номеру карты лояльности, которые были загружены на сайт автоматически. Таким образом, все зарегистрированные пользователи могут отслеживать свои выигрыши и участвовать в розыгрыше ГЛАВНОГО ПРИЗА - Поездка на двоих на гонку Гран-При в Сочи.\n\n![Разработка промо сайта G-Drive — 2](/uploads/projects/gdrive/ef90cbefcac94de1a9aeecc700acfa80.png)\n\nВажным аспектом разработки промо сайта было использование корпоративных цветов топливной марки Gdrive, что позволило создать узнаваемый бренд и повысить узнаваемость среди клиентов.\n\nНаша команда также разработала сайт, который адаптирован под все устройства. Это значит, что пользователи могут легко получать доступ к сайту и участвовать в розыгрыше призов с любого устройства, будь то смартфон, планшет или компьютер.\n\n![Разработка промо сайта G-Drive — 3](/uploads/projects/gdrive/71001c16009d4df082233827af1615fe.png)","subtitle":"Веб · Лендинг","challenge":"Для начала, наша команда разработчиков в Piplos Media провела анализ требований клиента и выявила основные задачи, которые должен решать сайт: регистрация/авторизация пользователей, отслеживание информации о выигравших кодах и номерах, розыгрыш призов.","description":"Разработка промо сайта для нефтегазового предприятия: отслеживание кодов и розыгрыш приза","stack_detail":"Symfony"}}$row_57$::jsonb)
