INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('voka-tv', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2019, false, true, 58, '/uploads/projects/voka-tv/86cbfcca43d84bacafe2b7674ed1ba49.jpg', $row_58${"en":{"title":"Voka's Birthday","result":"The project was successfully delivered to the client. The work was completed in 2019.","solution":"This game was held due to stimulate customers to use Voka's service \"Voka all inclusive\".\n\nAlso the project was timed to Voka's fifth birthday!\n\nThe essence of the project is simple - a user should log in and get a promo code after the registration,_given code can be used for voka.tv subscription.\n\n![Voka's Birthday — 1](/uploads/projects/voka-tv/e1db5fb52561415c982b8fe98e46b739-2.png)\n\n![Voka's Birthday — 2](/uploads/projects/voka-tv/7fe55810eb3246489cfbaf86de6d941e-2.jpg)\n\nAll styles, colours and fonts were used from Voka's corporate brend book.\n\n![Voka's Birthday — 3](/uploads/projects/voka-tv/4c4054f935984149879a3bbcdd426059-2.png)\n\nThis project could not do without an interective part.\n\nVideo game.\n\nThe essence of the game is in the possibility of sticking several videos together and the possibility of enterring congatulation on the video.\n\nEach user can share his results in social networksх.\n\n![Voka's Birthday — 4](/uploads/projects/voka-tv/7f9a02a3e76b4832a093ac22b31e5628-2.png)\n\nIt goes without saying that the project was realised/implemented adaptive for all the most popular mobile device resolutions.\n\n![Voka's Birthday — 5](/uploads/projects/voka-tv/394c650a76154f66a0da8842edfe210a-2.png)","subtitle":"Web · Landing page","challenge":"For \"A1\" company in the voka.tv project's bounderies we have developed promo site for participation in advertising game \"Voka's Birthday\".","description":"Advertising game dedicated to Voka's Birthday.","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"День Рождения VOKA","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2019 году.","solution":"Для компании \"А1\", в рамках проекта voka.tv, мы разработали промо сайт для участия в рекламной игре \"День Рождения VOKA\".\n\nДанная игра проводится с целью стимулировать потребителей использовать услугу VOKA - \"VOKA Все включено\".\n\nТак же проект приурочен ко дню рождения VOKA - 5 лет!\n\nСуть проекта заключается в простом - пользователю необходимо зарегистрироваться, после чего он получает промо код, который сможет использовать для подписки на voka.tv.\n\n![День Рождения VOKA — 1](/uploads/projects/voka-tv/e1db5fb52561415c982b8fe98e46b739.png)\n\n![День Рождения VOKA — 2](/uploads/projects/voka-tv/7fe55810eb3246489cfbaf86de6d941e.jpg)\n\nВсе стили, цвета и шрифты использовались из корпоративного брендбука VOKA.\n\n![День Рождения VOKA — 3](/uploads/projects/voka-tv/4c4054f935984149879a3bbcdd426059.png)\n\nТак же, в проект не обошлось и без интерактивной части.\n\nВИДЕО ИГРА.\n\nСуть игры заключается в возможности склейки нескольких видео, в одно единое. Так же, мы добавили возможность ввода поздравительного текста в само видео.\n\nРезультатом каждый пользователь сможет поделиться в социальных сетях.\n\n![День Рождения VOKA — 4](/uploads/projects/voka-tv/7f9a02a3e76b4832a093ac22b31e5628.png)\n\nКонечно же проект был реализован адаптивным под все самые популярные разрешения мобильных устройств.\n\n![День Рождения VOKA — 5](/uploads/projects/voka-tv/394c650a76154f66a0da8842edfe210a.png)","subtitle":"Веб · Лендинг","challenge":"Данная игра проводится с целью стимулировать потребителей использовать услугу VOKA - \"VOKA Все включено\".","description":"Рекламная игра ко дню рождения VOKA","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_58$::jsonb)
