INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('2gkb', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2019, false, true, 59, '/uploads/projects/2gkb/placeholder-2.jpg', $row_59${"en":{"title":"Concept for Hospital website","result":"The project was successfully launched and is available at 2gkb.by. The work was completed in 2019.","solution":"In a short period of time, we were able to present our vision of this project to the Customer..\n\nThe basic essence is the separation of all areas of the hospital's activity into promotional sites, with its structure, the ability to record and information for visitors.\n\n![Concept for Hospital website — 1](/uploads/projects/2gkb/d7a09f8a932c4065848f08f487af7951.png)\n\nThe main site is a summary of all the information about Olnitsa itself and the news feed, which Zakczyk decided to devote most of his time to.\n\n![Concept for Hospital website — 2](/uploads/projects/2gkb/bcbc21784cdc45b2bbbf8eff9c90a128.png)\n\nPromo sites - this is a separate site for each direction of the hospital, with the possibility of making an appointment with an accessible doctor.\n\n![Concept for Hospital website — 3](/uploads/projects/2gkb/ef5f48b4f5394cfe83d4bf4a9c14036f.png)\n\n![Concept for Hospital website — 4](/uploads/projects/2gkb/e93b6a4be9f84e04868bd29cc8af83d9.png)\n\n![Concept for Hospital website — 5](/uploads/projects/2gkb/8341be859a5d4adab081b74c07a9e4c7.png)\n\n**Project website:** [2gkb.by](https://2gkb.by)","subtitle":"Web · Website","challenge":"A little late, we received an invitation to participate in the competition for the development of the new site of the 2nd Clinical Hospital in Minsk.","description":"Development of a concept idea for the site of the 2nd Clinical Hospital in Minsk","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Концепт для сайта Больницы","result":"Проект успешно запущен и доступен по адресу 2gkb.by. Работы выполнены в 2019 году.","solution":"![Концепт для сайта Больницы — 1](/uploads/projects/2gkb/695646f1eccf431ea5fac0750087238e.png)\n\nЗа короткий срок мы все же сумели преподнести наше видение данного проекта для Заказчика.\n\nОсновная суть - разделение всех направлений деятельности больницы на промо сайты, со своей структурой, возможностью записи и информацией для посетителей.\n\n![Концепт для сайта Больницы — 2](/uploads/projects/2gkb/68ac2fd24ef34215852447272a5a9ebc.png)\n\nОсновной сайт, это сводка всей информации о самой больнице и новостной ленте, которой Заказчик решил уделить основное время.\n\n![Концепт для сайта Больницы — 3](/uploads/projects/2gkb/dabecc9bfb3a4c8d8f0eb55431b550f4.png)\n\nПромо сайты - это отдельный сайт каждого направления больницы, с возможностью записи пользователей на прием к доступным врачам.\n\n![Концепт для сайта Больницы — 4](/uploads/projects/2gkb/8bee9268bc3e440291cc4d970bd80d6a.png)\n\n![Концепт для сайта Больницы — 5](/uploads/projects/2gkb/499a3f27190d4d2ba1398e801691e1a0.png)\n\n![Концепт для сайта Больницы — 6](/uploads/projects/2gkb/604e9791abfd43429f459d4436499768.png)\n\n**Сайт проекта:** [2gkb.by](https://2gkb.by)","subtitle":"Веб · Сайт","challenge":"Немного с опозданием мы получили приглашение на участие в конкурсе на разработку нового сайта 2ой Клинической Больницы в Минске.","description":"Разработка концепт-идеи для сайта 2ой Клинической Больницы города Минска","stack_detail":"UI/UX, Figma, Photoshop"}}$row_59$::jsonb)
