INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('armtek-promo', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2019, false, true, 61, '/uploads/projects/armtek-promo/132534fc25744258b3bccb773460d1d6.jpg', $row_61${"en":{"title":"Promotional game Armtek","result":"The project was successfully launched and is available at promo.armtek.by. The work was completed in 2019.","solution":"This project was created in accordance with the brand book of the company and clear requirements for maintaining the corporate identity.\n\nThe site structure is presented in a single page (Home page) and user account, with the ability to register / log in.\n\n![Promotional game Armtek — 1](/uploads/projects/armtek-promo/a03e12f46e814f58bfbc3022fd37a138-2.png)\n\nUsed corporate colors and fonts.\n\nCustomer Requirements:\n- The project must be adapted to display on any mobile devices and tablets.\n- The resource should work without page reloads, open and function quickly and adequately, in order to avoid the formation of negative perception of the brand and the project by customers.\n\n![Promotional game Armtek — 2](/uploads/projects/armtek-promo/ed35bb9dd7a5474685a663d7288ac01f-2.png)\n\nThe project is designed for a wide target audience, so it was developed for all possible devices.\n\nIt was possible to upload an excel file with data from users who registered and validated. Unloading allows you to download a file for a given period of time (by date).\n\n![Promotional game Armtek — 3](/uploads/projects/armtek-promo/8f3056f7ce4f41b2ab3cd7340aa8df37-2.png)\n\n**Project website:** [promo.armtek.by](https://promo.armtek.by)","subtitle":"Web · Landing page","challenge":"As part of the development of Armtek, we have developed a promotional site for an advertising game.","description":"Development of an advertising game for Armtek","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Рекламная игра Armtek","result":"Проект успешно запущен и доступен по адресу promo.armtek.by. Работы выполнены в 2019 году.","solution":"Данный проект создавался исключительно с соответствием брендбука компании и четким требованиям к сохранению фирменного стиля.\n\nСтруктура сайта представлена в виде одной страницы (Главная страница) и личным кабинетом пользователя, с возможностью зарегистрироваться/авторизоваться.\n\n![Рекламная игра Armtek — 1](/uploads/projects/armtek-promo/a03e12f46e814f58bfbc3022fd37a138.png)\n\nИспользовались фирменные цвета и шрифты.\n\nТребования от заказчика:\n- Проект должен быть адаптирован под отображение на любых мобильных устройствах и планшетах.\n- Ресурс должен работать без перезагрузок страниц, открываться и функционировать быстро и адекватно, во избежание формирования негативного восприятия бренда и проекта клиентами.\n\n![Рекламная игра Armtek — 2](/uploads/projects/armtek-promo/ed35bb9dd7a5474685a663d7288ac01f.png)\n\nПроект рассчитан на широкую целевую аудиторию, поэтому он разрабатывался под все возможные устройства.\n\nБыла предусмотрена возможность выгрузки excel файла с данными пользователей, которые зарегистрировались и прошли валидацию. Выгрузка позволяет осуществлять скачивания файла за заданный промежуток времени (по датам).\n\n![Рекламная игра Armtek — 3](/uploads/projects/armtek-promo/8f3056f7ce4f41b2ab3cd7340aa8df37.png)\n\n**Сайт проекта:** [promo.armtek.by](https://promo.armtek.by)","subtitle":"Веб · Лендинг","challenge":"В рамках развития компании Armtek, мы разработали промо сайт для рекламной игры.","description":"Разработка рекламной игры для компании Armtek","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_61$::jsonb)
