INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('airon-redesign', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2019, false, true, 62, '/uploads/projects/airon-redesign/daaabf54fe674def9e2463836c372bf1.jpg', $row_62${"en":{"title":"Airon website redesign","result":"The project was successfully launched and is available at airon.by. The work was completed in 2019.","solution":"In the continuation of work on the [project](/en/portfolio/airon) of the construction company \"Airon\", we could not get around the design theme of the site itself.\n\nOur team carried out an analysis of this area of ​​activity, took into account the mistakes of the previous company in the process of creating the design, its structure and features of the content allocation.\n\n![Airon website redesign — 1](/uploads/projects/airon-redesign/95ab0c2bf78d487a9a83ce8184cba210.png)\n\nOur idea was to simplify the structure of the site to quickly find the necessary information.\n\nWe did not come up with a new look for the blocks of the main page, we only transformed its visual effect, for a simpler and more understandable look.\n\n![Airon website redesign — 2](/uploads/projects/airon-redesign/9068840961754b67bd60276e7c859f3b.png)\n\n![Airon website redesign — 3](/uploads/projects/airon-redesign/5d158e5f410e47b7892fdb030f2122d8.png)\n\nHaving studied the existing news posts of the company, we decided to make the news block more contrasting! The news itself is presented in large print, which in turn focuses on them.\n\n![Airon website redesign — 4](/uploads/projects/airon-redesign/bc657dc769a445caae0df41f46f94555.png)\n\n**Project website:** [airon.by](https://airon.by)","subtitle":"Web · Website","challenge":"In the continuation of work on the project of the construction company \"Airon\", we could not get around the design theme of the site itself.","description":"Development of a new design for the construction company \"Airon\"","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Редизайн сайта Айрон","result":"Проект успешно запущен и доступен по адресу airon.by. Работы выполнены в 2019 году.","solution":"В продолжении работы над [проектом ](/ru/portfolio/airon) строительной компании \"Айрон\", мы не могли обойти тему дизайна самого сайта.\n\nНашей командой был осуществлен анализ данной сферы деятельности, учтены ошибки предыдущей компании в процессе создания дизайна, его структуры и особенностей выделения контента.\n\n![Редизайн сайта Айрон — 1](/uploads/projects/airon-redesign/61e69d933e2148a1bab2ceb43d959479.png)\n\nНаша мысль заключалась в том, чтобы упростить структуру сайта для быстрого поиска необходимой информации.\n\nМы не стали придумывать новый вид блоков главной страницы, мы только преобразили его визуальный эффект, для более простого и понятного вида.\n\n![Редизайн сайта Айрон — 2](/uploads/projects/airon-redesign/ce1b8b0cc5494da1926dc032fd0a575b.png)\n\n![Редизайн сайта Айрон — 3](/uploads/projects/airon-redesign/230f922d32774180a624e4ba2e5f7787.png)\n\nИзучив уже существующие новостные посты компании, мы решили сделать блок новостей более контрастным! Сами новости представлены большим шрифтом, что в свою очередность акцентирует на них внимание.\n\n![Редизайн сайта Айрон — 4](/uploads/projects/airon-redesign/d8b3353fcfa846eaa243e7ec2d168aa1.png)\n\n**Сайт проекта:** [airon.by](https://airon.by)","subtitle":"Веб · Сайт","challenge":"В продолжении работы над проектом строительной компании \"Айрон\", мы не могли обойти тему дизайна самого сайта.","description":"Разработка нового дизайна для строительной компании \"Айрон\"","stack_detail":"UI/UX, Figma, Photoshop"}}$row_62$::jsonb)
