INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('prosmartmovers', 'web', ARRAY['web'], ARRAY['WordPress'], 2019, false, true, 63, '/uploads/projects/prosmartmovers/0c80f9d05840428f8481d747587face6.jpg', $row_63${"en":{"title":"Landing for an Advertising Company","result":"The project was successfully delivered to the client. The work was completed in 2019.","solution":"We were approached by a company from Chicago, which plans to launch a large advertising company. But for this they need a one-page site - a landing page.\n\n![Landing for an Advertising Company — 1](/uploads/projects/prosmartmovers/9bcd1ff219984f7eba08ebe3fe460b7c.png)\n\nThe main point to consider was the quick launch of the project. To do this, we resorted to a solution that we don’t like so much - a ready-made solution. More precisely, the template that the Customer independently bought on the drains.\n\n![Landing for an Advertising Company — 2](/uploads/projects/prosmartmovers/151fea725ccd42f0879f781e21bc6043.png)\n\nThe template was selected under the CMS Wordpress system. Well, we will use it means such a decision.\n\nThe project was deployed and configured completely in a few days. But unfortunately during this time, the Customer changed the plans and postponed the start of this Advertising company for an indefinite time.\n\n![Landing for an Advertising Company — 3](/uploads/projects/prosmartmovers/2650bc9653bf41579ab009894ae2c1d0.png)","subtitle":"Web · Landing page","challenge":"For a long time we have not been involved in such quick projects!","description":"Landing Development for a Moving company","stack_detail":"WordPress"},"ru":{"title":"Лендинг для Рекламной Компании","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2019 году.","solution":"Давно мы не занимались такими быстрыми проектами!\n\nК нам обратилась компания из Чикаго, которая планирует запуск большой рекламной компании. Но для этого им необходим одностраничный сайт - лендинг.\n\n![Лендинг для Рекламной Компании — 1](/uploads/projects/prosmartmovers/1cef501792594130ad585da751179f7c.png)\n\nОсновной момент который нужно было учитывать - быстрый запуск проекта. Для этого мы прибегнули к решению, которое так не любим - готовое решение. Точнее шаблон, который Заказчик самостоятельно купил на стоках.\n\n![Лендинг для Рекламной Компании — 2](/uploads/projects/prosmartmovers/303c73da54ca4bd8ac7d5a78fff01a30.png)\n\nШаблон был выбран под CMS систему Wordpress. Что ж, будем использовать значит такое решение.\n\nПроект был развернут и настроен полностью за несколько дней. Но к сожалению за это время Заказчик изменил планы и перенес старт данной Рекламной компании на неопределенное время.\n\n![Лендинг для Рекламной Компании — 3](/uploads/projects/prosmartmovers/e15a6b04faa041a5b7aeb2838c933d07.png)","subtitle":"Веб · Лендинг","challenge":"К нам обратилась компания из Чикаго, которая планирует запуск большой рекламной компании. Но для этого им необходим одностраничный сайт - лендинг.","description":"Разработка Лендинга для компании занимающейся перевозками и хранением вещей в период переезда","stack_detail":"WordPress"}}$row_63$::jsonb)
