INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('bilet-vir-by-concept', 'web', ARRAY['web', 'saas'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2019, false, true, 64, '/uploads/projects/bilet-vir-by-concept/bez-imeni.png', $row_64${"en":{"title":"UI/UX CRM Virage-M","result":"The project was successfully launched and is available at bilet.vir.by. The work was completed in 2019.","solution":"The current visual is obsolete. The project’s functionality has grown quite seriously, and the current location of design elements for CRM management did not allow for quick and efficient system management.\n\nWe have proposed two options:\n\nOPTION 1.\n\nTank navigation on the system, with the ability to hide it and focus on the main functional components of the page.\n\n![UI/UX CRM Virage-M — 1](/uploads/projects/bilet-vir-by-concept/3ffd74e19bd649548be42b8004712f36-2.png)\n\nThis option will allow you to focus on the desktop of the section that was selected or available for work.\n\nOPTION 2.\n\nNavigation in the header of the CRM system.\nThis option is considered the most successful, in terms of accessibility of information, as well as navigation between available sections.\n\n![UI/UX CRM Virage-M — 2](/uploads/projects/bilet-vir-by-concept/ae373614091f42a99782fd926bd47c0b-2.png)\n\n![UI/UX CRM Virage-M — 3](/uploads/projects/bilet-vir-by-concept/7ac92324ae4440f19c97cfac92749a87-2.png)\n\n**Project website:** [bilet.vir.by](https://bilet.vir.by)","subtitle":"Web · SaaS","challenge":"When working on a project in support of the Virage-M CRM system, we decided to offer our vision of displaying all the functional components of this project.","description":"Development of a UI/UX concept-idea for the CRM system of the Virage-M travel company","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"UI/UX CRM Вираж-М","result":"Проект успешно запущен и доступен по адресу bilet.vir.by. Работы выполнены в 2019 году.","solution":"Текущий визуал является устаревшим. С учетом того, что функционал проекта вырос достаточно серьезно, то нынешнее расположение элементов дизайна для управления CRM не позволяло быстро и эффективно управлять системой.\n\nНами было предложено два варианта:\n\nВАРИАНТ 1.\n\nБаковая навигация по системе, с возможностью скрывать ее и акцентировать внимание на основных функциональных составляющих страницы.\n\n![UI/UX CRM Вираж-М — 1](/uploads/projects/bilet-vir-by-concept/3ffd74e19bd649548be42b8004712f36.png)\n\nДанный вариант позволит концентрировать внимание на рабочем столе раздела который был выбран или доступен для работы.\n\nВАРИАНТ 2.\n\nНавигация в шапке CRM системы.\nДанный вариант считается самым удачным, с точки зрения доступности информации, а так же навигации между доступными разделами.\n\n![UI/UX CRM Вираж-М — 2](/uploads/projects/bilet-vir-by-concept/ae373614091f42a99782fd926bd47c0b.png)\n\n![UI/UX CRM Вираж-М — 3](/uploads/projects/bilet-vir-by-concept/7ac92324ae4440f19c97cfac92749a87.png)\n\n**Сайт проекта:** [bilet.vir.by](https://bilet.vir.by)","subtitle":"Веб · SaaS","challenge":"При работе над проектом по доработке CRM системы компании Вираж-М, мы решили предложить свое видение отображения всех функциональных составляющих данного проекта.","description":"Разработка UI/UX концепт-идеи CRM системы компании Вираж-М","stack_detail":"UI/UX, Figma, Photoshop"}}$row_64$::jsonb)
