INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('funtastik', 'web', ARRAY['web', 'ecommerce'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2019, false, true, 67, '/uploads/projects/funtastik/54a2dcad8da948b89a49ddfc5841869c.jpg', $row_67${"en":{"title":"Online Shop Funtastik","result":"The project was successfully launched and is available at www.funtastik.by. The work was completed in 2019.","solution":"Requirements:\n- development of site design only\n- take into account the requirements of the company’s brand book\n- preservation of the current project functionality\n- minimal change in project structure\n\n![Online Shop Funtastik — 1](/uploads/projects/funtastik/e1f54a0d3f344fadb7e22ba9413b4db9-2.png)\n\nHaving audited the current site of the Customer, we came to the conclusion that it requires a partial change in the structure of the site. In particular, information on the Personal Account is not obvious, as is the directory structure itself. Information on the availability and filtering capabilities only complicates the process of finding the right product.\n\n![Online Shop Funtastik — 2](/uploads/projects/funtastik/16dda54beab14a8cb85a9f895d8fcc3e-2.png)\n\nGiven these factors, we proposed minimal changes to the site, taking into account the ordering of its style.\n\nAt the same time, we tried to maintain its recognition and intuitive navigation throughout the site and the directory in particular.\n\n![Online Shop Funtastik — 3](/uploads/projects/funtastik/b3553329c5394182a311fcb38a7804b6-2.png)\n\n**Project website:** [www.funtastik.by](https://www.funtastik.by)","subtitle":"Web · E-commerce","challenge":"The customer posed the following task for us - Creation of a new website design funtastik.by.","description":"Redesign of an online toy store","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Интернет Магазин Funtastik","result":"Проект успешно запущен и доступен по адресу www.funtastik.by. Работы выполнены в 2019 году.","solution":"Требования: \n- разработка только дизайна сайта\n- учитывать требования брендбука компании\n- сохранение текущего функционала проекта\n- минимальное изменение структуры проекта\n\n![Интернет Магазин Funtastik — 1](/uploads/projects/funtastik/e1f54a0d3f344fadb7e22ba9413b4db9.png)\n\nПроанализировав текущий ИМ Заказчика мы пришли к выводу, что он требует частичной изменения структуры сайта. В частности информация по Личному Кабинету не очевидна, как и сама структура каталога. Информация по наличию и возможности фильтрации только усложняет процесс поиска нужного товара.\n\n![Интернет Магазин Funtastik — 2](/uploads/projects/funtastik/16dda54beab14a8cb85a9f895d8fcc3e.png)\n\nС учетом данных факторов, мы предложили минимальные изменения сайта, с учетом приведения в порядок его стилистики.\n\nВ тоже время, мы постарались сохранить его узнаваемость и интуитивно понятную навигацию по всему сайту и каталогу в частности.\n\n![Интернет Магазин Funtastik — 3](/uploads/projects/funtastik/b3553329c5394182a311fcb38a7804b6.png)\n\n**Сайт проекта:** [www.funtastik.by](https://www.funtastik.by)","subtitle":"Веб · E-commerce","challenge":"Заказчик поставил пред нами следующую задачу - Создание нового дизайна сайта funtastik.by.","description":"Редизайн интернет-магазина по продаже игрушек","stack_detail":"UI/UX, Figma, Photoshop"}}$row_67$::jsonb)
