INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('bolshedrayva', 'web', ARRAY['web'], ARRAY['Symfony'], 2019, false, true, 68, '/uploads/projects/bolshedrayva/bolshe-drajva-copy.png', $row_68${"en":{"title":"Promotional game \"More Drive!\"","result":"The project was successfully delivered to the client. The work was completed in 2019.","solution":"When registering on the website, all users are automatically checked against their card numbers. After successful registration, all the codes that have been assigned to a given user are displayed in their personal account on the website. The game \"More Drive!\" consists of a series of tasks that users must complete in order to earn more points and increase their chances of winning.\n\n![Promotional game \"More Drive!\" — 1](/uploads/projects/bolshedrayva/b2fe27e27bb347ffa1daf2b5a05def2e.png)\n\nThe developed project allows not only to carry out a successful advertising campaign, but also to collect information about all participants of the loyalty programme that can be further used by the company to improve the services provided and increase the level of customer satisfaction.\n\n![Promotional game \"More Drive!\" — 2](/uploads/projects/bolshedrayva/0cc1c8db281b4d71bf8aab02f5302d29.png)\n\nThis project was developed by Piplos Media team using modern technologies and frameworks such as Symfony, which guarantees high stability and performance of the site. The website was also adapted to all devices, allowing the participants to easily access their personal accounts and perform tasks anywhere and anytime.\n\nThe development of the advertising game \"More Drive!\" for an oil and gas company is a vivid example of how to use promo projects effectively to attract clients and increase their satisfaction with the services they provide.\n\n![Promotional game \"More Drive!\" — 3](/uploads/projects/bolshedrayva/96d7c6f1987e450286ca6ac69b013545.png)","subtitle":"Web · Landing page","challenge":"An oil and gas company, a member of the Razam z nami loyalty programme, decided to run a promotional campaign with a promotional game called More Drive! For this purpose, a project was developed that allows all participants in the loyalty programme to register on the website and take part in the game.","description":"Promotional game \"More Drive!\" for an oil and gas company: promo project development","stack_detail":"Symfony"},"ru":{"title":"Рекламная игра \"Больше Драйва!\"","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2019 году.","solution":"При регистрации на сайте происходит автоматическая проверка всех пользователей по их номерам карт. После успешной регистрации в личном кабинете на сайте отображаются все коды, которые были присвоены данному пользователю. Игра \"Больше Драйва!\" состоит из серии заданий, которые пользователи должны выполнить, чтобы заработать больше баллов и повысить свои шансы на победу.\n\n![Рекламная игра \"Больше Драйва!\" — 1](/uploads/projects/bolshedrayva/b2fe27e27bb347ffa1daf2b5a05def2e.png)\n\nРазработанный проект позволяет не только провести успешную рекламную акцию, но и собрать информацию о всех участниках программы лояльности, что в дальнейшем может быть использовано компанией для улучшения предоставляемых услуг и повышения уровня удовлетворенности клиентов.\n\n![Рекламная игра \"Больше Драйва!\" — 2](/uploads/projects/bolshedrayva/0cc1c8db281b4d71bf8aab02f5302d29.png)\n\nПроект был разработан командой Piplos Media на основе современных технологий и фреймворков, таких как Symfony, что обеспечило высокую стабильность и производительность сайта. Сайт также был адаптирован под все устройства, что позволило участникам игры легко получать доступ к своему личному кабинету и выполнять задания в любом месте и в любое время.\n\nРазработка рекламной игры \"Больше Драйва!\" для нефтегазовой компании - это яркий пример эффективного использования промо-проектов для привлечения клиентов и повышения уровня удовлетворенности ими предоставляемыми услугами.\n\n![Рекламная игра \"Больше Драйва!\" — 3](/uploads/projects/bolshedrayva/96d7c6f1987e450286ca6ac69b013545.png)","subtitle":"Веб · Лендинг","challenge":"Нефтегазовая компания, участник программы лояльности «Разам з намi», решила провести промо-акцию с помощью рекламной игры \"Больше Драйва!\". Для этого был разработан проект, который позволяет всем участникам программы лояльности зарегистрироваться на сайте и принять участие в игре.","description":"Рекламная игра \"Больше Драйва!\" для нефтегазовой компании: разработка промо проекта","stack_detail":"Symfony"}}$row_68$::jsonb)
