INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('belintertrans', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2019, false, true, 69, '/uploads/projects/belintertrans/group-491.png', $row_69${"en":{"title":"Belintertrans","result":"The project was successfully launched and is available at belint.by. The work was completed in 2019.","solution":"This time, a project under development for the state-owned logistics organization Belintertrans.\n\n![Belintertrans — 1](/uploads/projects/belintertrans/b4fb7da9b6ca4faa88d59903cf9e376d-2.png)\n\n![Belintertrans — 2](/uploads/projects/belintertrans/2e58db4940754c3e9ab4873acc822d91-2.png)\n\nAs we have provided a new rendering part of the project this company on the Internet.\n\n![Belintertrans — 3](/uploads/projects/belintertrans/6bd587f96b394a89a90cf90604f4ed0e-2.png)\n\n![Belintertrans — 4](/uploads/projects/belintertrans/5506d1d314234956865f25abf7c25815-2.png)\n\nImplemented serious functionality by selecting the parameters of mobile compositions , as well as a directory with data on goods and stations through which delivery is carried out.\n\n![Belintertrans — 5](/uploads/projects/belintertrans/1b778639387a4856a60ad3e2b87dd1b5-2.png)\n\n**Project website:** [belint.by](https://belint.by)","subtitle":"Web · Website","challenge":"Our team managed to work on another project for a transport and logistics company.","description":"Official site of the Belintertrans logistics company","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Белинтертранс","result":"Проект успешно запущен и доступен по адресу belint.by. Работы выполнены в 2019 году.","solution":"На этот раз это проект для экспедиторской организации «Белинтертранс».\n\n![Белинтертранс — 1](/uploads/projects/belintertrans/b4fb7da9b6ca4faa88d59903cf9e376d.png)\n\n![Белинтертранс — 2](/uploads/projects/belintertrans/2e58db4940754c3e9ab4873acc822d91.png)\n\nВ рамках данного проекта мы предоставили новую визуализацию данного предприятия в сети интернет.\n\n![Белинтертранс — 3](/uploads/projects/belintertrans/6bd587f96b394a89a90cf90604f4ed0e.png)\n\n![Белинтертранс — 4](/uploads/projects/belintertrans/5506d1d314234956865f25abf7c25815.png)\n\nРеализован серьезный функционал по подбору Параметров передвижных составов, а так же справочник с данным по грузам и станциям через которые осуществляется доставка.\n\n![Белинтертранс — 5](/uploads/projects/belintertrans/1b778639387a4856a60ad3e2b87dd1b5.png)\n\n**Сайт проекта:** [belint.by](https://belint.by)","subtitle":"Веб · Сайт","challenge":"Нашей команде удалось поработать над очередным проектом для транспортно-логистической компании.","description":"Официальный сайта предприятия «Белинтертранс»","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_69$::jsonb)
