INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('fito', 'web', ARRAY['web', 'ecommerce'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2019, false, true, 70, '/uploads/projects/fito/artboard-copy-2.jpg', $row_70${"en":{"title":"Network of pharmacies","result":"The project was successfully launched and is available at fito.by. The work was completed in 2019.","solution":"The Customer has contacted us on behalf of the Green Pharmacies network.\"\n\nThe task was of a character with the creation of the new online store fito.by.\n\nThe task of creating a new site: to combine an information site (large product catalog) with an online store. Update design, change and make user-friendly interface, etc.\n\nAesthetic perception is a very important point. The page should be informative, convenient and not overloaded with unnecessary text and other information. Our task is to preserve the old logo, but place it in a more modern space with which it will be combined.\n\nHaving studied this market segment, the customer’s corporate identity, as well as the Network logo, we came to the conclusion that the combination of the logo and modern design are incompatible.\n\nAs part of the development of the concept of the idea of ​​a new site, the current logo was tested for a possible connection with modern design. The result was negative. In this connection, we have prepared a new version of the logo implementation for the site, taking into account all modern trends in the development of logo visualization.\n\n![Network of pharmacies — 1](/uploads/projects/fito/bf7a5e71a9fb419a92e7acafca8e7b2f-2.jpg)\n\nLightweight, modern, readable logo that fully complements the site design proposed above. We act on simple associations: green\nA color with 3 leaves already hints at life and health. Old logo - stuck in the 90s like the current fito.by website\n![Network of pharmacies — 2](/uploads/projects/fito/faad5b37d7d249298b2c9f6501a7325a-2.jpg)\n![Network of pharmacies — 3](/uploads/projects/fito/e55137e6d6d34513953613f188f01783-2.jpg)\n\nThe customer also described his vision of the site design:\n\nThis is a bright and bright site with elements of eco-style, possibly interspersed with elements of a tree, medicinal plants, etc. When you get to our page, a person should have the feeling that they sell natural products based on medicinal herbs, etc., but so that everything does not look like a medicine man’s shop :)\n\nWe presented the concept-idea as a project that is located on one domain, all pages are designed in the same style and can be traced throughout the site.\n\nThe structure of the site allows you to quickly and without much difficulty find all the necessary information.\n\n![Network of pharmacies — 4](/uploads/projects/fito/dfa52a5f27884270bee907ddca6bf042-2.png)\n\n**Project website:** [fito.by](https://fito.by)","subtitle":"Web · E-commerce","challenge":"The task was of a character with the creation of the new online store fito.by.","description":"Development of a new website online store pharmacy network \"Green Pharmacy\"","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Зеленая Аптека","result":"Проект успешно запущен и доступен по адресу fito.by. Работы выполнены в 2019 году.","solution":"К нам обратился Заказчик от лица сети \"Зеленых Аптек\".\n\nПоставленная задача носила характер связанный с созданием нового Интернет-Магазина fito.by.\n\nЦели создания нового сайта: совместить информационный сайт (большой каталог продукции) с интернет-магазином. Обновить дизайн, изменить и сделать удобным интерфейс и пр.\n\nЭстетическое восприятие очень важный момент. Страница должна быть информативной, удобной и не перегруженной лишним текстом и пр. информацией. Наша цель сохранить старый логотип, но поместить его в более современное пространство, с которым он будет сочетаться.\n\nИзучив данный сегмент рынка, фирменный стиль Закзачика, а так же логотип Сети, мы пришли к выводу, что сочетание логотипа и современного дизайна несовместимы.\n\nВ рамках разработки концепт идеи нового сайта, было проведено тестирование текущего логотипа, для возможной связки с современным дизайном. Результат был отрицательный. В связи с чем мы подготовили новый вариант реализации логотипа для сайта, с учетом всех современных тенденций развития визуализации логотипов.\n\n![Зеленая Аптека — 1](/uploads/projects/fito/bf7a5e71a9fb419a92e7acafca8e7b2f.jpg)\n\nЛегкий, современный, читабельный лого, который в полной мере дополняет предложенный выше дизайн сайта. Действуем на простых ассоциациях: зеленый\nЦвет с 3-мя листками уже намекает на жизнь и здоровье. Старый лого - застрял в 90-х как и текущий сайт fito.by\n![Зеленая Аптека — 2](/uploads/projects/fito/faad5b37d7d249298b2c9f6501a7325a.jpg)\n![Зеленая Аптека — 3](/uploads/projects/fito/e55137e6d6d34513953613f188f01783.jpg)\n\nЗаказчик так же описал свое видение дизайна сайта:\n\nЭто светлый яркий сайт с элементами эко-стиля, возможно с вкраплениями элементов дерева, лечебных растений и пр. Попадая к нам на страницу, у человека должно возникать ощущение, что здесь продают натуральные продукты на основе лекарственных растений трав т.д., но при этом чтобы все не выглядело, как лавка знахаря :)\n\nМы же, представили концепт-идею как проект, который расположен на одном домене, все страницы выдержаны в едином стиле и прослеживаются на протяжении всего сайта.\n\nСтруктура сайта позволяет быстро и без особых сложностей находить всю необходимую информацию.\n\n![Зеленая Аптека — 4](/uploads/projects/fito/dfa52a5f27884270bee907ddca6bf042.png)\n\n**Сайт проекта:** [fito.by](https://fito.by)","subtitle":"Веб · E-commerce","challenge":"Поставленная задача носила характер связанный с созданием нового Интернет-Магазина fito.by.","description":"Создание нового сайта Интернет-Магазина сети аптек \"Зеленая Аптека\"","stack_detail":"UI/UX, Figma, Photoshop"}}$row_70$::jsonb)
