INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('geo', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2018, false, true, 71, '/uploads/projects/geo/belgeodesy-behance-placeholder.png', $row_71${"en":{"title":"Geodesic project","result":"The project was successfully launched and is available at geo.by. The work was completed in 2018.","solution":"Geodesy is an important field that involves the measurement and representation of the earth's surface. Geodetic enterprises often face difficulties in managing their vast amounts of data. In order to solve this problem, our team of designers decided to develop a minimalist design for the project. This was achieved by removing unnecessary content elements from the website's homepage. Additionally, we developed extended capabilities for the text editor to work with different sections of the website. To enhance the functionality of the project, we integrated geodetic services, including an interactive map and the SSTP RB map.\n\nDesign:\n\nThe minimalist design approach was chosen to improve the user experience and help the user navigate the site with ease. This was achieved by simplifying the website's interface and eliminating unnecessary elements. We used a clean, white background and a simple color scheme that allows the user to focus on the content. The use of high-quality images and icons also helped to create an aesthetically pleasing design.\n\n![Geodesic project — 1](/uploads/projects/geo/belgeodesy-behance-2.png)\n\nFunctionality:\n\nTo improve the functionality of the website, we developed a text editor with extended capabilities. This allows for easy editing and management of the website's text sections. The editor also has an option to add multimedia elements, such as images and videos, to enhance the website's visual appeal.\n\nIntegration of Geodetic Services:\n\nWe integrated two geodetic services to enhance the functionality of the project: an interactive map and the SSTP RB map. The interactive map allows the user to view geodetic information in real-time, including topographic features and terrain elevation. The SSTP RB map displays the location of geodetic benchmarks and control points in the Republic of Belarus.\n\nConclusion:\n\nIn conclusion, the development of a minimalist design and the integration of geodetic services have greatly improved the functionality and user experience of the project. The extended capabilities of the text editor have also made it easier to manage the website's content. With these improvements, geodetic enterprises can better manage their data and present it in a user-friendly and aesthetically pleasing manner.\n\n**Project website:** [geo.by](https://geo.by)","subtitle":"Web · Website","challenge":"Introduction:","description":"Developing a Minimalistic Design for a Geodetic Project with Advanced Text Editor Features and Geodetic Services\"","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Белгеодезия","result":"Проект успешно запущен и доступен по адресу geo.by. Работы выполнены в 2018 году.","solution":"Геодезия является важной областью, которая включает в себя измерение и представление земной поверхности. Геодезические предприятия часто сталкиваются с трудностями в управлении огромными объемами данных. Чтобы решить эту проблему, наша команда дизайнеров решила разработать минималистичный дизайн для проекта. Это было достигнуто путем удаления ненужных элементов контента с главной страницы сайта. Кроме того, мы разработали расширенные возможности текстового редактора для работы с различными разделами сайта. Для расширения функциональности проекта мы интегрировали геодезические сервисы, включая интерактивную карту и карту ГНТП РБ.\n\nДизайн:\n\nДля улучшения пользовательского опыта и облегчения навигации по сайту был выбран минималистский подход к дизайну. Это было достигнуто путем упрощения интерфейса сайта и устранения ненужных элементов. Мы использовали чистый, белый фон и простую цветовую схему, которая позволяет пользователю сосредоточиться на содержании. Использование высококачественных изображений и иконок также помогло создать эстетически приятный дизайн.\n\n![Белгеодезия — 1](/uploads/projects/geo/belgeodesy-behance.png)\n\nФункциональность:\n\nЧтобы улучшить функциональность сайта, мы разработали текстовый редактор с расширенными возможностями. Это позволяет легко редактировать и управлять текстовыми разделами сайта. В редакторе также есть возможность добавления мультимедийных элементов, таких как изображения и видео, для повышения визуальной привлекательности сайта.\n\nИнтеграция геодезических служб:\n\nДля расширения функциональности проекта мы интегрировали два геодезических сервиса: интерактивную карту и карту SSTP RB. Интерактивная карта позволяет пользователю просматривать геодезическую информацию в режиме реального времени, включая топографические особенности и высоту местности. Карта SSTP RB отображает расположение геодезических ориентиров и контрольных точек на территории Республики Беларусь.\n\nЗаключение:\n\nВ заключение следует отметить, что разработка минималистичного дизайна и интеграция геодезических сервисов значительно улучшили функциональность и пользовательский опыт проекта. Расширенные возможности текстового редактора также облегчили управление содержимым сайта. Благодаря этим усовершенствованиям геодезические предприятия могут лучше управлять своими данными и представлять их в удобной для пользователя и эстетически привлекательной форме.\n\n**Сайт проекта:** [geo.by](https://geo.by)","subtitle":"Веб · Сайт","challenge":"Введение:","description":"Разработка минималистического дизайна для геодезического проекта с использованием расширенных функций текстового редактора и геодезических сервисов","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_71$::jsonb)
