INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('bilet-vir-by', 'backend', ARRAY['backend', 'saas'], ARRAY['HTML/CSS'], 2018, false, true, 72, '/uploads/projects/bilet-vir-by/artboard-copy-11.jpg', $row_72${"en":{"title":"CRM system Virage-M","result":"The project was successfully launched and is available at bilet.vir.by. The work was completed in 2018.","solution":"In technical support, we include such types of work as:\n- Development / revision of design;\n- Layout of the project;\n- Programming;\n- quick fix problems in the work of CRM;\n- refinement of functionality.\n- \nIn support of this project, we are developing a new concept idea for visualizing and structure of this CRM system (which we will write in more detail about later).\n\nTo date, we have implemented a number of significant improvements to this project, integrated several different third-party systems to automate the work with the service inside the Virazh-M company\n\n**Project website:** [bilet.vir.by](https://bilet.vir.by)","subtitle":"Backend · SaaS","challenge":"As part of the development of the CRM system of Virage-M Company, we provide technical support for this project.","description":"Technical support for the CRM system of the Virage-M Travel Company","stack_detail":"HTML/CSS"},"ru":{"title":"CRM Вираж-М","result":"Проект успешно запущен и доступен по адресу bilet.vir.by. Работы выполнены в 2018 году.","solution":"В техническую поддержку мы включаем такие виды работы как:\n- Разработка/доработка дизайна;\n- Верстка проекта;\n- Программирование;\n- оперативное исправление проблем в работе CRM;\n- доработка функциональности.\n\nТак же в рамках данного проекта мы разрабатываем новую концепт-идею по визуализации и структуре данной CRM системе (О чем позже более детально напишем).\n\nНа текущий момент мы внедрили ряд существенных доработок по данному проекту, интегрировали несколько различных сторонних систем для автоматизации работы с сервисом внутри компании Вираж-М.\n\n**Сайт проекта:** [bilet.vir.by](https://bilet.vir.by)","subtitle":"Бэкенд · SaaS","challenge":"В рамках развития CRM системы Компании Вираж-М, мы оказываем техническую поддержку данного проекта.","description":"Техническая поддержка CRM системы туристической Компании «Вираж-М»","stack_detail":"HTML/CSS"}}$row_72$::jsonb)
