INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('malinovka', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2018, false, true, 75, '/uploads/projects/malinovka/2d846092ff0a4aafa3a3e0335af429d6.png', $row_75${"en":{"title":"Malinovka By Spamash","result":"The project was successfully launched and is available at spamash.by. The work was completed in 2018.","solution":"Tasks:\n1. Personal. Formation of the style and image of the company. The style of the site should be consistent with the corporate style of the company.\n2. Advertising. The site should contain information about the services provided by the center and provide the ability to view related text, sound and graphic materials.\n3. Information. The site should provide access to information about the center, activities, as well as inform users about changes in the center.\n\nWe tried to combine all these tasks with the unique execution and presentation of information for users in our [design] (https://www.youtube.com/watch?v=aWtiSs2EEQg).\n\n![Malinovka By Spamash — 1](/uploads/projects/malinovka/9a696a4b78924d5aba9592987c26b63f-2.png)\n\nWe have provided several options for the possible display of this [concept idea] (https://www.youtube.com/watch?v=sfuQaug_ptk) .\n\n![Malinovka By Spamash — 2](/uploads/projects/malinovka/e7ab61aa2d364bda9497207b0540b6e5-2.png)\n\nThe essence of this visualization is the interactive presentation of information for users.\n\n**Project website:** [spamash.by](https://spamash.by)","subtitle":"Web · Website","challenge":"The purpose of this concept idea is Website of the international cultural center \"Malinovka By Spamash.\"","description":"The concept-idea of ​​the site of the international cultural center","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Малiновка By Spamash","result":"Проект успешно запущен и доступен по адресу spamash.by. Работы выполнены в 2018 году.","solution":"Задачи:\n1. Имиджевая. Формирование стиля и образа компании. Стилевое оформление сайта должно соответствовать корпоративному стилю компании.\n2. Рекламная. Сайт должен содержать информацию об услугах предоставляемых центром и обеспечивать возможность просмотра связанных с ними текстовых, звуковых и графических материалов.\n3. Информационная. Сайт должен предоставлять доступ к информации о центре, деятельности, а также информировать пользователей об изменениях в работе центра.\n\nМы постарались объединить все эти задачи с уникальным исполнением и преподнесением информации для пользователей в нашем [дизайне](https://www.youtube.com/watch?v=aWtiSs2EEQg).\n\n![Малiновка By Spamash — 1](/uploads/projects/malinovka/9a696a4b78924d5aba9592987c26b63f.png)\n\nМы предоставили несколько вариантов возможного отображения данной [концепт-идеи](https://www.youtube.com/watch?v=sfuQaug_ptk).\n\n![Малiновка By Spamash — 2](/uploads/projects/malinovka/e7ab61aa2d364bda9497207b0540b6e5.png)\n\nСуть данной визуализации в интерактивном преподнесении информации для пользователей.\n\n**Сайт проекта:** [spamash.by](https://spamash.by)","subtitle":"Веб · Сайт","challenge":"Цель данной концепт-идеи - Сайт международного культурного центра «Малiновка By Spamash» .","description":"Концепт-идея сайта международного культурного центра","stack_detail":"UI/UX, Figma, Photoshop"}}$row_75$::jsonb)
