INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('horizont2', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2018, false, true, 76, '/uploads/projects/horizont2/b4bdba856595407289fb5c921c31016d.png', $row_76${"en":{"title":"Site Horizont v.2","result":"The project was successfully delivered to the client. The work was completed in 2018.","solution":"The layout includes the division of the site structure into two parts using the \"burger\" menu:\n1. Information sections (About the company, contacts, etc.)\n2. Company directory (various categories of goods and their division) The\n\nmain page is essentially represented by a display goods and product groups for quick access to this information.\n\n![Горизонт](/uploads/projects/horizont2/5f61f9a8fd0d4b918ea851124ae32ff9-2.png)","subtitle":"Web · Website","challenge":"The company Piplos Media has developed a new idea for visualizing the main page of the main website of the Horizont holding.","description":"New site visualization horizont.by","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Сайт Horizont v.2","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2018 году.","solution":"В компании [Piplos Media](/ru) была разработана новая идея визуализации главной страницы основного сайта холдинга Горизонт.\n\nМакет включает в себя разделение структуры сайта на две части по средством \"бургер\" меню:\n1. Информационные разделы (О компании, контакты и т.д.)\n2. Каталог предприятия (различные категории товаров и их разделение)\n\nГлавная страница по сути представлена отображением товаров и товарных групп для быстрого доступа к данной информации.\n\n![Горизонт](/uploads/projects/horizont2/5f61f9a8fd0d4b918ea851124ae32ff9.png)","subtitle":"Веб · Сайт","challenge":"В компании Piplos Media была разработана новая идея визуализации главной страницы основного сайта холдинга Горизонт.","description":"Редизайн сайта horizont.by","stack_detail":"UI/UX, Figma, Photoshop"}}$row_76$::jsonb)
