INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('zolotayabochka', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2018, false, true, 78, '/uploads/projects/zolotayabochka/artboard-copy-53.png', $row_78${"en":{"title":"Promotional website of the Golden Barrel","result":"The project was successfully delivered to the client. The work was completed in 2018.","solution":"![Золотая бочка](/uploads/projects/zolotayabochka/d0d427e2235446a58690878471b3944d-2.png)\n\nA unique fishing game was developed, the essence of which is to catch bottles and collect points for them.\n\nTimekiller game.\n\nThe essence of the game is to use a fishing rod to catch all 10 bottles of the Golden Barrel.\nOn the desktop version of the site, we control the fishing rod with the mouse. On mobile devices - using the touchpad. The game regulates the casting power of the float, as well as its trajectory.\n\n![Promotional website of the Golden Barrel — 2](/uploads/projects/zolotayabochka/a17b0a04c0fa4dc8bfa683a3c1b2061c-2.png)\n\nThe purpose of the site is to make the informational noise on the Internet a light refreshing beer with a pleasant and soft flavor that is drunk easily and pleasantly, perfectly refreshes in the summer heat .\n\n![Promotional website of the Golden Barrel — 3](/uploads/projects/zolotayabochka/dea3df6066534acbb58a24475ccc4675-2.png)","subtitle":"Web · Landing page","challenge":"It was necessary to create a promotional site as a secret basement or storage of oak barrels with Golden Barrel logos. In each barrel some interesting content is hidden. By selecting certain barrels (clicking on them with the mouse), the user becomes available a collection of true things.","description":"The Golden Barrel promotional game website: How to create an engaging online experience for your audience","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Промо-сайт рекламной игры \"Золотой бочки\"","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2018 году.","solution":"![Золотая бочка](/uploads/projects/zolotayabochka/d0d427e2235446a58690878471b3944d.png)\n\nБыла разработана уникальная игра-рыбалка, суть которой вылавливать бутылочки и собирать за них баллы.\n\nИгра-таймкиллер.\n\nСуть игры - с помощью удочки выловить все 10 бутылок «Золотая Бочка».\nНа десктопной версии сайта удочкой управляем с помощью мышки. На мобильных устройствах - с помощью тачпада. В игре регулируется сила забрасывания поплавка, а так же его траектория.\n\n![Промо-сайт рекламной игры \"Золотой бочки\" — 2](/uploads/projects/zolotayabochka/a17b0a04c0fa4dc8bfa683a3c1b2061c.png)\n\nЦель сайта - сделать информационный шум в Интернете светлого освежающего пива с приятным и мягким вкусовым оттенком, которое пьется легко и приятно, прекрасно освежает в летнюю жару.\n\n![Промо-сайт рекламной игры \"Золотой бочки\" — 3](/uploads/projects/zolotayabochka/dea3df6066534acbb58a24475ccc4675.png)","subtitle":"Веб · Лендинг","challenge":"Необходимо было создать промо-сайт как секретный подвал или хранилище дубовых бочек с логотипами Золотая Бочка. В каждой бочке спрятан какой-то интересный контент. Путем выбора определенных бочек (кликая по ним мышкой), пользователю становится доступна коллекция истинных вещей.","description":"Промо-сайт рекламной игры \"Золотой бочки\": как создать увлекательный онлайн-опыт для вашей аудитории","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_78$::jsonb)
