INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('orgpromstroy', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2018, false, true, 79, '/uploads/projects/orgpromstroy/artboard-copy-30.png', $row_79${"en":{"title":"Corporate site Orgpromstroy","result":"The project was successfully launched and is available at orgpromstroy.by. The work was completed in 2018.","solution":"LLC \"Orgpromstroy\" is part of the group of companies \"OPS-group\" engaged in the integrated supply of building materials in the Russian Federation and in the EU countries, as a result, we are ready to offer you professional service in these regions.\n\nWe were tasked with creating a new enterprise site.\n\nThe task is to display all the useful information about the company on the site.\n\nAt first, we prepared a concept idea for the main page of the new site. The concept idea consisted of a classic display of information regarding the company itself.\n\n![Corporate site Orgpromstroy — 1](/uploads/projects/orgpromstroy/9358f31649e1401fa5e0cb1ec72259a2-2.png)\n\nThis option was accepted, but after a while, the tasks of the new site were revised.\n\nSo a new task appeared before us - the formation of a positive and image-based perception of the organization on the Internet.\n\nFollowing it, the initial idea was modernized, under a new visual and successfully adopted by the company of the Customer.\n\n![Корпоративный сайт Оргпромстрой](/uploads/projects/orgpromstroy/7d561cb73e3a41899bfc2b6aaf16e95a-2.png)\n\n**Project website:** [orgpromstroy.by](https://orgpromstroy.by)","subtitle":"Web · Website","challenge":"LLC \"Orgpromstroy\" is the largest operator in the building materials market of the Republic of Belarus. For more than 5 years, it has been successfully supplying a wide range of building materials to the largest construction sites in the country.","description":"The leading wholesale and retail company in the market of thermal insulation and finishing materials in Belarus","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Корпоративный сайт Оргпромстрой","result":"Проект успешно запущен и доступен по адресу orgpromstroy.by. Работы выполнены в 2018 году.","solution":"ООО \"Оргпромстрой\" является крупнейшим оператором на рынке строительных материалов Республики Беларусь. Более 5 лет успешно осуществляет поставки широкого перечня строительных материалов на крупнейшие стройки страны.\n\nООО \"Оргпромстрой\" входит в группу компаний \"OPS-group\", осуществляющих деятельность по комплексным поставкам строительных материалов на территории Российской Федерации и в странах Евросоюза, как следствие, мы готовы предложить Вам профессиональный сервис и в данных регионах.\n\nПеред нами была поставлена задача создания нового сайта предприятия.\n\nЦель - отображение все полезной информации по предприятию на сайте.\n\nНа первых порах, нами была подготовлена концепт-идея главной страницы нового сайта. Концепт-идея состояла из классического отображения информации касающиеся самой компании.\n\n![Корпоративный сайт Оргпромстрой — 1](/uploads/projects/orgpromstroy/9358f31649e1401fa5e0cb1ec72259a2.png)\n\nДанный вариант был принят, но через некоторое время, были пересмотрены задачи нового сайта.\n\nТак перед нами появилась новая цель - формирования положительного и имиджевого восприятия организации в сети интернет.\n\nСледуя ей, была модернизирована первоначальная идея, под новый визуал и успешно принята компанией Заказчика.\n\n![Корпоративный сайт Оргпромстрой](/uploads/projects/orgpromstroy/7d561cb73e3a41899bfc2b6aaf16e95a.png)\n\n**Сайт проекта:** [orgpromstroy.by](https://orgpromstroy.by)","subtitle":"Веб · Сайт","challenge":"Перед нами была поставлена задача создания нового сайта предприятия.","description":"Ведущая оптово-розничная компания на рынке теплоизоляционных и отделочных материалов в Беларуси","stack_detail":"UI/UX, Figma, Photoshop"}}$row_79$::jsonb)
