INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('sontsa', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2018, false, true, 80, '/uploads/projects/sontsa/group-52.png', $row_80${"en":{"title":"Perfume and cosmetic factory \"SONZA\"","result":"The project was successfully delivered to the client. The work was completed in 2018.","solution":"In a limited amount of time, we prepared a visualization of the cover page of a possible site for the enterprise.\n\n![Perfume and cosmetic factory \"SONZA\" — 1](/uploads/projects/sontsa/ce563c75ee7945a58cffc332d8e951b2-2.png)\n\nWhen creating this idea, we focused on the ease of access to any information about the company and its products.We\n\nalso took into account the difficulty of displaying the vertical logo of the enterprise, so it was decided to center it Thus, dividing the main menu and allowing you to quickly navigate the site navigation.","subtitle":"Web · Website","challenge":"As part of a competitive assignment for the development of a new site for the SONCA enterprise, we were asked to develop a concept idea for a catalog site.","description":"Competition Task for the development of a concept idea","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Парфюмерно-косметическая фабрика \"СОНЦА\"","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2018 году.","solution":"В ограниченное количество времени, нами была подготовлена визуализация титульной страницы возможного сайта предприятия.\n\n![Парфюмерно-косметическая фабрика \"СОНЦА\" — 1](/uploads/projects/sontsa/ce563c75ee7945a58cffc332d8e951b2.png)\n\nПри создании данной идеи, мы сделали акцент внимания на простоте доступа к любой информация о компании и ее продукции.\n\nТак же мы учитывали сложность отображения вертикального логотипа предприятия, поэтому было принято решения центрировать его. Тем самым разделив основное меню и позволяя быстрее ориентироваться в навигации сайта.","subtitle":"Веб · Сайт","challenge":"В рамках конкурного задания на разработку нового сайта предприятия \"СОНЦА, перед нами поставили разработать концепт-идею сайта каталога.","description":"Конкурсное Задание на разработку концепт-идеи","stack_detail":"UI/UX, Figma, Photoshop"}}$row_80$::jsonb)
