INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('onega', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2018, false, true, 81, '/uploads/projects/onega/group-53.png', $row_81${"en":{"title":"ONEGA","result":"The project was successfully launched and is available at onega.by. The work was completed in 2018.","solution":"- The company's activity is food production\n- Selling goods - snacks, chips, plates, seeds, muesli bars\n- 19 years in the market of Belarus, the largest producer, a wide range of all types of snacks, extensive distribution\n- The task that we want to achieve with its help a new site - Modernity, adaptability, multilingualism, easy access for B2B clients.\n\nTaking this information and previous experience with Onega PODO into service, we went to create a new presentation of the company on the Internet.\n\n![ONEGA — 1](/uploads/projects/onega/b360564199fc4e93b037a7799e82ce7c-2.png)\n\nAs a basis, we took the ease of perception of information by the user and the well-known brand of the Customer.\n\nThe content part of course should be adjusted taking into account the comments of the Customer.\n\n![ONEGA — 2](/uploads/projects/onega/104f39b5e65b43f7b9e33981a8d95e5e-2.png)\n\nAll sections of the site are quickly accessible and understandable for user awareness.\n\nEXAMPLE: [Video](https://youtu.be/W_IQMdKNB4A) of the main page of the submitted idea.\n\n**Project website:** [onega.by](https://onega.by)","subtitle":"Web · Website","challenge":"We received a request from Onega to develop a proposal to create a new corporate website for their production. In addition to the assessment, we decided to offer our visualization options for this project, based on the topics of this company. The customer designated the following items as Basic parameters for the new site:","description":"Development of a proposal for a corporate website PODO ONEGA","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"ОНЕГА","result":"Проект успешно запущен и доступен по адресу onega.by. Работы выполнены в 2018 году.","solution":"К нам поступил запрос от компании Онега, на разработку предложения по созданию нового корпоративного сайта их производства. \nПо мимо оценки, мы решили предложить свой варианты визуализации данного проекта, на основании тематики данной компании. \nЗаказчик обозначил следующие пункты как Основные параметры для нового сайта:\n\n- Сфера деятельности компании - производство пищевой продукции \n- Реализуемые товары - снеки, чипсы-пластинки, семечки, батончики-мюсли \n- 19 лет на рынке РБ, крупнейший производитель, широкий ассортимент всех видов снеков, обширная дистрибуция\n- Цель, которую мы хотим достичь с его помощью нового сайта - Современность, адаптивность, мультиязычность, легкий доступ для B2B-клиентов.\n\nВзяв на вооружение данную информацию и предыдущий опыт работы с ПОДО Онега, мы отправились творить новое представление компании в интернете.\n\n![ОНЕГА — 1](/uploads/projects/onega/b360564199fc4e93b037a7799e82ce7c.png)\n\nЗа основу мы брали простоту восприятия информации пользователем и общеизвестность бренда Заказчика.\n\nКонтентная часть конечно же должна быть подкорректирован с учетом комментариев Заказчика.\n\n![ОНЕГА — 2](/uploads/projects/onega/104f39b5e65b43f7b9e33981a8d95e5e.png)\n\nВсе разделы сайта быстро доступны и понятны для осознания пользователя.\n\nПРИМЕР: [Видео](https://youtu.be/W_IQMdKNB4A) главной страницы сданной идеи.\n\n**Сайт проекта:** [onega.by](https://onega.by)","subtitle":"Веб · Сайт","challenge":"Сфера деятельности компании - производство пищевой продукции Реализуемые товары - снеки, чипсы-пластинки, семечки, батончики-мюсли 19 лет на рынке РБ, крупнейший производитель, широкий ассортимент всех видов снеков, обширная дистрибуция Цель, которую мы хотим достичь с его помощью нового сайта - Современность, адаптивность, мультиязычность, легкий доступ для B2B-клиентов.","description":"Разработка предложения для корпоративного сайта ПОДО ОНЕГА","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_81$::jsonb)
