INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('brest-litovsk', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2018, false, true, 82, '/uploads/projects/brest-litovsk/8dc4e726ab504f828ee21c310c9c84e0.png', $row_82${"en":{"title":"Savushkin Product","result":"The project was successfully launched and is available at brest-litovsk.by. The work was completed in 2018.","solution":"The requirements for the project were very high. But having assessed all the risks, we still decided to take on this project and implement it.\n\nThe main thing that had to be taken into account when developing the design was that the site design should match the brand colors of the Brest-Litovsk brand.\n\n![Savushkin Product — 1](/uploads/projects/brest-litovsk/d72cedbd660840d18284abe5697ae2dd-2.png)\n\nOur first concept idea was well received, but the Customer wanted more ease of perception of the information.\n\nThe second attempt at Piplos Media always hits the target!\n\n![Savushkin Product — 2](/uploads/projects/brest-litovsk/da519ea6c5ea4df18afec1714599d492-2.png)\n\nIn addition to the site, a win management system and the moderation of the checks sent were also developed.\n\nDates from May 10 to July 10, 2018.\n\n![Savushkin Product — 3](/uploads/projects/brest-litovsk/b2b314117b9f4b9f994c8290401a10cb-2.png)\n\n**Project website:** [brest-litovsk.by](https://brest-litovsk.by)","subtitle":"Web · Landing page","challenge":"In a very short time we developed a promotional site for the advertising game \"Brest - Litovsk\" on the table - win a vacation in the Chalet! \"","description":"Promotional site of the game \"Brest-Litovsk on the table\"","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"«Брест — Литовск» на столе","result":"Проект успешно запущен и доступен по адресу brest-litovsk.by. Работы выполнены в 2018 году.","solution":"В очень сжатые сроки нами был разработан промо-сайт для рекламной игры «Брест — Литовск» на столе – выиграй отдых в Шале!».\n\nТребования к проекту были очень высокие. Но оценив все риски, мы все же решились взяться за данный проект и реализовать его.\n\nОсновное что необходимо было учесть при разработке дизайна - это дизайн сайта должен соответствовать фирменным цветам бренда торговой марки Брест-Литовск.\n\n![«Брест — Литовск» на столе — 1](/uploads/projects/brest-litovsk/d72cedbd660840d18284abe5697ae2dd.png)\n\nНаша первая концепт-идея была воспринята хорошо, но Заказчик хотел большей простоты восприятия информации.\n\nВторая попытка в Piplos Media всегда попадает в цель!\n\n![«Брест — Литовск» на столе — 2](/uploads/projects/brest-litovsk/da519ea6c5ea4df18afec1714599d492.png)\n\nПомимо сайта была так же разработана система управления выигрышей и модерацию отправленных чеков.\n\nСрок проведения с 10 мая по 10 июля 2018г.\n\n![«Брест — Литовск» на столе — 3](/uploads/projects/brest-litovsk/b2b314117b9f4b9f994c8290401a10cb.png)\n\n**Сайт проекта:** [brest-litovsk.by](https://brest-litovsk.by)","subtitle":"Веб · Лендинг","challenge":"Основное что необходимо было учесть при разработке дизайна - это дизайн сайта должен соответствовать фирменным цветам бренда торговой марки Брест-Литовск.","description":"Промо-сайт игры \"Брест-Литовск на столе\"","stack_detail":"UI/UX, Figma, Photoshop"}}$row_82$::jsonb)
