INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('callifornia', 'backend', ARRAY['backend', 'saas'], ARRAY['PHP', 'MySQL', 'JavaScript'], 2018, false, true, 83, '/uploads/projects/callifornia/2d991ccd8efa4a568319f3c5cf5b109b.jpeg', $row_83${"en":{"title":"Call tracking system California","result":"The project was successfully delivered to the client. The work was completed in 2018.","solution":"This call tracking has no analogues and in terms of functionality will give a head start to everyone on the market.\n\n![Колл-трекинг система Сallifornia](/uploads/projects/callifornia/f2ba3e4530214ceda8c1d050deeebea1-2.png)\n\nmechanics of the project are as follows:\n\nThe site displays different numbers for different people. Next, you can download the call report, analytics, which users and when they called. All data is uploaded to Google Analytics. It is also possible to view certain reports in the personal account of the client.\n\n![Call tracking system California — 2](/uploads/projects/callifornia/80984b07c82343a78c1c74cf5dd15b5a-2.png)\n\nMy account can be divided into two types:\n- Dynamic gives different numbers to each person who arrives.\n- Static gives identical numbers to everyone who came by url with a certain parameter.\n\n![Call tracking system California — 3](/uploads/projects/callifornia/f5c1124d6cd44a35932d2823bc541135-2.png)","subtitle":"Backend · SaaS","challenge":"We have developed call tracking, which each company can install on its server and monitor the effectiveness of its marketing without involving third-party services.","description":"Development of a CRM call tracking system to track marketing performance","stack_detail":"PHP, MySQL, JavaScript"},"ru":{"title":"Колл-трекинг система Сallifornia","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2018 году.","solution":"Данный колл-трекинг не имеет аналогов и по функционалу даст фору всем имеющим на рынке.\n\n![Колл-трекинг система Сallifornia](/uploads/projects/callifornia/f2ba3e4530214ceda8c1d050deeebea1.png)\n\nМеханика проекта такова:\n\nНа сайте выводятся разные номера разным людям. Далее есть возможность скачать отчет о звонках, аналитику, какие пользователи и когда звонили. Все данные загружаются в Google Analytics. Также есть возможность просмотра определенных отчетов в личном кабинете клиента.\n\n![Колл-трекинг система Сallifornia — 2](/uploads/projects/callifornia/80984b07c82343a78c1c74cf5dd15b5a.png)\n\nЛичный кабинет делиться на два типа:\n- Динамический выдает разные номера каждому пришедшему.\n- Статический выдает одинаковые номера всем, кто пришел по url с определенным параметром.\n\n![Колл-трекинг система Сallifornia — 3](/uploads/projects/callifornia/f5c1124d6cd44a35932d2823bc541135.png)","subtitle":"Бэкенд · SaaS","challenge":"Мы разработали колл-трекинг, который каждая компания может установить себе на сервер и отслеживать эффективность своего маркетинга без привлечения сторонних сервисов.","description":"Разработка CRM системы колл-трекинга для отслеживания эффективности маркетинга","stack_detail":"PHP, MySQL, JavaScript"}}$row_83$::jsonb)
