INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('avtoradio-app', 'mobile', ARRAY['mobile'], ARRAY['Android', 'iOS'], 2018, false, true, 84, '/uploads/projects/avtoradio-app/1452a04f9eca494c916c61ec31aac227.png', $row_84${"en":{"title":"Mobile app \"Autoradio\"","result":"The project was successfully delivered to the client. The work was completed in 2018.","solution":"This app allows you to listen and search for music, take part in various promotions of the radio station.\n\n![Mobile app \"Autoradio\" — 1](/uploads/projects/avtoradio-app/2da859169f2946aa94f68bcff8dcdb25-2.png)\n\n![Mobile app \"Autoradio\" — 2](/uploads/projects/avtoradio-app/25b2ea0e981846298947b9ee59f9adba-2.png)\n\nYou can listen AutoRadio online and save mobile traffic, find songs that were heard on the air using the convenient search for songs, take part in promotions and win valuable gifts.\n\n![Mobile app \"Autoradio\" — 3](/uploads/projects/avtoradio-app/798738bbc8624d8f8f9f8a73b04f74d6-2.png)","subtitle":"Mobile · Mobile app","challenge":"In connection with the launch of the new Autoradio radio station in Minsk, we developed a mobile application for Android and iOS.","description":"Development of a mobile app (Android and iOS) for radio stations AutoRadio","stack_detail":"Android, iOS"},"ru":{"title":"Мобильное приложение \"Авторадио\"","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2018 году.","solution":"Данное приложение позволяет прослушивать и искать музыку, участвовать в различны акциях радиостанции.\n\n![Мобильное приложение \"Авторадио\" — 1](/uploads/projects/avtoradio-app/2da859169f2946aa94f68bcff8dcdb25.png)\n\n![Мобильное приложение \"Авторадио\" — 2](/uploads/projects/avtoradio-app/25b2ea0e981846298947b9ee59f9adba.png)\n\nВы можете слушать \"Авторадио\" online и экономить мобильный трафик, находить песни, которые звучали в эфире, с помощью удобного поиска песен, участвовать в акциях и выигрывать ценные подарки.\n\n![Мобильное приложение \"Авторадио\" — 3](/uploads/projects/avtoradio-app/798738bbc8624d8f8f9f8a73b04f74d6.png)","subtitle":"Мобильное · Приложение","challenge":"В связи запуском новой радиостанции \"Авторадио\" в городе Минске, мы разработали мобильное приложение для Android и iOS.","description":"Разработка мобильного приложения для Android и iOS радиостанции АвтоРадио","stack_detail":"Android, iOS"}}$row_84$::jsonb)
