INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('avtoradio', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2018, false, true, 85, '/uploads/projects/avtoradio/b79773355f924d74ada059d7f11dece4.png', $row_85${"en":{"title":"Autoradio Radio Website","result":"The project was successfully launched and is available at avtoradio.by. The work was completed in 2018.","solution":"The site is made in a light style and without unnecessary grace, but at the same time, displays the essence of the radio station-ROCK.\n\n![Autoradio Radio Website — 1](/uploads/projects/avtoradio/15b232f3ad334f1cac48b38bab2258a5-2.png)\n\nColor schemes were used based on the corporate identity of the radio station, as well as the music they broadcast.\n\n![Autoradio Radio Website — 2](/uploads/projects/avtoradio/f959e83b2a5443af9e112eb3aa77823c-2.png)\n\nhe site includes a wide functionality of searching and listening to music online.\n\n![Autoradio Radio Website — 3](/uploads/projects/avtoradio/693de7c4f8ff49c69301cfa9c2121350-2.png)\n\n**Project website:** [avtoradio.by](http://avtoradio.by)","subtitle":"Web · Website","challenge":"The Piplos Media team has developed a website for a young radio station broadcasting only in Minsk at a frequency of 98.0 FM.","description":"Website development for the new radio station \"Autoradio\"","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Сайт радиостанции Авторадио","result":"Проект успешно запущен и доступен по адресу avtoradio.by. Работы выполнены в 2018 году.","solution":"[Команда](/ru#about) PIplos Media разработала сайт для молодой радиостанция вещающая только в Минске на частоте 98,0 FM.\n\nСайт сделан в легком стиле и без лишних изяществ, но и в тоже время, отображает суть радиостанции -РОК.\n\n![Сайт радиостанции Авторадио — 1](/uploads/projects/avtoradio/15b232f3ad334f1cac48b38bab2258a5.png)\n\nЦветовые решения были использованы исходя из фирменного стиля радиостанции, а так же музыки, которую они вещают.\n\n![Сайт радиостанции Авторадио — 2](/uploads/projects/avtoradio/f959e83b2a5443af9e112eb3aa77823c.png)\n\nСайт включает в себя широкий функционал поиска и прослушивания музыки онлайн.\n\n![Сайт радиостанции Авторадио — 3](/uploads/projects/avtoradio/693de7c4f8ff49c69301cfa9c2121350.png)\n\n**Сайт проекта:** [avtoradio.by](http://avtoradio.by)","subtitle":"Веб · Сайт","challenge":"Команда PIplos Media разработала сайт для молодой радиостанция вещающая только в Минске на частоте 98,0 FM.","description":"Разработка сайта для новой радиостанции \"Авторадио\"","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_85$::jsonb)
