INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('bnb', 'backend', ARRAY['backend', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript'], 2018, false, true, 87, '/uploads/projects/bnb/b006bc91c7284832864610ceba493902.png', $row_87${"en":{"title":"Belarusian National Bank","result":"The project was successfully delivered to the client. The work was completed in 2018.","solution":"- The small functionality of the smartbusiness.by service\n- Use of third-party services (Assistant)\n- The scalability of this service\n- Security. Any\nuser can register.\n- There is no way to integrate the Bank’s internal services with\nthis project.\n\nRESOLUTION OF PROBLEMS WILL BE CONCLUDED IN OUR FOLLOWING\nOFFERS:\n\n1. Creation of a completely new service from scratch, with full\nfunctionality for the needs of the Bank\n2. Integration of all necessary services of the Bank with this\nproject\n3. Moderation of all types of users using\nthis service\n4. Provide the possibility of further\nscaling of the project\n\n![Белорусский народный банк](/uploads/projects/bnb/f2561fda227e4670ac6fa8e4d5a4ba7c-2.png)","subtitle":"Backend · E-commerce","challenge":"THE PROBLEM WHICH HAS BEEN DELIVERED BEFORE US, CONCLUDES IN SEVERAL ITEMS:","description":"Marketplace for small and medium-sized businesses","stack_detail":"PHP, MySQL, JavaScript"},"ru":{"title":"Белорусский народный банк","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2018 году.","solution":"- Узкий функционал сервиса smartbusiness.by\n- Использование сторонних сервисов (Ассистент)\n- Не масштабируемость данного сервиса\n- Безопасность. Регистрацию может проходить любой\nпользователь\n- Нет возможности интеграции внутренних сервисов Банка с\nданным проектом.\n\nРЕШЕНИЕ ПРОБЛЕМ ЗАКЛЮЧЕТСЯ В СЛЕДУЮШИХ НАШИХ\nПРЕДЛОЖЕНИЯХ:\n\n1. Создание абсолютно нового сервиса с нуля, с полноценным\nфункционалом под потребности Банка\n2. Интеграция всех необходимы сервисов Банка с данным\nпроектом\n3. Модерация всех типов пользователей использующие\nданный сервис\n4. Предусмотреть возможность дальнейшего\nмасштабирование проекта\n\n![Белорусский народный банк](/uploads/projects/bnb/f2561fda227e4670ac6fa8e4d5a4ba7c.png)","subtitle":"Бэкенд · E-commerce","challenge":"ПРОБЛЕМА КОТОРАЯ БЫЛА ПЕРЕД НАМИ ПОСТАВЛЕНА, ЗАКЛЮЧАЕТСЯ В НЕСКОЛЬКИХ ПУНКТАХ:","description":"Маркетплейс для малого и среднего бизнеса.","stack_detail":"PHP, MySQL, JavaScript"}}$row_87$::jsonb)
