INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('kocmo', 'web', ARRAY['web', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2018, false, true, 88, '/uploads/projects/kocmo/artboard-copy-35.png', $row_88${"en":{"title":"Chain of stores \"Cosmo\"","result":"The project was successfully launched and is available at kocmo.by. The work was completed in 2018.","solution":"Given this fact, the Customer has set for us the task of creating an Online Store for his company.\n\n![Chain of stores \"Cosmo\" — 1](/uploads/projects/kocmo/6d8a7ecb3fdf4880a0dab3ac846de6d5-2.png)\n\nFor a quicker start of a new site, it was decided to launch the first truncated version of the Online Store, that is, the site directory.\n\nAfter launching the catalog site, its optimization, SEO promotion, we started implementing the functionality for the Online Store.\n\n![Chain of stores \"Cosmo\" — 2](/uploads/projects/kocmo/b321968591634f3f89c7cdcaa905fee0-2.png)\n\nWe had a difficult task to put together all the projects of the company within one site and optimize its business processes on the Internet.\n\n![Chain of stores \"Cosmo\" — 3](/uploads/projects/kocmo/c8db7c297fa642a0b61e45d35ec77197-2.png)\n\n**Project website:** [kocmo.by](https://kocmo.by)","subtitle":"Web · E-commerce","challenge":"The Cosmo store chain is constantly growing and already has 25 stores in Belarus.","description":"Online Store COSMO","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Сеть магазинов \"Космо\"","result":"Проект успешно запущен и доступен по адресу kocmo.by. Работы выполнены в 2018 году.","solution":"Сеть магазинов Космо постоянно растет и насчитывает уже 25 магазинов в г. Минске, Гомеле, Могилеве, Витебске, Бресте и Солигорске.\n\nС учетом данного факта, Заказчик поставил для нас задачу о создании Интернет Магазина для своей компании.\n\n![Сеть магазинов \"Космо\" — 1](/uploads/projects/kocmo/6d8a7ecb3fdf4880a0dab3ac846de6d5.png)\n\nДля более быстрого старта нового сайта, было принято решение о запуске сперва урезанной версии ИМ, то есть сайт каталог.\n\nПосле запуска сайта каталога, его оптимизации, SEO продвижения, мы приступили к реализации функционала для Интернет Магазина.\n\n![Сеть магазинов \"Космо\" — 2](/uploads/projects/kocmo/b321968591634f3f89c7cdcaa905fee0.png)\n\nПеред нами стояла сложная задача собрать воедино все проекты компании в рамках одного сайта и оптимизировать ее бизнес процессы в интернете.\n\n![Сеть магазинов \"Космо\" — 3](/uploads/projects/kocmo/c8db7c297fa642a0b61e45d35ec77197.png)\n\n**Сайт проекта:** [kocmo.by](https://kocmo.by)","subtitle":"Веб · E-commerce","challenge":"С учетом данного факта, Заказчик поставил для нас задачу о создании Интернет Магазина для своей компании.","description":"Интернет Магазин КОСМО","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_88$::jsonb)
