INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('parfumstandard', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2018, false, true, 89, '/uploads/projects/parfumstandard/artboard-copy-41.png', $row_89${"en":{"title":"Corporate website \"Perfumestandart\"","result":"The project was successfully launched and is available at parfumstandard.by. The work was completed in 2018.","solution":"Parfyumstandart is included in the TOP 200 largest private enterprises of the Republic of Belarus and is one of the largest importers and distributors of cosmetics and perfumes in the mass market category!\n\nOur task was to make a simple and at the same time informative resource for a dynamically developing company.\n\n![Corporate website \"Perfumestandart\" — 1](/uploads/projects/parfumstandard/6c7dda5b36e94671bcf092939ab4cdcc-2.png)\n\nWebsite under development is the corporate website of the distributor company.\n\n![Corporate website \"Perfumestandart\" — 2](/uploads/projects/parfumstandard/e115de97245a420e89c033e76c3bae36-2.png)\n\nThe main task of the site is to show our potential and current partners and customers that we are a reliable and experienced partner, an expert in the cosmetic market, which brands are included our portfolio. All the advantages of the company must be visualized, quickly and easily read.\n\n![Corporate website \"Perfumestandart\" — 3](/uploads/projects/parfumstandard/f56e3f428e9b4371acb500374b6b9a96-2.png)\n\nIn this project, a personal account was developed for company employees, which stores all the organization’s documentation for study.\n\n![Corporate website \"Perfumestandart\" — 4](/uploads/projects/parfumstandard/4bd13751a7604a61b17c67320530ebd5-2.png)\n\n**Project website:** [parfumstandard.by](https://parfumstandard.by)","subtitle":"Web · Website","challenge":"Our task was to make a simple and at the same time informative resource for a dynamically developing company.","description":"The largest importer and distributor of cosmetics and perfumes","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Корпоративный сайт \"Парфюмстандарт\"","result":"Проект успешно запущен и доступен по адресу parfumstandard.by. Работы выполнены в 2018 году.","solution":"Компания «Парфюмстандарт» включена в «ТОП-200 крупнейших частных предприятий Республики Беларусь» и является одним из крупнейших импортеров и дистрибьюторов косметики и парфюмерии категории «масс-маркет»!\n\nПеред нами стояла задача сделать простой и в тоже время информативный ресурс для динамически развивающей компании.\n\n![Корпоративный сайт \"Парфюмстандарт\" — 1](/uploads/projects/parfumstandard/6c7dda5b36e94671bcf092939ab4cdcc.png)\n\nРазрабатываемый Веб-сайт является корпоративным сайтом компании дистрибутора.\n\n![Корпоративный сайт \"Парфюмстандарт\" — 2](/uploads/projects/parfumstandard/e115de97245a420e89c033e76c3bae36.png)\n\nОсновная цель сайта – показать нашим потенциальным и текущим партнерам и клиентам, что мы надежный и опытный партнер, эксперт на косметическом рынке, какие бренды входят в наш портфель. Все преимущества компании должны быть визуализированы, быстро и легко считываться.\n\n![Корпоративный сайт \"Парфюмстандарт\" — 3](/uploads/projects/parfumstandard/f56e3f428e9b4371acb500374b6b9a96.png)\n\nВ рамках проекта был разработан личный кабинет для сотрудников компании, в котором храниться вся документация по организации для изучения.\n\n![Корпоративный сайт \"Парфюмстандарт\" — 4](/uploads/projects/parfumstandard/4bd13751a7604a61b17c67320530ebd5.png)\n\n**Сайт проекта:** [parfumstandard.by](https://parfumstandard.by)","subtitle":"Веб · Сайт","challenge":"Перед нами стояла задача сделать простой и в тоже время информативный ресурс для динамически развивающей компании.","description":"Самый крупный импортер и дистрибьютор косметики и парфюмерии","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_89$::jsonb)
