INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('humorfm-app', 'mobile', ARRAY['mobile'], ARRAY['Android', 'iOS'], 2017, false, true, 93, '/uploads/projects/humorfm-app/584eb8a9fe1641d5b92af8037b13f532.png', $row_93${"en":{"title":"Mobile app \"Humor FM\"","result":"The project was successfully delivered to the client. The work was completed in 2017.","solution":"This mobile application is a continuation of the [site] of this radio station.\n\nIt contains all the basic functions for communication with the user, as well as listening and searching for music that played on the air..\n\n![Mobile app \"Humor FM\" — 1](/uploads/projects/humorfm-app/21eefccbfa544a48b537aa93823fd04f-2.png)\n\n![Mobile app \"Humor FM\" — 2](/uploads/projects/humorfm-app/36766a042b3e4dbf93bf5c2009395969-2.png)\n\nThe mobile radio app “Humor FM” is available in [“Play Store”] (https://play.google.com/store/apps/details?id=by.humorfm) {: rel = nofollow} and [“App Store”] (https: // itunes. apple.com/us/app/radio-humor-fm-Belarus / id1300339560?mt=8){:rel=nofollow}.\n\n![Mobile app \"Humor FM\" — 3](/uploads/projects/humorfm-app/1757267c4da44e63b2d2d7420346b01a-2.png)\n\n**Related projects:** [Website \"Humor FM\"](/en/portfolio/humorfm), [Redesign of the site \"HUMOR FM\"](/en/portfolio/redesign-humorfm), [Redesign of the app \"Humor FM\"](/en/portfolio/redesign-humorfmapp)","subtitle":"Mobile · Mobile app","challenge":"You can listen to fun radio online and save mobile traffic, find songs that were played on the air using the convenient search for songs, participate in promotions and win valuable gifts.","description":"Android and iOS application of the radio station \"Humor FM\"","stack_detail":"Android, iOS"},"ru":{"title":"Мобильное приложение \"Юмор FM\"","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2017 году.","solution":"Данное мобильное приложение - это продолжение сайта данной радиостанции.\n\nВ нем вынесены все основные функции, для коммуникации с пользователем, а так же прослушиванию и поиску музыки которая играла в эфире.\n\n![Мобильное приложение \"Юмор FM\" — 1](/uploads/projects/humorfm-app/21eefccbfa544a48b537aa93823fd04f.png)\n\n![Мобильное приложение \"Юмор FM\" — 2](/uploads/projects/humorfm-app/36766a042b3e4dbf93bf5c2009395969.png)\n\nМобильное приложение радио «Юмор ФМ» доступно в «Play Маркет» и «App Store».\n\n![Мобильное приложение \"Юмор FM\" — 3](/uploads/projects/humorfm-app/1757267c4da44e63b2d2d7420346b01a.png)\n\n**Связанные проекты:** [Сайт \"Юмор ФМ\"](/ru/portfolio/humorfm), [Редизайн Сайта \"ЮМОР FM\"](/ru/portfolio/redesign-humorfm), [Редизайн приложения \"Юмор FM\"](/ru/portfolio/redesign-humorfmapp)","subtitle":"Мобильное · Приложение","challenge":"Вы можете слушать веселое радио online и экономить мобильный трафик, находить песни, которые звучали в эфире, с помощью удобного поиска песен, участвовать в акциях и выигрывать ценные подарки.","description":"Android и iOS приложение радиостанции \"Юмор FM\"","stack_detail":"Android, iOS"}}$row_93$::jsonb)
