INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('emarkwin', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2017, false, true, 94, '/uploads/projects/emarkwin/e82eaf98ca604a028fb51fba3e9d4f99.jpeg', $row_94${"en":{"title":"Lottery site \"EMARK\"","result":"The project was successfully delivered to the client. The work was completed in 2017.","solution":"![Лотерейный сайт \"EMARK\"](/uploads/projects/emarkwin/a479c95663d44c8a81d2707a51dfd73c-2.png)\n\nGeneral requirements:\n- All pages of the Website must be able to configure SEO content and tags.\n- The system should NOT provide the site administrator with the creation of the same type and default pages.\n- The system should provide the site administrator with convenient site content management, database control through the interface.\n- The system should allow the placement of lots for draws by category, adding and removing products in groups of categories with the appropriate setting of the price of the lot.\n- The design of the site is adaptive. Developed for three resolutions (1280px, 768px, 320px)\n- The system should allow you to add documents for download.\n\n![Lottery site \"EMARK\" — 2](/uploads/projects/emarkwin/410dcd24fc0f459dafccbb9a189d110a-2.png)\n\n![Lottery site \"EMARK\" — 3](/uploads/projects/emarkwin/7ee8b708736d4be280d72f0aba8de839-2.png)","subtitle":"Web · Website","challenge":"This project is intended to provide users with a convenient interface and information for participating in the draws of various groups of goods, convenient and quick search for the necessary lot and participating in its drawing for residents of Kazakhstan.","description":"Online Prize Draw","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Лотерейный сайт \"EMARK\"","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2017 году.","solution":"![Лотерейный сайт \"EMARK\"](/uploads/projects/emarkwin/a479c95663d44c8a81d2707a51dfd73c.png)\n\nОбщие требования:\n- Все страницы Веб-сайта должны иметь возможность настройки SEO контента и тегов.\n- Система НЕ должна предоставлять администратору сайта создание однотипных и страниц по умолчанию.\n- Система должна предоставлять администратору сайта удобное управление контентом сайта, контроль БД через интерфейс.\n- Система должна позволять размещение лотов для розыгрышей по категориям, добавления и удаление товаров в группах категорий с соответствующим установлением цены лота.\n- Дизайн сайта адаптивный. Разрабатывается под три разрешения(1280px, 768px, 320px)\n- Система должна позволять добавлять документы для скачивания.\n\n![Лотерейный сайт \"EMARK\" — 2](/uploads/projects/emarkwin/410dcd24fc0f459dafccbb9a189d110a.png)\n\n![Лотерейный сайт \"EMARK\" — 3](/uploads/projects/emarkwin/7ee8b708736d4be280d72f0aba8de839.png)","subtitle":"Веб · Сайт","challenge":"Данный проект предназначен предоставления пользователям удобного интерфейса и информации для участия в розыгрышах различных групп товаров, удобного и быстрого поиска необходимого лота и участия в его розыгрыше для жителей Казахстана.","description":"Площадка розыгрышей призов через интернет","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_94$::jsonb)
