INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('aps-concept-idea', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2017, false, true, 95, '/uploads/projects/aps-concept-idea/effd728d32db4cb489c55371c2ab7922.png', $row_95${"en":{"title":"The concept idea of ​​the site APS","result":"The project was successfully delivered to the client. The work was completed in 2017.","solution":"road transport Implementation of a separate block \"APS Industry Solutions\" with the identification of individual transportation sectors.\n\n![Концепт-идея сайта aps.by](/uploads/projects/aps-concept-idea/ce998957e393466abdcb9889cdfe4b2e-2.png)","subtitle":"Web · Website","challenge":"As part of the support aps.by project, was developed a concept for a new visualization of the APS Solver website. It was necessary to distinguish the following services: International project transportation Oversized cargo transportation Dangerous goods","description":"Concept-idea of ​​a new visualization of the site of a logistics company","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Концепт-идея сайта APS","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2017 году.","solution":"Реализация отдельного блока \"Отраслевые решения APS\" с выделением отдельных отраслей перевозок.\n\n![Концепт-идея сайта aps.by](/uploads/projects/aps-concept-idea/ce998957e393466abdcb9889cdfe4b2e.png)","subtitle":"Веб · Сайт","challenge":"В рамках проекта aps.by была разработана концепт-идя новой визуализации сайта компании APS Solver. Необходимо было выделить следующие услуги: Международные проектные перевозки Перевозка негабаритных грузов Автоперевозки опасных грузов","description":"Концепт-идея новой визуализации сайта логистической компании.","stack_detail":"UI/UX, Figma, Photoshop"}}$row_95$::jsonb)
