INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('airon', 'web', ARRAY['web'], ARRAY['HTML/CSS'], 2017, false, true, 97, '/uploads/projects/airon/6ca06d20a6fc42ffa254f142f1088fef.jpeg', $row_97${"en":{"title":"Construction company \"AIRON\"","result":"The project was successfully launched and is available at airon.by. The work was completed in 2017.","solution":"Namely:\n1. Development of the front-end\n2. Development of the software part of the site\n\n![Construction company \"AIRON\" — 1](/uploads/projects/airon/b7716bbd8c3a4d42a81bf4a4e4c6386e-2.png)\n\nThe project includes a wide functionality for the sale and rental of real estate, with various possibilities for individual selection.\n\n![Construction company \"AIRON\" — 2](/uploads/projects/airon/8db4531af3694cf4a749361839ebdc0e-2.png)\n\nThe most basic and interesting piece of this project was the development of the so-called \"Chess\".\nIt is necessary for the administration of real estate data.\n\nThe output of data on real estate objects in a list in tabular form, with the possibility of an administrator to make changes -\nput a bird in the column:\n- The state of the object - under construction, being designed, built, and leased, sold,\n- Change all text information on the object — description, price, cost per square meter.\n\nIt was also provided the ability to download data on real estate through EXCEL c display information in the data table.\n\n![Construction company \"AIRON\" — 3](/uploads/projects/airon/67867e86082d4813a35f9a64e42acbc8-2.png)\n\n**Project website:** [airon.by](https://airon.by)\n\n**Related projects:** [Airon website redesign](/en/portfolio/airon-redesign)","subtitle":"Web · Website","challenge":"We were faced with an ambush for the development of the corporate website of ODO “IONON for the sale and rental of real estate.","description":"Dynamically developing construction company ODO “AIRON”","stack_detail":"HTML/CSS"},"ru":{"title":"Строительная компания \"Айрон\"","result":"Проект успешно запущен и доступен по адресу airon.by. Работы выполнены в 2017 году.","solution":"А именно:\n1. Разработка верстки дизайна проекта\n2. Разработка программной части сайта\n\n![Строительная компания \"Айрон\" — 1](/uploads/projects/airon/b7716bbd8c3a4d42a81bf4a4e4c6386e.png)\n\nПроект включает в себя широкий функционал по продаже и аренде объектов недвижимости, с различными возможностями по индивидуальному подбору.\n\n![Строительная компания \"Айрон\" — 2](/uploads/projects/airon/8db4531af3694cf4a749361839ebdc0e.png)\n\nСамым основным и интересным куском данного проекта, была разработка так называемой \"Шахматки\". \nОна необходима для администрирования данными по недвижимости.\n\nВывод данных по объектам недвижимости списком в табличной форме, с возможностью администратором внесения изменений –\nпростановки птичкой в графе:\n- Состояние объекта – строящиеся, проектируемые, построенные, а аренде, продано,\n- Изменение всей текстовой информации по объекту –описание , цена, стоимость квадратного метра.\n\nТак же была предусмотрена возможность загрузки данных по объектам недвижимости через EXCEL c отображением информации в таблице данных.\n\n![Строительная компания \"Айрон\" — 3](/uploads/projects/airon/67867e86082d4813a35f9a64e42acbc8.png)\n\n**Сайт проекта:** [airon.by](https://airon.by)\n\n**Связанные проекты:** [Редизайн сайта Айрон](/ru/portfolio/airon-redesign)","subtitle":"Веб · Сайт","challenge":"Перед нами была поставлена засада по разработке корпоративного сайта ОДО «АЙРОН по продаже и аренде недвижимости.","description":"Динамично развивающаяся строительная компания ОДО “АЙРОН”","stack_detail":"HTML/CSS"}}$row_97$::jsonb)
