INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('versusports', 'web', ARRAY['web'], ARRAY['Android', 'iOS'], 2017, false, true, 99, '/uploads/projects/versusports/623d01e534224a718ec05a9686b222c7.jpeg', $row_99${"en":{"title":"Enhancing VERSUSPORTS: Extending Functionality through Our Website","result":"The project was successfully launched and is available at versusports.com. The work was completed in 2017.","solution":"As we continuously strive to enhance the VERSUSPORTS experience, we're excited to introduce a new development that opens up additional dimensions of user engagement. Our latest project involves the expansion of functionality from our mobile application to our website, creating an information hub that empowers users with vital insights.\n\n## Instant Access to Sports Information\n\nOur website serves as a portal for accessing essential information related to games, teams, and activities in your selected region. We believe in simplifying the process of discovering and participating in sports events, and our website plays a pivotal role in achieving this goal.\n\n![Спортивная социальная сеть Versusports](/uploads/projects/versusports/3c53a5581a404992b774b3c49330594f.png)\n\n## Seamless Transition to Mobile App\n\nWhile you can quickly access crucial sports data on our website, the full potential of VERSUSPORTS comes to life when you transition to our mobile application. Available in both iOS and Android versions, the app offers an immersive experience for creating and engaging with teams and games.\n\n## Promoting Sports for All\n\nAt Piplos Media, we're passionate about making sports accessible to everyone, whether you're an amateur enthusiast or a seasoned professional. Our latest development underscores our commitment to this mission by providing quick and convenient access to sports activities.\n\n## Join the VERSUSPORTS Movement\n\nWe invite you to be a part of the VERSUSPORTS community, where sports enthusiasts come together to celebrate the spirit of competition, camaraderie, and a shared love for sports. With our website and mobile app, we're redefining how individuals engage with sports, ensuring that everyone can participate in the activities they're passionate about.\n\nExperience the future of sports networking with VERSUSPORTS, where accessibility, information, and engagement converge. Join us today, and let's celebrate the power of sports together!\n\n![Enhancing VERSUSPORTS: Extending Functionality through Our Website — 2](/uploads/projects/versusports/9e97d81258c94f9bab149f3474227685.png)\n\n**Project website:** [versusports.com](https://versusports.com)","subtitle":"Web · Website","challenge":"Our website serves as a portal for accessing essential information related to games, teams, and activities in your selected region. We believe in simplifying the process of discovering and participating in sports events, and our website plays a pivotal role in achieving this goal.","description":"VERSUSPORTS Website Expansion: Amplifying Sports Engagement","stack_detail":"Android, iOS"},"ru":{"title":"Совершенствование VERSUSPORTS: Расширение функциональных возможностей нашего сайта","result":"Проект успешно запущен и доступен по адресу versusports.com. Работы выполнены в 2017 году.","solution":"Постоянно совершенствуя возможности VERSUSPORTS, мы рады представить новую разработку, открывающую новые грани взаимодействия с пользователями. Наш последний проект предусматривает расширение функциональности мобильного приложения на веб-сайт, создавая информационный центр, позволяющий пользователям получать жизненно важные сведения.\n\n## Мгновенный доступ к спортивной информации\n\nНаш сайт служит порталом для доступа к важной информации о матчах, командах и мероприятиях в выбранном вами регионе. Мы стремимся упростить процесс поиска и участия в спортивных мероприятиях, и наш сайт играет ключевую роль в достижении этой цели.\n\n![Спортивная социальная сеть Versusports](/uploads/projects/versusports/3c53a5581a404992b774b3c49330594f.png)\n\n## Плавный переход к мобильному приложению\n\nХотя на нашем сайте можно быстро получить доступ к важнейшим спортивным данным, весь потенциал VERSUSPORTS раскрывается при переходе на наше мобильное приложение. Приложение, доступное в версиях для iOS и Android, предлагает захватывающий опыт создания и взаимодействия с командами и играми.\n\n## Продвижение спорта для всех\n\nКомпания Piplos Media стремится сделать спорт доступным для всех, будь то любитель или опытный профессионал. Наша последняя разработка подчеркивает нашу приверженность этой миссии, предоставляя быстрый и удобный доступ к спортивным мероприятиям.\n\n## Присоединяйтесь к движению VERSUSPORTS\n\nМы приглашаем вас стать частью сообщества VERSUSPORTS, где любители спорта собираются вместе, чтобы воспеть дух соперничества, товарищества и общей любви к спорту. С помощью нашего сайта и мобильного приложения мы меняем представление о том, как люди занимаются спортом, обеспечивая каждому возможность участвовать в занятиях, которыми он увлекается.\n\nПознакомьтесь с будущим спортивных сетей вместе с VERSUSPORTS, где доступность, информация и вовлеченность сливаются воедино. Присоединяйтесь к нам сегодня, и давайте вместе прославим силу спорта!\n\n![Совершенствование VERSUSPORTS: Расширение функциональных возможностей нашего сайта — 2](/uploads/projects/versusports/9e97d81258c94f9bab149f3474227685.png)\n\n**Сайт проекта:** [versusports.com](https://versusports.com)","subtitle":"Веб · Сайт","challenge":"Постоянно совершенствуя возможности VERSUSPORTS, мы рады представить новую разработку, открывающую новые грани взаимодействия с пользователями. Наш последний проект предусматривает расширение функциональности мобильного приложения на веб-сайт, создавая информационный центр, позволяющий пользователям получать жизненно важные сведения.","description":"Разработка web версии спортивной социальной сети Versusports","stack_detail":"Android, iOS"}}$row_99$::jsonb)
