INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('uplast-calculator', 'backend', ARRAY['backend'], ARRAY['PHP', 'MySQL', 'JavaScript'], 2017, false, true, 101, '/uploads/projects/uplast-calculator/artboard-copy-107.png', $row_101${"en":{"title":"Developing calculator software","result":"The project was successfully launched and is available at shop.u-plast.by. The work was completed in 2017.","solution":"Piplos Media is a young and dynamic software development company. A recent Piplos Media project involved the development of a siding costing software for Yu-Plast, one of the largest siding manufacturers.\n\nThe goal of this project was to develop a handy and fast tool to allow the customer to get the exact cost of siding for their house or building in a few clicks. To achieve this goal Piplos Media used advanced programming technology and paid attention to every detail of the development.\n\n![Developing calculator software — 1](/uploads/projects/uplast-calculator/fd83ca61fe8441618b1d6962453d35fe.png)\n\nOne of the key features of the software is its intuitive interface which allows users to easily adjust calculation parameters and get accurate results. In addition, the software allows calculations to be made not only for typical buildings but also for complex architectural structures, taking into account every detail and feature of the building.\n\nThe result of U-Plast software development is a comfortable and accurate tool that helps customers to quickly and easily calculate the cost of required siding, taking into account all peculiarities and requirements. Piplos Media is proud of its project and continues to work on developing new innovative software solutions.\n\n**Project website:** [shop.u-plast.by](https://shop.u-plast.by)\n\n**Related projects:** [Case 1. U-Plast website](/en/portfolio/design-uplast), [Case 3. Analytics and dashboards for U-Plast CRM](/en/portfolio/u-plast-analytics), [Case 2: House Visualiser for U-Plast](/en/portfolio/u-plast-app)","subtitle":"Backend · Platform","challenge":"The goal of this project was to develop a handy and fast tool to allow the customer to get the exact cost of siding for their house or building in a few clicks. To achieve this goal Piplos Media used advanced programming technology and paid attention to every detail of the development.","description":"Development of U-Plast siding costing software","stack_detail":"PHP, MySQL, JavaScript"},"ru":{"title":"Разработка ПО калькулятора","result":"Результатом разработки ПО для Ю-Пласт стал удобный и точный инструмент, который помогает Заказчикам быстро и легко расчитать стоимость необходимого сайдинга, учитывая все особенности и требования. Piplos Media гордится своим проектом и продолжает работать над разработкой новых инновационных решений в области программного обеспечения.","solution":"Piplos Media – молодая и динамично развивающаяся компания в сфере разработки программного обеспечения. В одном из недавних проектов Piplos Media было разработано ПО для расчета стоимости необходимого сайдинга для компании Ю-Пласт, одного из крупнейших производителей сайдинга.\n\nЦель проекта была разработка удобного и быстрого инструмента, который позволяет Заказчику в несколько кликов получить точную стоимость необходимого сайдинга для дома или здания. Для достижения этой цели, Piplos Media использовала передовые технологии программирования и уделяла внимание каждой детали разработки.\n\n![Разработка ПО калькулятора — 1](/uploads/projects/uplast-calculator/fd83ca61fe8441618b1d6962453d35fe.png)\n\nОдной из ключевых особенностей ПО является его интуитивно понятный интерфейс, который позволяет пользователям легко настраивать параметры расчета и получать точные результаты. Кроме того, ПО позволяет проводить расчеты не только для типовых зданий, но и для сложных архитектурных конструкций, учитывая каждую деталь и особенность здания.\n\n**Сайт проекта:** [shop.u-plast.by](https://shop.u-plast.by)\n\n**Связанные проекты:** [Кейс 1. Веб-сайт Ю-Пласт](/ru/portfolio/design-uplast), [Кейс 3. Аналитика и дашборды для CRM Ю-Пласт](/ru/portfolio/u-plast-analytics), [Кейс 2: Визуализатор домов для Ю-Пласт](/ru/portfolio/u-plast-app)","subtitle":"Бэкенд · Платформа","challenge":"Цель проекта была разработка удобного и быстрого инструмента, который позволяет Заказчику в несколько кликов получить точную стоимость необходимого сайдинга для дома или здания. Для достижения этой цели, Piplos Media использовала передовые технологии программирования и уделяла внимание каждой детали разработки.","description":"Разработка программного обеспечения для расчета стоимости сайдинга Ю-Пласт","stack_detail":"PHP, MySQL, JavaScript"}}$row_101$::jsonb)
