INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('detskidom', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2017, false, true, 102, '/uploads/projects/detskidom/image-12.png', $row_102${"en":{"title":"charity project","result":"The project was successfully delivered to the client. The work was completed in 2017.","solution":"One of the keys to designing a website for an orphanage is a user-friendly interface that makes it easy to find the information needed. It is also important to ensure data security, especially when it comes to photographs of children. The site should be adaptive and easy to use, so anyone can easily find the information they need and make a donation.\n\n![charity project — 1](/uploads/projects/detskidom/4ee6165963a443a48293e60515c8fe5c.png)\n\nDeveloping a website for an orphanage is an important step towards improving the lives of children who find themselves in difficult situations. Such a website can facilitate the process of finding the right things or products for the orphanage, as well as get more people involved in charity work. Moreover, the website can help make the interaction between the orphanage and the community more transparent and effective.\n\nIn order to create such a website, the company-developer has to work thoroughly on every aspect - from design to functionality. All the needs of the orphanage and its staff should be taken into account, as well as the needs of the users of the site who want to provide charitable assistance. In the end, a quality website for an orphanage will help make the world a better place for those in need.","subtitle":"Web · Website","challenge":"Orphanages always need help and attention from society. Developing a website for an orphanage is a step towards making the process more transparent and convenient for all involved. A company developing a website for an orphanage should have an understanding of how it can make the site as useful as possible for the children and staff of the orphanage, as well as for people who want to provide charitable assistance.","description":"Developing a website for an orphanage: how technology can help charities","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"благотворительный проект","result":"Для того чтобы создать такой сайт, компания-разработчик должна тщательно проработать каждый момент - от дизайна до функционала. Необходимо учитывать все потребности детского дома и его сотрудников, а также потребности пользователей сайта, которые хотят оказать благотворительную помощь. В итоге, качественный сайт для детского дома поможет сделать мир лучше для тех, кто в нем нуждается.","solution":"Один из ключевых моментов в разработке сайта для детского дома - это удобный интерфейс, который позволяет легко находить необходимую информацию. Также важно обеспечить безопасность данных, особенно если речь идет о фотографиях детей. Сайт должен быть адаптивным и простым в использовании, чтобы любой пользователь мог легко находить нужную информацию и сделать пожертвование.\n\n![благотворительный проект — 1](/uploads/projects/detskidom/4ee6165963a443a48293e60515c8fe5c.png)\n\nРазработка сайта для детского дома - это важный шаг в направлении улучшения жизни детей, которые оказались в трудной жизненной ситуации. Благодаря такому сайту можно облегчить процесс поиска нужных вещей или продуктов для детского дома, а также привлечь больше людей к благотворительности. Кроме того, сайт может помочь сделать процесс взаимодействия между детским домом и обществом более прозрачным и эффективным.","subtitle":"Веб · Сайт","challenge":"Детские дома всегда нуждаются в помощи и внимании со стороны общества. Разработка сайта для детского дома - это шаг к тому, чтобы сделать этот процесс более прозрачным и удобным для всех участников. Компания, занимающаяся разработкой сайта для детского дома, должна иметь понимание того, каким образом она может сделать сайт максимально полезным для детей и сотрудников детского дома, а также для людей, которые хотят оказать благотворительную помощь.","description":"Разработка сайта Детскому Дому: как технологии могут помочь в благотворительности","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_102$::jsonb)
