INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('molochnyymir', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2017, false, true, 104, '/uploads/projects/molochnyymir/group-54.png', $row_104${"en":{"title":"Milky World","result":"The project was successfully delivered to the client. The work was completed in 2017.","solution":"The concept idea was created using corporate colors of the enterprise and simplifying the structure of the site for quick access to information on it.\n\n![Молочный Мир](/uploads/projects/molochnyymir/54f1816fd5a1475e8ccf91c8289a8214-2.png)","subtitle":"Web · Website","challenge":"s part of the tender proposal, a concept idea was developed for the main page of one of the leaders in the dairy industry of the Republic of Belarus OJSC \"Milk World\". The concept includes the title block of the main page, on which we have placed the main categories of goods produced at this enterprise, with the allocation of goods.","description":"The concept-idea of ​​the site of OJSC \"Milk World\"","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Молочный Мир","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2017 году.","solution":"Концепт-идея создана с использованием фирменных цветов предприятия и упрощения структуры сайта для быстрого доступа информации на нем.\n\n![Молочный Мир](/uploads/projects/molochnyymir/54f1816fd5a1475e8ccf91c8289a8214.png)","subtitle":"Веб · Сайт","challenge":"В рамках конкурсного предложения, была разработана концепт-идея главной страницы одного из лидеров в молочной отросли РБ ОАО \"Молочный Мир\". Концепция включает в себя титульный блок главной страницы, на который мы вынесли основные категории товаров производимые на данном предприятии, с выделением товаров.","description":"Концепт-идея сайта ОАО \"Молочный Мир\"","stack_detail":"UI/UX, Figma, Photoshop"}}$row_104$::jsonb)
