INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('radiorelax-app', 'mobile', ARRAY['mobile'], ARRAY['Android', 'iOS'], 2017, false, true, 105, '/uploads/projects/radiorelax-app/44e1d0a9160a4d6ba7ce6948e46f688e.png', $row_105${"en":{"title":"RADIO RELAX app","result":"The project was successfully delivered to the client. The work was completed in 2017.","solution":"The functionality of the application should be as identical as possible with the site and allow you to easily listen to the radio, search for music and participate in promotions.\n\n![Приложение \"Рэлакс ФМ\"](/uploads/projects/radiorelax-app/6f473086d96346b2a4edbcd693872f7a-2.png)\n\nhe style of the application should be as similar as possible to the site of the Radio Station. To be light and unobtrusive.\n\n![RADIO RELAX app — 2](/uploads/projects/radiorelax-app/f6cc8a2e34ec416ca73fc290c834eefd-2.png)","subtitle":"Mobile · Mobile app","challenge":"As part of the project to create the Relax FM radio station website (radiorelax.by), we were also tasked with creating a mobile application for Android and iOS.","description":"Development of iOS and Android applications of the radio station \"RADIO RELAX\"","stack_detail":"Android, iOS"},"ru":{"title":"Приложение РАДЫЁ RELAX","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2017 году.","solution":"Функционал приложения должен быть максимально идентичным с сайтом и позволять без проблемно слушать радио, искать музыку и участвовать в акциях.\n\n![Приложение \"Рэлакс ФМ\"](/uploads/projects/radiorelax-app/6f473086d96346b2a4edbcd693872f7a.png)\n\nСтиль приложения, должен максимально быть схож с сайтом Радиостанции. Быть легким и ненавязчивым.\n\n![Приложение РАДЫЁ RELAX — 2](/uploads/projects/radiorelax-app/f6cc8a2e34ec416ca73fc290c834eefd.png)","subtitle":"Мобильное · Приложение","challenge":"В рамках проекта по созданию сайта радиостанции \"Рэлакс ФМ\" перед нами была поставлена также задача по созданию мобильного приложения для Android и iOS.","description":"Разработка iOS и Android приложения радиостанции РАДЫЁ RELAX","stack_detail":"Android, iOS"}}$row_105$::jsonb)
