INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('expobel', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2017, false, true, 106, '/uploads/projects/expobel/e04f0f7a2fea4bc9bb998d0d2b59e29d.jpg', $row_106${"en":{"title":"SEC \"EXPOBEL\"","result":"The project was successfully launched and is available at expobel.by. The work was completed in 2017.","solution":"Nevertheless, we approached very responsibly and creatively the solution of the Tasks that the Customer set for us.\n\nThe main point we made was that the implementation of the 3D tour is an outdated and unnecessary technology for the implementation of such projects. And they convinced the customer to implement the Interactive map of the shopping center.\n\n![SEC \"EXPOBEL\" — 1](/uploads/projects/expobel/87180d98810e4da296e6ac4138989ce9-2.png)\n\nIt was a very useful and necessary experience in implementing this kind of functionality.\n\nThe site design was executed in the style of Brandbook. The site navigation was thought out for the convenience of finding information by the user. The emphasis was also on the target audience - on youth.\nWell, and, of course, the main thing we achieved was the dissimilarity with other shopping and entertainment centers in the Republic.\n\n![ТРЦ «EXPOBEL»](/uploads/projects/expobel/99c5bbc82efb44d69de115affae1786a-2.png)\n\n**Project website:** [expobel.by](http://expobel.by)","subtitle":"Web · Website","challenge":"This is the first experience of creating projects for shopping centers at Piplos Media.","description":"Regional shopping and entertainment complex with a long history \"EXPOBEL\"","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"ТРЦ «EXPOBEL»","result":"Проект успешно запущен и доступен по адресу expobel.by. Работы выполнены в 2017 году.","solution":"Это первый опыт создания проектов для торговых центров в компании Piplos Media.\n\nТем не менее мы подошли очень ответственно и креативно к решению Задач которые поставил нам Заказчик.\n\nОсновной момент мы сделали на том, что реализация 3D-тура – это устаревшая и не нужная технология для реализации таких проектов. И убедили заказчика в реализации Интерактивной карты ТРЦ.\n\n![ТРЦ «EXPOBEL» — 1](/uploads/projects/expobel/87180d98810e4da296e6ac4138989ce9.png)\n\nЭто был очень полезный и нужный опыт в реализации такого рода функционала.\n\nДизайн сайта был исполнен в стиле Брендбука. Была продумана навигация по сайту для удобства поиска информации пользователем. Так же делался акцент на целевую аудиторию - на молодежь.\nНу и, конечно, основное чего мы добивались — это несхожесть с другими ТРЦ в Республике.\n\n![ТРЦ «EXPOBEL»](/uploads/projects/expobel/99c5bbc82efb44d69de115affae1786a.png)\n\n**Сайт проекта:** [expobel.by](http://expobel.by)","subtitle":"Веб · Сайт","challenge":"Тем не менее мы подошли очень ответственно и креативно к решению Задач которые поставил нам Заказчик.","description":"Региональный торгово-развлекательный комплекс с многолетней историей «EXPOBEL»","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_106$::jsonb)
