INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('radiorelax', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2017, false, true, 107, '/uploads/projects/radiorelax/3d5f76e25bfc4385b0bd0172729003f8.png', $row_107${"en":{"title":"Radio \"Radio Relax\"","result":"The project was successfully launched and is available at radiorelax.by. The work was completed in 2017.","solution":"Develop a website for Radio Relax, specializing in the best collections of calm, soft and melodic popular music, which is an ideal backdrop for work and leisure.\n\nThere is no host or news on Relax Radio. The personality of Relax radio is that, with the help of the ether, the radio station transmits light and calm emotions.\n\n![Радио \"Релакс ФМ\"](/uploads/projects/radiorelax/2c93f61fd2334d4eba1fe315f7e623d6-2.png)\n\nThe project functionality is similar to other projects that we created earlier for radio stations:\n\n- Player with online broadcasting radio station streams\n- Search and listen to music that played on the air\n- Search and listen to programs\n- Carrying out various Promotions on the radio station\n\n![Radio \"Radio Relax\" — 2](/uploads/projects/radiorelax/409355ebe32b46e08d89e75984cb0ac3-2.png)\n\n**Project website:** [radiorelax.by](http://radiorelax.by)","subtitle":"Web · Website","challenge":"We were faced with a not new and very interesting task:","description":"Website development for Radio \"Relax Relax\"","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Радио \"Радыё Relax\"","result":"Проект успешно запущен и доступен по адресу radiorelax.by. Работы выполнены в 2017 году.","solution":"Разработать сайт радиостанции \"Радыё Relax, специализирующиеся на лучших коллекциях спокойной, мягкой и мелодичной популярной музыки, которая является идеальным фоном для работы и отдыха.\n\nВ эфире радио Relax нет ведущего и новостей. Индивидуальностей радио Relax в том, что с помощью эфира, радиостанция передает легкие и спокойные эмоции.\n\n![Радио \"Релакс ФМ\"](/uploads/projects/radiorelax/2c93f61fd2334d4eba1fe315f7e623d6.png)\n\nФункционал проекта схож с другими проектами созданными нами ранее для радиостанций:\n\n- Плеер с онлайн вещанием потоков радиостанции\n- Поиск и прослушивание музыки которая играла в эфире\n- Поиск и прослушивание программ \n- Проведение различных Акций на радиостанции\n\n![Радио \"Радыё Relax\" — 2](/uploads/projects/radiorelax/409355ebe32b46e08d89e75984cb0ac3.png)\n\n**Сайт проекта:** [radiorelax.by](http://radiorelax.by)","subtitle":"Веб · Сайт","challenge":"Перед нами стояла уже не новая и весьма интересная задача:","description":"Создание сайта радиостанции \"Радыё Relax\"","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_107$::jsonb)
