INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('autoactive', 'mobile', ARRAY['mobile'], ARRAY['Android', 'iOS'], 2017, false, true, 108, '/uploads/projects/autoactive/artboard-copy-55.png', $row_108${"en":{"title":"Autoactive app","result":"Moderator mode: view queues for the service for today and tomorrow the ability to cancel the client’s record to the moderator 3 modes are available: Free (changes to green on the map), queue (the color on the map is yellow, the label changes after 2 hours to green), pause / play (default is play, the color on the map is red if there is a pause and means that this point does not work)","solution":"AutoActive is an application that is designed to save time and provide convenient service for car maintenance. It is possible to sort car washes and tire service by type. A personal account of the user and an admin panel for managing car washes and tire fitting have been developed.\n\nIn this project were developed an API and promosite.\n\nThe mobile application combines 2 use modes:\n1. Client mode\n2. Car wash or Tire Moderator mode\n\n![Autoactive app — 1](/uploads/projects/autoactive/0679aee563af4b66baf3c269ceca36e9-2.png)\n\nClient mode:\n- Geolocation\n- Display on an interactive map of the location points of Carwash and Tire service\n- Division into Carwash categories\n- Ability to sign up (Time, date)\n- Display price list with service prices\n\n![Autoactive app — 2](/uploads/projects/autoactive/e0848c639291495a8df3e439ee737dc0-2.png)\n\n![Autoactive app — 3](/uploads/projects/autoactive/45655ce3a09f43bb8d18519cf13a6754-2.png)\n\n**Related projects:** [Autoactive Landing](/en/portfolio/autoactive-site)","subtitle":"Mobile · Mobile app","challenge":"his project is a mobile app for Android and iOS and a web interface for administration.","description":"Development of a mobile assistant application for driver","stack_detail":"Android, iOS"},"ru":{"title":"Приложение Автоактив","result":"Режим модератора: просмотр очереди на услугу на сегодня и на завтра возможность отменить запись клиента модератору доступны 3 режима : Свободно (меняет на зеленый цвет на карте), очередь (цвет на карте желтый, метка меняется по истечению 2 часов на зеленый цвет), pause/play (по умолчанию play, цвет на карте красный если стоит пауза и означает, что данная точка не работает)","solution":"АвтоАктив – приложение, которое предназначено для того, что бы сэкономить время и предоставить удобный сервис по обслуживанию автомобиля. Предусмотрена возможность отсортировать автомойки и шиномонтажи по типу. Разработан личный кабинет пользователя и админка управления автомойками ишиномонтажами.\n\nВ рамках проекта было разработано API и [промосайт](/ru/portfolio/autoactive-site).\n\nМобильное приложение совмещает 2 режима использования:\n1. Режим Клиента\n2. Режим Модератора Автомойки или Шиномонтажа\n\n![Приложение Автоактив — 1](/uploads/projects/autoactive/0679aee563af4b66baf3c269ceca36e9.png)\n\nРежим Клиента:\n- Геолокация\n- Отображение на интерактивной карте месторасположения точек Автомоек и Шиномонтажей\n- Разделение на категории Автомоек \n- Возможность записаться (Время, дата)\n- Отображение прайса с ценами на услуги\n\n![Приложение Автоактив — 2](/uploads/projects/autoactive/e0848c639291495a8df3e439ee737dc0.png)\n\n![Приложение Автоактив — 3](/uploads/projects/autoactive/45655ce3a09f43bb8d18519cf13a6754.png)","subtitle":"Мобильное · Приложение","challenge":"Данный проект представляет собой мобильное приложение для Android и iOS и веб-интерфейс для администрирования.","description":"Разработка мобильного приложения-помощника автомобилистам","stack_detail":"Android, iOS"}}$row_108$::jsonb)
