INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('farmina-shop', 'web', ARRAY['web', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2017, false, true, 109, '/uploads/projects/farmina-shop/group-55.png', $row_109${"en":{"title":"Farmina Online Store","result":"The project was successfully launched and is available at farmina-shop.by. The work was completed in 2017.","solution":"Based on the topics of this Project, we approached non-standardly to the implementation of the visualization of this project. Namely, a clear division of the main page into two categories of food:\n- Food for Dogs\n- Food for Cats\n\nBased on this logic, the project structure was formed.\n\n![Farmina Online Store — 1](/uploads/projects/farmina-shop/ffa1eb2b7ba946e9b7da7fd1fb88a001-2.png)\n\nAll color solutions were used from the corporate identity of Farmina Pet Foods.\n\nThe structure of the Product Card consists of the following elements:\n- photo of feed\n- detailed description\n- composition\n- reviews\n- ability to choose the desired package size\n\n![Farmina Online Store — 2](/uploads/projects/farmina-shop/1952d0b8f12948d1923de79ab28b5f96-2.png)\n\nFunctionality of this Online Store was as simple as possible.\n\n![Farmina Online Store — 3](/uploads/projects/farmina-shop/35875ee03b744df4ad91c16afeff58ca-2.png)\n\nNevertheless, we tried to implement the most interesting design of the project in order to emphasize this.\n\n![Farmina Online Store — 4](/uploads/projects/farmina-shop/fd0a20005a8341c3af8334290e004f33-2.png)\n\n**Project website:** [farmina-shop.by](https://farmina-shop.by)\n\n**Related projects:** [Farmina Pet Foods](/en/portfolio/farmina-promo)","subtitle":"Web · E-commerce","challenge":"As part of the development of the Farmina Pet Foods trading network, it was decided to create an Online Store.","description":"Online Store of the official distributor of the Farmina Pet Foods trademark","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Интернет Магазин Farmina","result":"Проект успешно запущен и доступен по адресу farmina-shop.by. Работы выполнены в 2017 году.","solution":"Исходя из тематики данного ИМ, мы подошли нестандартно к реализации визуализации данного проекта. А именно Четкого разделения главной страницы на две категории кормов:\n- Корма для Собак\n- Корма для Кошек\n\nИсходя из данной логики и формировалась структура проекта.\n\n![Интернет Магазин Farmina — 1](/uploads/projects/farmina-shop/ffa1eb2b7ba946e9b7da7fd1fb88a001.png)\n\nВсе цветовые решения были использованы из фирменного стиля компании «Farmina Pet Foods».\n\nСтруктура Карточки Товара состоит из следующих элементов:\n- фото корма\n- подробного описания\n- состав\n- отзывы\n- возможность выбрать нужный размер упаковки\n\n![Интернет Магазин Farmina — 2](/uploads/projects/farmina-shop/1952d0b8f12948d1923de79ab28b5f96.png)\n\nФункционал данного Интернет-Магазина был максимально простым.\n\n![Интернет Магазин Farmina — 3](/uploads/projects/farmina-shop/35875ee03b744df4ad91c16afeff58ca.png)\n\nТем не менее, мы постарались реализовать максимально интересный дизайн проекта, чтобы сделать на это акцент.\n\n![Интернет Магазин Farmina — 4](/uploads/projects/farmina-shop/fd0a20005a8341c3af8334290e004f33.png)\n\n**Сайт проекта:** [farmina-shop.by](https://farmina-shop.by)\n\n**Связанные проекты:** [Корма от Farmina](/ru/portfolio/farmina-promo)","subtitle":"Веб · E-commerce","challenge":"В рамках развития торговой сети «Farmina Pet Foods», было принято решение о создании Интернет Магазина.","description":"Интернет Магазин официального дистрибьютора торговой марки «Farmina Pet Foods»","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_109$::jsonb)
