INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('mini-mba', 'web', ARRAY['web', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2017, false, true, 110, '/uploads/projects/mini-mba/1ae8be4a1c29494bb047374ea3f2907c.png', $row_110${"en":{"title":"Site Mini-MBA","result":"The project was successfully delivered to the client. The work was completed in 2017.","solution":"The site is made in the current design of the seminar program. But it can be supplemented, improved. It is important that it looks modern, dynamic, bright, interesting, evokes positive emotions.\n\nThe design was developed based on the advertising booklet of these courses..\n\n![Site Mini-MBA — 1](/uploads/projects/mini-mba/182407eb1b874e2ba5cf90b568b79a44-2.png)\n\nAn important requirement for this project was collecting data from all feedback forms into one database.\n\nThis will be the following: “What form the application came from” + information that was filled in the form itself (Name, phone, e-mail, comment). In the admin panel, the ability to sort this table will work, making a selection according to the feedback forms that interest us.\n\nImplement the ability to download from the admin panel the database of email addresses collected from the feedback forms (in Excel table format).\n\n![Site Mini-MBA — 2](/uploads/projects/mini-mba/fa60590d2adb4c29b6e434628a2d778c-2.png)","subtitle":"Web · E-commerce","challenge":"This project was developed for the Consulting Group \"Here and Now\".","description":"Development of a new workshop site in the Mini-MBA format","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Сайт Mini-MBA","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2017 году.","solution":"Сайт выполнен в сложившемся дизайне программы семинаров. Но можно его дополнять, улучшать. Важно, чтобы смотрелось современно, динамично, ярко, интересно, вызывало положительные эмоции.\n\nДизайн разрабатывался исходя из рекламного буклета данных курсов.\n\n![Сайт Mini-MBA — 1](/uploads/projects/mini-mba/182407eb1b874e2ba5cf90b568b79a44.png)\n\nВажное требованеи к данному проекту было сбор данных со всех форм обратной связи в одну базу.\n\nДаннуе будут следующие: «С какой формы пришла заявка» + информация, которая была заполнена в самой форме (Имя, телефон, e-mail, комментарий). В админ-панеле будет работать возможность сортировки данной таблицы, делая выборку по интересующим нас формам обратной связи.\n\nРеализовать возможность выгружать из админ-панели базу собранных из форм обратной связи электронных адресов (в формате Excel таблицы).\n\n![Сайт Mini-MBA — 2](/uploads/projects/mini-mba/fa60590d2adb4c29b6e434628a2d778c.png)","subtitle":"Веб · E-commerce","challenge":"Данный проект разработан для Консалтинговой группы \"Здесь и Сейчас\".","description":"Разработка нового сайта семинаров в формате «Mini-MBA»","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_110$::jsonb)
