INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('addicted-agency', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2017, false, true, 111, '/uploads/projects/addicted-agency/7432632f90454798b619b6bde60168bd.png', $row_111${"en":{"title":"Website for the Addicted Agency","result":"The project was successfully delivered to the client. The work was completed in 2017.","solution":"The developed Website will be designed to provide users with a convenient interface and information about the company and the projects that it has implemented. In the further implementation of the online store based on this site.\n![Website for the Addicted Agency — 1](/uploads/projects/addicted-agency/74ac8d5b3e3140ff8f9b64fa7e7ec3a6-2.png)\n\nThe website will be presented in the following structure:\n- Website main page;\n- page About us\n- page Projects\n- page ventures (venture investments)\n- page Contacts\n- page News\n\n![Website for the Addicted Agency — 2](/uploads/projects/addicted-agency/adc67ad659f14326ab533f279adc01ad-2.png)\n\nWe tried to maximize all the advantages of the projects that implemented agency. Each section of the site is unique and unique in structure \n![Website for the Addicted Agency — 3](/uploads/projects/addicted-agency/898d506197a64a6491730e8d8974c73a-2.png)\n\nThe project will concentrate its attention on working with content, namely with images.\n\n![Website for the Addicted Agency — 4](/uploads/projects/addicted-agency/9150088c88c446db87bd72f0041b6c06-2.png)","subtitle":"Web · Website","challenge":"We were contacted by an advertising agency for the development of a site for their company. The essence of the project was the most creative approach to the implementation of the site with the display of the agency’s portfolio.","description":"Website Development Advertising Agency","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Сайт агенства Addicted Agency","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2017 году.","solution":"Разрабатываемый Веб-сайт будет предназначен для предоставления пользователям удобного интерфейса и информации о компании и проектов которые оно реализовало. В дальнейшем реализации интернет-магазина на основе данного сайта.\n![Сайт агенства Addicted Agency — 1](/uploads/projects/addicted-agency/74ac8d5b3e3140ff8f9b64fa7e7ec3a6.png)\n\nВеб-сайт будет представлен в виде следующей структуры:\n- Главная страница сайта;\n- страница О нас\n- страница Проекты\n- страница ventures(венчурные инвестиции)\n- страница Контакты\n- страница Новости\n\n![Сайт агенства Addicted Agency — 2](/uploads/projects/addicted-agency/adc67ad659f14326ab533f279adc01ad.png)\n\nМы постарались максимально отобразить все преимущества проектов которые реализовало агенство. Каждый раздел сайта носит уникальный характер и уникальную структуру. \n![Сайт агенства Addicted Agency — 3](/uploads/projects/addicted-agency/898d506197a64a6491730e8d8974c73a.png)\n\nПроект максимально концентрирет свое вниманеи на работу с контентом, а именно с изображениями.\n\n![Сайт агенства Addicted Agency — 4](/uploads/projects/addicted-agency/9150088c88c446db87bd72f0041b6c06.png)","subtitle":"Веб · Сайт","challenge":"К нам обратилось рекламное Агенство за разработкой сайта для своей компании. Суть проекта заключалась в максимально креативном подходе реализации сайта с отображением портфолио агенства.","description":"Разработка сайта Рекламного Агенства","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_111$::jsonb)
