INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('factios', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2017, false, true, 112, '/uploads/projects/factios/e0f972aea9924197b86fceca2a941a8d.jpg', $row_112${"en":{"title":"Cognitive facts","result":"The project was successfully launched and is available at factios.com. The work was completed in 2017.","solution":"The site displays interesting facts from completely different areas of life.\nThe site will display links to the source, if any.\n\n![Cognitive facts — 1](/uploads/projects/factios/6051d23b1ed549d2b736665c6d81a754-2.png)\n\nThe site will be in 3 languages (Russian, English, French).\n\n![Cognitive facts — 2](/uploads/projects/factios/f722366593cf4f89918efe5cbeee3013-2.png)\n\nThis project is a kind of application for desktop and mobile devices.\n\n![Cognitive facts — 3](/uploads/projects/factios/9c6febdc624448788b51bacb4e773f22-2.png)\n\n**Project website:** [factios.com](https://factios.com)","subtitle":"Web · Website","challenge":"The essence of the project is simple - interesting facts.","description":"Cognitive facts","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Познавательные факты","result":"Проект успешно запущен и доступен по адресу factios.com. Работы выполнены в 2017 году.","solution":"На сайте выводятся интересные факты из абсолютно разных сфер жизни. \nНа сайте будут выводиться ссылки на первоисточник при наличии такового.\n\n![Познавательные факты — 1](/uploads/projects/factios/6051d23b1ed549d2b736665c6d81a754.png)\n\nСайт будет на 3 языках (русский, английский, французский).\n\n![Познавательные факты — 2](/uploads/projects/factios/f722366593cf4f89918efe5cbeee3013.png)\n\nДанный проект - это подобие приложения для десктопа и мобильников устройств.\n\n![Познавательные факты — 3](/uploads/projects/factios/9c6febdc624448788b51bacb4e773f22.png)\n\n**Сайт проекта:** [factios.com](https://factios.com)","subtitle":"Веб · Сайт","challenge":"Суть проекта проста - интересные факты.","description":"Познавательные факты","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_112$::jsonb)
