INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('v-tv', 'web', ARRAY['web'], ARRAY['HTML/CSS'], 2016, false, true, 113, '/uploads/projects/v-tv/053f8bbb721b437794af161bae154d9a.jpg', $row_113${"en":{"title":"VTV channel","result":"The project was successfully launched and is available at v-tv.by. The work was completed in 2016.","solution":"The most basic tasks included:\n\n1. Development of adaptive design\n2. Front-end\n\n![VTV channel — 1](/uploads/projects/v-tv/e92da2c2ea2640d198651d42f211aaa2-2.png)\n\nWe also solved a number of technical problems associated with the publication of \"Projects\" \"and\" Programs \"\n\n![Телеканал ВТВ](/uploads/projects/v-tv/c54bc2e8d7464716b91bcd0f02a68592-2.png)\n\n**Project website:** [v-tv.by](http://v-tv.by)","subtitle":"Web · Website","challenge":"As part of technical support, a number of tasks were set for the valiant Piplos Media team to finalize the main site of the VTV channel.","description":"Belarusian entertainment channel","stack_detail":"HTML/CSS"},"ru":{"title":"Телеканал ВТВ","result":"Проект успешно запущен и доступен по адресу v-tv.by. Работы выполнены в 2016 году.","solution":"Самые основные задачи включали в себя:\n\n1. Разработку адаптивного дизайна\n2. Верстку адаптивного дизайна\n\n![Телеканал ВТВ — 1](/uploads/projects/v-tv/e92da2c2ea2640d198651d42f211aaa2.png)\n\nТак же мы решили ряд технических проблем связанных с публикациями \"Проектов\" и \"Программ\"\n\n![Телеканал ВТВ](/uploads/projects/v-tv/c54bc2e8d7464716b91bcd0f02a68592.png)\n\n**Сайт проекта:** [v-tv.by](http://v-tv.by)","subtitle":"Веб · Сайт","challenge":"В рамках технической поддержки, перед доблестной командой Piplos Media были поставлены ряд задач по доработке основного сайта телеканала ВТВ.","description":"Белорусский развлекательный телеканал.","stack_detail":"HTML/CSS"}}$row_113$::jsonb)
