INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('ecyberbet', 'backend', ARRAY['backend'], ARRAY['PHP', 'MySQL', 'JavaScript'], 2016, false, true, 115, '/uploads/projects/ecyberbet/a71fb9b0a230462886ce2e650b73d444.jpeg', $row_115${"en":{"title":"ECyberBet eSports Betting","result":"The project was successfully delivered to the client. The work was completed in 2016.","solution":"![ECyberBet eSports Betting — 1](/uploads/projects/ecyberbet/b7c60606b38a4f7183099a287e64464c-2.png)\n\nThe main feature of this project is the calculation of odds for bets on various events, well, the bets themselve.\n\n![ECyberBet eSports Betting — 2](/uploads/projects/ecyberbet/6b32641d2afa4bf38780ee28f059d174-2.png)\n\nThe project is constantly being developed and improved.\n\n![ECyberBet eSports Betting — 3](/uploads/projects/ecyberbet/89654fc68f1b4ba78a280160774fe1cb-2.png)","subtitle":"Backend · Platform","challenge":"The eCyberBet.com project is designed for online broadcasting of cyber games. As well as various news and team review.","description":"ECyberBet eSports Betting","stack_detail":"PHP, MySQL, JavaScript"},"ru":{"title":"Ставки на киберспорт ECyberBet","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2016 году.","solution":"![Ставки на киберспорт ECyberBet — 1](/uploads/projects/ecyberbet/b7c60606b38a4f7183099a287e64464c.png)\n\nОсновная фишка данного проекта - просчет коэффициентов на ставки на различные события, ну и сами ставки.\n\n![Ставки на киберспорт ECyberBet — 2](/uploads/projects/ecyberbet/6b32641d2afa4bf38780ee28f059d174.png)\n\nПроект постоянно дорабатывается и совершенствуется.\n\n![Ставки на киберспорт ECyberBet — 3](/uploads/projects/ecyberbet/89654fc68f1b4ba78a280160774fe1cb.png)","subtitle":"Бэкенд · Платформа","challenge":"Проект eCyberBet.com разработан для онлайн трансляции кибер игр. А так же различным новостям и обзорам команд.","description":"Ставки на киберспорт ECyberBet","stack_detail":"PHP, MySQL, JavaScript"}}$row_115$::jsonb)
