INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('pg-arch', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2016, false, true, 116, '/uploads/projects/pg-arch/2f69a4e5a9834eb984ad1abe2dc3b6fb.png', $row_116${"en":{"title":"George Pryanichnikov","result":"The project was successfully launched and is available at pg-arch.ru. The work was completed in 2016.","solution":"![George Pryanichnikov — 1](/uploads/projects/pg-arch/5e83fec965d646f989210ef71eb74927-2.png)\n\nThe site was created under the close supervision of the Customer. All his \"Wishlist\" were taken into account when developing the site visualization.\n\n![George Pryanichnikov — 2](/uploads/projects/pg-arch/deb4cbb3a3484bfa800329c10b630b2a-2.png)\n\n**Project website:** [pg-arch.ru](http://pg-arch.ru)","subtitle":"Web · Website","challenge":"The main characteristics of the site: maximum speed of access to site materials clarity and simplicity of the user's internal movements on the site graphic and color restraint the presence of elements readable by search engines on the site FULL absence of animation and advertising on the fields maximum protection of the site against viruses","description":"The site of the Georgy Pryanichnikov Architectural Studio","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Георгий Пряничников","result":"Проект успешно запущен и доступен по адресу pg-arch.ru. Работы выполнены в 2016 году.","solution":"![Георгий Пряничников — 1](/uploads/projects/pg-arch/5e83fec965d646f989210ef71eb74927.png)\n\nСайт был создан под чутким контролем Заказчика. Все его \"хотелки\" были учтены при разработке визуализации сайта.\n\n![Георгий Пряничников — 2](/uploads/projects/pg-arch/deb4cbb3a3484bfa800329c10b630b2a.png)\n\n**Сайт проекта:** [pg-arch.ru](http://pg-arch.ru)","subtitle":"Веб · Сайт","challenge":"Основные характеристика сайта: максимальная скорость доступа к материалам сайта ясность и простота внутренних перемещений пользователя по сайту графическая и цветовая сдержанность наличие в сайте элементов, считываемых поисковыми системами ПОЛНОЕ отсутствие анимации и рекламы на полях максимальная защищенность сайта от вирусов","description":"Сайт Архитектурной мастерской Георгия Пряничникова","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_116$::jsonb)
