INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('aps-solver', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2016, false, true, 117, '/uploads/projects/aps-solver/c5d7ed3b19a548d1ab2933b20f872c8f.jpg', $row_117${"en":{"title":"International Freight Carrier APS","result":"The project was successfully launched and is available at aps-solver.ru. The work was completed in 2016.","solution":"he old company website was developed in 2011. It was developed at the time the brand was launched, when the company did not have its own building, and the fleet consisted of disparate, non-branded equipment. In this regard, during the initial development, they resorted to creating graphic visual images for the main page and description of services (creative 3d-visualizations). At the moment, a significant stock of media content has been created (photos and videos) with new equipment, a new building, reports on completed transportation, etc. Thus, the current site does not reflect the changes that have occurred in the company over the past 3 years.\n\nThe main goal of creating a new site is the formation of a steadily growing number of calls (leads) in key areas of the company:\n\n1. selling services\n2. attracting employees\n3. selling equipment\n\nAdditional tasks:\n\n- to create a positive brand image, create the necessary image that promotes effective communication with targeted groups from different countries and regions;\n- provide prompt feedback from target groups to the company;\n- help potential customers quickly find the necessary information necessary when choosing company services;\n- create a convenient channel for two-way communication of the HR department of the company with potential employees.\n\nPriorities in development:\n\n1. design (spectacular, memorable);\n2. ease of use of the site (find and receive information);\n3. software implementation (innovative technical solutions);\n\n![Международный грузоперевозчик APS](/uploads/projects/aps-solver/eece957730f4412f8d79393579612852-2.png)\n\n**Project website:** [aps-solver.ru](https://aps-solver.ru)","subtitle":"Web · Website","challenge":"The main goal of creating a new site is the formation of a steadily growing number of calls (leads) in key areas of the company:","description":"Website development for the logistics company APS-Solver","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Международный грузоперевозчик APS","result":"Проект успешно запущен и доступен по адресу aps-solver.ru. Работы выполнены в 2016 году.","solution":"Старый сайт компании был разработан в 2011 году. Он разрабатывался в момент запуска бренда, когда у компании не было собственного здания, а автопарк состоял из разрозненной, не брендированной техники. В связи с этим при первичной разработке прибегли к созданию графических визуальных образов для главной страницы и описания услуг (креативные 3d-визуализации) . На данный момент создан значительный запас медиаконтента (фото и видеоматериалы) с новой техникой, новым зданием, отчетами по выполненным перевозкам, и т.п. Таким образом, текущий сайт не отражает изменений, которые произошли в компании за последние 3 года.\n\nОсновная цель создания нового сайта – формирование устойчиво растущего количества обращений (лидов) по ключевым направлениям деятельности компании:\n\n1. продажа услуг\n2. привлечение сотрудников\n3. продажа техники\n\nДополнительные цели:\n\n- формировать положительный имидж бренда, создавать необходимый образ, способствующий эффективной коммуникации с целевыми группами из разных стран и регионов;\n- обеспечивать оперативную обратную связь целевых групп с компанией;\n- помогать потенциальным клиентам быстро найти необходимую информацию, необходимую при выборе услуг компании;\n- создать удобный канал двусторонней связи hr-отдела компании с потенциальными сотрудниками.\n\nПриоритеты в разработке:\n\n1. дизайн (эффектный, запоминающийся);\n2. удобство использования сайта (найти и получить информацию);\n3. программная реализация (инновационные технические решения);\n\n![Международный грузоперевозчик APS](/uploads/projects/aps-solver/eece957730f4412f8d79393579612852.png)\n\n**Сайт проекта:** [aps-solver.ru](https://aps-solver.ru)","subtitle":"Веб · Сайт","challenge":"Основная цель создания нового сайта – формирование устойчиво растущего количества обращений (лидов) по ключевым направлениям деятельности компании:","description":"Разработка сайта логистической компании APS-Solver","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_117$::jsonb)
