VALUES ('milkavita', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2016, false, true, 118, '/uploads/projects/milkavita/fb686dee334a4dcc9165c19ec7826a2f.png', $row_118${"en":{"title":"Milkavita","result":"The project was successfully delivered to the client. The work was completed in 2016.","solution":"![Милкавита](/uploads/projects/milkavita/98b6098890c74c1bb63131dec26252b0-2.png)","subtitle":"Web · Website","challenge":"he Milkavita company has launched a rebranding of its enterprise. In this connection, a concept idea was developed for a new vizaul of the main page of the site..","description":"Website design development for company rebranding","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Милкавита","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2016 году.","solution":"![Милкавита](/uploads/projects/milkavita/98b6098890c74c1bb63131dec26252b0.png)","subtitle":"Веб · Сайт","challenge":"Компания \"Милкавита\" запустила ребрендинг своего предприятия. В связи с чем была разработана концепт-идея нового визаула главной страницы сайта.","description":"Разработка дизайна сайта под ребрендинг компании","stack_detail":"UI/UX, Figma, Photoshop"}}$row_118$::jsonb)
