INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('selfiest', 'web', ARRAY['web'], ARRAY['Android', 'iOS'], 2016, false, true, 120, '/uploads/projects/selfiest/0f087b31f52d407ea25c02b3861592d9.jpeg', $row_120${"en":{"title":"Selfiest Promo Site","result":"The project was successfully launched and is available at selfiest.com. The work was completed in 2016.","solution":"The promo site includes general information about the project, links to downloading, information about the privacy policy, etc.\n\nThis project was developed for the Spanish Customer to promote a mobile app for selfie lovers.\n\n![Промо-сайт Selfiest](/uploads/projects/selfiest/348884a171774202a3a72ea5baaae270-2.png)\n\n**Project website:** [selfiest.com](https://selfiest.com)\n\n**Related projects:** [Selfiest mobile app](/en/portfolio/selfiest-app)","subtitle":"Web · Website","challenge":"The Selfiest site is a reference to the mobile application of this project, which is the main driver of this social network.","description":"Social network of selfie lovers","stack_detail":"Android, iOS"},"ru":{"title":"Промо-сайт Selfiest","result":"Проект успешно запущен и доступен по адресу selfiest.com. Работы выполнены в 2016 году.","solution":"Сайт Selfiest - это отсылка к [мобильному приложению](/ru/portfolio/selfiest-app) этого проекта, которое является основным русерсом данной социальной сети.\n\nПромо сайт включает в себя общую информацию о проекте, ссылки на скачивания его, инофрмацию о политике конфидинциальности и т.д.\n\nДанный проект разрабатывался для Испанского Заказчика для продвижения мобильного приложения любителей селфи.\n\n![Промо-сайт Selfiest](/uploads/projects/selfiest/348884a171774202a3a72ea5baaae270.png)\n\n**Сайт проекта:** [selfiest.com](https://selfiest.com)","subtitle":"Веб · Сайт","challenge":"Сайт Selfiest - это отсылка к мобильному приложению этого проекта, которое является основным русерсом данной социальной сети.","description":"Социальная сеть любителей селфи","stack_detail":"Android, iOS"}}$row_120$::jsonb)
