INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('metallobaza-concept-idea', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2016, false, true, 121, '/uploads/projects/metallobaza-concept-idea/artboard-copy-112.png', $row_121${"en":{"title":"Almier-Metallobaza","result":"The project was successfully launched and is available at metallobaza.by. The work was completed in 2016.","solution":"The main message is the creation of a new visual, taking into account the preservation of the functionality of the current project.\n\n![Металлобаза-Алмиер](/uploads/projects/metallobaza-concept-idea/3bda078017f64f029b586d064af0f945-2.png)\n\nWe have proposed the classical structure of such a project. It reflects all the main sections of the site, and the visual is presented strict and concise.\n\n**Project website:** [metallobaza.by](https://metallobaza.by)\n\n**Related projects:** [Almier Metal Base](/en/portfolio/metallobaza)","subtitle":"Web · Website","challenge":"As part of the support service, at the request of the Customer, a concept idea was developed for the Main page of a possible new Metallobaza website.","description":"Concept-idea of the new Metallobaza website","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Алмиер-Металлобаза (концепт)","result":"Проект успешно запущен и доступен по адресу metallobaza.by. Работы выполнены в 2016 году.","solution":"Основной посыл - это создание нового визуала с учетом сохранения функционала текущего проекта.\n\n![Металлобаза-Алмиер](/uploads/projects/metallobaza-concept-idea/3bda078017f64f029b586d064af0f945.png)\n\nНами была предложена классическая структура такого проекта. Она отражает все основные разделы сайта, а визуал, представлен строгим и лаконичным.\n\n**Сайт проекта:** [metallobaza.by](https://metallobaza.by)\n\n**Связанные проекты:** [Алмиер-Металлобаза](/ru/portfolio/metallobaza)","subtitle":"Веб · Сайт","challenge":"В рамках услуги поддержки, по запросу Заказчика была разработана концепт-идея Главной страницы возможного нового сайта Металлобазы.","description":"Концепт-идея нового сайта Металлобаз","stack_detail":"UI/UX, Figma, Photoshop"}}$row_121$::jsonb)
