INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('selfiest-app', 'mobile', ARRAY['mobile'], ARRAY['Android', 'iOS'], 2016, false, true, 122, '/uploads/projects/selfiest-app/650d8c1000e043d78a70fe845af76ac4.jpg', $row_122${"en":{"title":"Selfiest mobile app","result":"The project was successfully launched and is available at selfiest.com. The work was completed in 2016.","solution":"The application is a whole social network of fans to take pictures of others and themselves.\nA flexible competition mechanism has been implemented, participating in which the user can get valuable prizes.\n\nWithin the framework of the project, a complex API system and [promo site] (/en/portfolio/selfiest) were developed.\n\n![Мобильное приложение Selfiest](/uploads/projects/selfiest-app/d578082d46f341dcb36e01b372147708-2.png)\n\n**Project website:** [selfiest.com](https://selfiest.com)","subtitle":"Mobile · Mobile app","challenge":"Selfiest is a daily application that is designed exclusively for selfies.","description":"Social network of selfie lovers","stack_detail":"Android, iOS"},"ru":{"title":"Мобильное приложение Selfiest","result":"Проект успешно запущен и доступен по адресу selfiest.com. Работы выполнены в 2016 году.","solution":"Приложение - это целая социальная сеть любителей фотографировать окружающих и себя.\nРеализован гибкий механизм конкурсов, участвуя в которых пользователь может получить ценные призы.\n\nВ рамках проекта было разработано сложная API система и [промо сайт](/ru/portfolio/selfiest).\n\n![Мобильное приложение Selfiest](/uploads/projects/selfiest-app/d578082d46f341dcb36e01b372147708.png)\n\n**Сайт проекта:** [selfiest.com](https://selfiest.com)","subtitle":"Мобильное · Приложение","challenge":"Selfiest - тредневное приложение которое предназначено исключительно для селфи.","description":"Социальная сеть любителей селфи","stack_detail":"Android, iOS"}}$row_122$::jsonb)
