INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('horizont', 'web', ARRAY['web'], ARRAY['Bitrix', '1C'], 2016, false, true, 123, '/uploads/projects/horizont/a621902bbd654668ae9dedcb6dc378d8.jpeg', $row_123${"en":{"title":"Official website of the Horizon holding","result":"The project was successfully launched and is available at horizont.by. The work was completed in 2016.","solution":"The purpose of the site is to provide information support for the Customer’s activities.\n\n![Official website of the Horizon holding — 1](/uploads/projects/horizont/4ed09b325e7e4d89aecc5119d5ef13f5-2.png)\n\nWebsite purpose:\n- providing information about the Customer;\n- providing information about products sold by the Customer, and above all about products under the HORIZONT brand;\n- providing information about the service of goods sold by the Customer;\n- technical and information this support for customers and partners of the Customer;\n- informing about marketing activities carried out by the Customer and related information about the activities and events of the Customer;\n- feedback via e-mail, questionnaires and online application for goods, as well as providing contact information;\n- interaction with 1C Enterprise.\n\n![Official website of the Horizon holding — 2](/uploads/projects/horizont/0ef2970b0ffc41f39ea0ce4dac6d1b4c-2.png)\n\n![Official website of the Horizon holding — 3](/uploads/projects/horizont/66bf62c0fb244c3fb7f2f1af29f58548-2.png)\n\n**Project website:** [horizont.by](https://horizont.by)","subtitle":"Web · Website","challenge":"he subject of development is the website of the Horizont Trading Company Unitary Enterprise, with a dynamic content management system based on CMS 1C-Bitrix.","description":"Development of a catalog site for one of the largest holdings in the Republic of Belarus","stack_detail":"Bitrix, 1C"},"ru":{"title":"Официальный сайт холдинга Горизонт","result":"Проект успешно запущен и доступен по адресу horizont.by. Работы выполнены в 2016 году.","solution":"Предметом разработки является Интернет-сайт Унитарного предприятия \"Торговая компания \"Горизонт\", с системой динамического управления наполнением на базе CMS 1С-Битрикс.\n\nЦель создания сайта – информационная поддержка деятельности Заказчика\n\n![Официальный сайт холдинга Горизонт — 1](/uploads/projects/horizont/4ed09b325e7e4d89aecc5119d5ef13f5.png)\n\nНазначение сайта: \n- предоставление информации о Заказчике;\n- предоставление информации о товарах, продаваемых Заказчиком, и прежде всего о товарах под брендом HORIZONT;\n- предоставление информации о сервисе товаров, продаваемых Заказчиком; \n- техническая и информационная поддержка потребителей и партнёров Заказчика;\n- информирование о проводимых Заказчиком маркетинговых мероприятиях и сопутствующая информация о деятельности и событиях Заказчика;\n- обратная связь посредством электронной почты, анкетирования и онлайн-заявки на товар, а так же предоставления контактной информации;\n- взаимодействие с 1С Торговля Заказчика.\n\n![Официальный сайт холдинга Горизонт — 2](/uploads/projects/horizont/0ef2970b0ffc41f39ea0ce4dac6d1b4c.png)\n\n![Официальный сайт холдинга Горизонт — 3](/uploads/projects/horizont/66bf62c0fb244c3fb7f2f1af29f58548.png)\n\n**Сайт проекта:** [horizont.by](https://horizont.by)","subtitle":"Веб · Сайт","challenge":"Цель создания сайта – информационная поддержка деятельности Заказчика","description":"Разработка сайта каталога одного из крупнейших холдингов в Республике Беларусь","stack_detail":"Bitrix, 1C"}}$row_123$::jsonb)
