INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('tekro', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2016, false, true, 124, '/uploads/projects/tekro/5723bb822fff450e8ec3ae6f5edb19df.jpeg', $row_124${"en":{"title":"Tekro Corporate Website","result":"The project was successfully launched and is available at tekro-rf.ru. The work was completed in 2016.","solution":"We needed to implement the project (the new site of the enterprise) in a very short time with a limited budget.\n\nNevertheless, we were able to combine all areas of the company into a single structure of the new site, providing all the necessary capabilities for managing the customer.\nOne of the proposed services of the enterprise is a rich service and expert advice. We also tried to highlight this aspect.\n\n![Корпоративный сайт Текро](/uploads/projects/tekro/d5b11487321b4232977a24d8212ab77a-2.png)\n\n**Project website:** [tekro-rf.ru](http://tekro-rf.ru/)","subtitle":"Web · Website","challenge":"The company Tekro has been operating in the Czech market since 1991 and specializes in the manufacture of feed and breeding of domestic animals and farm animals, and also provides consulting services in these areas.","description":"Manufacturer of premixes, concentrates and starter feed","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Корпоративный сайт Текро","result":"Проект успешно запущен и доступен по адресу tekro-rf.ru. Работы выполнены в 2016 году.","solution":"Компания Текро действует на чешском рынке с 1991 года и специализируется в области изготовления кормов и разведения домашних животных и сельскохозяйственных животных, а также предоставляет консультационные услуги в этих областях.\n\nНам необходимо было реализовать проект (новый сайт предприятия) в очень короткие сроки с ограниченным бюджетом.\n\nТем не менее мы смогли воссоединить все направления компании в единую структуру нового сайта, предоставив все необходимые возможности по управлению заказчику.\n\nОдной из предлагаемых услуг предприятия является богатый сервис и консультации специалистов. Мы такде постарались выделить данный аспект.\n\n![Корпоративный сайт Текро](/uploads/projects/tekro/d5b11487321b4232977a24d8212ab77a.png)\n\n**Сайт проекта:** [tekro-rf.ru](http://tekro-rf.ru/)","subtitle":"Веб · Сайт","challenge":"Нам необходимо было реализовать проект (новый сайт предприятия) в очень короткие сроки с ограниченным бюджетом.","description":"Производитель премиксов, концентратов и престартерных кормов","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_124$::jsonb)
