INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('satio', 'web', ARRAY['web'], ARRAY['MODX'], 2016, false, true, 125, '/uploads/projects/satio/a668ecf8bb764572b29798ad7d5007c1.png', $row_125${"en":{"title":"Satio Corporate Website","result":"The project was successfully launched and is available at satio.by. The work was completed in 2016.","solution":"There was not much information on the projects, but we tried to take into account all the key wishes of the Customer:\n\n- The site should be executed in blue tones (colors of the SATIO logo).\n- The site should allow users to: choose the language: English and Russian (language switch).\n- The content management system should allow you to: change information in the sections \"News\", \"About Us\", \"Our Team\", \"Feedback\", \"Partners\", \"Contacts\".\n- The site has a responsive design.\n\nHaving accepted all this information, we set about creating a website design. After a short period of time, we were able to translate all the wishes of the customer into a single site.\n\n![Satio Corporate Website — 1](/uploads/projects/satio/7680545da4e84b9ea4ae7878f134ced2-2.png)\n\n**Project website:** [satio.by](https://satio.by)","subtitle":"Web · Website","challenge":"The site was developed on the CMS ModX.","description":"Satio Corporate Website","stack_detail":"MODX"},"ru":{"title":"Корпоративный сайт компании Сатио","result":"Проект успешно запущен и доступен по адресу satio.by. Работы выполнены в 2016 году.","solution":"Информации по проекты было не так много, но мы старались учесть все ключевые пожелания Заказчика:\n\n- Сайт должен быть выполнен в синих тонах (цвета логотипа SATIO). \n- Сайт должен позволять пользователям: выбирать язык :английский и русский (переключатель языка).\n- Система управления сайтом должна позволять: изменять информацию в разделах «Новости», «О нас», «Наша команда», «Отзывы», «Партнёры», «Контакты».\n- Сайт имеет адаптивный дизайн.\n\nПриняв всю данную информацию мы принялись создавать дизайн сайта. После не большого временного отрезка нам удалось воплотить все пожелания заказчика в единый сайт.\n\n![Корпоративный сайт компании Сатио — 1](/uploads/projects/satio/7680545da4e84b9ea4ae7878f134ced2.png)\n\n**Сайт проекта:** [satio.by](https://satio.by)","subtitle":"Веб · Сайт","challenge":"Сайт разрабатывался на систему управления ModX.","description":"Корпоративный сайт компании Сатио","stack_detail":"MODX"}}$row_125$::jsonb)
