INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('travelspot', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2016, false, true, 126, '/uploads/projects/travelspot/1db211b1ade24a4087ec52cec62f316b.jpeg', $row_126${"en":{"title":"Travel aggregator TravelSpot","result":"The project was successfully launched and is available at travelspot.by. The work was completed in 2016.","solution":"Daily information is published about the most profitable offers for the purchase of air dealerships in different parts of the world.\n\nThe site has an individual hot ticket search function.\n\nVarious useful notes are also published for all travel enthusiasts.\n\n![Туристический агрегатор TravelSpot](/uploads/projects/travelspot/212e00f3dfd34b5198182a39bd94dc39-2.png)\n\n**Project website:** [travelspot.by](https://travelspot.by)","subtitle":"Web · Website","challenge":"Travelspot.by is a project dedicated to travel, but also information about how it is more profitable to organize your vacation, where to buy cheap plane tickets and how to get from the airport to the vacation spot.","description":"The most interesting low-cost offers","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Туристический агрегатор TravelSpot","result":"Проект успешно запущен и доступен по адресу travelspot.by. Работы выполнены в 2016 году.","solution":"Ежедневно публикуется информация о самых выгодных предложениях о покупке авиа дилетов в разные точки Мира.\n\nНа сайте реализована функция индивидуального поиска горячих билетов.\n\nТак же публикуются различные полезные заметки всем люителям путешествий.\n\n![Туристический агрегатор TravelSpot](/uploads/projects/travelspot/212e00f3dfd34b5198182a39bd94dc39.png)\n\n**Сайт проекта:** [travelspot.by](https://travelspot.by)","subtitle":"Веб · Сайт","challenge":"Travelspot.by - это проект посвященный путешествиям, но и нинформацией о том, как выгоднее организовать свой отпуск, где купить дешевые билеты на самолет и как добраться из аэропорта к месту отдыха.","description":"Самые интересные лоукост предложения.","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_126$::jsonb)
