INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('univermag-belarus', 'web', ARRAY['web', 'ecommerce'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2016, false, true, 127, '/uploads/projects/univermag-belarus/a845e42f579142738773c1a5edc509bb.png', $row_127${"en":{"title":"Shopping center Belarus","result":"The project was successfully launched and is available at univermagbelarus.by. The work was completed in 2016.","solution":"A structured and thoughtful visualization of all product categories on the main page provides quick access to the product catalog. As well as the allocation of Promotional news, allows the user to quickly find the information that interests him most.\n\nThis concept idea was implemented as part of the creation of a Commercial Proposal for the development of the Online Store Department Store \"Belarus\".\n\n![Универмаг Беларусь](/uploads/projects/univermag-belarus/9d6b55224b2641a2989b7e2f99456d6e-2.png)\n\n**Project website:** [univermagbelarus.by](https://univermagbelarus.by)","subtitle":"Web · E-commerce","challenge":"Our team prepared a visualization of a completely different presentation of product groups on the website of the Belarus Shopping Center.","description":"Concept idea of ​​an online store of a Shopping center","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Универмаг Беларусь","result":"Проект успешно запущен и доступен по адресу univermagbelarus.by. Работы выполнены в 2016 году.","solution":"Нашей [командой](/ru#about) была подготовлена визуализация совершенного иного представления товарных групп на сайте Универмага Беларусь.\n\nСтруктурированная и продуманная визуализация всех категорий товаров на главной странице предоствляет быстрый доступ к каталогу продукции. А также выделение Акционных новостей, позволяет пользователю быстро находить ту информацию, котора яинтересует его больше всего.\n\nДанная концепт-идея реализована в рамках создания Коммерческого Предложения по разработке Интернет-Магазина Универмаг \"Беларусь\".\n\n![Универмаг Беларусь](/uploads/projects/univermag-belarus/9d6b55224b2641a2989b7e2f99456d6e.png)\n\n**Сайт проекта:** [univermagbelarus.by](https://univermagbelarus.by)","subtitle":"Веб · E-commerce","challenge":"Нашей командой была подготовлена визуализация совершенного иного представления товарных групп на сайте Универмага Беларусь.","description":"Концепт-идея Интернет Магазина универмага.","stack_detail":"UI/UX, Figma, Photoshop"}}$row_127$::jsonb)
