INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('piplos2', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2016, false, true, 128, '/uploads/projects/piplos2/a0bf94784a52489b917de37c43824a10.png', $row_128${"en":{"title":"Design Studio Piplos Media v2","result":"The project was successfully launched and is available at piplos-media.com. The work was completed in 2016.","solution":"A well-structured menu allows the user to immediately get acquainted with all the advantages of the company, and special tools, including an online consultant and the ability to quickly fill out the brief, allow the resource to successfully perform the most important function - to promote and sell services.\n\n![Дизайн-студия Пиплос Медиа вторая версия](/uploads/projects/piplos2/870175c1e5a44bd6957ff02f36ee86de-2.png)\n\n**Project website:** [piplos-media.com](http://piplos-media.com)","subtitle":"Web · Landing page","challenge":"Thanks to the original, modern design, the site is able to really interest users.. The use of additional modules in the development not only simplifies the visit process, but also makes it pleasant and exciting.","description":"Development a second version of the site for the Piplos Media design studio, capable of demonstrating to the maximum all the advantages and capabilities of the company","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Дизайн-студия Пиплос Медиа v2","result":"Проект успешно запущен и доступен по адресу piplos-media.com. Работы выполнены в 2016 году.","solution":"Грамотная структурированность меню дает возможность потенциальному клиенту полностью ознакомиться со всеми преимуществами компании, а специальные инструменты, в число которых входит онлайн-консультант и возможность быстрого заполнения брифа позволяют ресурсу успешно выполнять самую важную функцию – продвигать и продавать услуги.\n\n![Дизайн-студия Пиплос Медиа вторая версия](/uploads/projects/piplos2/870175c1e5a44bd6957ff02f36ee86de.png)\n\n**Сайт проекта:** [piplos-media.com](http://piplos-media.com)","subtitle":"Веб · Лендинг","challenge":"Благодаря оригинальному, современному дизайну сайт способен по-настоящему заинтересовать самого искушенного посетителя. Использование в разработке дополнительных модулей не только упрощает процесс посещения, но и делают его приятным и увлекательным.","description":"Разработать вторую версию сайта для дизайн-студии Пиплос Медиа, способную продемонстрировать по максимуму все преимущества и возможности компании.","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_128$::jsonb)
