INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('tabak', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2016, false, true, 129, '/uploads/projects/tabak/artboard-copy-4.png', $row_129${"en":{"title":"Grodno Tobacco Factory \"Neman\"","result":"The project was successfully launched and is available at tabak.by. The work was completed in 2016.","solution":"Tasks:\n1. The site should be an information structure available on the Internet under the domain name www.tabak.by.\n2. The site should consist of interconnected sections with clearly separated functions.\n3. The content management system should include a backup mechanism for the structure and contents of the database.\n\n![Гродненская табачная фабрика \"Неман\"](/uploads/projects/tabak/616130672d2043c0b628ef6095988d69-2.png)\n\n**Project website:** [tabak.by](http://tabak.by)","subtitle":"Web · Website","challenge":"The task of the new site is to provide information about the enterprise, its lines of business, and the equipment and products used, to provide information on how to purchase products.","description":"Developing website for tobacco company in the Republic of Belarus","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Гродненская табачная фабрика \"Неман\"","result":"Проект успешно запущен и доступен по адресу tabak.by. Работы выполнены в 2016 году.","solution":"Задачи:\n1. Сайт должен представлять собой информационную структуру, доступную в сети Интернет под доменным именем www.tabak.by.\n2. Сайт должен состоять из взаимосвязанных разделов с четко разделенными функциями.\n3. В системе управления сайтом должен быть предусмотрен механизм резервного копирования структуры и содержимого базы данных.\n\n![Гродненская табачная фабрика \"Неман\"](/uploads/projects/tabak/616130672d2043c0b628ef6095988d69.png)\n\n**Сайт проекта:** [tabak.by](http://tabak.by)","subtitle":"Веб · Сайт","challenge":"Цель нового сайта – познакомить посетителей с предприятием, направлениями его деятельности, мощностями, и используемым оборудованием и продукцией, предоставить информацию о способах приобретения продукции.","description":"Ведущая табачная компания в Республике Беларусь","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_129$::jsonb)
