INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('marshallsmokers', 'web', ARRAY['web', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2016, false, true, 130, '/uploads/projects/marshallsmokers/b67227b28f3d45f99a2af85a50bd250b.jpeg', $row_130${"en":{"title":"MarshallSmokers Online Store","result":"The project was successfully launched and is available at www.bbq.by. The work was completed in 2016.","solution":"The online store is classic in nature with standard features for it.\n\nAlso the site is multilingual.\n\nThe following functionality was implemented within the framework of this project:\n- calculator of delivery cost.\n- online payment system is connected.\n\n![Огненные скульптуры для сада](/uploads/projects/marshallsmokers/52605ab95874428eb119f72dfc0597f4-2.png)\n\n**Project website:** [www.bbq.by](http://www.bbq.by)","subtitle":"Web · E-commerce","challenge":"We have developed an online store selling various grills and hearths for a bonfire.","description":"Online Shop of Fire sculptures for the garden","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Интернет Магазин MarshallSmokers","result":"Проект успешно запущен и доступен по адресу www.bbq.by. Работы выполнены в 2016 году.","solution":"Интернет магазин носит классический характер с стандартным функционалам для него.\n\nТакже сайт является мультиязычным.\n\nВ рамках данного проекта был реализован следующий функционал:\n- калькулятор просчета стоимости доставки. \n- подключена система онлайн оплаты.\n\n![Огненные скульптуры для сада](/uploads/projects/marshallsmokers/52605ab95874428eb119f72dfc0597f4.png)\n\n**Сайт проекта:** [www.bbq.by](http://www.bbq.by)","subtitle":"Веб · E-commerce","challenge":"Нами был разработан Интернет Магазин по продаже различных грилей и очагов для костра.","description":"Интернет Магазин Огненных скульптур для сада","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_130$::jsonb)
