INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('sankusm', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2016, false, true, 131, '/uploads/projects/sankusm/66ad6d39e0ed474199cc796009f3d5d9.jpg', $row_131${"en":{"title":"Designer furniture Sankus-M","result":"The project was successfully launched and is available at sankus-m.by. The work was completed in 2016.","solution":"The classic menu and intuitive navigation facilitate the search, and the site management system provides the ability to independently make adjustments to the content of the resource.\n\n![Дизайнерская мебель Санкус-М](/uploads/projects/sankusm/93b8865b53e24cf1bc292879b03cf4be-2.png)\n\nEach category of the site seems to help you find exactly the furniture you are looking for..\n\n![Designer furniture Sankus-M — 2](/uploads/projects/sankusm/fe343a0ed1d64d48a9ef4be50aa68df8-2.png)\n\n**Project website:** [sankus-m.by](http://sankus-m.by/)","subtitle":"Web · Website","challenge":"Given the specifics of the customer company’s activity, the main focus in the website design was on visualization, and the color scheme of the resource was done in calm colors, which focuses the visitor’s attention on the proposed product.","description":"Website for the manufacturer of designer and furniture in Minsk","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Дизайнерская мебель Санкус-М","result":"Проект успешно запущен и доступен по адресу sankus-m.by. Работы выполнены в 2016 году.","solution":"Классическое меню и понятная навигация облегчают поиск, а система управления сайтом предоставляет возможность самостоятельного внесения корректировок в контент ресурса.\n\n![Дизайнерская мебель Санкус-М](/uploads/projects/sankusm/93b8865b53e24cf1bc292879b03cf4be.png)\n\nКаждая категория сайта словно помогает вам найти именно ту мебель, которую вы ищете.\n\n![Дизайнерская мебель Санкус-М — 2](/uploads/projects/sankusm/fe343a0ed1d64d48a9ef4be50aa68df8.png)\n\n**Сайт проекта:** [sankus-m.by](http://sankus-m.by/)","subtitle":"Веб · Сайт","challenge":"Учитывая специфику направления деятельности компании-заказчика, основной акцент в дизайне сайта был поставлен на визуализации, а цветовая гамма ресурса выполнена в спокойных тонах, что сосредоточивает внимание посетителя на предлагаемом товаре.","description":"Производство дизайнерской и корпусной мебели в Минске","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_131$::jsonb)
