INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('mehuborka', 'web', ARRAY['web'], ARRAY['MODX'], 2016, false, true, 132, '/uploads/projects/mehuborka/artboard-copy-12.png', $row_132${"en":{"title":"City cleaning","result":"The project was successfully launched and is available at mehuborka.by. The work was completed in 2016.","solution":"Tasks for the project:\n1. project identification;\n2. Submission of information of various types;\n3. site navigation that is simple and intuitive..\n\n![Механизированная уборка города](/uploads/projects/mehuborka/1018c8fd6c9c46e697e56dcde33bc689-2.png)\n\nThe site should allow users to:\n- Ability to view the gallery of equipment and other services provided.\n- Registration of the application through the feedback form.\n- Feedback from e-mail, with the result of the processing of the application.\n- Information about the types of activities and services of the enterprise\n\n![City cleaning — 2](/uploads/projects/mehuborka/aeaa2e701d424bb8851940aa32aeb50b-2.png)\n\n**Project website:** [mehuborka.by](https://mehuborka.by)","subtitle":"Web · Website","challenge":"The site of UE “City cleaning” was developed on the CMS ModX.","description":"Transport unitary enterprise","stack_detail":"MODX"},"ru":{"title":"Механизированная уборка города","result":"Сайт должен позволять пользователям: Возможность просмотра галереи техники и иных предоставляемых услуг. Оформление заявки через форму обратной связи. Обратная связь через электронную почту, с результатом обработки заявки. Информация (краткая, полная) о видах деятельности и услугах предприятия,","solution":"Разработка сайта УП «механизированная уборка города» происходила на системе управления ModX.\n\nЗадачи перед проектом:\n1. идентификации проекта;\n2. подачи информации разного типа;\n3. навигации по сайту, которая, независимо от сложности структуры сайта, проста и интуитивно понятна.\n\n![Механизированная уборка города](/uploads/projects/mehuborka/1018c8fd6c9c46e697e56dcde33bc689.png)\n\n![Механизированная уборка города — 2](/uploads/projects/mehuborka/aeaa2e701d424bb8851940aa32aeb50b.png)\n\n**Сайт проекта:** [mehuborka.by](https://mehuborka.by)","subtitle":"Веб · Сайт","challenge":"Задачи перед проектом: идентификации проекта; подачи информации разного типа; навигации по сайту, которая, независимо от сложности структуры сайта, проста и интуитивно понятна.","description":"Автотранспортное коммунальное унитарное предприятие","stack_detail":"MODX"}}$row_132$::jsonb)
