INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('almishop', 'web', ARRAY['web', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2016, false, true, 133, '/uploads/projects/almishop/artboard-copy-14.png', $row_133${"en":{"title":"Almier Online Store","result":"The project was successfully launched and is available at almishop.by. The work was completed in 2016.","solution":"This project includes the standard functionality of the Online Store:\n- Catalog with product categories\n- Information on each product individually\n- Shopping basket\n\n![Интернет-магазин Алмиер](/uploads/projects/almishop/c935b67d40fb46c3b0f3026c81289d3a-2.png)\n\nThe peculiarity of this project was the implementation of such functionality as - Product Design Tool and calculator.\n\nProduct Design Tool.\n\nThis section allowed users to create a visual design of their own gates using various forged elements that are already offered to the user to choose from. This functionality was developed on Flash Player.\n\nCalculator.\n\nThanks to the calculator, the user could calculate the cost of the gate by entering certain types of data and parameters, after which he formed the approximate budget for this project..\n\n![Almier Online Store — 2](/uploads/projects/almishop/ff23da55dd3e415e9e2ed21f96c40454-2.png)\n\n**Project website:** [almishop.by](https://almishop.by)","subtitle":"Web · E-commerce","challenge":"For the leader in the market of ferrous metal in the Republic of Belarus, it was necessary to develop an online store.","description":"Creation of an online metal rolling store","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Интернет-магазин Алмиер","result":"Проект успешно запущен и доступен по адресу almishop.by. Работы выполнены в 2016 году.","solution":"Данный проект включает в себя стандартный функционал Интернет-Магазина:\n- Каталог с категориями товаров \n- Информацию по каждому товару в отдельности \n- Корзину покупок\n\n![Интернет-магазин Алмиер](/uploads/projects/almishop/c935b67d40fb46c3b0f3026c81289d3a.png)\n\nОсобенность данного проекта заключалась в реализации такого функционала как - Проектировщик и калькулятор.\n\nПроектировщик.\n\nДанный раздел позволял пользователям создать визуальный проект собственных ворот используя различные кованные элементы, уже предлагающиеся пользователю на выбор. Данный функционал был разработан на Flash Player.\n\nКалькулятор.\n\nБлагодаря калькулятору, пользователь мог рассчитать стоимость ворот вводя определенные типы данных и параметров, после чего у него формировался приблизительный бюджет по данному проекту.\n\n![Интернет-магазин Алмиер — 2](/uploads/projects/almishop/ff23da55dd3e415e9e2ed21f96c40454.png)\n\n**Сайт проекта:** [almishop.by](https://almishop.by)","subtitle":"Веб · E-commerce","challenge":"Для лидера на рынке чёрного металлопроката в Республике Беларусь, необходимо было разработать Интернет-магазин.","description":"Создание Интернет-магазина металлопроката","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_133$::jsonb)
