INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('bellact', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2015, false, true, 134, '/uploads/projects/bellact/artboard-copy-113.png', $row_134${"en":{"title":"Bellact Company","result":"The project was successfully delivered to the client. The work was completed in 2015.","solution":"The visual perception of the site should be simple, without a lot of information. The site is informational, without the possibility of online sales, so its central part is the product catalog, a high-quality clear presentation of the product and its description.\n\nDesign:\n- Minimalism and uniform design style\n- Basic: the use of light, soft shades that cause an associative relationship with milk\n- products, baby food.\n- Optional: partial use of bright spots is possible\n- Soft, rounded font.\n\n![Концепт дизайн для Беллакт](/uploads/projects/bellact/23d09d200a0e4d82a265bd07ef134719-2.png)\n\n![Bellact Company — 2](/uploads/projects/bellact/6ed7463b15c44b69b2a7b09c7683d711-2.png)","subtitle":"Web · Website","challenge":"As part of the development of the new site of Bellact OJSC, the Customer has set us the following website design tasks:","description":"Design for a dairy producer","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Компания «Беллакт»","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2015 году.","solution":"Визуальное восприятие сайта д.б простым, без утяжеления большим кол-вом информации. Сайт будет\nнести информационную составляющую, без возможности он-лайн продаж, поэтому основной упор\nнеобходимо сделать на продуктовый каталог, качественное понятное представление продукта и его\nописание.\n\nДизайн:\n- Минимализм и выдержка сайта в едином стиле\n- Основное: использование светлых, мягких оттенков, которые вызывают ассоциативную связь с молочной\n- продукцией, детским питанием.\n- Дополнительно: возможно частичное использование ярких пятен\n- Мягкий, округлый шрифт.\n\n![Концепт дизайн для Беллакт](/uploads/projects/bellact/23d09d200a0e4d82a265bd07ef134719.png)\n\n![Компания «Беллакт» — 2](/uploads/projects/bellact/6ed7463b15c44b69b2a7b09c7683d711.png)","subtitle":"Веб · Сайт","challenge":"В рамках разработки нового сайта ОАО\"Беллакт\" Заказчик поставил перед нами следующие задачи по дизайну сайта:","description":"Концепт дизайн для единственный производителя сухих молочных продуктов","stack_detail":"UI/UX, Figma, Photoshop"}}$row_134$::jsonb)
