INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('artox-media', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2015, false, true, 135, '/uploads/projects/artox-media/ac9836b3e65941a6bce61f9d187e33b1.png', $row_135${"en":{"title":"ARTOX media - digital agency","result":"The project was successfully launched and is available at artox-media.by. The work was completed in 2015.","solution":"The project included the functions of the site of the company, which provides services for promotion in social networks, SEO promotion, contextual advertising, display advertising, video advertising and other services.\n\nThe structure of the site is that the user can easily find the information of interest to him about the cases and services of the company.\n\n![ARTOX media – digital-агентство](/uploads/projects/artox-media/60496de70b214a19ad0829d8a7f3ce7e-2.png)\n\n**Project website:** [artox-media.by](https://artox-media.by)","subtitle":"Web · Website","challenge":"We have developed and implemented a new website of the digital agency ARTOX media.","description":"A full range of business promotion services on the Internet","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"ARTOX media – digital-агентство","result":"Проект успешно запущен и доступен по адресу artox-media.by. Работы выполнены в 2015 году.","solution":"Проект включал в себя функции сайта компании, которая предоставляет услуги по продвижению в социальных сетях, SEO продвижению, контекстной рекламе, медийной рекламе, видеорекламе и других услуг.\n\nСайт представляет собой структуру таким образом, чтобы пользователю можно было с легкостью найти интересующую его информацию о кейсах и услугах компании.\n\n![ARTOX media – digital-агентство](/uploads/projects/artox-media/60496de70b214a19ad0829d8a7f3ce7e.png)\n\n**Сайт проекта:** [artox-media.by](https://artox-media.by)","subtitle":"Веб · Сайт","challenge":"Нами была разработан и внедрен новый сайт digital-агентства ARTOX media.","description":"Полный комплекс услуг продвижения бизнеса в интернете.","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_135$::jsonb)
