INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('edison', 'web', ARRAY['web', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2015, false, true, 136, '/uploads/projects/edison/artboard-copy-23.png', $row_136${"en":{"title":"Online store Edison","result":"The project was successfully launched and is available at edison.by. The work was completed in 2015.","solution":"It is important to focus on the development of the Personal Account, which monitors all information about the user's purchases and the status of the current order.\n\nThe structure of catalog is formed in such a way that any information on the site is available in a maximum of three clicks.\n\n![Интернет магазин Edison](/uploads/projects/edison/362eb70f79014315a3213693b88a1535-2.png)\n\nThe management system for developing this site is CMS NetCat.\n\n![Online store Edison — 2](/uploads/projects/edison/5b200d70b5d941c19bc01b5a9c161083-2.png)\n\n**Project website:** [edison.by](http://edison.by)","subtitle":"Web · E-commerce","challenge":"A specialized store with a large distributor of computer equipment has set the task for our team to develop the Online Store.","description":"Internet-shop of computer equipment","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Интернет магазин Edison","result":"Проект успешно запущен и доступен по адресу edison.by. Работы выполнены в 2015 году.","solution":"Важно сделать акцент на разработку Личного Кабинета, в котором отслеживается вся информация о покупках пользователя и о статусе текущего заказа.\n\nСтруктура каталога сформирована таким образом, что любая информация на сайте доступна максимум в три клика.\n\n![Интернет магазин Edison](/uploads/projects/edison/362eb70f79014315a3213693b88a1535.png)\n\nСистема управленяи при разработке данного сайта - CMS NetCat.\n\n![Интернет магазин Edison — 2](/uploads/projects/edison/5b200d70b5d941c19bc01b5a9c161083.png)\n\n**Сайт проекта:** [edison.by](http://edison.by)","subtitle":"Веб · E-commerce","challenge":"Специализированный магазин при крупном дистрибьюторе компьютерной техники поставил задачу перед нашей командой по разработке Интернет-Магазина.","description":"Интернет-Магазин компьютерной техники","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_136$::jsonb)
