INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('piplos', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2015, false, true, 137, '/uploads/projects/piplos/7f68a19ad4b64673b518188044eb5edb.jpg', $row_137${"en":{"title":"Design studio 'Piplos Media'","result":"The project was successfully launched and is available at piplos-media.com. The work was completed in 2015.","solution":"It was decided to implement lendnig with basic information about the company's services, projects and contact details.\n\nThis landing page was developed using parallax effects technologies.\n\nAn adaptive design has also been developed for the best display on mobile devices.\n\n![Дизайн-студия 'Пиплос Медиа'](/uploads/projects/piplos/5e32d99416d349ddbbce021080bdf559-2.png)\n\n**Project website:** [piplos-media.com](https://piplos-media.com/)","subtitle":"Web · Landing page","challenge":"This project was developed by our team as part of the promotion of our company services in foreign markets.","description":"Landing Page of 'Piplos Media","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Дизайн-студия 'Пиплос Медиа'","result":"Проект успешно запущен и доступен по адресу piplos-media.com. Работы выполнены в 2015 году.","solution":"Было принято решение о реалиазции ленднига с основной информацией о услугах компании, проектах и контактных данных.\n\nДанный лендинг, был разработан с применением технологий параллакс эффектов.\n\nТак же был разработан адаптивный дизайн для наилучшего отображения на мобильных устройствах.\n\n![Дизайн-студия 'Пиплос Медиа'](/uploads/projects/piplos/5e32d99416d349ddbbce021080bdf559.png)\n\n**Сайт проекта:** [piplos-media.com](https://piplos-media.com/)","subtitle":"Веб · Лендинг","challenge":"Данный проект разработан нашей командой в рамках продвижения услуг нашей компании на зарбуежных рынках.","description":"Дизайн-студия 'Пиплос Медиа' - Landing Page","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_137$::jsonb)
