INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('planeta-grioz', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2015, false, true, 138, '/uploads/projects/planeta-grioz/artboard-copy-10.png', $row_138${"en":{"title":"Travel agency \"Planet of dreams\"","result":"The project was successfully launched and is available at plg.by. The work was completed in 2015.","solution":"The task of the project that the Customer described to us:\n\n1. As for the design: the site is the face of the company, I want a decent expression! :)) We are agents, so we cannot attract tourists at the best price. On the site, leisure options should be depicted in such a way as to attract a tourist to the actions - to call and inquire, but we will convince us to come to us with our competence and quality of services.\n2. Everything should be delicious! Pleasant tones, beautiful photos.\n3. Also, the main functionality of this project was the introduction of a service for selecting airline tickets and tours.\n\nWe have proposed the first version of displaying the style of the main page. The main message is the ease of displaying information and a quick search for the tour of interest.\n\n![Travel agency \"Planet of dreams\" — 1](/uploads/projects/planeta-grioz/f382f5ae3ed7499d93dc72fc14fb3656-2.png)\n\nHowever, the customer wanted something bright, memorable.\n\nAfter a short discussion. we proposed the following option.\n\n![Travel agency \"Planet of dreams\" — 2](/uploads/projects/planeta-grioz/8413693765344bdfa48257932ecc41dd-2.png)\n\nNaturally, we hit the target.\n\nThe style of the site was set, and the matter remained small.\n\nWe also introduced a tour selection functionality on the site. All information is pulled to the site through a specialized service for travel companies.\n\n![Travel agency \"Planet of dreams\" — 3](/uploads/projects/planeta-grioz/e3c3fa3bdb0047ff805c24c7c7e2266e-2.png)\n\n**Project website:** [plg.by](https://plg.by)","subtitle":"Web · Website","challenge":"The site of the travel company \"PLANETA DREAMS\" was developed on the NetCat CMS.","description":"Travel company website with individual tour selection","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Туристическое агенство \"Планета грез\"","result":"Проект успешно запущен и доступен по адресу plg.by. Работы выполнены в 2015 году.","solution":"Сайт туристической компании \"ПЛАНЕТА ГРЕЗ\" разрабатывался на системе управления NetCat.\n\nЦель проекта которую нам описал Заказчик:\n\n1. Что касается дизайна: сайт –лицо фирмы, хочется достойного выражения!:)) Мы являемся агентами, поэтому привлечь туристов лучшей ценой мы не можем. На сайте варианты отдыха должны быть изображены так, чтобы привлечь к действиям туриста – позвонить и поинтересоваться, а вот мы уже своей компетентностью и качеством услуг будем убеждать придти к нам. \n2. Всё должно быть вкусно! Приятные тона, красивые фото. \n3. Так же основным функционалом данного проекта - было внедрение сервиса по подбору авиабилетов и туров.\n\nНами был предложен первый вариант отображения стилистики Главной страницы. Основной посыл - простота отображения информации и быстрый поиск интересующего тура.\n\n![Туристическое агенство \"Планета грез\" — 1](/uploads/projects/planeta-grioz/f382f5ae3ed7499d93dc72fc14fb3656.png)\n\nОднако заказчик хотел нечто яркое, запоминающееся.\n\nПосле недолгого обсуждения. мы предложили следующий вариант.\n\n![Туристическое агенство \"Планета грез\" — 2](/uploads/projects/planeta-grioz/8413693765344bdfa48257932ecc41dd.png)\n\nЕстественно, мы попали в цель.\n\nСтилистика сайта была задана, и дело оставалось за малым.\n\nТакже мы внедрили на сайт функционал подбора тура. Вся информация подтягивается на сайт через специализированный сервис для туристических компаний.\n\n![Туристическое агенство \"Планета грез\" — 3](/uploads/projects/planeta-grioz/e3c3fa3bdb0047ff805c24c7c7e2266e.png)\n\n**Сайт проекта:** [plg.by](https://plg.by)","subtitle":"Веб · Сайт","challenge":"Цель проекта которую нам описал Заказчик:","description":"Сайт Туристической компании с подбором индивидуального тура","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_138$::jsonb)
