INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('lidskaya-muka', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2015, false, true, 139, '/uploads/projects/lidskaya-muka/bd8b4f0d01604acbbfa68725f19d0db0.png', $row_139${"en":{"title":"Lidahlebproduct","result":"The project was successfully delivered to the client. The work was completed in 2015.","solution":"We were given very little input for this concept.\n\nNevertheless, we studied the company's business domain and market and prepared our own vision of the project.\n\n![Lidahlebproduct](/uploads/projects/lidskaya-muka/ad7d537168914038adfa7c03dd97926d.png)\n\nAnd this is how we envisioned the product card.\n\n![Lidahlebproduct — 2](/uploads/projects/lidskaya-muka/7c677c3bac114267ab8570ca72ae82bb.png)","subtitle":"Web · Website","challenge":"As part of a competitive pitch, Piplos Media developed a concept design for the homepage of a flour and animal feed production company website.","description":"Concept design for the Lida Flour website","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Лидахлебопродукт","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2015 году.","solution":"Нам было предоставлено минимум информации для создания данной концепт-идеи.\n\nТем не менее мы изучили тематику данного предпрития, рынок и смогли подготовить наше видение данного проекта.\n\n![Лидахлебопродукт](/uploads/projects/lidskaya-muka/ad7d537168914038adfa7c03dd97926d.png)\n\nА вот так мы представили карточку товара.\n\n![Лидахлебопродукт — 2](/uploads/projects/lidskaya-muka/7c677c3bac114267ab8570ca72ae82bb.png)","subtitle":"Веб · Сайт","challenge":"В рамках конкурсного предложения, компания Piplos Media разработала концепт-идею главной страницы сайта производства мукомольной и комбикормовой продукции.","description":"Концепт-идея сайта Лидской Муки","stack_detail":"UI/UX, Figma, Photoshop"}}$row_139$::jsonb)
