INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('chelobanov', 'web', ARRAY['web', 'ecommerce'], ARRAY['jQuery', 'PHP', 'MySQL', 'JavaScript'], 2015, false, true, 140, '/uploads/projects/chelobanov/artboard-copy-15.png', $row_140${"en":{"title":"Door Manufacturing Workshop","result":"The project was successfully delivered to the client. The work was completed in 2015.","solution":"Andrey Chelobanov is a renowned master in the field of door production, offering unique and customized door designs. To showcase his work and provide clients with a user-friendly platform to select their desired door design, a website catalog was developed specifically for his workshop.\n\nThe website catalog provides not only information about the products offered by the workshop but also a customized door selection feature. The website offers an extensive filtering system based on various criteria, allowing users to quickly navigate through the large catalog of door designs. The design of the website was chosen to be in line with the workshop's aesthetic, with a focus on showcasing the beauty of wood.\n\n![Мастерская Андрея Челобанова](/uploads/projects/chelobanov/db711ab277db491fa1ff19c02741485d.png)\n\nThe website has a complex structure that was carefully grouped to facilitate quick access to all the information about the workshop. The project was developed using the latest technologies and frameworks such as HTML5, CSS3, JavaScript, and jQuery. The back-end of the website was built on the PHP programming language with the MySQL database management system.\n\nThe website catalog is optimized for different devices, such as desktops, tablets, and smartphones, providing a seamless user experience. The website catalog has several features such as a contact form, interactive map, and customer reviews. The website was also optimized for search engines to increase its visibility and attract more customers.\n\nIn conclusion, the website catalog for Andrey Chelobanov's workshop is an excellent example of an individual project tailored to meet the unique needs of a business. It provides a user-friendly platform for clients to select their desired door design and showcases the workshop's exquisite work. The website catalog's structure, design, and optimization make it a valuable asset for the business and an effective marketing tool.\n\n![Door Manufacturing Workshop — 2](/uploads/projects/chelobanov/3ab27d8cc9e4433787dcfa7a583f8b01.png)","subtitle":"Web · E-commerce","challenge":"Individual Project Development for the Website Catalog of Andrey Chelobanov's Workshop for Unique Doors","description":"Creating a Custom Website for Andrey Chelobanov's Unique Door Manufacturing Workshop","stack_detail":"jQuery, PHP, MySQL, JavaScript"},"ru":{"title":"Мастерская по производству дверей","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2015 году.","solution":"Андрей Челобанов - признанный мастер в области производства дверей, предлагающий уникальные и индивидуальные конструкции дверей. Чтобы продемонстрировать его работу и предоставить клиентам удобную платформу для выбора желаемого дизайна двери, специально для его мастерской был разработан сайт-каталог.\n\nВ каталоге сайта представлена не только информация о продукции, предлагаемой мастерской, но и функция индивидуального подбора дверей. Сайт предлагает обширную систему фильтрации по различным критериям, что позволяет пользователям быстро ориентироваться в большом каталоге дверных конструкций. Дизайн сайта был выбран в соответствии с эстетикой мастерской, с акцентом на демонстрацию красоты дерева.\n\n![Мастерская Андрея Челобанова](/uploads/projects/chelobanov/db711ab277db491fa1ff19c02741485d.png)\n\nСайт имеет сложную структуру, которая была тщательно сгруппирована, чтобы облегчить быстрый доступ ко всей информации о мастерской. Проект был разработан с использованием новейших технологий и фреймворков, таких как HTML5, CSS3, JavaScript и jQuery. Внутренняя часть сайта была построена на языке программирования PHP с системой управления базами данных MySQL.\n\nКаталог сайта оптимизирован для различных устройств, таких как настольные компьютеры, планшеты и смартфоны, обеспечивая беспрепятственный пользовательский опыт. Сайт-каталог имеет несколько функций, таких как контактная форма, интерактивная карта и отзывы клиентов. Сайт также был оптимизирован для поисковых систем, чтобы повысить его видимость и привлечь больше клиентов.\n\nВ заключение следует отметить, что сайт-каталог для мастерской Андрея Челобанова является отличным примером индивидуального проекта, разработанного с учетом уникальных потребностей бизнеса. Он предоставляет клиентам удобную платформу для выбора желаемого дизайна двери и демонстрирует изысканные работы мастерской. Структура, дизайн и оптимизация сайта-каталога делают его ценным активом компании и эффективным маркетинговым инструментом.\n\n![Мастерская по производству дверей — 1](/uploads/projects/chelobanov/3ab27d8cc9e4433787dcfa7a583f8b01.png)","subtitle":"Веб · E-commerce","challenge":"Разработка индивидуального проекта для каталога сайта мастерской уникальных дверей Андрея Челобанова","description":"Создание сайта для уникальной мастерской по производству дверей Андрея Челобанова","stack_detail":"jQuery, PHP, MySQL, JavaScript"}}$row_140$::jsonb)
