INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('mbg', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2015, false, true, 141, '/uploads/projects/mbg/b2b7544301924de0988b6c2dde9cb614.jpeg', $row_141${"en":{"title":"Language School","result":"The project was successfully launched and is available at mbg.by. The work was completed in 2015.","solution":"CMS NetCat contributes to the ease and convenience of managing the site, and also provides the ability to update and change content on the site without involving a developer.\n\n![Языковая школа Мир без границ](/uploads/projects/mbg/d07392a2b758475cb8e6eecdecb28082-2.png)\n\nThe developed content management functionality provides extensive publishing opportunities for various materials, as well as a detailed description of all school courses.\n\n![Language School — 2](/uploads/projects/mbg/1685b680c0ca42a3887900f3f879eda7-2.png)\n\nThe possibility of enrolling in school courses has been developed through a special system with individual selection of courses.\n\n![Language School — 3](/uploads/projects/mbg/92f7c2e2a5ae460ba2262be547211f58-2.png)\n\n**Project website:** [mbg.by](https://mbg.by)","subtitle":"Web · Website","challenge":"Thoughtful navigation, interesting design and a memorable image of the site are the main criteria that guided the team of Piplos Media professionals in the process of developing the site for the center for learning foreign languages A world without borders. As a result - a great result!","description":"Develop a high-quality and thoughtful website with an interesting design, taking into account the direction of the customer's company","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Языковая школа Мир без границ","result":"Проект успешно запущен и доступен по адресу mbg.by. Работы выполнены в 2015 году.","solution":"Применение CMS NetCat способствует легкости и удобству управления сайтом, а также предоставляет возможность обновлять и изменять контент на сайте без привлечения разработчика.\n\n![Языковая школа Мир без границ](/uploads/projects/mbg/d07392a2b758475cb8e6eecdecb28082.png)\n\nСозданный функционал управления контентом, предоставляет широкие возможности публикации различных материалов, а также подробному описанию всех курсов школы.\n\n![Языковая школа Мир без границ — 2](/uploads/projects/mbg/1685b680c0ca42a3887900f3f879eda7.png)\n\nВ рамках проекта создана возможность записи на курсов всех интересующих пользователей через систему обратной связи с индивидуальным подбором курсов.\n\n![Языковая школа Мир без границ — 3](/uploads/projects/mbg/92f7c2e2a5ae460ba2262be547211f58.png)\n\n**Сайт проекта:** [mbg.by](https://mbg.by)","subtitle":"Веб · Сайт","challenge":"Удобная навигация, яркий дизайн и запоминающийся образ основные критерии, которыми руководствовалась команда профессионалов Piplos Media в процессе разработки сайта для центра изучения иностранных языков Мир без границ. Как итог - отличный результат!","description":"Разработать качественный и продуманный веб-сайт с интересным дизайном, учитывая направление деятельности компании-заказчика.","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_141$::jsonb)
