INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('nereida', 'web', ARRAY['web'], ARRAY['Electron'], 2015, false, true, 142, '/uploads/projects/nereida/e5cdb389399242bf85c0f56425284e12.png', $row_142${"en":{"title":"Nereid company website","result":"The project was successfully launched and is available at nereida.by. The work was completed in 2015.","solution":"So, the design of the web resource is made in accordance with the corporate identity of the company, and the site itself was developed on CMS Netcat, which simplifies the management process.\n\nThe original idea was to implement a catalog site.\n\nA concept idea for the main page was developed.\n\n![Nereid company website — 1](/uploads/projects/nereida/a0fc6a9d82134bbb993c15e41fa03b8b-2.png)\n\nBut after a series of discussions, the Customer refused to implement the catalog site, and just develoed a corporate website with information on those brands and product categories that are selling.\n\n![Сайт компании Нереида](/uploads/projects/nereida/1244d73a265a49bfa19df7f7352ac82b-2.png)\n\nA convenient and understandable catalog with a large number of positions, as well as simple navigation allow the visitor to quickly find all the necessary information about the product. All this contributes to the key tasks of the company and increase sales.\n\n**Project website:** [nereida.by](https://nereida.by)","subtitle":"Web · Website","challenge":"When developing a site for one of the leading distributors of consumer electronics and computer equipment in Belarus \"NEREIDA\", our specialists took into account all the requirements of the client.","description":"Functional corporate site representing the entire list of products offered","stack_detail":"Electron"},"ru":{"title":"Сайт компании Нереида","result":"Проект успешно запущен и доступен по адресу nereida.by. Работы выполнены в 2015 году.","solution":"Так, дизайн веб-ресурса выполнен в соответствии с фирменным стилем компании, а сам сайт разработан на CMS Netcat, что упрощает процесс управления.\n\nПервоначальная идея заключалась в реализации сайта каталога.\n\nБыла разработана концепт-идея главной страницы.\n\n![Сайт компании Нереида — 1](/uploads/projects/nereida/a0fc6a9d82134bbb993c15e41fa03b8b.png)\n\nНо после ряда обсуждений, Заказчик отказался от реализации сайта каталога, и нацелился на просто корпоративный сайт с отображением информации о тех брендах и категориях товара, которую продают.\n\n![Сайт компании Нереида](/uploads/projects/nereida/1244d73a265a49bfa19df7f7352ac82b.png)\n\nУдобный и понятный каталог с большим количеством позиций, а также простая навигация позволяют посетителю сайта быстро найти всю необходимую информацию о товаре. Все это в полной мере способствует ключевой цели компании &ndash; увеличению продаж.\n\n**Сайт проекта:** [nereida.by](https://nereida.by)","subtitle":"Веб · Сайт","challenge":"При разработке сайта для одного из ведущих дистрибьюторов бытовой электроники и компьютерной техники в РБ \"NEREIDA\" наши специалисты учли все требования клиента.","description":"Функциональный корпоративный сайт, представляющий весь перечень предлагаемой продукции","stack_detail":"Electron"}}$row_142$::jsonb)
