INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('saleo', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2015, false, true, 143, '/uploads/projects/saleo/5c990238383e4210ba6524365c46fa18.jpeg', $row_143${"en":{"title":"Holding \"Saleo\"","result":"The project was successfully launched and is available at saleo.by. The work was completed in 2015.","solution":"In this idea, we focused on the use of corporate identity, the market segment on which the enterprise operates and the basic information that needs to be conveyed to the site visitor.\n\n![Концепт сайта производства Салео](/uploads/projects/saleo/3bf5e741c52c4f27944de9aa7ac00e1b-2.png)\n\n**Project website:** [saleo.by](http://saleo.by)","subtitle":"Web · Website","challenge":"Our team has prepared a concept idea for the implementation of the new holding site.","description":"Saleo production site concept","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Холдинг \"Салео\"","result":"Проект успешно запущен и доступен по адресу saleo.by. Работы выполнены в 2015 году.","solution":"В данной идеи мы акцентировали внимание на использование фирменных стилей, сегмента рынка на котором работает предприятие и основную информацию которую необходимо донести посетителю сайта.\n\n![Концепт сайта производства Салео](/uploads/projects/saleo/3bf5e741c52c4f27944de9aa7ac00e1b.png)\n\n**Сайт проекта:** [saleo.by](http://saleo.by)","subtitle":"Веб · Сайт","challenge":"Наша команда подготовила концепт-идею реализации нового сайта холдинга.","description":"Концепт сайта производства Салео","stack_detail":"UI/UX, Figma, Photoshop"}}$row_143$::jsonb)
