INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('bitva-pollov', 'web', ARRAY['web'], ARRAY['JavaScript', 'PHP'], 2015, false, true, 144, '/uploads/projects/bitva-pollov/c715d3e634e44de18c12568f9374ca1c.jpg', $row_144${"en":{"title":"Battle of the pALLOs","result":"The project was successfully launched and is available at vk.com. The work was completed in 2015.","solution":"Piplos Media developed the Battle of the pALLOs SMM application to help the brand stand out from its competitors. The game removes the usual limitations of social media and lets the audience express their creativity through play and competition.\n\nBattle of the pALLOs is an interactive application that allows users to create their own avatars and compete for the most creative and original character. The game is designed to let the audience interact with the brand in a new way, increasing awareness and loyalty.\n\nIn this case study we describe how we built Battle of the pALLOs, how it can help promote a company on social media, and the advantages of using SMM applications in a marketing strategy.\n\n**Project website:** [vk.com](https://vk.com/games/app4203884)\n\n**Related projects:** [Allo Photo Contest](/en/portfolio/fotokonkurs-allo), [Allo. Lovers' Photo Contest](/en/portfolio/allo-fotokonkurs-vlublennih)","subtitle":"Web · SMM app","challenge":"Social networks have become an essential platform for brand marketing. Every year more companies try to capture their audience's attention through social media, and it is no easy task: competition on platforms such as Facebook and Instagram is extremely high.","description":"Battle of the pALLOs: how our SMM app helped the company succeed","stack_detail":"JavaScript, PHP"},"ru":{"title":"Битва пАЛЛОв","result":"Проект успешно запущен и доступен по адресу vk.com. Работы выполнены в 2015 году.","solution":"Компания Piplos Media разработала SMM-приложение \"Битва пАЛЛОв\", которое поможет вашему бренду выделиться на фоне конкурентов. Игра снимет все ограничения социальных медиа и позволит вашей аудитории выразить свое творческое начало в форме игры и конкурса.\n\n\"Битва пАЛЛОв\" - это интерактивное приложение, которое позволяет пользователям создавать собственные аватары и участвовать в конкурсе на самого креативного и оригинального персонажа. Игра нацелена на то, чтобы позволить вашей аудитории взаимодействовать с вашим брендом в новой форме, увеличивая узнаваемость и лояльность к нему.\n\nВ статье мы расскажем о том, как мы создали \"Битву пАЛЛОв\", как она может помочь вашей компании в продвижении в социальных медиа, и какие преимущества имеет использование SMM-приложений в вашей маркетинговой стратегии.\n\n**Сайт проекта:** [vk.com](https://vk.com/games/app4203884)\n\n**Связанные проекты:** [Фотоконкурс Алло](/ru/portfolio/fotokonkurs-allo), [Алло. Фотоконкурс влюбленных](/ru/portfolio/allo-fotokonkurs-vlublennih)","subtitle":"Веб · SMM-приложение","challenge":"Социальные сети стали незаменимой площадкой для маркетинга брендов. С каждым годом все больше компаний стараются привлечь внимание аудитории через социальные медиа, и это оказывается непростой задачей. Ведь на платформах, таких как Facebook и Instagram, конкуренция очень высока.","description":"Битва пАЛЛОв: как наше SMM приложение помогло компании достичь успеха","stack_detail":"JavaScript, PHP"}}$row_144$::jsonb)
