INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('trionis', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2015, false, true, 146, '/uploads/projects/trionis/d3aab117b3d7480083a0394fbefecebd.jpeg', $row_146${"en":{"title":"Trionis Agricultural Company","result":"The project was successfully launched and is available at trionis.soy. The work was completed in 2015.","solution":"The project includes a well-planned site structure for quick access to information across all sections — from product search to job vacancies and company contacts.\n\n![Trionis agricultural company](/uploads/projects/trionis/80a3ef59a7d24179affcb8ef01f5993f.png)\n\n**Project website:** [trionis.soy](https://trionis.soy)","subtitle":"Web · Website","challenge":"Development of a catalogue website for a leading agricultural company operating in the Russian Federation.","description":"Catalogue website for an agricultural company","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Сельскохозяйственная компания Трионис","result":"Проект успешно запущен и доступен по адресу trionis.soy. Работы выполнены в 2015 году.","solution":"Проект включает в себя продуманную структуру сайта для быстрого поиска информации по всем разделам сайта, начиная от поиска продукции, заканчивая информацией о вакансиях и контактах предприятия.\n\n![Сельскохозяйственная компания Трионис](/uploads/projects/trionis/80a3ef59a7d24179affcb8ef01f5993f.png)\n\n**Сайт проекта:** [trionis.soy](https://trionis.soy)","subtitle":"Веб · Сайт","challenge":"Разработка сайта каталога ведущая сельскохозяйственная компания на территории Российской Федерации.","description":"Каталог сельскохозяйственной компании","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_146$::jsonb)
