INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('budutam-android', 'mobile', ARRAY['mobile'], ARRAY['Android', 'iOS'], 2015, false, true, 147, '/uploads/projects/budutam-android/artboard-copy-42.png', $row_147${"en":{"title":"The mobile app BuduTam","result":"The project was successfully delivered to the client. The work was completed in 2015.","solution":"One of the features of the app is the ability to register users, who can receive information about upcoming events and parties, mark their wish to get there and sign up when needed. By upgrading their account, users can create their own events which are moderated by the app administrators.\n![BuduTam mobile app](/uploads/projects/budutam-android/4d89e0d387124cd5ad6954ccb93adf75.png)\n\nIn addition, the app has a system for earning points for active users, which can be exchanged for various bonuses from event organizers or app administrators. This system allows you to increase the level of interaction between users and the company.\n\nOne of the key points in the development of the application was the creation of a fault-tolerant API system which ensures stable operation of the functionality under high loads and simultaneous visits to the application or website. Such a system allows the company to provide quality service and improve interaction with clients.\n\nThe development of Future there for JapanTabacco is a shining example of how a company can use modern technology to improve their business processes and customer interactions.\n![The mobile app BuduTam — 2](/uploads/projects/budutam-android/8c2fd56de5c1492493b56e9baa55b6e9.png)\n\n**Related projects:** [SMM app BuduTam](/en/portfolio/budutam)","subtitle":"Mobile · Mobile app","challenge":"These days, mobile apps are becoming increasingly popular, and companies are looking to use them to improve business processes and customer interaction. JapanTabacco is no exception and decided to develop a mobile app Buda there, which has become a kind of social network for party lovers.","description":"Development of the BuduTam mobile app for Japan Tobacco: creating a social network for party organisation","stack_detail":"Android, iOS"},"ru":{"title":"Мобильное приложение БудуТам","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2015 году.","solution":"Одной из особенностей приложения является возможность регистрации пользователей, которые могут получать информацию о предстоящих событиях и праздниках, отмечаться о своем желании попасть туда и проходить регистрацию при необходимости. При повышении уровня своего аккаунта пользователь может создавать собственные мероприятия, которые проходят модерацию у администраторов приложения.\n![Мобильное приложение БудуТам](/uploads/projects/budutam-android/4d89e0d387124cd5ad6954ccb93adf75.png)\n\nКроме того, в приложении реализована система начисления баллов для активных пользователей, которые могут быть обменены на различные бонусы от организаторов событий или администраторов приложения. Эта система позволяет повысить уровень взаимодействия между пользователями и компанией.\n\nОдним из ключевых моментов в разработке приложения было создание отказоустойчивой API системы, которая обеспечивает стабильную работу функционала при высоких нагрузках и одновременном посещении приложения или сайта. Такая система позволяет компании предоставлять качественный сервис и улучшать взаимодействие с клиентами.\n\nРазработка мобильного приложения Буду там для компании JapanTabacco - это яркий пример того, как компания может использовать современные технологии для улучшения бизнес-процессов и взаимодействия с клиентами.\n![Мобильное приложение БудуТам — 2](/uploads/projects/budutam-android/8c2fd56de5c1492493b56e9baa55b6e9.png)\n\n**Связанные проекты:** [SMM приложение БудуТам](/ru/portfolio/budutam)","subtitle":"Мобильное · Приложение","challenge":"В наше время мобильные приложения становятся все более популярными, и компании стремятся использовать их для улучшения бизнес-процессов и взаимодействия с клиентами. Компания JapanTabacco не исключение и решила разработать мобильное приложение Буду там, которое стало своего рода социальной сетью для любителей вечеринок.","description":"Разработка мобильного приложения БудуТам для компании Japan Tobacco: создание социальной сети для организации вечеринок","stack_detail":"Android, iOS"}}$row_147$::jsonb)
