VALUES ('promo-site-ren', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2014, false, true, 149, '/uploads/projects/promo-site-ren/ee8efea873fe436fbf92d0e79512e8ac.png', $row_149${"en":{"title":"Ren Promo Website","result":"The project was successfully delivered to the client. The work was completed in 2014.","solution":"We designed and built a promotional website for the Ren brand, focused on clear brand presentation and campaign support.\n\n**Related projects:** [Striped Calendar Ren](/en/portfolio/calendar-ren), [Zakatki Ren: Building an SMM Application](/en/portfolio/zakatki-ren)","subtitle":"Web · Website","challenge":"Development of a promotional website for the Ren brand to support its marketing campaigns online.","description":"Promotional website for the Ren brand","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Промо-сайт Рень","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2014 году.","solution":"Промо-сайт Рень\n\n**Связанные проекты:** [Полосатый календарь Рень](/ru/portfolio/calendar-ren), [Закатки Рень: создание SMM-приложения](/ru/portfolio/zakatki-ren)","subtitle":"Веб · Сайт","challenge":"Промо-сайт Рень","description":"Промо-сайт Рень","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_149$::jsonb)
