INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('maldini', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2014, false, true, 150, '/uploads/projects/maldini/505d9d3423db451fb8827870fe51d543.jpeg', $row_150${"en":{"title":"Minsk grape wine factory","result":"The project was successfully launched and is available at maldini.by. The work was completed in 2014.","solution":"** Requirements **:\n\n- The purpose of the site (the purpose of the site).\nBrand Awareness. The formation of consumer loyalty to the product.\n- Site structure.\nThe site has a monolingual one-page structure.\n- Design Design\nconcept - club theme. Vermouth Maldini - an alcoholic drink for parties, for romantic evenings, which can be consumed both ready-made and in cocktails. The main target audience is girls living a vibrant life, seeking to know all its pleasures.\n\n![Minsk grape wine factory — 1](/uploads/projects/maldini/90f89c0b02ab4154973b5c1f924da62f-2.png)\n\nWe tried to take into account all the requirements of the customer for this project when creating the structure and visualization of this site.\n\nWe have done a lot of work on processing images of bottles, because they should have a transparency effect. We maximally gave them the effect of real transparency.\n\n![Minsk grape wine factory — 2](/uploads/projects/maldini/d1fbe87a30214dbe92f92e1fcb64b336-2.png)\n\nAlso, when developing this project, the parallax effect was used when scrolling the bottles in the product block.\n\n**Project website:** [maldini.by](http://maldini.by/)","subtitle":"Web · Landing page","challenge":"To launch the new Maldini brand, we have developed a promotional project reflecting the entire range of this product, as well as all its possible advantages.","description":"Landing under the new Maldini Trademark","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Минский завод виноградных вин","result":"Проект успешно запущен и доступен по адресу maldini.by. Работы выполнены в 2014 году.","solution":"Для запуска новой торговой марки Мальдини, нами был разработан промо проект отражающий весь ассортимент данного продукта, а так же все возможные его преимущества.\n\n**Требования**:\n\n- Назначение сайта (цель создания сайта).\nПовышение узнаваемости торговой марки. Формирование лояльности потребителей к продукту.\n- Структура Сайта.\nСайт имеет одноязычную одностраничную структуру.\n- Дизайн\nКонцепция дизайна - клубная тематика. Вермут Maldini - алкогольный напиток для вечеринок, для романтических вечеров, который можно употреблять как в готовом виде, так и в коктейлях. Основная целевая аудитория - девушки, живущие яркой жизнью, стремящиеся познать все ее удовольствия.\n\n![Минский завод виноградных вин — 1](/uploads/projects/maldini/90f89c0b02ab4154973b5c1f924da62f.png)\n\nМы постарались учесть все требования заказчика по данному проекту при создании структуры и визуализации данного сайта.\n\nНами была проделана большая работа по обработке изображений бутылок,, т.к. они должны были иметь эффект прозрачности. Мы максимально придали им эффект реальной прозрачности.\n\n![Минский завод виноградных вин — 2](/uploads/projects/maldini/d1fbe87a30214dbe92f92e1fcb64b336.png)\n\nТак же при разработке данного проекта применялся эффект параллакса при скролле бутылок в блоке продукции.\n\n**Сайт проекта:** [maldini.by](http://maldini.by/)","subtitle":"Веб · Лендинг","challenge":"Назначение сайта (цель создания сайта). Повышение узнаваемости торговой марки. Формирование лояльности потребителей к продукту. Структура Сайта. Сайт имеет одноязычную одностраничную структуру. Дизайн Концепция дизайна - клубная тематика. Вермут Maldini - алкогольный напиток для вечеринок, для романтических вечеров, который можно употреблять как в готовом виде, так и в коктейлях. Основная целевая аудитория - девушки, живущие яркой жизнью, стремящиеся познать все ее удовольствия.","description":"Лендинг под новую Торговую Марку \"Мальдини\"","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_150$::jsonb)
