INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('tontiag-app', 'mobile', ARRAY['mobile'], ARRAY['iOS'], 2014, false, true, 152, '/uploads/projects/tontiag-app/993ca9035c6243f5bf8d3c1d78ec8e04.png', $row_152${"en":{"title":"Tontiag mobile app","result":"The project was successfully launched and is available at tontiag.com. The work was completed in 2014.","solution":"This is a social network for movie and series. The application database contains detailed information about the films.\nThe highlight of the application is the popular replicas from movies that you can listen to.\n\nWithin the framework of the project, a portal was developed in 2 languages; API for interacting with third-party applications.\n\n![Tontiag mobile app — 1](/uploads/projects/tontiag-app/91d6afd8f2ff432b9c4094341a3c20bc-2.png)\n\n![Tontiag mobile app — 2](/uploads/projects/tontiag-app/d394d8b724b74c2a94686bf5b4b66e52-2.png)\n\n**Project website:** [tontiag.com](https://tontiag.com)\n\n**Related projects:** [The social network of movie fans Tontiag](/en/portfolio/tontiag)","subtitle":"Mobile · Mobile app","challenge":"Tontiag mobile application was developed on the iOS platform.","description":"Mobile app of the social network of movie fans Tontiag","stack_detail":"iOS"},"ru":{"title":"Мобильное приложение Tontiag","result":"Проект успешно запущен и доступен по адресу tontiag.com. Работы выполнены в 2014 году.","solution":"Это социальная сеть для любителей кино и сериалов. База приложения содержит подробнейшую информацию о фильмах.\nИзюминкой приложения является популярные реплики с фильмов, которые можно прослушать.\n\nВ рамках проекта разработан портал на 2 языках; API для взаимодействия со сторонними приложениями.\n\n![Мобильное приложение Tontiag — 1](/uploads/projects/tontiag-app/91d6afd8f2ff432b9c4094341a3c20bc.png)\n\n![Мобильное приложение Tontiag — 2](/uploads/projects/tontiag-app/d394d8b724b74c2a94686bf5b4b66e52.png)\n\n**Сайт проекта:** [tontiag.com](https://tontiag.com)\n\n**Связанные проекты:** [Социальная сеть киноманов Tontiag](/ru/portfolio/tontiag)","subtitle":"Мобильное · Приложение","challenge":"Мобильное приложение Tontiag разрабатывалось на платформе iOS.","description":"Мобильное приложение социальной сети киноманов Tontiag","stack_detail":"iOS"}}$row_152$::jsonb)
