VALUES ('geopromsk', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2014, false, true, 154, '/uploads/projects/geopromsk/artboard-copy-17.png', $row_154${"en":{"title":"Elite Doors from Space Geometry","result":"The project was successfully launched and is available at geopromsk.ru. The work was completed in 2014.","solution":"By the time the company expanded, it was time to create a catalog site with a presentation of the work of Space Geometry.\n\n![Элитные двери от Геометрии Пространства](/uploads/projects/geopromsk/34cd06fa28614b989b756efcae229853-2.png)\n\n**Project website:** [geopromsk.ru](http://geopromsk.ru)","subtitle":"Web · Website","challenge":"The site for the sale of Elite Doors of one of the largest companies in Moscow engaged in the production and installation of panoramic sliding glass facades and conservatories.","description":"Site directory of luxury doors","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Элитные двери от Геометрии Пространства","result":"Проект успешно запущен и доступен по адресу geopromsk.ru. Работы выполнены в 2014 году.","solution":"К моменту расширения компании, пришла пора создания сайта каталога с представлением работ Геометрии Пространства.\n\n![Элитные двери от Геометрии Пространства](/uploads/projects/geopromsk/34cd06fa28614b989b756efcae229853.png)\n\n**Сайт проекта:** [geopromsk.ru](http://geopromsk.ru)","subtitle":"Веб · Сайт","challenge":"Проект посвящён продаже, а точнее демонстрации пользователям Элитных Дверей одной из крупнейших в Москве компании, занимающейся производством и монтажом панорамных раздвижных стеклянных фасадов и зимних садов.","description":"Сайт каталог элитных дверей","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_154$::jsonb)
