INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('autoactive-site', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2014, false, true, 155, '/uploads/projects/autoactive-site/9b3c77323a924f63b0718bb0c57116ac.png', $row_155${"en":{"title":"Autoactive Landing","result":"The project was successfully delivered to the client. The work was completed in 2014.","solution":"Including used as an additional channel to attract customers.\n\n![Autoactive Landing — 1](/uploads/projects/autoactive-site/821d012047d24e5280d9d9c7c77ab340-2.png)\n\n**Related projects:** [Autoactive app](/en/portfolio/autoactive)","subtitle":"Web · Landing page","challenge":"This landing page was developed to inform about the mobile app, which is designed to save time and provide a convenient car maintenance service. It is possible to sort car washes and tire services by type. A personal user account and an admin panel for managing car washes and tire fitting have been developed.","description":"Landing for the Autoactive mobile app","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Автоактив Лендинг","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2014 году.","solution":"Данный лендинг разрабатывался для информировании о [мобильном приложении](/ru/portfolio/autoactive), которое предназначено для того, что бы сэкономить время и предоставить удобный сервис по обслуживанию автомобиля. Предусмотрена возможность отсортировать автомойки и шиномонтажи по типу. Разработан личный кабинет пользователя и админка управления автомойками ишиномонтажами.\n\nВ том числе использован как дополнительный канал привлечения клиентов.\n\n![Автоактив Лендинг — 1](/uploads/projects/autoactive-site/821d012047d24e5280d9d9c7c77ab340.png)","subtitle":"Веб · Лендинг","challenge":"Данный лендинг разрабатывался для информировании о мобильном приложении, которое предназначено для того, что бы сэкономить время и предоставить удобный сервис по обслуживанию автомобиля. Предусмотрена возможность отсортировать автомойки и шиномонтажи по типу. Разработан личный кабинет пользователя и админка управления автомойками ишиномонтажами.","description":"Лендинг для мобильного приложения Авто актив","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_155$::jsonb)
