INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('tvoydom-promo', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2014, false, true, 156, '/uploads/projects/tvoydom-promo/f6fd2d2e993a4f83a3878c3f920ab919.png', $row_156${"en":{"title":"Landing \"Your House\"","result":"The project was successfully launched and is available at tvoydom.by. The work was completed in 2014.","solution":"This project was intended to advertise company services through contextual advertising. \n![Landing \"Your House\" — 1](/uploads/projects/tvoydom-promo/5b05cd643c1b400f950d744fa7e1775d-2.png)\nThe project should be aimed at selling marker paint.\n\nWe needed to provide the most detailed information about it and the products that are available in the company.\n\n**Project website:** [tvoydom.by](https://tvoydom.by)","subtitle":"Web · Landing page","challenge":"As part of supporting Your Home projects, we were tasked with making a one-page site as soon as possible.","description":"Development of a promotional site for the studio of finishing solutions Your Home","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Лендинг Твой Дом","result":"Проект успешно запущен и доступен по адресу tvoydom.by. Работы выполнены в 2014 году.","solution":"Данный проект был предназначен для рекламировании услуг компании по средством контекстной рекламы. \n![Лендинг Твой Дом — 1](/uploads/projects/tvoydom-promo/5b05cd643c1b400f950d744fa7e1775d.png)\nПроект должен быть нацелен на продажу маркерной краски.\n\nНам необходимо было максимально подробно предоставить информацию о ней и товарах которые доступны в компании.\n\n**Сайт проекта:** [tvoydom.by](https://tvoydom.by)","subtitle":"Веб · Лендинг","challenge":"В рамках поддержки проекта Твой Дом, нам была поставлена задача сделать в кротчайшие сроки одностраничный сайта.","description":"Разработка промо сайта для студии отделочных решений Твой Дом","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_156$::jsonb)
