INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('buyarearugs', 'web', ARRAY['web', 'ecommerce'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2014, false, true, 157, '/uploads/projects/buyarearugs/c30225cabda841f8997577eb74585118.jpg', $row_157${"en":{"title":"Site Buy Area Rugs","result":"The project was successfully delivered to the client. The work was completed in 2014.","solution":"The main work was to redesign the site design while maintaining the structure and functionality of the current project.\n\nThe new design should be based on the company's brand book.\n![Site Buy Area Rugs — 1](/uploads/projects/buyarearugs/e7fcdde46e704fbcb397b2bccb7c06b9-2.png)\n\nWe have revised the general concept of the current site and proposed simplified visualization of the project.\n![Site Buy Area Rugs — 2](/uploads/projects/buyarearugs/84496c8308134ff29c178bbcd1604b34-2.png)\n\nAll sections of the site began to look like a single whole of one project. \n![Site Buy Area Rugs — 3](/uploads/projects/buyarearugs/23d6734e30b74729ad9e2b047d5a3131-2.png)\n\nAlso, in this proposal, the project functionality was also improved, allowing users to purchase goods through the site.","subtitle":"Web · E-commerce","challenge":"The task of finalizing the existing site of the company selling exclusive carpets.","description":"Carpet online store","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Сайт Buy Area Rugs","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2014 году.","solution":"Основная работа заключалась в переработке Дизайна сайта с сохранением структуры и функционала текущего проекта.\n\nНовый дизайн должен быть выполнен на основании бренд-бука компании.\n![Сайт Buy Area Rugs — 1](/uploads/projects/buyarearugs/e7fcdde46e704fbcb397b2bccb7c06b9.png)\n\nНами был пересмотрен общий концепт текущего сайта и предложена упращенная визуализации проекта.\n![Сайт Buy Area Rugs — 2](/uploads/projects/buyarearugs/84496c8308134ff29c178bbcd1604b34.png)\n\nВсе разделы сайта стали выглядеть как единой целое одного проекта. \n![Сайт Buy Area Rugs — 3](/uploads/projects/buyarearugs/23d6734e30b74729ad9e2b047d5a3131.png)\n\nТак же, в рамках данной заявки, был доработан и функционал проекта, позволяющий пользователям приобретать товар через сайт.","subtitle":"Веб · E-commerce","challenge":"Перед нами была поставлена задача по доработке существующего сайта компании по продаже эксклюзивных ковров.","description":"Интернет-магазин по продаже ковров","stack_detail":"UI/UX, Figma, Photoshop"}}$row_157$::jsonb)
