INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('harmony', 'web', ARRAY['web'], ARRAY['Symfony'], 2014, false, true, 158, '/uploads/projects/harmony/75b43fdd9adf42dd95b3bae356a94374.jpeg', $row_158${"en":{"title":"Harmony of Comfort Promo Website","result":"The project was successfully delivered to the client. The work was completed in 2014.","solution":"The client's goal was to attract customers and expand their stretch ceiling business.\n\n1. Purpose of the website: promoting the company's services on the Bulgarian market, raising brand awareness and building customer loyalty.\n2. Languages: the development language was Russian, while the site content was in Bulgarian.\n3. Content management: Symfony 2. The CMS allows the site administrator to manage three landing pages — editing text content and adding testimonials and photos to the slider.\n4. Site structure: a single-language, one-page layout.\n\n![Harmony of Comfort](/uploads/projects/harmony/8f65d241b55041bbbb55d54e25d471f2.png)\n\nThe project was developed from a preliminary prototype we prepared.\n\n![Harmony of Comfort promo website — 2](/uploads/projects/harmony/f2ea80c102d0431eaca5819ca9a9fc59.png)\n\nBased on this prototype we created the original visual design of the landing page. The core idea: capturing the user's attention with a variety of call-to-action elements.\n\n![Harmony of Comfort promo website — 3](/uploads/projects/harmony/32fbf41539df41d796c002b5d5a4b748.png)\n\nThe project was built with the promotion of the company's services on the Bulgarian market in mind.\n![Harmony of Comfort promo website — 4](/uploads/projects/harmony/c695d0f645724aeeb55d17fc4f95cb29.jpg)","subtitle":"Web · Landing page","challenge":"We were tasked with creating a high-converting landing page for a Western market.","description":"Landing page development for promoting stretch ceiling services","stack_detail":"Symfony"},"ru":{"title":"Промо Сайт Гармония Уюта","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2014 году.","solution":"Цель заказчика - привлечение клиентов и расширение производства натяжных потолков.\n\n1. Назначение сайта (цель создания сайта). Сайт разрабатывается с целью продвижения услуг компании на рынке Болгарии. Повышение узнаваемости торговой марки. Формирование лояльности потребителей к продукту.Язык. Язык разработки - Русский. Язык наполнения сайта – Болгарский. \n2. Язык. Язык разработки - Русский. Язык наполнения сайта – Болгарский. Система управления.\n3. Система управления - Symfony 2. Система управления должна позволять администратору сайта, управлять тремя лендингами. Администратор сайта должен иметь возможность наполнять и изменять текстовую часть трех лендингов, а так же вставлять отзывы и фото в слайдер. \n4. Структура Сайта. Сайт имеет одноязычную одностраничную структуру.\n\n![Гармония Уюта](/uploads/projects/harmony/8f65d241b55041bbbb55d54e25d471f2.png)\n\nПроект разрабатывался на основании подготовленной нами предварительного прототипа проекта.\n\n![Промо Сайт Гармония Уюта — 2](/uploads/projects/harmony/f2ea80c102d0431eaca5819ca9a9fc59.png)\n\nНа основании данного прототипа создавался оригинальный визуал дизайна лендинга. Основной посыл - Захват внимания пользователя различными элементами обратной связи.\n\n![Промо Сайт Гармония Уюта — 3](/uploads/projects/harmony/32fbf41539df41d796c002b5d5a4b748.png)\n\nДанный проект разрабатывался с учетом продвижения услуг компании на рынке Болгарии. \n![Промо Сайт Гармония Уюта — 4](/uploads/projects/harmony/c695d0f645724aeeb55d17fc4f95cb29.jpg)","subtitle":"Веб · Лендинг","challenge":"Перед нами была поставлена задача создания продающего лендинга для западного рынка.","description":"Разработка лендинга для продвижения услуг натяжных потолков","stack_detail":"Symfony"}}$row_158$::jsonb)
