INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('jemchug', 'mobile', ARRAY['mobile'], ARRAY['Swift', 'iOS'], 2014, false, true, 159, '/uploads/projects/jemchug/b6be20dd-4128-4ead-bde3-f6c7082bdaf8.png', $row_159${"en":{"title":"Karaoke mobile app development","result":"The project was successfully delivered to the client. The work was completed in 2014.","solution":"Development of Karaoke Pearls began in 2019 when Piplos Media received a request from a client to create a mobile karaoke app. The team started working on the project and held a series of meetings with the client to clarify their requirements and wishes.\n\nOne of the main requirements was the ability to record performances and share them with friends on social networks. The client also wanted the app to have a large database of songs and be easy to use for users of all levels.\n\nThe Piplos Media team used the Swift programming language and Xcode development tool to implement the project. They also used many third-party libraries and tools to create a high quality application.\n\nOne of the main tasks was to create a song database that was large enough and diverse enough to satisfy the users. To do this, the development team undertook the task of finding and licensing music tracks so that users could play the songs of their favourite artists.\n\nIn addition, the development team used artificial intelligence technology to improve the quality of users' recordings and enable them to make more professional recordings.\n\nAfter months of development, the app was ready to launch. It was sent to the App Store for validation and after approval was made available for download.\n\nSince then, Karaoke Pearls has become popular with users who love to sing and record their performances. The app has a high rating","subtitle":"Mobile · Mobile app","challenge":"Karaoke Pearls is a mobile app for karaoke fans that allows users to perform songs, record their performances and share them with their friends on social media. The app was developed by the Piplos Media team for the iOS platform and has since become popular with karaoke fans.","description":"Karaoke: The story of mobile app development by Piplos Media team","stack_detail":"Swift, iOS"},"ru":{"title":"Разработка мобильного приложения Караоке Жемчуг","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2014 году.","solution":"Караоке Жемчуг - это мобильное приложение для поклонников караоке, которое позволяет пользователям исполнять песни, записывать свои выступления и делиться ими со своими друзьями в социальных сетях. Это приложение было разработано командой Piplos Media для платформы iOS и с тех пор стало популярным среди любителей караоке.\n\nРазработка Караоке Жемчуг началась в 2019 году, когда Piplos Media получили запрос от клиента на создание мобильного приложения для караоке. Команда приступила к работе над проектом и провела серию встреч с клиентом, чтобы уточнить его требования и пожелания.\n\nОдним из основных требований была возможность записывать выступления и делиться ими с друзьями в социальных сетях. Также клиент хотел, чтобы приложение имело большую базу песен и было легко использовать для пользователей всех уровней.\n\nДля реализации проекта команда Piplos Media использовала язык программирования Swift и инструмент разработки Xcode. Они также использовали множество сторонних библиотек и инструментов, чтобы создать приложение высокого качества.\n\nОдной из основных задач было создание базы данных песен, которая была достаточно большой и разнообразной, чтобы удовлетворить запросы пользователей. Для этого команда разработчиков взяла на себя задачу найти и лицензировать музыкальные композиции, чтобы пользователи могли исполнять песни своих любимых исполнителей.\n\nКроме того, команда разработчиков использовала технологии искусственного интеллекта, чтобы улучшить качество записи пользователей и предоставить им возможность делать более профессиональные записи.\n\nПосле нескольких месяцев разработки приложение было готово к запуску. Оно было отправлено на проверку в App Store и после утверждения было доступно для загрузки.\n\nС тех пор Караоке Жемчуг стало популярным среди пользователей, которые любят петь и записывать свои выступления. Приложение имеет высокий рейт","subtitle":"Мобильное · Приложение","challenge":"Одним из основных требований была возможность записывать выступления и делиться ими с друзьями в социальных сетях. Также клиент хотел, чтобы приложение имело большую базу песен и было легко использовать для пользователей всех уровней.","description":"Караоке Жемчуг: История разработки мобильного приложения командой Piplos Media","stack_detail":"Swift, iOS"}}$row_159$::jsonb)
