INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('tontiag', 'backend', ARRAY['backend'], ARRAY['PHP', 'MySQL', 'JavaScript'], 2014, false, true, 161, '/uploads/projects/tontiag/3f9c6f850afd4b86a55ec7b2f8b2d442.jpg', $row_161${"en":{"title":"The social network of movie fans Tontiag","result":"The project was successfully launched and is available at tontiag.com. The work was completed in 2014.","solution":"This resource is the first of its kind that gives users the opportunity to learn new things about the world of cinema. In our social networking site users can share their knowledge and experience, post their reviews of movies they've seen and enter contests and earn rewards for their efforts.\n\n![Социальная сеть киноманов Tontiag](/uploads/projects/tontiag/51ba4976127541d791da73e608391866.png)\n\nOur users can create a personal account where they can add various clips and scenes from movies to their favorites and share them with friends. We have also implemented messaging functionality between users in this project.\n\nWe are sure that our social network will be useful both for professionals of film industry and for people, who simply like to watch films and want to learn more about the world of cinema.\n\nIn addition, our project is focused on further development and development of [mobile app](/en/portfolio/tontiag-app) so that users can use our service anytime and anywhere. We hope that our social network will become one of the key resources for movie lovers and continue to delight them in the near future.\n\n![The social network of movie fans Tontiag — 2](/uploads/projects/tontiag/c58e3f5440434ffe8ef572b33e76f439.png)\n\n**Project website:** [tontiag.com](https://tontiag.com)","subtitle":"Backend · Platform","challenge":"In the world of cinema, there are many resources where you can find information about films, actors and writers. However, our team has developed a social network that allows you to dive even deeper into the world of cinema.","description":"Development of a social network for film lovers and the film industry","stack_detail":"PHP, MySQL, JavaScript"},"ru":{"title":"Социальная сеть киноманов Tontiag","result":"Проект успешно запущен и доступен по адресу tontiag.com. Работы выполнены в 2014 году.","solution":"Этот ресурс - первый из подобных, который предоставляет возможность пользователям познавать новое в мире кино. В нашей социальной сети пользователи могут делиться своими знаниями и опытом, публиковать свои отзывы о просмотренных фильмах и участвовать в различных конкурсах, получая за это призы.\n\n![Социальная сеть киноманов Tontiag](/uploads/projects/tontiag/51ba4976127541d791da73e608391866.png)\n\nНаши пользователи могут создавать свой личный кабинет, где они могут добавлять различные вырезки и сцены из фильмов в избранное и делиться ими с друзьями. В том числе, в данном проекте мы реализовали функционал обмена сообщениями между пользователями.\n\nМы уверены, что наша социальная сеть будет полезна как для профессионалов киноиндустрии, так и для людей, которые просто любят смотреть фильмы и желают узнать больше о мире кино.\n\nКроме того, наш проект заточен на дальнейшее развитие и разработку [мобильного приложения](/ru/portfolio/tontiag-app), чтобы пользователи могли пользоваться нашим сервисом в любое время и в любом месте. Мы надеемся, что наша социальная сеть станет одним из ключевых ресурсов для любителей кино и будет продолжать радовать их в ближайшем будущем.\n\n![Социальная сеть киноманов Tontiag — 2](/uploads/projects/tontiag/c58e3f5440434ffe8ef572b33e76f439.png)\n\n**Сайт проекта:** [tontiag.com](https://tontiag.com)","subtitle":"Бэкенд · Платформа","challenge":"В мире кино существует множество ресурсов, где можно найти информацию о фильмах, актерах и сценаристах. Однако, наша команда разработала социальную сеть, которая позволяет погрузиться в мир кино еще глубже.","description":"Разработка социальной сети для любителей кино и сферы киноиндустрии","stack_detail":"PHP, MySQL, JavaScript"}}$row_161$::jsonb)
