INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('teos', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2014, false, true, 162, '/uploads/projects/teos/45d36e8b0cf546a89615c6b70f702257.png', $row_162${"en":{"title":"Promo site TEOS","result":"The project was successfully launched and is available at teos.by. The work was completed in 2014.","solution":"The tasks we have set:\n1. Post on the site the entire line of products, as well as image processing;\n2. To finalize the site structure taking into account changes / additions to product packaging;\n3. Post on the website text information about the product (provided by the Customer);\n4. Finalization of the main page\n5. Changing the structure of the product group catalog\n\n![Promo site TEOS — 1](/uploads/projects/teos/0c6daeade44d4b47a2ac372c2c92c183-2.png)\n\n**Project website:** [teos.by](http://teos.by)","subtitle":"Web · Website","challenge":"The essence of the project is modernization, modernization of the site, taking into account the change of brand name (branding) and the introduction of a new product line - Teos (previously the Savushkin. Greek line).","description":"Finalization of TM TEOS promo site for Savushkin Product","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Промо сайт TEOS","result":"Проект успешно запущен и доступен по адресу teos.by. Работы выполнены в 2014 году.","solution":"Суть проекта - модернизация модернизация сайта с учетом смены названия бренда (фирменной символики)\nи введения новой линейки продукции – Teos (ранее линейка «Савушкин. Греческий»).\n\nЗадачи которые перед нами поставили:\n1. Разместить на сайте всю линейку продукции, а так же обработка изображений;\n2. Доработать структуру сайта с учетом изменения / добавления упаковки продукции;\n3. Разместить на сайте текстовую информацию о продукте (предоставляет Заказчик);\n4. Доработка главной страницы\n5. Изменение структуры каталога товарной группы\n\n![Промо сайт TEOS — 1](/uploads/projects/teos/0c6daeade44d4b47a2ac372c2c92c183.png)\n\n**Сайт проекта:** [teos.by](http://teos.by)","subtitle":"Веб · Сайт","challenge":"Задачи которые перед нами поставили: Разместить на сайте всю линейку продукции, а так же обработка изображений; Доработать структуру сайта с учетом изменения / добавления упаковки продукции; Разместить на сайте текстовую информацию о продукте (предоставляет Заказчик); Доработка главной страницы Изменение структуры каталога товарной группы","description":"Доработка промо сайта ТМ TEOS для Савушкин Продукт","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_162$::jsonb)
