INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('fotokonkurs-allo', 'web', ARRAY['web'], ARRAY['Node.js', 'MongoDB'], 2014, false, true, 163, '/uploads/projects/fotokonkurs-allo/e5610c99772446fe991022e3f53c9197.jpg', $row_163${"en":{"title":"Allo Photo Contest","result":"The Allo Photo Contest SMM application helped Allo run a successful photo contest and attract new customers. The project also confirmed that modern technology and a user-friendly interface are key factors in building a successful SMM application.","solution":"Our team developed the Allo Photo Contest SMM application for the Allo company, which helped run a successful contest and increase brand awareness.\n\nThe Allo Photo Contest application allowed users to upload photos on a given theme, vote for the best entries and follow the progress of the contest. Users could also share their entries on social networks, extending the campaign's reach.\n\nThe development involved a range of technologies and tools: ReactJS for the interface, Node.js for the server side and MongoDB for storing contest and user data.\n\nUsability was a key aspect of the project. We created a simple, intuitive interface that made it easy for participants to upload photos and vote for the best entries.\n\n**Project website:** [vk.com](https://vk.com/app3837952)\n\n**Related projects:** [Allo. Lovers' Photo Contest](/en/portfolio/allo-fotokonkurs-vlublennih), [Battle of the pALLOs](/en/portfolio/bitva-pollov)","subtitle":"Web · SMM app","challenge":"More and more companies use social networks to promote their brands and products. Social media platforms help attract new customers and retain existing ones. One effective way to raise brand awareness and engage an audience is to run a photo contest.","description":"Developing the Allo Photo Contest SMM application: how we built a successful audience engagement tool","stack_detail":"Node.js, MongoDB"},"ru":{"title":"Фотоконкурс Алло","result":"В итоге, SMM приложение \"Фотоконкурс Алло\" помогло компании Allo провести успешный фотоконкурс и привлечь новых клиентов. Разработка приложения также показала, что использование современных технологий и удобный интерфейс - важные факторы для создания успешного SMM приложения.","solution":"Нашей командой было разработано SMM приложение \"Фотоконкурс Алло\" для компании Allo, которое помогло организовать успешный конкурс и увеличить узнаваемость бренда.\n\nПриложение \"Фотоконкурс Алло\" позволяло пользователям загружать фотографии на заданную тему, голосовать за лучшие работы и следить за прогрессом конкурса. Кроме того, была реализована возможность поделиться своими работами в социальных сетях, что позволило расширить охват аудитории.\n\nРазработка SMM приложения включала в себя использование различных технологий и инструментов. Мы использовали фреймворк ReactJS для создания интерфейса, Node.js для серверной части приложения и базу данных MongoDB для хранения информации о конкурсе и пользователях.\n\nТакже важным аспектом разработки SMM приложения является удобство использования для пользователей. Мы создали простой и интуитивно понятный интерфейс, который позволил участникам легко загружать свои фотографии и голосовать за лучшие работы.\n\n**Сайт проекта:** [vk.com](https://vk.com/app3837952)\n\n**Связанные проекты:** [Алло. Фотоконкурс влюбленных](/ru/portfolio/allo-fotokonkurs-vlublennih), [Битва пАЛЛОв](/ru/portfolio/bitva-pollov)","subtitle":"Веб · SMM-приложение","challenge":"Сегодня все больше компаний используют социальные сети для продвижения своих брендов и товаров. С помощью социальных медиа-платформ можно привлечь новых клиентов и удерживать уже имеющихся. Одним из способов повышения узнаваемости компании и привлечения внимания аудитории является организация фотоконкурса.","description":"Разработка SMM приложения для Фотоконкурса Алло: как мы создали успешный инструмент привлечения аудитории","stack_detail":"Node.js, MongoDB"}}$row_163$::jsonb)
