INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('lifegadget', 'web', ARRAY['web'], ARRAY['Electron'], 2014, false, true, 165, '/uploads/projects/lifegadget/2f8a04a5eec84c3fbf043d3a3c53ff71.png', $row_165${"en":{"title":"Online Magazine, LifeGadget, Electronics, News, Reviews, Technology, Blog, Comments, Site Development, Portfolio","result":"The project was successfully delivered to the client. The work was completed in 2014.","solution":"In addition, at LifeGadget, you'll find a blog where any user can express their opinion on various topics related to electronics. We value the opinion of our readers and therefore try to create a comfortable environment for communication and exchange of experiences.\n\n![Online Magazine, LifeGadget, Electronics, News, Reviews, Technology, Blog, Comments, Site Development, Portfolio — 1](/uploads/projects/lifegadget/7396227a8d2e44218cfe8cbad6ba0ce3-2.png)\n\nOne of the features of our magazine is that we actively use modern technology, including artificial intelligence, to analyse and process data. This allows us to provide our readers with more accurate and useful information, as well as a more user-friendly and intuitive website interface.\n\nWe believe that LifeGadget is not just an online magazine, but a real community of people who are passionate about electronics. Join us and stay up to date with all the latest developments in the electronics market!\n\n![Online Magazine, LifeGadget, Electronics, News, Reviews, Technology, Blog, Comments, Site Development, Portfolio — 2](/uploads/projects/lifegadget/c829f5f4e12a4e2d97f948756025b8c2-2.png)","subtitle":"Web · Website","challenge":"Our Pilos Media team has developed LifeGadget magazine, a unique resource dedicated to electronics. The site is packed with articles, news and reviews on the latest and most interesting gadgets such as smartphones, laptops, TVs and other gadgets. Thanks to our team of experienced authors and journalists, we are constantly monitoring what's new on the market and sharing the most current and interesting information with our readers.","description":"LifeGadget: a new online magazine about the world of electronics from the Pilos Media team","stack_detail":"Electron"},"ru":{"title":"LifeGadget: новый интернет-журнал","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2014 году.","solution":"Кроме того, на LifeGadget вы найдете блог, где любой пользователь может высказать свое мнение на различные темы, связанные с электроникой. Мы ценим мнение наших читателей и поэтому стараемся создать удобные условия для общения и обмена опытом.\n\n![LifeGadget: новый интернет-журнал — 1](/uploads/projects/lifegadget/7396227a8d2e44218cfe8cbad6ba0ce3.png)\n\nОдной из особенностей нашего журнала является то, что мы активно используем современные технологии, включая искусственный интеллект, для анализа и обработки данных. Это позволяет нам предоставлять нашим читателям более точную и полезную информацию, а также более удобный и интуитивно понятный интерфейс сайта.\n\nМы верим, что LifeGadget - это не просто интернет-журнал, а настоящее сообщество людей, увлеченных электроникой. Присоединяйтесь к нам и будьте в курсе всех новинок рынка электроники!\n\n![LifeGadget: новый интернет-журнал — 2](/uploads/projects/lifegadget/c829f5f4e12a4e2d97f948756025b8c2.png)","subtitle":"Веб · Сайт","challenge":"Нашей командой Pilos Media был разработан Интернет Журнал LifeGadget - уникальный ресурс, посвященный электронной технике. На сайте вы найдете множество статей, новостей и обзоров на самые актуальные и интересные устройства, такие как смартфоны, ноутбуки, телевизоры и другие гаджеты. Благодаря нашей команде опытных авторов и журналистов, мы постоянно следим за новинками рынка и делимся с нашими читателями самой актуальной и интересной информацией.","description":"LifeGadget: новый интернет-журнал о мире электроники от команды Pilos Media","stack_detail":"Electron"}}$row_165$::jsonb)
