INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('allo-fotokonkurs-vlublennih', 'web', ARRAY['web'], ARRAY['JavaScript', 'PHP'], 2013, false, true, 167, '/uploads/projects/allo-fotokonkurs-vlublennih/d471119f87694729875b7f7805a50714.jpg', $row_167${"en":{"title":"Allo. Lovers' Photo Contest","result":"The project was successfully launched and is available at vk.com. The work was completed in 2013.","solution":"We also share some practical advice for anyone planning to build their own SMM application and succeed in the social media market.\n\nWe are confident that Allo. Lovers' Photo Contest is a great tool for raising brand awareness and improving audience engagement. After all, love is what unites us all, and our application helps users express their feelings and share them with others.\n\n**Project website:** [vk.com](https://vk.com/app4181138)\n\n**Related projects:** [Allo Photo Contest](/en/portfolio/fotokonkurs-allo), [Battle of the pALLOs](/en/portfolio/bitva-pollov)","subtitle":"Web · SMM app","challenge":"Our team recently developed a new SMM application, Allo. Lovers' Photo Contest, which lets users upload and share photos expressing their love. The application includes a voting system that allows users to vote for their favourite photos and determine the winners.","description":"Allo: Lovers' Photo Contest — a new SMM application by Piplos Media","stack_detail":"JavaScript, PHP"},"ru":{"title":"Алло. Фотоконкурс влюбленных","result":"Проект успешно запущен и доступен по адресу vk.com. Работы выполнены в 2013 году.","solution":"Мы также поделимся некоторыми полезными советами для тех, кто планирует разработать свое SMM приложение и достичь успеха на рынке социальных сетей.\n\nМы уверены, что \"Алло. Фотоконкурс влюбленных\" станет отличным инструментом для повышения узнаваемости бренда и улучшения взаимодействия с аудиторией. Ведь любовь - это то, что объединяет нас всех, и наше приложение поможет пользователям выразить свои чувства и поделиться ими с другими.\n\n**Сайт проекта:** [vk.com](https://vk.com/app4181138)\n\n**Связанные проекты:** [Фотоконкурс Алло](/ru/portfolio/fotokonkurs-allo), [Битва пАЛЛОв](/ru/portfolio/bitva-pollov)","subtitle":"Веб · SMM-приложение","challenge":"Недавно наша команда разработала новое SMM приложение \"Алло. Фотоконкурс влюбленных\", которое позволяет пользователям загружать и делиться своими фотографиями, выражающими любовь. В приложении реализована система голосования, позволяющая пользователям голосовать за понравившиеся фотографии и определять победителей.","description":"Алло: Фотоконкурс влюбленных - новое SMM приложение от Piplos Media","stack_detail":"JavaScript, PHP"}}$row_167$::jsonb)
