VALUES ('aplus', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2013, false, true, 168, '/uploads/projects/aplus/fb4e13243a2b4382906294c1a7b4b069.png', $row_168${"en":{"title":"Aichyna Plus Internet Provider","result":"The project was successfully launched and is available at aplus.by. The work was completed in 2013.","solution":"![Aichyna Plus internet provider — 1](/uploads/projects/aplus/00c69bc04d30410ca0dc35fd800bfd89.png)\n\n![Aichyna Plus internet provider — 2](/uploads/projects/aplus/a0f93be8257b485f88fd23f19a4dd785.png)\n\n![Aichyna Plus internet provider — 3](/uploads/projects/aplus/382a04e7318a454aa03a2fa063b1581a.png)\n\n**Project website:** [aplus.by](http://aplus.by/ru/)","subtitle":"Web · Website","challenge":"Development of a website for the Aichyna Plus internet provider.","description":"Website for the Aichyna Plus internet provider","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Интернет-провайдер Айчына плюс","result":"Проект успешно запущен и доступен по адресу aplus.by. Работы выполнены в 2013 году.","solution":"![Интернет-провайдер Айчына плюс — 1](/uploads/projects/aplus/00c69bc04d30410ca0dc35fd800bfd89.png)\n\n![Интернет-провайдер Айчына плюс — 2](/uploads/projects/aplus/a0f93be8257b485f88fd23f19a4dd785.png)\n\n![Интернет-провайдер Айчына плюс — 3](/uploads/projects/aplus/382a04e7318a454aa03a2fa063b1581a.png)\n\n**Сайт проекта:** [aplus.by](http://aplus.by/ru/)","subtitle":"Веб · Сайт","challenge":"Интернет-провайдер Айчына плюс","description":"Интернет-провайдер Айчына плюс","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_168$::jsonb)
