VALUES ('csat', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2013, false, true, 170, '/uploads/projects/csat/1f84aae011ae4977a443c6b6b1ce18ab.jpeg', $row_170${"en":{"title":"Security Systems Caesar Satellite","result":"The project was successfully launched and is available at www.csat.ru. The work was completed in 2013.","solution":"![Security Systems Caesar Satellite — 1](/uploads/projects/csat/1ed016a244314a4bb8b5acd0b90c5b50-2.png)\n\n![Security Systems Caesar Satellite — 2](/uploads/projects/csat/38d73d1f8d304dd38bd86f4537a59736-2.png)\n\n![Security Systems Caesar Satellite — 3](/uploads/projects/csat/44d23eab091641c89c2d4fac18d71d98-2.png)\n\n**Project website:** [www.csat.ru](https://www.csat.ru/)","subtitle":"Web · Website","challenge":"Development of a corporate site for a leading operator of security systems for cars and real estate.","description":"Leading operator of security systems for cars and real estate","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Системы безопасности «Цезарь Сателлит»","result":"Проект успешно запущен и доступен по адресу www.csat.ru. Работы выполнены в 2013 году.","solution":"![Системы безопасности «Цезарь Сателлит» — 1](/uploads/projects/csat/1ed016a244314a4bb8b5acd0b90c5b50.png)\n\n![Системы безопасности «Цезарь Сателлит» — 2](/uploads/projects/csat/38d73d1f8d304dd38bd86f4537a59736.png)\n\n![Системы безопасности «Цезарь Сателлит» — 3](/uploads/projects/csat/44d23eab091641c89c2d4fac18d71d98.png)\n\n**Сайт проекта:** [www.csat.ru](https://www.csat.ru/)","subtitle":"Веб · Сайт","challenge":"Разработка корпоративного сайта ведущего оператора систем безопасности для автомобилей и недвижимости.","description":"Ведущий оператор систем безопасности для автомобилей и недвижимости","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_170$::jsonb)
