INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('noodlescity', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2013, false, true, 171, '/uploads/projects/noodlescity/038f18cf68c444a0bd72587a5c3ea693.png', $row_171${"en":{"title":"Moscow fast food chain Noodles City","result":"The project was successfully delivered to the client. The work was completed in 2013.","solution":"The Moscow fast food chain Noodles City has set us the task of developing a new website for there chain of stores.\n\n1. The objectives of the site - Sales through the site. Show the prestige and merits of the company.\n2. Target audience - Potential client: youth, office workers, lovers of Asian food, people spending a lot of time outside the home. The age of the main consumer group is 15-50 years. Our guests are active people who follow new trends, who have little time to cook food or eat out, but at the same time they want to eat nutritious food of high quality. The income level is above low, medium, high.\n3. Product / company positioning - Product quality, high service, integrated approach (there will be related areas).\n4. Design - based on corporate identity.\n\n![Moscow fast food chain Noodles City — 1](/uploads/projects/noodlescity/cb1e02ee04c84c12bc15e8ab26b14905-2.png)\n\n![Moscow fast food chain Noodles City — 2](/uploads/projects/noodlescity/1c0d885a4bd741618225a9dafe77c52f-2.png)\n![Moscow fast food chain Noodles City — 3](/uploads/projects/noodlescity/c56d25f7dd5f437194d0ea2c0a5f34cb-2.png)","subtitle":"Web · Website","challenge":"The objectives of the site - Sales through the site. Show the prestige and merits of the company. Target audience - Potential client: youth, office workers, lovers of Asian food, people spending a lot of time outside the home. The age of the main consumer group is 15-50 years. Our guests are active people who follow new trends, who have little time to cook food or eat out, but at the same time they want to eat nutritious food of high quality. The income level is above low, medium, high.","description":"website development Moscow fast food chain Noodles City","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Московская сеть фастфуда Noodles City","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2013 году.","solution":"1. Цели создания сайта - Осуществление продаж через сайт. Показать престиж и достоинства компании. \n2. Целевая аудитория - Потенциальный клиент: молодежь, офисные работники, любители азиатской еды, люди, проводящие много времени вне дома. Возраст основной группы потребителей 15 - 50 лет. Наши гости это активные люди, которые следуют новым трендам, которые имею немного времени на готовку еды или питаются вне дома, но одновременно с этим хотят есть питательную еду и высокого качества. Уровень дохода выше низкого, средний, высокий.\n3. Позиционирование продукта/компании - Качество продукта, высокий сервис, комплексный подход (будут смежные направления).\n4. Дизайн - на основании фирменного стиля.\n\n![Московская сеть фастфуда Noodles City — 1](/uploads/projects/noodlescity/cb1e02ee04c84c12bc15e8ab26b14905.png)\n\n![Московская сеть фастфуда Noodles City — 2](/uploads/projects/noodlescity/1c0d885a4bd741618225a9dafe77c52f.png)\n![Московская сеть фастфуда Noodles City — 3](/uploads/projects/noodlescity/c56d25f7dd5f437194d0ea2c0a5f34cb.png)","subtitle":"Веб · Сайт","challenge":"Московская сеть фастфуда Noodles City поставила перед нами задачу по разработке нового сайта своей сети.","description":"Московская сеть фастфуда Noodles City","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_171$::jsonb)
