INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('pismo-dedu-morozu', 'web', ARRAY['web'], ARRAY['JavaScript', 'PHP'], 2013, false, true, 172, '/uploads/projects/pismo-dedu-morozu/ebd99d44a5b74b038b5a9c22e4dcf88b.jpg', $row_172${"en":{"title":"Letter to Father Frost","result":"The project was successfully launched and is available at vk.com. The work was completed in 2013.","solution":"We also cover the technical aspects of the application, such as its architecture, functionality and integration options with other social media platforms.\n\nIn this case study you will learn how the development of the Letter to Father Frost SMM application helps Piplos Media promote its services and attract new clients.\n\n**Project website:** [vk.com](https://vk.com/app4050040)","subtitle":"Web · SMM app","challenge":"The Letter to Father Frost application was developed by the Piplos Media team to create a festive atmosphere and brighten up the New Year holidays.","description":"Letter to Father Frost: an SMM application for children developed by Piplos Media","stack_detail":"JavaScript, PHP"},"ru":{"title":"Письмо деду Морозу","result":"Проект успешно запущен и доступен по адресу vk.com. Работы выполнены в 2013 году.","solution":"Также мы обсудим технические особенности приложения, такие как его архитектура, функциональность и возможности для интеграции с другими платформами социальных сетей.\n\nВ этой статье вы узнаете о том, как разработка SMM приложения \"Письмо деду Морозу\" помогает компании Piplos Media продвигать свои услуги на рынке и привлекать новых клиентов.\n\n**Сайт проекта:** [vk.com](https://vk.com/app4050040)","subtitle":"Веб · SMM-приложение","challenge":"Приложение \"Письмо деду Морозу\" разработано командой специалистов Piplos Media с целью создания праздничной атмосферы и украшения новогодних праздников.","description":"Письмо деду Морозу: разработка SMM приложения для детей компанией Piplos Media","stack_detail":"JavaScript, PHP"}}$row_172$::jsonb)
