INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('elithouse', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2013, false, true, 174, '/uploads/projects/elithouse/fffb434284b8493090a1b5f0255cdba8.jpeg', $row_174${"en":{"title":"House Reservation System","result":"The project was successfully delivered to the client. The work was completed in 2013.","solution":"This site has been developed with functionality for searching and booking different types of housing.\nThe site took into account two possibilities:\n1. Buy a home\n2. Rent a house\nAll information came to the site through two types of users:\n1. renter\n2. Seller\n\nFor this we developed a personal account for them with a wide range of functions, for the most detailed description of the objects that they publish on this resource.\n\n![Система бронирования жилья Elite House](/uploads/projects/elithouse/45219e7c7645420ab3101c6d0ad6586f-2.png)","subtitle":"Web · Website","challenge":"his project was the debut of our company in the development of projects for the real estate market.","description":"Elite House Reservation System","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Система бронирования жилья Elite House","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2013 году.","solution":"Данный сайт, был разработан с функционалом поиска и бронирования жилья разного типа.\nВ том числе мы учитывали возможность как покупки, так и аренды.\n\nВся информация попадала на сайт через пользователей двух типов:\n1. Арендатор\n2. Продавец\n\nДля этого мы разработали для них личный кабинет с широким набором функций, для максимально подробного описания тех объектов которые они публикуют на данном ресурсе.\n\n![Система бронирования жилья Elite House](/uploads/projects/elithouse/45219e7c7645420ab3101c6d0ad6586f.png)","subtitle":"Веб · Сайт","challenge":"Данный проект был дебютом нашей компании на рынке разработке проектов для рынка недвижимости.","description":"Система бронирования жилья Elite House","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_174$::jsonb)
