INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('rasti', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2013, false, true, 175, '/uploads/projects/rasti/artboard-copy-75.png', $row_175${"en":{"title":"Business School Grow","result":"The project was successfully launched and is available at rasti.by. The work was completed in 2013.","solution":"![Business School Grow — 1](/uploads/projects/rasti/61bda889e3aa460eb75ef3173d8c4f39-2.png)\n\n**Project website:** [rasti.by](https://rasti.by)","subtitle":"Web · Website","challenge":"Development of an original corporate site for the Rusty Business School.","description":"Development of an original corporate site for the Rusty Business School","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Бизнес-школа Расти","result":"Проект успешно запущен и доступен по адресу rasti.by. Работы выполнены в 2013 году.","solution":"Главное меню веб-сайта служит определенным навигатором по направлениям компании, что облегчает поиск необходимого раздела.\n\nДизайн сайта в меру сдержанный и оригинальный, что позволяет получать эстетическое удовольствие при посещении.\n\nПри разработке сайта, профессионалы Piplos Media использовали систему Framework Codeigniter, что в несколько раз сократило время создания ресурса. \nБлагодаря грамотной концепции, ресурс полностью выполняет свою основную функцию, являясь эффективным инструментом бизнеса.\n\n![Бизнес-школа Расти — 1](/uploads/projects/rasti/61bda889e3aa460eb75ef3173d8c4f39.png)\n\n**Сайт проекта:** [rasti.by](https://rasti.by)","subtitle":"Веб · Сайт","challenge":"Цель проекта - Разработать оригинальный корпоративный сайт для бизнес-школы «Расти», который сможет объединить все существующие проекты компании в единую систему, а также предоставить посетителю всю необходимую информацию о школе.","description":"Разработка оригинального корпоративного сайта для бизнес-школы «Расти».","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_175$::jsonb)
