INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('farmina-promo', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2013, false, true, 176, '/uploads/projects/farmina-promo/c577d72ada2841199f8dba06eccc1684.jpg', $row_176${"en":{"title":"Farmina Pet Foods","result":"The project was successfully launched and is available at farminapetfoods.by. The work was completed in 2013.","solution":"As part of the launch of the new Farmina Pet Foods [online store](/en/portfolio/farmina-shop), we developed a company landing page presenting the full product range.\n\nThe project was timed to a pet food exhibition, so the deadline was extremely tight.\n\nNevertheless, we launched the project on time, increasing the flow of new potential customers for the client.\n\n![Farmina pet foods](/uploads/projects/farmina-promo/698c1c9d71824d8bb0c7bc8e2edfbcb3.png)\n\nAlongside building buzz for the exhibition, the project promotes the company online — in particular the [online store](/en/portfolio/farmina-shop).\n\n![Farmina pet foods — 2](/uploads/projects/farmina-promo/79d9a26e423248718d4331f1b8979e96.png)\n\nThe landing page provides users with complete information about the food types and products.\n\n![Farmina pet foods — 3](/uploads/projects/farmina-promo/6526951d8be14d1a9e1b5cf9accefeaa.png)\n\nThe standout feature of the project is its parallax effect.\n\n![Farmina pet foods — 4](/uploads/projects/farmina-promo/95ccfad619ea4ac9bd7b250b1971a6ac.png)\n\n**Project website:** [farminapetfoods.by](http://farminapetfoods.by)","subtitle":"Web · Landing page","challenge":"Alongside building buzz for the trade exhibition, the project aimed to promote the company online — in particular its online store.","description":"Landing page for the official distributor of Farmina Pet Foods","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Корма от Farmina","result":"Проект успешно запущен и доступен по адресу farminapetfoods.by. Работы выполнены в 2013 году.","solution":"В рамках Запуска нового [Интернет Магазина](/ru/portfolio/farmina-shop) «Farmina Pet Foods», был разработан лендинг компании на котором размещается вся основная продукция компании.\n\nДанный проект был приурочен выставке кормов, поэтому сроки на реализацию его были очень короткие.\n\nТем не менее за данный период времени нам удалось запустить этот проект,тем самым увеличить входящую возможность новых потенциальных клиентов Заказчика.\n\n![Корма от Farmina](/uploads/projects/farmina-promo/698c1c9d71824d8bb0c7bc8e2edfbcb3.png)\n\nПо мимо задачи информационного шума к выставке, данный проект нацелен на продвижение компании в сети интернет, в частности [Интернет Магазина](/ru/portfolio/farmina-shop).\n\n![Корма от Farmina — 2](/uploads/projects/farmina-promo/79d9a26e423248718d4331f1b8979e96.png)\n\nДанный лендинг предоставляет полноценную информацию о типах кормов и самих кормов для пользователей.\n\n![Корма от Farmina — 3](/uploads/projects/farmina-promo/6526951d8be14d1a9e1b5cf9accefeaa.png)\n\nОсновной фишкой данного проекта стал эффект параллакса.\n\n![Корма от Farmina — 4](/uploads/projects/farmina-promo/95ccfad619ea4ac9bd7b250b1971a6ac.png)\n\n**Сайт проекта:** [farminapetfoods.by](http://farminapetfoods.by)","subtitle":"Веб · Лендинг","challenge":"По мимо задачи информационного шума к выставке, данный проект нацелен на продвижение компании в сети интернет, в частности Интернет Магазина.","description":"Лендинг для Официального дистрибьютора «Farmina Pet Foods»","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_176$::jsonb)
