INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('corado', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 178, '/uploads/projects/corado/5a0093d84fa14bcd947a79f6fbbd134b.png', $row_178${"en":{"title":"Corrado Furniture Manufacturers","result":"As a result, we delivered a bold design with strong usability and a convenient interface that helps users quickly find the information they need.","solution":"To reach a wider audience and strengthen the company's image, the client decided to develop a corporate website.\n\nWe set out to build a unique catalogue website providing detailed information about the company and highlighting the products it sells.\n\n![Corrado furniture manufacturers](/uploads/projects/corado/a059f1e3b0fe4430a77f4108a5e3154d.png)","subtitle":"Web · Website","challenge":"Our goal was to build a unique catalogue website providing detailed information about the company and highlighting the products it sells.","description":"Website for the Corrado furniture manufacturer","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Производители мебели Коррадо","result":"Как итог, мы получили не только смелое решение в плане дизайна и юзабилити, но и удобный интерфейс поиска нужной информации для пользователя.","solution":"Заказчик для повышения целевой аудитории, а также повышения имиджа своей компании, решил разработать сайт своего предприятия.\n\nМы поставили перед собой задачу реализации уникального сайта каталога, с предоставлением подробной информации о самой компании, в том силе, выделением самой продукции, которую продает данная компания.\n\n![Производители мебели Коррадо](/uploads/projects/corado/a059f1e3b0fe4430a77f4108a5e3154d.png)","subtitle":"Веб · Сайт","challenge":"Мы поставили перед собой задачу реализации уникального сайта каталога, с предоставлением подробной информации о самой компании, в том силе, выделением самой продукции, которую продает данная компания.","description":"Производители мебели Коррадо","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_178$::jsonb)
