INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('modnikov', 'web', ARRAY['web', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 179, '/uploads/projects/modnikov/43bc492e46544e56aab215f19748c062.png', $row_179${"en":{"title":"Online Shop Modnikov","result":"The project was successfully launched and is available at modnikov.com. The work was completed in 2012.","solution":"The main requirements of the Customer for the project:\n- Moderation of users\n- Simple management of the product group through the administration system\n- Notification of applications for goods from the site\n- Personal account of the user with a list of his orders\n- Order form with validation\n- Advanced administration of text sections..\n\n![Online Shop Modnikov — 1](/uploads/projects/modnikov/6a0e27158fb84558a8f1ab1e89281f56-2.png)\n\nAll requirements of the Order were taken into account when developing this project.\n\n**Project website:** [modnikov.com](https://modnikov.com)","subtitle":"Web · E-commerce","challenge":"We would develop an Internet Shop for the largest specialized supplier of automobile calipers, starters and alternators, as well as all components for their repair, in the largest Belarus Republic.","description":"Online Shop of car calipers, starters and alternators, as well as all components for their repair","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Интернет Магазин Modnikov","result":"Проект успешно запущен и доступен по адресу modnikov.com. Работы выполнены в 2012 году.","solution":"Основные требования Заказчика к проекту:\n- Модерация пользователей \n- Простое управление товарной группой через систему администрирования \n- Уведомления заявок на товары с сайта \n- Личный кабинет пользователя с списком его заказов\n- Форма заказа с валидацией \n- Расширенные возможности администрирования текстовых разделов.\n\n![Интернет Магазин Modnikov — 1](/uploads/projects/modnikov/6a0e27158fb84558a8f1ab1e89281f56.png)\n\nВсе требования Заказчка были учтены пр разработке данного проекта.\n\n**Сайт проекта:** [modnikov.com](https://modnikov.com)","subtitle":"Веб · E-commerce","challenge":"Нами бы разработан Интернет Магазин для крупнейшего в Республике Беларусь специализированный поставщика автомобильных суппортов, стартеров и генераторов, а также всех комплектующих для их ремонта.","description":"Интернет Магазин автомобильных суппортов, стартеров и генераторов, а также всех комплектующих для их ремонта","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_179$::jsonb)
