INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('kalilaska', 'backend', ARRAY['backend', 'saas'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2012, false, true, 180, '/uploads/projects/kalilaska/62f6063447404b6891032b1c030da825.png', $row_180${"en":{"title":"Tourist web portal","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"The concept included the entire set of functionality for such projects.\n\nWe also took into account the corporate style of the company, for maximum similarity with the site itself\n\n![Туристический портал Калиласка Беларусь](/uploads/projects/kalilaska/23911ca67a5646bcbf253f21325b4ff2-2.png)","subtitle":"Backend · SaaS","challenge":"As part of the tender proposal, we have developed a concept idea of ​​the official tourist portal of the Republic of Belarus “Kalilaska”.","description":"Travel portal Kali Laska Belarus","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Туристический портал Кали ласка Беларусь","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Концепция включала весь набор функционала для такого рода проектов.\n\nТак же мы учитывали корпоративный стиль компании, для максимальной схожести с самим сайтом\n\n![Туристический портал Калиласка Беларусь](/uploads/projects/kalilaska/23911ca67a5646bcbf253f21325b4ff2.png)","subtitle":"Бэкенд · SaaS","challenge":"В рамках конкурсного предложения нами была разработан концепт-идея официального туристического портала Республики Беларусь «КалиЛаска».","description":"Туристический портал Калиласка Беларусь","stack_detail":"UI/UX, Figma, Photoshop"}}$row_180$::jsonb)
