INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('shootmemore', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 182, '/uploads/projects/shootmemore/5f08de88e5474cd4be3614297dcbe28c.png', $row_182${"en":{"title":"Virtual Fashion Magazine ShootMeMore","result":"The project was successfully launched and is available at shootmemore.com. The work was completed in 2012.","solution":"We came up with and developed a convenient structure for this resource for quick user access to various materials related to High Fashion.\nWarm colors, a pleasant font, all this only complemented and attracted the user's attention to the content of this project.\n\n![Виртуальный журнал о моде ShootMeMore](/uploads/projects/shootmemore/24d4c5c6c95b4e0d8c9dfd36dabdd8ee-2.png)\n\n**Project website:** [shootmemore.com](https://shootmemore.com)","subtitle":"Web · Website","challenge":"Another project dedicated to High Fashion, as well as online magazines.","description":"Virtual Fashion Magazine ShootMeMore","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Виртуальный журнал о моде ShootMeMore","result":"Проект успешно запущен и доступен по адресу shootmemore.com. Работы выполнены в 2012 году.","solution":"Нами была продумана и реализована удобная навигация по данному ресурсу для быстрого доступа пользователя к различным материалам касающиеся Высокой моды.\n\nТеплые тона, приятный шрифт, все это только дополняло и привлекало внимание пользователя к контенту данного проекта.\n\n![Виртуальный журнал о моде ShootMeMore](/uploads/projects/shootmemore/24d4c5c6c95b4e0d8c9dfd36dabdd8ee.png)\n\n**Сайт проекта:** [shootmemore.com](https://shootmemore.com)","subtitle":"Веб · Сайт","challenge":"Очередной проект посвященный Высокой моде, а также интернет журналам.","description":"Виртуальный журнал о моде ShootMeMore","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_182$::jsonb)
