INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('orgpromstroy-concept', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2012, false, true, 183, '/uploads/projects/orgpromstroy-concept/group-56.png', $row_183${"en":{"title":"The concept idea of ​​Orgpromstroy","result":"The project was successfully launched and is available at orgpromstroy.by. The work was completed in 2012.","solution":"This concept idea remained unclaimed, but nevertheless laid the foundation for close cooperation between our companies.\n\n![The concept idea of ​​Orgpromstroy — 1](/uploads/projects/orgpromstroy-concept/f107765c31a44ef4a1a5b6c207139ae5-2.png)\n\n![The concept idea of ​​Orgpromstroy — 2](/uploads/projects/orgpromstroy-concept/a6ca7277802747bdae36d71f68cf7bab-2.png)\n\n**Project website:** [orgpromstroy.by](https://orgpromstroy.by)","subtitle":"Web · Website","challenge":"As part of the development of the Commercial Offer, our company has prepared a concept for the idea of displaying the Main page of the corporate website of Orgpromstroy.","description":"Development of the concept idea of ​​the corporate website of Orgpromstroy","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"Концепт-идея Оргпромстрой","result":"Проект успешно запущен и доступен по адресу orgpromstroy.by. Работы выполнены в 2012 году.","solution":"Данная концепт-идея осталась невостребована, но тем не менее положила начало тесного сотрудничества между нашими компаниями.\n\n![Концепт-идея Оргпромстрой — 1](/uploads/projects/orgpromstroy-concept/f107765c31a44ef4a1a5b6c207139ae5.png)\n\n![Концепт-идея Оргпромстрой — 2](/uploads/projects/orgpromstroy-concept/a6ca7277802747bdae36d71f68cf7bab.png)\n\n**Сайт проекта:** [orgpromstroy.by](https://orgpromstroy.by)","subtitle":"Веб · Сайт","challenge":"В рамках разработки Коммерческого Предложения, нашей компанией была подготовлена концепт идея отображения Главной страницы корпоративного сайта Оргпромстрой.","description":"Разработка концепт-идеи корпоративного сайта Оргпромстроя","stack_detail":"UI/UX, Figma, Photoshop"}}$row_183$::jsonb)
