VALUES ('souser', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 186, '/uploads/projects/souser/a6246615021d4e5f9c01d705fe958e0d.jpg', $row_186${"en":{"title":"SoUser Social Network","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"Social network of the Union State.\n![SoUser social network](/uploads/projects/souser/cca22ee83c244f52868a2eb69fa34199.png)","subtitle":"Web · Website","challenge":"Development of a social network for the Union State.","description":"Social network of the Union State","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Социальная сеть СоЮзер","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Социальная сеть союзного государства\n![Социальная сеть СоЮзер](/uploads/projects/souser/cca22ee83c244f52868a2eb69fa34199.png)","subtitle":"Веб · Сайт","challenge":"Социальная сеть союзного государства","description":"Социальная сеть союзного государства","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_186$::jsonb)
