INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('qcs', 'web', ARRAY['web'], ARRAY['JavaScript', 'HTML/CSS', 'PHP'], 2012, false, true, 187, '/uploads/projects/qcs/a5e294256cc64c40acce51509bb0cecf.png', $row_187${"en":{"title":"Car Body Repair and Painting","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"The website lets users submit enquiries through a contact form, with email notifications delivered to the company.\n\nThe design was based on a prototype provided by the client.\n\n![Car body repair and painting — 1](/uploads/projects/qcs/56c45816bdba4376823619878cbd1f52.png)","subtitle":"Web · Landing page","challenge":"We were tasked with developing a one-page website for a company specialising in car body repair and painting. The project aimed to promote the company's services online.","description":"Landing page development for a car body repair and painting service","stack_detail":"JavaScript, HTML/CSS, PHP"},"ru":{"title":"Ремонту и покраска кузова авто","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Сайт должен позволять пользователям оставлять заявки через форму обратной связи, оповещения о которых должно приходить на электронную почту компании.\n\nРазработка дизайна сайта велась на основании прототипа предоставленного для нас Заказчиком.\n\n![Ремонту и покраска кузова авто — 1](/uploads/projects/qcs/56c45816bdba4376823619878cbd1f52.png)","subtitle":"Веб · Лендинг","challenge":"Перед нами поставили задачу разработать одностраничный сайт для компании занимающейся ремонтом и покраской автомобилей. Данный проект был нацелен на продвижение услуг компании в сети интернет.","description":"Разработка Лендинг страницы для автосервиса по ремонту и покраске кузова авто","stack_detail":"JavaScript, HTML/CSS, PHP"}}$row_187$::jsonb)
