INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('ojoobo', 'web', ARRAY['web', 'saas'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 188, '/uploads/projects/ojoobo/9e3a711feafe4779a3f174f884cd30d5.jpg', $row_188${"en":{"title":"Ojoobo Fashion News Portal","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"![Ojoobo fashion news portal](/uploads/projects/ojoobo/a5a0110c5c5d4f619076ebf996cb17e8-2.png)","subtitle":"Web · SaaS","challenge":"We were tasked with creating an online magazine dedicated to Fashion. We have developed a unique corporate style for this online magazine. The functional component was classic for such projects. Articles and news are made into categories with the ability to view and share on social networks.","description":"Ojoobo Fashion News Portal","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Новостной портал о моде Ojoobo","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"![Новостной портал о моде Ojoobo](/uploads/projects/ojoobo/a5a0110c5c5d4f619076ebf996cb17e8.png)","subtitle":"Веб · SaaS","challenge":"Перед нами поставили задачу по созданию интернет журнала посвященный Моде. Нами был разработан уникальный корпоративный стиль данного интернет журнала. Функциональная составляющая была классическая для такого рода проектов. Статьи и новости делаться на категории с возможностью просмотра и шаринга в социальных сетях.","description":"Новостной портал о моде Ojoobo","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_188$::jsonb)
