INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('ulmus', 'web', ARRAY['web', 'ecommerce'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 190, '/uploads/projects/ulmus/f9d1888b372c4849a12ea0857cd18fcd.png', $row_190${"en":{"title":"Architectural workshop Ulmus","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"The main message is to focus on the portfolio of this workshop. For the user to pay attention to the projects from the first page.\n\n![Архитектурная мастерская Ульмус](/uploads/projects/ulmus/6e2e9c8d0cdc441c9855860d55edba22-2.png)\n\nAnd also provide the opportunity to order workshop services through the site.\n\n![Architectural workshop Ulmus — 2](/uploads/projects/ulmus/0fdf28a543e04928b5153ab7871586c5-2.png)\n\nWe tried to create a modern design that is ahead of its time. To give maximum attention to visualization, as well as various elements of site navigation.\n\n![Architectural workshop Ulmus — 3](/uploads/projects/ulmus/8291c7e98d904fec9f0b829eb3fc65d3-2.png)","subtitle":"Web · E-commerce","challenge":"The purpose of this development is the site of the Architectural Studio, with a complete list of all implemented projects of the company.","description":"Website development Architectural workshop Ulmus","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Архитектурная мастерская Ульмус","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Основной посыл - сделать акцент на портфолио данной мастерской. Чтобы пользователь обратил с первой страницы внимание на проекты.\n\n![Архитектурная мастерская Ульмус](/uploads/projects/ulmus/6e2e9c8d0cdc441c9855860d55edba22.png)\n\nА также предусмотреть возможность заказать услуги мастерской через сайт.\n\n![Архитектурная мастерская Ульмус — 2](/uploads/projects/ulmus/0fdf28a543e04928b5153ab7871586c5.png)\n\nМы постарались сделать современный дизайн, который опережает свое время. Придать максимальное внимание визуализации, а также различным элементам навигации по сайту.\n\n![Архитектурная мастерская Ульмус — 3](/uploads/projects/ulmus/8291c7e98d904fec9f0b829eb3fc65d3.png)","subtitle":"Веб · E-commerce","challenge":"Цель данной разработки - сайт Архитектурной мастерской, с полным перечнем всех реализованных проектов компании.","description":"Создание сайта Архитектурной мастерская Ульмус","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_190$::jsonb)
