INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('sugarmotel', 'mobile', ARRAY['mobile', 'saas'], ARRAY['Swift', 'iOS'], 2012, false, true, 192, '/uploads/projects/sugarmotel/0c086678dc8d4a5f85373647f98bd2cd.jpg', $row_192${"en":{"title":"Sugar Motel Blog App","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"Our Pilos Media team develops various mobile apps, and we're proud to present our latest achievement, the Sugar Motel mobile blog app for the iOS platform.\n\nSugar Motel is a blog dedicated to life in the city and everything that goes with it: fashion, beauty, food, travel and more. Our goal was to create a mobile app that would allow users to easily and quickly access the blog's content, as well as comment and share it with their friends.\n\nWe started the project with a thorough analysis of user needs and the design of the app's interface. We made sure that the app design was simple and intuitive, so that users could find the information they needed quickly and easily. We also designed a user-friendly commenting system and the ability to share content via social media.\n\nTechnically, the app was developed using the Swift language and various iOS SDK tools, allowing us to create a stable and responsive app. Our team has also thoroughly tested the app to make sure it is reliable and secure.\n\nWe are proud of the result of our work - Sugar Motel's mobile blog app for iOS which provides easy and quick access to blog content and allows users to comment and share it with their friends. We thank our team for their hard work and diligence and our client for their trust.","subtitle":"Mobile · SaaS","challenge":"Sugar Motel is a blog dedicated to life in the city and everything that goes with it: fashion, beauty, food, travel and more. Our goal was to create a mobile app that would allow users to easily and quickly access the blog's content, as well as comment and share it with their friends.","description":"Pilos Media team: developing the Sugar Motel blog mobile app for iOS platform","stack_detail":"Swift, iOS"},"ru":{"title":"Приложение для блога Sugar Motel","result":"Мы гордимся результатом нашей работы - мобильным приложением блога Sugar Motel для платформы iOS, которое обеспечивает удобный и быстрый доступ к контенту блога и позволяет пользователям комментировать и делиться им со своими друзьями. Мы благодарим нашу команду за труд и усердие и нашего клиента за доверие.","solution":"Наша команда Pilos Media занимается разработкой различных мобильных приложений, и мы с гордостью представляем наше последнее достижение - мобильное приложение блога Sugar Motel для платформы iOS.\n\nSugar Motel - это блог, посвященный жизни в городе и всему, что с ней связано: моде, красоте, еде, путешествиях и многому другому. Наша задача заключалась в том, чтобы создать мобильное приложение, которое позволит пользователям удобно и быстро получать доступ к контенту блога, а также комментировать и делиться им со своими друзьями.\n\nМы начали работу над проектом с тщательного анализа потребностей пользователей и дизайна интерфейса приложения. Мы убедились, что дизайн приложения прост и интуитивно понятен, чтобы пользователи могли быстро и легко находить нужную информацию. Мы также разработали удобную систему комментариев и возможность делиться контентом через социальные сети.\n\nТехнически приложение было разработано с использованием языка Swift и различных инструментов iOS SDK, что позволило нам создать стабильное и быстро работающее приложение. Наша команда также провела тщательное тестирование приложения, чтобы убедиться в его надежности и безопасности.","subtitle":"Мобильное · SaaS","challenge":"Sugar Motel - это блог, посвященный жизни в городе и всему, что с ней связано: моде, красоте, еде, путешествиях и многому другому. Наша задача заключалась в том, чтобы создать мобильное приложение, которое позволит пользователям удобно и быстро получать доступ к контенту блога, а также комментировать и делиться им со своими друзьями.","description":"Команда Pilos Media: разработка мобильного приложения блога Sugar Motel для платформы iOS","stack_detail":"Swift, iOS"}}$row_192$::jsonb)
