INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('metallobaza', 'web', ARRAY['web'], ARRAY['Bitrix', '1C'], 2012, false, true, 193, '/uploads/projects/metallobaza/artboard-copy-21.png', $row_193${"en":{"title":"Almier Metal Base","result":"The project was successfully launched and is available at metallobaza.by. The work was completed in 2012.","solution":"![Almier Metal Base — 1](/uploads/projects/metallobaza/4e84e6b618074f718576d91070977e98-2.png)\n\nThe site contains a special metal rolling calculator, which simplifies the choice of a particular service and pushes the client to the main action - the purchase.\n\n![Almier Metal Base — 2](/uploads/projects/metallobaza/7ac1ce4fa38f4ec4b370af8839513fcf-2.png)\n\nThe site was developed on the CMS 1С-Bitrix , which subsequently ensured high reliability, security, as well as stable updating of the web resource.\n\n**Project website:** [metallobaza.by](https://metallobaza.by)\n\n**Related projects:** [Almier-Metallobaza](/en/portfolio/metallobaza-concept-idea)","subtitle":"Web · Website","challenge":"The main tasks in the development of sites were set on the convenience of finding company services. To do this, we designed the site menu, which helps the visitor quickly navigate and find the necessary information.","description":"Website for the leader of the Belarusian metal marketа","stack_detail":"Bitrix, 1C"},"ru":{"title":"Алмиер-Металлобаза","result":"Проект успешно запущен и доступен по адресу metallobaza.by. Работы выполнены в 2012 году.","solution":"![Алмиер-Металлобаза — 1](/uploads/projects/metallobaza/4e84e6b618074f718576d91070977e98.png)\n\nСайт содержит специальный калькулятор металлопроката, что в разы упрощает выбор конкретной услуги и &laquo;подталкивает&raquo; клиента к главному действию - покупке.\n\n![Алмиер-Металлобаза — 2](/uploads/projects/metallobaza/7ac1ce4fa38f4ec4b370af8839513fcf.png)\n\nРазработка сайта велась на системе CMS-Битрикс, что впоследствии обеспечило высокую надежность, безопасность, а также стабильное обновление веб-ресурса.\n\n**Сайт проекта:** [metallobaza.by](https://metallobaza.by)\n\n**Связанные проекты:** [Алмиер-Металлобаза (концепт)](/ru/portfolio/metallobaza-concept-idea)","subtitle":"Веб · Сайт","challenge":"Основные акценты при разработке сайты были поставлены на удобстве поиска услуг компании. Это было достигнуто при помощи грамотно спроектированном меню веб-ресурса, которое помогает посетителю быстро сориентироваться и найти необходимую информацию.","description":"Сайт для лидера белорусского рынка металлопроката","stack_detail":"Bitrix, 1C"}}$row_193$::jsonb)
