INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('dom', 'mobile', ARRAY['mobile', 'saas'], ARRAY['iOS'], 2012, false, true, 194, '/uploads/projects/dom/92649078867a467f9123f457ccf84535.png', $row_194${"en":{"title":"App dom.by","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"If you are engaged in repair or construction, you probably know about the site dom.by.\n![Приложение дом.by](/uploads/projects/dom/2b1904dd592447bf83a7a7a7b9bedd16-2.png)\n\nWe have developed an application that allows you to have in your pocket all the relevant information from this service.\nYou can always quickly find the nearest construction store, a company that installs doors or windows, a ceramic tile store, etc.\n![App dom.by — 2](/uploads/projects/dom/64f4c402c0a846228b6128f83b416114-2.png)\n![App dom.by — 3](/uploads/projects/dom/153ce5d76489491994f2cd7f3ce19199-2.png)","subtitle":"Mobile · SaaS","challenge":"If you are engaged in repair or construction, you probably know about the site dom.by.","description":"Mobile app written for the iOS for the building portal dom.by","stack_detail":"iOS"},"ru":{"title":"Приложение дом.by","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Если Вы занимаетесь ремонтом или строительством, Вы наверняка знаете про сайт dom.by.\n![Приложение дом.by](/uploads/projects/dom/2b1904dd592447bf83a7a7a7b9bedd16.png)\n\nМы разработали приложение, которое позволяет иметь у себя в кармане всю актуальную информацию с данного сервиса.\nВы всегда оперативно сможете найти ближайший строительный магазин, компанию которая устанавливает двери или окна, магазин керамической плитки и т.д.\n![Приложение дом.by — 2](/uploads/projects/dom/64f4c402c0a846228b6128f83b416114.png)\n![Приложение дом.by — 3](/uploads/projects/dom/153ce5d76489491994f2cd7f3ce19199.png)","subtitle":"Мобильное · SaaS","challenge":"Если Вы занимаетесь ремонтом или строительством, Вы наверняка знаете про сайт dom.by.","description":"Мобильное приложение написанное для iPhone для строительного портала дом.by","stack_detail":"iOS"}}$row_194$::jsonb)
