INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('souz-agro', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 195, '/uploads/projects/souz-agro/b9d7555d51c64aee9eedf9d9f780647f.png', $row_195${"en":{"title":"UnionSpecStal","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"Here's how they formed the task before us:\n\nWe will assume that this is a completely new site. We want to make it in the form of a kind of block, self-promotion and advertising of our ideas and products. Within the framework of our agricultural project, we have gained certain experience and knowledge that can help other agricultural enterprises to get to effective work in the shortest possible time and\nwhich we want to share in the form of articles, photos and videos and accordingly put it on our website. And also offer specific things on\nequipment and technologies, including second-hand, our services with equipment and consulting in the field of agricultural production, as well as construction in the field of agricultural. With the right advertising in specialized print media and using other opportunities and technologies to promote this site, we want to turn it into a kind of bestseller. Because all the things we offer are simple and clear and allow you to quickly get a significant result. As well as the ability to put all our agricultural equipment up for sale, will allow us to create the largest trading portal in the Republic of Belarus from scratch.\n![UnionSpecStal — 1](/uploads/projects/souz-agro/65dfcc2b1cfd44f6b8eaf59b31665dce-2.png)\n![UnionSpecStal — 2](/uploads/projects/souz-agro/b08e77a26234415a946a0a6273ba06af-2.png)","subtitle":"Web · Website","challenge":"We were contacted by a company working with agricultural machinery LLC SoyuzSpetsStal. For their branch \"Soyuz-agro\", it is necessary to develop a new site.","description":"Development of the corporate site of the Soyuz-agro branch","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"СоюзСпецСталь","result":"Будем считать, что это абсолютно новый сайт. Мы хотим его сделать в виде своеобразного блока, саморекламы и рекламы наших идей и продуктов. В рамках нашего сельхоз проекта нами наработан определенный опыт и знания, которые могут помочь другим с/х предприятиям в кратчайшие сроки выйти на эффективную работу и которыми мы хотим поделиться в виде статей, фотографий и видеороликов и соответственно это выложить на наш сайт.","solution":"Вот как они сформировали задачу перед нами:\n\nБудем считать, что это абсолютно новый сайт. Мы хотим его сделать в виде своеобразного блока, саморекламы и рекламы наших идей и продуктов. В рамках нашего сельхоз проекта нами наработан определенный опыт и знания, которые могут помочь другим с/х предприятиям в кратчайшие сроки выйти на эффективную работу и\nкоторыми мы хотим поделиться в виде статей, фотографий и видеороликов и соответственно это выложить на наш сайт. А также предложить конкретные вещи по\nтехнике и технологиям, в том числе и б/у, наши услуги техникой и консалтинг в области с/х производства, а также и строительства в области с/х. При правильной рекламе в специализированных печатных изданиях и применяя другие возможности и технологии по продвижению данного сайта, хотим превратить его в своеобразный бестселлер. Т.к. все вещи, предлагаемые нами просты и понятны и позволяют быстро получить существенный результат. А также возможность выставить всю свою с/х технику на продажу, позволит нам с нуля создать крупнейший торговый портал в РБ.\n![СоюзСпецСталь — 1](/uploads/projects/souz-agro/65dfcc2b1cfd44f6b8eaf59b31665dce.png)\n![СоюзСпецСталь — 2](/uploads/projects/souz-agro/b08e77a26234415a946a0a6273ba06af.png)","subtitle":"Веб · Сайт","challenge":"К нам обратилась компания рабтающую с сельхоз техникой ООО «СоюзСпецСталь» . Для их филиала «Союз-агро», необходимо разработать новый сайт.","description":"Разработка корпоративного сайта филиала «Союз-агро»","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_195$::jsonb)
