INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('zhemchug', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 196, '/uploads/projects/zhemchug/artboard-copy-11.png', $row_196${"en":{"title":"Karaoke Club","result":"The project was successfully launched and is available at zhemchug.by. The work was completed in 2012.","solution":"This site publishes all the events that take place or took place in the institution.\n\nThe site is designed in the style of the interior of the institution.\n\n![Караоке-клуб Жемчуг](/uploads/projects/zhemchug/5119b20287c04cc0842776fe85046fc5-2.png)\n\n![Karaoke Club — 2](/uploads/projects/zhemchug/c6bd86aa19a94f1e8c3b34763db75550-2.png)\n\n**Project website:** [zhemchug.by](https://zhemchug.by)","subtitle":"Web · Website","challenge":"We have developed a project for karaoke and restaurant Pearls.","description":"Karaoke Club Pearl","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Караоке-клуб Жемчуг","result":"Проект успешно запущен и доступен по адресу zhemchug.by. Работы выполнены в 2012 году.","solution":"На данном сайте публикуются все мероприятия которые проходят или проходили в заведении.\n\nСайт разработан в стили интерьера самого заведения.\n\n![Караоке-клуб Жемчуг](/uploads/projects/zhemchug/5119b20287c04cc0842776fe85046fc5.png)\n\n![Караоке-клуб Жемчуг — 2](/uploads/projects/zhemchug/c6bd86aa19a94f1e8c3b34763db75550.png)\n\n**Сайт проекта:** [zhemchug.by](https://zhemchug.by)","subtitle":"Веб · Сайт","challenge":"Нами был разработан проект для караоке и ресторана Жемчуг.","description":"Караоке-клуб Жемчуг","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_196$::jsonb)
