INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('alniko', 'web', ARRAY['web', 'fintech'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 200, '/uploads/projects/alniko/d2d3bb5f265446ceb2190b35321497d7.jpg', $row_200${"en":{"title":"Alniko Payment Terminals","result":"The project was successfully launched and is available at alniko.ru. The work was completed in 2012.","solution":"![Alniko payment terminals](/uploads/projects/alniko/4f9fe24d376e433ba37c3b108f8ccd14.png)\n\nWe built a system that organises the product range into categories and subcategories.\n\n![Alniko payment terminals — 2](/uploads/projects/alniko/41ef0074c6764558aafb5f450ceed969.png)\n\nEach product card includes a detailed description and specifications of the equipment.\n\n![Alniko payment terminals — 3](/uploads/projects/alniko/b18d1f773e214625a4a07ffaa02a9584.png)\n\n**Project website:** [alniko.ru](https://alniko.ru/)","subtitle":"Web · Fintech","challenge":"Development of a catalogue website presenting a manufacturer of self-service kiosks and the equipment the company produces.","description":"Website for the Alniko payment terminal manufacturer","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Платежные терминалы Алнико","result":"Проект успешно запущен и доступен по адресу alniko.ru. Работы выполнены в 2012 году.","solution":"![Платежные терминалы Алнико](/uploads/projects/alniko/4f9fe24d376e433ba37c3b108f8ccd14.png)\n\nРазработана система позволяющая разграничивать товарную группу на категории и под категории.\n\n![Платежные терминалы Алнико — 2](/uploads/projects/alniko/41ef0074c6764558aafb5f450ceed969.png)\n\nКарточка товара включает в себя подробное описание и характеристики каждого оборудования.\n\n![Платежные терминалы Алнико — 3](/uploads/projects/alniko/b18d1f773e214625a4a07ffaa02a9584.png)\n\n**Сайт проекта:** [alniko.ru](https://alniko.ru/)","subtitle":"Веб · Финтех","challenge":"Разработка сайта каталога для преподнесения информации о производителей киосков самообслуживания и оборудования которое данная компания производит.","description":"Платежные терминалы Алнико","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_200$::jsonb)
