VALUES ('shokozamok', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 204, '/uploads/projects/shokozamok/d8783ba2d15148c8956be956f3b2301c.png', $row_204${"en":{"title":"Impresso Chocolate Castle","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"We built the Chocolate Castle promotional website for the Impresso brand, presenting the product line in a playful visual style.","subtitle":"Web · Website","challenge":"Development of the Chocolate Castle promotional website for the Impresso brand.","description":"Chocolate Castle promo website for the Impresso brand","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Шоколадный замок \"Impresso\"","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Шоколадный замок \"Impresso\"","subtitle":"Веб · Сайт","challenge":"Шоколадный замок \"Impresso\"","description":"Шоколадный замок \"Impresso\"","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_204$::jsonb)
