INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('25-let-belita', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 205, '/uploads/projects/25-let-belita/artboard-copy-87.png', $row_205${"en":{"title":"25th of Belita","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"A promo site is a project where a user can watch a video with compliments in Italian and give his answer + share a promo site on social networks and participate in a competition when buying products.\n\n![25th of Belita — 1](/uploads/projects/25-let-belita/2eda4c5245194a8e832f9aeb0781d2a3-2.png)\n\nAfter clicking on the “get a compliment” button, a video opens.\n\nNext, you can view the following videos by clicking \"see all videos\", after which a plate with 4 videos opens. You can hide it, or you can view any video.\n\n![25th of Belita — 2](/uploads/projects/25-let-belita/853fefa1cd844bcf84dfbc4f6cf88da3-2.png)\n\nWhen you click on \"take part in the competition\" pop-up opens.\n- Name - required field.\n- E-mail - required field \n- Contact phone - optional field.\n- Check number - required field.\n\n(!) A check check has been developed so that the same number is not entered twice.\nAfter filling in the required fields correctly and clicking send, a “thank you” page appears..\n\n![25th of Belita — 3](/uploads/projects/25-let-belita/9f0e8e6f54f3406c8bf6daf6e6f084b0-2.png)","subtitle":"Web · Website","challenge":"his promotion site will be developed as part of the company's anniversary - the 25th of Belita.","description":"Promo site for the 25th of Belita","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"25-летие Белиты","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Промо-сайт представляет собой проект, где пользователь может просмотреть видео с комплиментами на итальянском языке и дать свой ответ + расшарить промо-сайт в соц.сетях и участвовать в конкурсе при покупки продукции.\n\n![25-летие Белиты — 1](/uploads/projects/25-let-belita/2eda4c5245194a8e832f9aeb0781d2a3.png)\n\nПосле нажатия на кнопку «получить комплимент» открывается видеоролик.\n\nДалее можно просмотреть следюущие видео, нажав «посмотреть все ролики», после чего открывается плашка с 4 роликами. Ее можно скрыть, а можно просмотреть любой ролик.\n\n![25-летие Белиты — 2](/uploads/projects/25-let-belita/853fefa1cd844bcf84dfbc4f6cf88da3.png)\n\nПри клике на «участвовать в конкурсе» открывается поп-ап.\n- ФИО – обязательное поле для заполнения. Сообщение об ошибке: Введите Ваше имя.\n- Е-mail – обязательное поле для заполнения (сделать валидацию e-mail). Сообщение об ошибке: Введите Ваш e-mail.\n- Контактный телефон – не обязательное поле для заполнения.\n- Номер чека – обязательное поле. Сообщение об ошибке «Введите верный номер чека».\n\n(!) Должна быть проверка, чтобы не вводили один и тот же номер чека дважды.\nПри верном заполнении обязательных полей и клике отправить появляется страничка «спасибо».\n\n![25-летие Белиты — 3](/uploads/projects/25-let-belita/9f0e8e6f54f3406c8bf6daf6e6f084b0.png)","subtitle":"Веб · Сайт","challenge":"Данный промо-сайт будет разрабатываться в рамках юбилея компании - 25-летию Белиты.","description":"Промо сайт к 25-летию Белиты","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_205$::jsonb)
