INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('uznai-svoi-tip-vneshnosti', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 206, '/uploads/projects/uznai-svoi-tip-vneshnosti/8f1ba4a96a76489d830b17c800e224b6.jpeg', $row_206${"en":{"title":"Discover Your Look Type by Bielita","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"We built the Discover Your Look Type social application for the Bielita cosmetics brand, engaging users with an interactive appearance-type quiz.\n\n**Related projects:** [Dream Tree by Bielita](/en/portfolio/derevo-mechti)","subtitle":"Web · Website","challenge":"Development of a social application for the Bielita cosmetics company.","description":"Discover Your Look Type — a social app for the Bielita brand","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Узнай свой тип внешности от Белиты","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Социальное приложение для компании Белита\n\n**Связанные проекты:** [Дерево мечты от Биелиты](/ru/portfolio/derevo-mechti)","subtitle":"Веб · Сайт","challenge":"Социальное приложение для компании Белита","description":"Узнай свой тип внешности от Белиты","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_206$::jsonb)
