INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('viberi-svoi-opel', 'web', ARRAY['web'], ARRAY['JavaScript', 'PHP'], 2012, false, true, 209, '/uploads/projects/viberi-svoi-opel/c12626a9d048471c9ce9ef486f98fd19.jpeg', $row_209${"en":{"title":"Choose Your Opel","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"The \"Pick your Opel\" application is designed for use on the Facebook platform and includes a number of features that help potential customers to select their ideal vehicle from the Opel range.\n\nThrough the app, users can view photos, descriptions and specifications of each Opel model and access a variety of interesting features to help them choose their ideal car.\n\nOne of the key features of Choose Your Opel is the ability to take a virtual test drive of each Opel model. Users can take a test drive on their computer using the app's built-in tools and get a realistic idea of how they would feel behind the wheel of each model.\n\nIn addition, 'Choose Your Opel' gives users the opportunity to customise their ideal car using the built-in configurator. They can choose the body colour, engine type, gearbox type and more to create a car that is just right for them.\n\nFor those who have already bought an Opel car, the app offers many useful functions. They can find the nearest Opel service centre, access exclusive promotions and offers and much more.\n\nWith this \"Choose Your Opel\" SMM app, Piplos Media helped to increase awareness and loyalty to the Opel brand by providing potential and current customers with a convenient way to get information about Opel cars, conduct a virtual test drive and customise their ideal car.","subtitle":"Web · SMM app","challenge":"Opel is one of the most popular car brands in the world, and its loyal fans are always looking for new ways to get more information about the brand. That's why Piplos Media has developed a new SMM app called 'Pick your Opel' to help increase awareness and loyalty to the brand.","description":"Choose Your Opel: Developing an SMM App to Increase Brand Loyalty","stack_detail":"JavaScript, PHP"},"ru":{"title":"Выбери свой Opel","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Приложение «Выбери свой Opel» создано для платформы Facebook и включает ряд функций, которые помогают потенциальным клиентам подобрать идеальный автомобиль из модельного ряда Opel.\n\nЧерез приложение пользователи могут просматривать фотографии, описания и характеристики каждой модели Opel, а также пользоваться интересными функциями, помогающими выбрать идеальный автомобиль.\n\nОдна из ключевых возможностей приложения — виртуальный тест-драйв каждой модели Opel. Пользователи могут пройти тест-драйв на своём компьютере с помощью встроенных инструментов приложения и получить реалистичное представление о том, каково это — оказаться за рулём каждой модели.\n\nКроме того, «Выбери свой Opel» даёт пользователям возможность собрать автомобиль мечты с помощью встроенного конфигуратора: выбрать цвет кузова, тип двигателя, коробку передач и многое другое.\n\nДля тех, кто уже приобрёл автомобиль Opel, приложение предлагает множество полезных функций: поиск ближайшего сервисного центра Opel, доступ к эксклюзивным акциям и предложениям и многое другое.\n\nС помощью SMM-приложения «Выбери свой Opel» Piplos Media помогла повысить узнаваемость бренда Opel и лояльность к нему, предоставив потенциальным и действующим клиентам удобный способ получать информацию об автомобилях Opel, проходить виртуальный тест-драйв и собирать автомобиль своей мечты.","subtitle":"Веб · SMM-приложение","challenge":"Opel — один из самых популярных автомобильных брендов в мире, и его преданные поклонники всегда ищут новые способы узнать больше о марке. Поэтому Piplos Media разработала новое SMM-приложение «Выбери свой Opel», призванное повысить узнаваемость бренда и лояльность к нему.","description":"Выбери свой Opel: разработка SMM-приложения для повышения лояльности к бренду","stack_detail":"JavaScript, PHP"}}$row_209$::jsonb)
