INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('viberi-svoi-auto', 'web', ARRAY['web'], ARRAY['UI/UX', 'Figma', 'Photoshop'], 2012, false, true, 210, '/uploads/projects/viberi-svoi-auto/a609a2dbe30e452a8e1b12b60a5c0aa7.png', $row_210${"en":{"title":"applications for FAVORIT MOTORS","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"Piplos Media has developed a successful SMM application for FAVORIT MOTORS which allows customers to quickly and easily get information about new car models, promotions and special offers. The app was developed using state-of-the-art technology and a design concept that combines simplicity and ease of use.\n\nThe key element of the app is its user interface, which provides users with quick access to necessary information as well as easy navigation. The design of the application matches the FAVORIT MOTORS brand, which creates a unified style and brand recognition.\n\nFurthermore, the app enables users to receive personalised notifications about new models, promotions and offers, which helps maintain customer interest in the brand and improve service levels.\n\nAn important factor in the app's success is its integration with social networking sites, allowing users to quickly and easily share information about FAVORIT MOTORS brand with friends and followers. This increases brand awareness and helps attract new customers.\n\nUsing modern technology and professional design allowed Piplos Media to create a successful SMM application for FAVORIT MOTORS which not only increased brand awareness, but also improved customer service.","subtitle":"Web · SMM app","challenge":"Social media is becoming increasingly popular amongst marketers and business people, and no wonder, as it can quickly and effectively engage new customers and build brand awareness. One of the most important aspects of social media is creating an attractive and functional application that attracts the attention of potential customers.","description":"How Piplos Media created an SMM app for FAVORIT MOTORS","stack_detail":"UI/UX, Figma, Photoshop"},"ru":{"title":"приложения для FAVORIT MOTORS","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"Компания Piplos Media разработала успешное SMM-приложение для FAVORIT MOTORS, который позволяет клиентам быстро и удобно получать информацию о новых моделях автомобилей, акциях и специальных предложениях. Приложение было разработано с использованием современных технологий и дизайнерской концепции, которая сочетает в себе простоту и удобство использования.\n\nКлючевым элементом приложения является его пользовательский интерфейс, который предоставляет пользователям быстрый доступ к необходимой информации, а также удобную навигацию. Дизайн приложения соответствует бренду FAVORIT MOTORS, что создает единый стиль и узнаваемость бренда.\n\nБолее того, приложение позволяет пользователям получать персонализированные уведомления о новых моделях, акциях и предложениях, что позволяет поддерживать интерес клиентов к бренду и улучшать уровень обслуживания.\n\nВажным фактором успеха приложения является его интеграция с социальными сетями, что позволяет пользователям быстро и просто делиться информацией о бренде FAVORIT MOTORS с друзьями и подписчиками. Это увеличивает узнаваемость бренда и помогает привлекать новых клиентов.\n\nИспользование современных технологий и профессионального дизайна позволило компании Piplos Media создать удачное SMM-приложение для FAVORIT MOTORS, которое не только повысило узнаваемость бренда, но и улучшило уровень обслуживания клиентов.","subtitle":"Веб · SMM-приложение","challenge":"Социальные сети становятся все более популярными среди маркетологов и бизнесменов, и это неудивительно, ведь благодаря им можно быстро и эффективно привлекать новых клиентов и повышать узнаваемость бренда. Одним из наиболее важных аспектов работы в социальных сетях является создание привлекательного и функционального приложения, которое бы привлекло внимание потенциальных клиентов.","description":"Как Piplos Media создало SMM-приложение для FAVORIT MOTORS","stack_detail":"UI/UX, Figma, Photoshop"}}$row_210$::jsonb)
