INSERT INTO projects (slug, category, categories, tags, year, featured, published, sort_order, image, translations)
VALUES ('ultrabooksreview', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 214, '/uploads/projects/ultrabooksreview/9a3d7b5021fb485e8d32e847b58d68d0.jpeg', $row_214${"en":{"title":"Virtual journal 'Ultrabooks Review'","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"- Development of an online version of an English magazine about ultrabooks.\n\nThe site will publish materials in the following categories:\n- Articles,\n- News,\n- and reviews of modern technology.\n\nThe last section was given a lot of time, because it has become a central project.\n\n![Virtual journal 'Ultrabooks Review' — 1](/uploads/projects/ultrabooksreview/884ceb4b03c443dcb0927ed9c9025b9d-2.png)\n\npossibility of publishing user reviews on the technique was also taken into account.\n\n![Virtual journal 'Ultrabooks Review' — 2](/uploads/projects/ultrabooksreview/83e6a3f4b39e4dae8094c67e9485723d-2.png)","subtitle":"Web · Website","challenge":"The task that faced our team:","description":"Website development for an English ultrabook magazine. Articles, news and reviews of modern technology","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Виртуальный журнал - Ultrabooks Review","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"- Разарботка интернет версию английского журнала о ультрабуках.\n\nНа сайте будут публиковаться материалы следующих категорий:\n- Статьи, \n- Новости,\n- и обзоры соверменной техники.\n\nПоследнему разделу было уделено большое количество времени, т.к. на него делался акцент всего проекта.\n\n![Виртуальный журнал - Ultrabooks Review — 1](/uploads/projects/ultrabooksreview/884ceb4b03c443dcb0927ed9c9025b9d.png)\n\nТак же учитывалось возможность публикации отзывов пользователей на технику.\n\n![Виртуальный журнал - Ultrabooks Review — 2](/uploads/projects/ultrabooksreview/83e6a3f4b39e4dae8094c67e9485723d.png)","subtitle":"Веб · Сайт","challenge":"Задача, которая стояла перед нашей командой:","description":"Разработка сайта для английского журнала о ультрабуках. Статьи, новости и обзоры современной техники","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_214$::jsonb)
