VALUES ('milalolcontest', 'web', ARRAY['web'], ARRAY['PHP', 'MySQL', 'JavaScript', 'HTML/CSS'], 2012, false, true, 215, '/uploads/projects/milalolcontest/56f7f18dc2fa4a6bbc8857a19b81ac2f.jpeg', $row_215${"en":{"title":"Milalol Contest Gallery","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"![Milalol contest gallery — 1](/uploads/projects/milalolcontest/f89530f636c64f559805bebc0266ce67.png)\n\n![Milalol contest gallery — 2](/uploads/projects/milalolcontest/02abda944abd48e290b7d00e84f2ea45.png)\n\n**Related projects:** [Landing Page v.1 for Milalol](/en/portfolio/milalolcover1), [Landing Page v.2 for Milalol](/en/portfolio/milalolcover2), [Landing Page v.3 for Milalol](/en/portfolio/milalolcover3)","subtitle":"Web · Website","challenge":"Development of a contest gallery for the Milalol website.","description":"Contest gallery for the Milalol dating website","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"},"ru":{"title":"Milalol contest галерея","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"![Milalol contest галерея — 1](/uploads/projects/milalolcontest/f89530f636c64f559805bebc0266ce67.png)\n\n![Milalol contest галерея — 2](/uploads/projects/milalolcontest/02abda944abd48e290b7d00e84f2ea45.png)\n\n**Связанные проекты:** [Лендингпейдж v.1 для сайта Milalol](/ru/portfolio/milalolcover1), [Лендингпейдж v.2 для сайта Milalol](/ru/portfolio/milalolcover2), [Лендингпейдж v.3 для сайта Milalol](/ru/portfolio/milalolcover3)","subtitle":"Веб · Сайт","challenge":"Milalol contest галерея","description":"Milalol contest галерея","stack_detail":"PHP, MySQL, JavaScript, HTML/CSS"}}$row_215$::jsonb)
