VALUES ('calendar-ren', 'web', ARRAY['web'], ARRAY['Stripe'], 2012, false, true, 216, '/uploads/projects/calendar-ren/a80617f398a84ea6a133f3028a9b4cf5.png', $row_216${"en":{"title":"Striped Calendar Ren","result":"The project was successfully delivered to the client. The work was completed in 2012.","solution":"The site publishes various calendar events that are published and which can be shared via social networks.\n\n![Striped Calendar Ren — 1](/uploads/projects/calendar-ren/f7cb10a8492846a6af37c3ebaf669c8a-2.png)\n\n![Striped Calendar Ren — 2](/uploads/projects/calendar-ren/fadeded603b8463d93e67949b901209d-2.png)\n\n**Related projects:** [Ren Promo Website](/en/portfolio/promo-site-ren), [Zakatki Ren: Building an SMM Application](/en/portfolio/zakatki-ren)","subtitle":"Web · Website","challenge":"This promotional site is dedicated to the advertising company for the development of the Ren brand.","description":"Promo website calendar Ren","stack_detail":"Stripe"},"ru":{"title":"Полосатый календарь Рень","result":"Проект успешно реализован и передан заказчику. Работы выполнены в 2012 году.","solution":"На сайте публикуются различные календарные события, которые публикуются и которыми можно поделиться через социальные сети.\n\n![Полосатый календарь Рень — 1](/uploads/projects/calendar-ren/f7cb10a8492846a6af37c3ebaf669c8a.png)\n\n![Полосатый календарь Рень — 2](/uploads/projects/calendar-ren/fadeded603b8463d93e67949b901209d.png)\n\n**Связанные проекты:** [Промо-сайт Рень](/ru/portfolio/promo-site-ren), [Закатки Рень: создание SMM-приложения](/ru/portfolio/zakatki-ren)","subtitle":"Веб · Сайт","challenge":"Данный промо-сайт посвещен рекламной компании по развитию торговой марки \"Рень\".","description":"Промо сайт-календарь Рень","stack_detail":"Stripe"}}$row_216$::jsonb)
