INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/abff', $row_3${"en":{"title":"Belarusian Football Federation | Piplos Media","og_image":"/uploads/projects/abff/bez-imeni.png","og_title":"Developing the official website of the Belarus Football Federation: structure and functionality","description":"Developing the official website of the Belarus Football Federation: structure and functionality. A project by Piplos Media.","og_description":"This article is about how our development team created the complex structure and functionality of the official website of the Belarus Football Federation, including the division of the site into three parts, the use of the database, API and other technologies. It also describes the features of the site for users and the plans for its further development."},"ru":{"title":"Белорусская федерация футбола — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/abff/bez-imeni.png","og_title":"Разработка официального сайта футбольной федерации Беларуси: структура и функциональность","description":"Разработка официального сайта футбольной федерации Беларуси: структура и функциональность. Проект студии Piplos Media.","og_description":"Статья о том, как наша команда разработчиков создала сложную структуру и функциональную составляющую официального сайта футбольной федерации Беларуси, включая разделение сайта на три части, использование базы данных, API и других технологий. Также описаны возможности сайта для пользователей и планы на его дальнейшее развитие."}}$row_3$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/abff-comet', $row_4${"en":{"title":"Integration with COMET — Backend Case Study | Piplos Media","og_image":"/uploads/projects/abff-comet/bez-imeni-2.png","og_title":"Football federation website integration with COMET: automating the process of entering match protocols and statistics","description":"Football federation website integration with COMET: automating the process of entering match protocols and statistics. A project by Piplos Media.","og_description":"In this article we will describe the process of integrating the COMET system with the RB Club Championship website to automate match data entry and generate statistics on players, clubs and coaches. Thanks to the API of the COMET system the data entered in the match protocol is automatically uploaded to the championship website and processed, which allows getting up-to-date and accurate statistics for all games. Both general club statistics and individual statistics for each player are taken into account separately."},"ru":{"title":"Интеграция с COMET — Кейс backend-разработки | Piplos Media","og_image":"/uploads/projects/abff-comet/bez-imeni-2.png","og_title":"Интеграция сайта футбольной федерации с COMET: автоматизация процессов введения протоколов матчей и статистики","description":"Интеграция сайта футбольной федерации с COMET: автоматизация процессов введения протоколов матчей и статистики. Проект студии Piplos Media.","og_description":"В данной статье мы расскажем о процессе интеграции системы COMET с сайтом клубного чемпионата РБ для автоматизации ввода данных по матчам и формирования статистики по игрокам, клубам и тренерам. Благодаря API системы COMET данные, вносимые в протокол матча, автоматически подтягиваются на сайт чемпионата и обрабатываются, что позволяет получать актуальную и точную статистику по всем играм. Отдельно учитывается как общая статистика клубов, так и индивидуальная по каждому игроку."}}$row_4$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

