INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/aifront', $row_7${"en":{"title":"AI visualiser for building facades — Backend Case Study | Piplos Media","og_image":"/uploads/projects/aifront/group-2.png","og_title":"AI visualiser for building facades - AiFront web application from Piplos Media","description":"AiFront transforms façade visualisation using generative artificial intelligence. Piplos Media's own product.","og_description":"AiFront is an AI platform for visualising building facades. It is a web application built on React and Go with a REST API, supporting Gemini and OpenAI. It allows users to upload photos, mark areas, select materials, and generate realistic exteriors using artificial intelligence."},"ru":{"title":"AI-визуализатор фасадов домов — веб-приложение AiFront от Piplos Media","og_image":"/uploads/projects/aifront/group-2.png","og_title":"AI-визуализатор фасадов домов — веб-приложение AiFront от Piplos Media","description":"AiFront преобразует визуализацию фасадов с помощью генеративного искусственного интеллекта.Собственный продукт Piplos Media","og_description":"AiFront - AI-платформа для визуализации фасадов домов. Веб-приложение на React и Go с REST API, поддержкой Gemini и OpenAI. Загрузка фото, разметка зон, выбор материалов и генерация реалистичного экстерьера с помощью искусственного интеллекта."}}$row_7$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/aifront-app', $row_8${"en":{"title":"AiFront mobile app — Mobile App Case Study | Piplos Media","og_image":"/uploads/projects/aifront-app/group-6.jpg","og_title":"AiFront PWA: Mobile AI-powered façade visualisation and home design using a neural network.","description":"AiFront PWA – a mobile app for AI-powered façade visualisation. A project by Piplos Media.","og_description":"Discover how AiFront PWA turns your smartphone into a powerful tool for on-site work. Upload photos from home and get dozens of photorealistic finish options in seconds, powered by AI. The PWA version offers quick access, one-click installation and accurate material calculations, with no need to download from the App Store or Google Play."},"ru":{"title":"AiFront мобильное приложение | Piplos Media","og_image":"/uploads/projects/aifront-app/group-6.jpg","og_title":"AiFront PWA: Мобильная AI-визуализация фасадов и дизайн дома с помощью нейросети.","description":"AiFront PWA - мобильное приложение для AI-визуализации фасадов. Проект студии Piplos Media.","og_description":"Узнайте, как AiFront PWA превращает смартфон в мощный инструмент для работы «в поле». Загружайте фото дома и получайте десятки вариантов фотореалистичной отделки за секунды с помощью ИИ. PWA-версия обеспечивает быстрый доступ, установку в один клик и точный расчет материалов без необходимости скачивания из App Store или Google Play."}}$row_8$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

