VALUES ('/portfolio/artinsheffield', $row_21${"en":{"title":"Art in Sheffield: How we developed a mobile app for iOS","og_image":"/uploads/projects/artinsheffield/bbf46d9edf9d4410b0cd9f8bfbf0c193.png","og_title":"Art in Sheffield: How we developed a mobile app for iOS","description":"Art in Sheffield: How we developed a mobile app for iOS. In recent years, mobile apps have become an indispensable part of our everyday lives. They allow us to…","og_description":"\"Developing Art in Sheffield mobile app for iOS\" is an article that will describe the process of developing an app for visitors to the city of Sheffield to easily and conveniently find places related to art and culture. The article will cover the stages of development, the technologies used, and the specifics of working with the API and database."},"ru":{"title":"Art in Sheffield: Как мы разработали мобильное приложение для iOS","og_image":"/uploads/projects/artinsheffield/bbf46d9edf9d4410b0cd9f8bfbf0c193.png","og_title":"Art in Sheffield: Как мы разработали мобильное приложение для iOS","description":"Art in Sheffield: Как мы разработали мобильное приложение для iOS. Проект студии Piplos Media.","og_description":"\"Разработка мобильного приложения Art in Sheffield для iOS\" - статья, в которой будет описан процесс разработки приложения для посетителей города Шеффилд, позволяющего легко и удобно находить места, связанные с искусством и культурой. В статье будут рассмотрены этапы разработки, используемые технологии, а также особенности работы с API и базой данных."}}$row_21$::jsonb)
