INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/belint-new', $row_27${"en":{"title":"Redesign of the Belitertrans homepage: a new look at logistics","og_image":"/uploads/projects/belint-new/placeholder-mobile.png","og_title":"Redesign of the Belitertrans homepage: a new look at logistics","description":"Redesign of the Belitertrans homepage: a new look at logistics. A project by Piplos Media.","og_description":"This article is about the process of redesigning the homepage of the Belitertrans logistics company website, which was developed through the popular design tool Figma. It describes the process of creating the new design, its main features and benefits, as well as future plans to improve and develop the site."},"ru":{"title":"Редизайн Belitertrans — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/belint-new/placeholder-mobile.png","og_title":"Редизайн главной страницы сайта Belitertrans: новый взгляд на логистику","description":"Редизайн главной страницы сайта Belitertrans: новый взгляд на логистику. Проект студии Piplos Media.","og_description":"Эта статья о процессе редизайна главной страницы сайта логистической компании Belitertrans, который был разработан через популярный инструмент дизайна Figma. Описывается процесс создания нового дизайна, его основные особенности и преимущества, а также планы на будущее по улучшению и развитию сайта."}}$row_27$::jsonb)
