INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/bolshedrayva', $row_36${"en":{"title":"Advertising game, Gazpromneft, landing, more drive","og_image":"/uploads/projects/bolshedrayva/bolshe-drajva-copy.png","og_title":"Advertising game, Gazpromneft, landing, more drive","description":"Promotional game \"More Drive!\" for an oil and gas company: promo project development. A project by Piplos Media.","og_description":"This article describes the development of a promotional game called \"More Drive!\" for an Oil and Gas company. The project allows participants in the loyalty programme to register on the website and take part in the game. Once registered, users can automatically check their card numbers and see all the codes assigned to them in their personal account on the website."},"ru":{"title":"Рекламная игра \"Больше Драйва!\" — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/bolshedrayva/bolshe-drajva-copy.png","og_title":"Рекламная игра \"Больше Драйва!\" для нефтегазовой компании: разработка промо проекта","description":"Рекламная игра \"Больше Драйва!\" для нефтегазовой компании: разработка промо проекта. Проект студии Piplos Media.","og_description":"В данной статье рассказывается о разработке рекламной игры \"Больше Драйва!\" для Нефтегазовой компании. Проект позволяет участникам программы лояльности зарегистрироваться на сайте и принять участие в игре. После регистрации пользователи могут автоматически проверить свои номера карт и увидеть все присвоенные им коды в личном кабинете на сайте."}}$row_36$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
