INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/brest-litovsk', $row_37${"en":{"title":"Advertising game \"Brest - Litovsk\" on the table.","og_image":"/uploads/projects/brest-litovsk/8dc4e726ab504f828ee21c310c9c84e0.png","og_title":"Advertising game \"Brest - Litovsk\" on the table.","description":"Promotional site of the game \"Brest-Litovsk on the table\"","og_description":"Promotional site of the game \"Brest-Litovsk on the table\""},"ru":{"title":"Рекламная игра «Брест — Литовск» на столе.","og_image":"/uploads/projects/brest-litovsk/8dc4e726ab504f828ee21c310c9c84e0.png","og_title":"Рекламная игра «Брест — Литовск» на столе.","description":"Промо-сайт игры \"Брест-Литовск на столе\". Основное что необходимо было учесть при разработке дизайна - это дизайн сайта должен соответствовать фирменным цветам…","og_description":"Промо-сайт игры \"Брест-Литовск на столе\""}}$row_37$::jsonb)
