INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/brillianti-hyndai', $row_38${"en":{"title":"Hyundai Diamonds — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/brillianti-hyndai/group-4.png","og_title":"Hyundai Diamonds: How to develop a Facebook SMM app and increase brand awareness","description":"Hyundai Diamonds: How to develop a Facebook SMM app and increase brand awareness. A project by Piplos Media.","og_description":"This article looks at the development of a Facebook SMM app called \"Hyundai Diamonds\" by Hyundai. The article describes the functions of the application, its features and capabilities. It also gives examples of successful use of the application for attracting new customers and increasing the loyalty of existing ones. At the end of the article there is an overview of the effectiveness of using SMM applications to promote a brand on Facebook."},"ru":{"title":"Бриллианты Hyundai — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/brillianti-hyndai/group-4.png","og_title":"Бриллианты Hyundai: как разработать SMM-приложение для Facebook и повысить узнаваемость бренда","description":"Бриллианты Hyundai: как разработать SMM-приложение для Facebook и повысить узнаваемость бренда. Проект студии Piplos Media.","og_description":"В данной статье рассмотрена разработка SMM-приложения для Facebook под названием \"Бриллианты Hyundai\" компанией Hyundai. В статье описываются функции приложения, его особенности и возможности. Также приводятся примеры успешного использования приложения для привлечения новых клиентов и увеличения лояльности уже существующих. В конце статьи дается обзор эффективности использования SMM-приложений для продвижения бренда на Facebook."}}$row_38$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/budutam', $row_39${"en":{"title":"SMM app BuduTam — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/budutam/group-7.png","og_title":"BuduTam: developing a Facebook SMM application to increase brand loyalty for Japan Tabak International","description":"BuduTam: developing a Facebook SMM application to increase brand loyalty Japan Tabak International. A project by Piplos Media.","og_description":"This article describes a project developed by Piplos Media for Japan Tabak International. The task was to develop an SMM application to collect marketing surveys and increase brand loyalty. The app includes a mobile app for users and an SMM app to collect marketing data that was hidden under various surveys. Through thoughtful development, the app gained a lot of popularity through social media and grew into an entire social network, increasing user loyalty to the brand."},"ru":{"title":"SMM приложение БудуТам — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/budutam/group-7.png","og_title":"БудуТам: разработка SMM-приложения для Facebook, увеличивающего лояльность к бренду Japan Tabak International","description":"БудуТам: разработка SMM-приложения для Facebook, увеличивающего лояльность к бренду Japan Tabak International. Проект студии Piplos Media.","og_description":"В статье рассказывается о проекте, разработанном компанией Piplos Media для Japan Tabak International. Была поставлена задача разработать SMM-приложение для сбора маркетинговых исследований и повышения лояльности к бренду. Приложение включает мобильное приложение для пользователей и SMM-приложение для сбора маркетинговых данных, которые были скрыты под различными опросами. Благодаря продуманной разработке, приложение получило большую популярность через социальные сети и разрослось до целой социальной сети, увеличивая лояльность пользователей к бренду."}}$row_39$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/budutam-android', $row_40${"en":{"title":"The mobile app BuduTam — Mobile App Case Study | Piplos Media","og_image":"/uploads/projects/budutam-android/artboard-copy-42.png","og_title":"Development of the BuduTam mobile app for Japan Tobacco: creating a social network for party organisation","description":"Development of the BuduTam mobile app for Japan Tobacco: creating a social network for party organisation. A project by Piplos Media.","og_description":"The BuduTam mobile app has been developed to organise and attend parties and events hosted by Japan Tobacco. Users can receive information about upcoming events and check in if they plan to attend an event. Users with a high account level can create events themselves, which are moderated by the app administrators. The app also provides the opportunity to accumulate points and redeem them for rewards. BuduTam is a complete social network based on a fault-tolerant API system, which ensures the app will work even with high loads."},"ru":{"title":"Мобильное приложение БудуТам | Piplos Media","og_image":"/uploads/projects/budutam-android/artboard-copy-42.png","og_title":"Разработка мобильного приложения БудуТам для компании Japan Tobacco: создание социальной сети для организации вечеринок","description":"Разработка мобильного приложения БудуТам для компании Japan Tobacco: создание социальной сети для организации вечеринок. Проект студии Piplos Media.","og_description":"Мобильное приложение БудуТам разработано для организации и посетителей вечеринок и мероприятий, проводимых компанией Japan Tobacco. Пользователи могут получать информацию о предстоящих событиях и отмечаться, если они планируют посетить мероприятие. Пользователи с высоким уровнем аккаунта могут самостоятельно создавать мероприятия, которые проходят модерацию администраторами приложения. Приложение также предоставляет возможность накопления баллов и их обмена на бонусы. БудуТам - это целая социальная сеть, основанная на отказоустойчивой API-системе, которая обеспечивает работу приложения даже при высоких нагрузках."}}$row_40$::jsonb)
