INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/chelobanov', $row_45${"en":{"title":"Door Manufacturing Workshop | Piplos Media","og_image":"/uploads/projects/chelobanov/artboard-copy-15.png","og_title":"Creating a Custom Website for Andrey Chelobanov's Unique Door Manufacturing Workshop","description":"Creating a Custom Website for Andrey Chelobanov's Unique Door Manufacturing Workshop. A project by Piplos Media.","og_description":"This technical article details the development of an individual project to create a website catalog for Andrey Chelobanov's workshop, which specializes in producing unique doors. The catalog not only provides information on the workshop's products but also offers a personalized door selection tool. The website's extensive filtering functionality allows users to quickly navigate through the company's large catalog. At the client's request, the site's design is inspired by wood, and its complex structure is streamlined for easy navigation."},"ru":{"title":"Мастерская по производству дверей — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/chelobanov/artboard-copy-15.png","og_title":"Создание сайта для уникальной мастерской по производству дверей Андрея Челобанова","description":"Создание сайта для уникальной мастерской по производству дверей Андрея Челобанова. Проект студии Piplos Media.","og_description":"В данной технической статье подробно описывается разработка индивидуального проекта по созданию сайта-каталога для мастерской Андрея Челобанова, специализирующейся на производстве уникальных дверей. Каталог не только предоставляет информацию о продукции мастерской, но и предлагает инструмент индивидуального подбора дверей. Широкие возможности фильтрации на сайте позволяют пользователям быстро ориентироваться в большом каталоге компании. По просьбе клиента дизайн сайта вдохновлен деревом, а его сложная структура оптимизирована для удобной навигации."}}$row_45$::jsonb)
