INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/deck-tikoo', $row_51${"en":{"title":"TiKoo: Israel B2B2C Trade Platform and Pitch Deck Lending","og_image":"/uploads/projects/deck-tikoo/group-11.png","og_title":"TiKoo: Israel B2B2C Trade Platform and Pitch Deck Lending","description":"TiKoo project by Piplos Media: Unified platform for B2B2C online trading and trade tenders with Israel","og_description":"Meet TiKoo, an innovative platform for international B2B2C trade with Israel. Learn how we provide a unified shopping experience, provide online shopping ratings and support the globalisation of business. Explore the Pitch Deck ribbon for an in-depth understanding of the TiKoo project."},"ru":{"title":"TiKoo: Израильская B2B2C Торговая Платформа и Лендинг Pitch Deck","og_image":"/uploads/projects/deck-tikoo/group-11.png","og_title":"TiKoo: Израильская B2B2C Торговая Платформа и Лендинг Pitch Deck","description":"Проект TiKoo от компании Piplos Media: Унифицированная платформа для онлайн-торговли B2B2C и торговых тендеров с Израилем","og_description":"Познакомьтесь с TiKoo - инновационной платформой для международной B2B2C торговли с Израилем. Узнайте, как мы обеспечиваем унифицированный опыт покупки, предоставляем рейтинги онлайн-магазинов и поддерживаем глобализацию бизнеса. Исследуйте лендинг Pitch Deck для углубленного понимания проекта TiKoo."}}$row_51$::jsonb)
