VALUES ('/portfolio/drawevent', $row_57${"en":{"title":"DrawEvent — Backend Case Study | Piplos Media","og_image":"/uploads/projects/drawevent/frame-64.png","og_title":"Development of DrawEvent Project: Automating and Simplifying Tournament Draws","description":"Development of DrawEvent Project: Automating and Simplifying Tournament Draws. A project by Piplos Media.","og_description":"DrawEvent is a software solution for drawing lots in sports that makes the process efficient and reliable. With Piplos Draw you can draw any format quickly and error-free, reducing time and improving the quality of the competition. It enables you to save the results of your draws, generate reports and work online or offline. DrawEvent is an indispensable tool for coaches, athletes and competition organisers looking to ensure fair and transparent competitions."},"ru":{"title":"DrawEvent — Кейс backend-разработки | Piplos Media","og_image":"/uploads/projects/drawevent/frame-64.png","og_title":"Разработка проекта DrawEvent: Автоматизация и Упрощение Жеребьевок Турниров","description":"Разработка проекта DrawEvent: Автоматизация и Упрощение Жеребьевок Турниров. Проект студии Piplos Media.","og_description":"DrawEvent - это программное решение для проведения жеребьевок в спорте, которое обеспечивает эффективность и надежность процесса. С помощью Piplos Draw вы можете провести жеребьевку любого формата быстро и безошибочно, сократив время и улучшив качество проведения соревнований. Программа позволяет сохранять результаты жеребьевок, генерировать отчеты и работать в режиме онлайн или оффлайн. Piplos Draw - незаменимый инструмент для тренеров, спортсменов и организаторов соревнований, которые стремятся обеспечить честные и прозрачные соревнования."}}$row_57$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

