VALUES ('/portfolio/fcneman', $row_67${"en":{"title":"Football Club Case Study — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/fcneman/group-205.png","og_title":"Sports Analytics & Data Automation Platform Development for Football Clubs | Piplos Media","description":"Development of a digital platform and an automated sports statistics system for FC Neman. A project by Piplos Media.","og_description":"Custom sports analytics platform developed by Piplos Media for a professional football club. Automated data parsing, real-time statistics, tournament logic, and scalable backend architecture. Ideal solution for sports organizations seeking reliable data automation and high-performance web systems."},"ru":{"title":"Кейс Футбольного Клуба — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/fcneman/group-205.png","og_title":"Разработка спортивного портала и системы статистики — кейс ФК Неман | Piplos Media","description":"Разработка цифровой платформы и системы автоматизации спортивной статистики для ФК «Неман». Проект студии Piplos Media.","og_description":"Кейс Piplos Media: разработка цифрового портала ФК «Неман» с системой автоматического парсинга и обработки спортивной статистики. Интеграция с внешними источниками, расчет турнирных таблиц, управление данными через САП и стабильная работа под высокой нагрузкой."}}$row_67$::jsonb)
