INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/fotokonkurs-allo', $row_71${"en":{"title":"Allo Photo Contest — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/fotokonkurs-allo/e5610c99772446fe991022e3f53c9197.jpg","og_title":"Allo Photo Contest — Web Development Case Study | Piplos Media","description":"Developing the Allo Photo Contest SMM application: how we built a successful audience engagement tool. A project by Piplos Media.","og_description":"Developing the Allo Photo Contest SMM application: how we built a successful audience engagement tool. A project by Piplos Media."},"ru":{"title":"Фотоконкурс Алло — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/fotokonkurs-allo/e5610c99772446fe991022e3f53c9197.jpg","og_title":"Разработка SMM приложения для Фотоконкурса Алло: как мы создали успешный инструмент привлечения аудитории","description":"Разработка SMM приложения для Фотоконкурса Алло: как мы создали успешный инструмент привлечения аудитории. Проект студии Piplos Media.","og_description":"В данной статье рассмотрена разработка SMM приложения \"Фотоконкурс Алло\", созданного компанией Piplos Media. В приложении были реализованы функции для проведения фотоконкурсов, привлечения новых клиентов и повышения лояльности существующей аудитории. Описаны технологии, использованные при разработке, а также преимущества использования SMM приложений для проведения маркетинговых кампаний в социальных сетях."}}$row_71$::jsonb)
