INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/gdrive', $row_76${"en":{"title":"Development of the G-Drive promotional website | Piplos Media","og_image":"/uploads/projects/gdrive/group-24.png","og_title":"Promotional website development for an oil and gas enterprise: code tracking and prize draw","description":"Promotional website development for an oil and gas enterprise: code tracking and prize draw. A project by Piplos Media.","og_description":"Piplos Media developed a promo site for Oil & Gas Enterprise allowing the users to register and keep track of the codes and numbers they've won. The site was developed using Symfony framework with automated code download and adaptive design for all devices. In addition, an email system was developed with the ability to track the status of sending and resending, and every second code is entered into a drawing for the grand prize - a trip to the Sochi Grand Prix race."},"ru":{"title":"Рекламная игра, Газпромнефть, лендинг, Гонка за Призами","og_image":"/uploads/projects/gdrive/group-24.png","og_title":"Рекламная игра, Газпромнефть, лендинг, Гонка за Призами","description":"Разработка промо сайта для нефтегазового предприятия: отслеживание кодов и розыгрыш приза. Проект студии Piplos Media.","og_description":"Компания Piplos Media разработала промо сайт для нефтегазового предприятия, который позволяет пользователям зарегистрироваться и отслеживать информацию о выигравших кодах и номерах. Сайт был создан на базе фреймворка Symfony с автоматической подгрузкой кодов и адаптивным дизайном под все устройства. Кроме того, была разработана система email-рассылок с возможностью отслеживания статусов отправки и повторной отправки, а каждый второй код участвует в розыгрыше главного приза - поездки на гонку Гран-При в Сочи."}}$row_76$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
