VALUES ('/portfolio/geo', $row_77${"en":{"title":"Geodesic project — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/geo/belgeodesy-behance-placeholder.png","og_title":"Developing a Minimalistic Design for a Geodetic Project with Advanced Text Editor Features and Geodetic Services\"","description":"Developing a Minimalistic Design for a Geodetic Project with Advanced Text Editor Features and Geodetic Services\". A project by Piplos Media.","og_description":"Learn how our team of designers tackled the challenge of working with complex data for a geodetic project by implementing a minimalist design approach and incorporating advanced text editor features and geodetic services like interactive maps and the CSTP RB map."},"ru":{"title":"Белгеодезия — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/geo/belgeodesy-behance-placeholder.png","og_title":"Разработка минималистического дизайна для геодезического проекта с использованием расширенных функций текстового редактора и геодезических сервисов","description":"Разработка минималистического дизайна для геодезического проекта с использованием расширенных функций текстового редактора и геодезических сервисов","og_description":"Узнайте, как наша команда дизайнеров справилась с задачей работы со сложными данными для геодезического проекта, применив минималистский подход к дизайну и включив передовые функции текстового редактора и геодезические сервисы, такие как интерактивные карты и карта CSTP RB."}}$row_77$::jsonb)
