INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/lifegadget', $row_92${"en":{"title":"Online Magazine, LifeGadget, Electronics, News, Reviews, Technology…","og_image":"/uploads/projects/lifegadget/2f8a04a5eec84c3fbf043d3a3c53ff71.png","og_title":"LifeGadget: a new online magazine about the world of electronics from the Pilos Media team","description":"LifeGadget: a new online magazine about the world of electronics from the Pilos Media team. A project by Piplos Media.","og_description":"We're proud to present our new project - the online magazine LifeGadget, dedicated to news and articles from the world of electronics. The site is packed with reviews on various electronic gadgets as well as a lot of fascinating articles. We invite all technology enthusiasts to leave their comments on the blog, which has been created especially for our readers' communication."},"ru":{"title":"LifeGadget: новый интернет-журнал — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/lifegadget/2f8a04a5eec84c3fbf043d3a3c53ff71.png","og_title":"LifeGadget: новый интернет-журнал о мире электроники от команды Pilos Media","description":"LifeGadget: новый интернет-журнал о мире электроники от команды Pilos Media. Проект студии Piplos Media.","og_description":"Мы с гордостью представляем наш новый проект - интернет-журнал LifeGadget, который посвящен новостям и статьям из мира электронной техники. На сайте вы найдете множество обзоров на различные электронные устройства, а также увлекательные статьи. Приглашаем всех почитателей техники оставлять свои комментарии в блоге, созданном специально для общения наших читателей."}}$row_92$::jsonb)
