INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/lubimi-napitok-blondinki', $row_95${"en":{"title":"How to create a viral SMM game | Piplos Media","og_image":"/uploads/projects/lubimi-napitok-blondinki/620b44ad-dc5a-4c39-b4ea-eba08fedda49.png","og_title":"Blonde's favourite drink: how Piplos Media developed an exciting SMM game","description":"How to create a viral SMM game: development experience Blonde's favourite drink. A project by Piplos Media.","og_description":"In this article, we'll take an in-depth look at the development process of Piplos Media's SMM game 'Blondie's Favorite Drink'. You'll learn what technologies were used, what challenges arose during development, and how to achieve maximum virality and attract a large number of users to your company's social media page."},"ru":{"title":"Как создать вирусную SMM игру — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/lubimi-napitok-blondinki/620b44ad-dc5a-4c39-b4ea-eba08fedda49.png","og_title":"Любимый напиток блондинки: как Piplos Media разработала захватывающую SMM игру","description":"Как создать вирусную SMM игру: опыт разработки Любимый напиток блондинки. Проект студии Piplos Media.","og_description":"В данной статье мы подробно рассмотрим процесс разработки SMM игры \"Любимый напиток блондинки\", созданной компанией Piplos Media. Вы узнаете, какие технологии использовались, какие проблемы возникали в ходе разработки, а также как достичь максимального эффекта вирусности и привлечь большое количество пользователей на страницу вашей компании в социальных сетях."}}$row_95$::jsonb)
