INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/mylabel', $row_112${"en":{"title":"Microservice platform migration — Backend Case Study | Piplos Media","og_image":"/uploads/projects/mylabel/my-label-portfolio-preview-ru-03-03-2026-02-25-pm.png","og_title":"Migrating microservices to Symfony – backend audit and refactoring | Piplos Media","description":"Type of work: audit, architectural analysis, complete backend rework. A project by Piplos Media.","og_description":"Piplos Media case study: audit of microservice architecture and complete migration of the project to a single Symfony monolith with PostgreSQL. Stabilisation of the backend, consolidation of disparate databases, elimination of production errors, and improvement of system fault tolerance."},"ru":{"title":"Миграция микросервисной платформы | Piplos Media","og_image":"/uploads/projects/mylabel/my-label-portfolio-preview-ru-03-03-2026-02-25-pm.png","og_title":"Миграция микросервисов в Symfony - аудит и рефакторинг backend | Piplos Media","description":"Тип работ: аудит, архитектурный анализ, полная переработка backend. Проект студии Piplos Media.","og_description":"Кейс Piplos Media: аудит микросервисной архитектуры и полный перенос проекта на единый Symfony-монолит с PostgreSQL. Стабилизация backend, объединение разрозненных баз данных, устранение production-ошибок и повышение отказоустойчивости системы."}}$row_112$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

