INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/newabff', $row_114${"en":{"title":"Football Federation Website Redesign | Piplos Media","og_image":"/uploads/projects/newabff/1.jpg","og_title":"Explore Piplos Media's web redesign project for the Belarusian Football Federation","description":"Explore Piplos Media's web redesign project for the Belarusian Football Federation.","og_description":"Explore Piplos Media's recent web redesign project for the Belarusian Football Federation (ABFF). Discover how our team revamped the site's design, implemented user-friendly navigation, and enhanced key pages like the home page, match list, and news section. Dive into our design elements, including colour schemes and fonts, and experience the convenience of the burger menu for swift navigation across multiple sites. Witness how we prioritized user experience, making video viewing more accessible and ensuring news is categorized intuitively. Join us in this journey of modernization and innovation in web design."},"ru":{"title":"Редизайн сайта Федерации футбола — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/newabff/1.jpg","og_title":"Ознакомьтесь с проектом Piplos Media по редизайну сайта Белорусской федерации футбола.","description":"Ознакомьтесь с проектом Piplos Media по редизайну сайта Белорусской федерации футбола.","og_description":"Ознакомьтесь с недавним проектом Piplos Media по редизайну сайта Белорусской федерации футбола (АБФФ). Узнайте, как наша команда изменила дизайн сайта, внедрила удобную навигацию и улучшила ключевые страницы, такие как главная, список матчей и раздел новостей. Ознакомьтесь с элементами дизайна, включая цветовые схемы и шрифты, и оцените удобство меню-гамбургера для быстрой навигации по нескольким сайтам. Узнайте, как мы уделяли первостепенное внимание удобству пользователей, сделав просмотр видео более доступным и обеспечив интуитивно понятную категоризацию новостей. Присоединяйтесь к нам в этом путешествии модернизации и инноваций в области веб-дизайна."}}$row_114$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

