INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/pflk', $row_123${"en":{"title":"Kazakhstan Football Federation | Piplos Media","og_image":"/uploads/projects/pflk/frame-547.png","og_title":"Project development for the Professional Football League of Kazakhstan (PFLK): Genius Sports data integration and powerful functionality.","description":"Project Development for the Professional Football League of Kazakhstan: Information, Administration and Integration. A project by Piplos Media.","og_description":"Article describes development of project for Professional Football League of Kazakhstan (PFLK), including creation of web-portal and information resource. The process of data integration with Genius Sports is described, including obtaining live match information. Also covered is the use of technologies and frameworks such as Bootstrap 4.x, HTML Files, CSS Files, JS Files, PHP, PostgreSQL, Symfony and JQuery. The article describes in detail the functionality of the project, such as smart search, displaying tables, statistics, match protocols, team and player information. Particular attention is paid to the administration and management of tournaments, as well as the promotion of football tournaments in Kazakhstan."},"ru":{"title":"Профессиональная Футбольная Лига Казахстана | Piplos Media","og_image":"/uploads/projects/pflk/frame-547.png","og_title":"Разработка проекта для Профессиональной Футбольной Лиги Казахстана (ПФЛК): Интеграция данных Genius Sports и мощные функциональные возможности.","description":"Разработка проекта для Профессиональной Футбольной Лиги Казахстана: Информативность, Администрирование и Интеграция. Проект студии Piplos Media.","og_description":"Статья рассказывает о разработке проекта для Профессиональной Футбольной Лиги Казахстана (ПФЛК), включающего создание веб-портала и информационного ресурса. Описывается процесс интеграции данных с Genius Sports, включая получение Live информации о матчах. Также рассматривается использование технологий и фреймворков, таких как Bootstrap 4.x, HTML Files, CSS Files, JS Files, PHP, PostgreSQL, Symfony и JQuery. Статья подробно описывает функциональные возможности проекта, такие как умный поиск, отображение таблиц, статистики, протоколов матчей, информации о командах и игроках. Особое внимание уделяется администрированию и управлению турнирами, а также популяризации футбольных турниров Казахстана."}}$row_123$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/pflk-api', $row_124${"en":{"title":"Integration with Genius Sports and WyScout | Piplos Media","og_image":"/uploads/projects/pflk-api/wepik-export-20230629104307o-s-pj.jpeg","og_title":"Integration of the Football League of Kazakhstan (PFLK) project with Genius Sports and WyScout: Improving data quality and analytics","description":"Integration of the Football League of Kazakhstan (PFLK) project with Genius Sports and WyScout: Improving data quality and analytics","og_description":"The article describes the process of integration with the Genius Sports and WyScout API systems in the Football League of Kazakhstan project. Learn how the data and statistics are pulled into the project, as well as the technical details of the integration. Explore the key aspects, technologies and solutions used in this process to improve the football experience and analytics."},"ru":{"title":"Интеграция с Genius Sports и WyScout | Piplos Media","og_image":"/uploads/projects/pflk-api/wepik-export-20230629104307o-s-pj.jpeg","og_title":"Интеграция проекта Футбольной Лиги Казахстана (ПФЛК) с Genius Sports и WyScout: Повышение качества данных и аналитики","description":"Интеграция проекта Футбольной Лиги Казахстана (ПФЛК) с Genius Sports и WyScout: Повышение качества данных и аналитики. Проект студии Piplos Media.","og_description":"Статья описывает процесс интеграции с API системами Genius Sports и WyScout в проекте Футбольной Лиги Казахстана. Узнайте, как данные и статистика тянутся в проект, а также о подробностях технической части интеграции. Изучите ключевые аспекты, технологии и решения, применяемые в этом процессе для улучшения футбольного опыта и аналитики."}}$row_124$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

