INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/port-aliance', $row_133${"en":{"title":"Airport Duty Free Online Shop","og_image":"/uploads/projects/port-aliance/artboard-copy-86.png","og_title":"Airport Duty Free Online Shop","description":"Development of the Port Alliance Duty Free Internet Shop at the airport. A project by Piplos Media.","og_description":"This technical paper deals with the process of developing the online shop of Duty Free Port Alliance, located at the airport. The main functionalities such as integration with 1C, possibility to edit product information and ordering through the website are described. It also describes the flexible functionality of the online shop, which allows users to purchase the company's products without leaving the waiting area, as well as a personal account with information on orders."},"ru":{"title":"Разработка Интернет-Магазина Дьюти-Фри Порт-Альянс при аэропорте","og_image":"/uploads/projects/port-aliance/artboard-copy-86.png","og_title":"Разработка Интернет-Магазина Дьюти-Фри Порт-Альянс при аэропорте","description":"Разработка Интернет-Магазина Дьюти-Фри Порт-Альянс при аэропорте. Проект студии Piplos Media.","og_description":"В данной технической статье рассматривается процесс разработки интернет-магазина Дьюти-Фри Порт-Альянс, расположенного в аэропорту. Описываются основные функциональные возможности, такие как интеграция с 1С, возможность редактирования информации по продукции и оформления заказа через сайт. Также описывается гибкий функционал интернет-магазина, который позволяет пользователям приобретать продукцию компании не выходя из зоны ожидания, а также личный кабинет с информацией по заказам."}}$row_133$::jsonb)
