INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/radioplayer-stage1', $row_139${"en":{"title":"RadioPlayer Stage 1 — Backend Case Study | Piplos Media","og_image":"/uploads/projects/radioplayer-stage1/placeholder-mobile.png","og_title":"How to create an effective corporate identity and logo: design experience","description":"Key steps in creating a unique brand: developing the TOR and corporate identity. A project by Piplos Media.","og_description":"In this article you'll find detailed information on how to develop terms of reference and corporate identity for your project. We'll cover every step of the process: from defining your goals and objectives to creating a logo and setting up a brand identity. You'll learn how to make your project unique and memorable, and how to formulate functionality and design requirements. At the end of the article, you will get useful tips on how to create a quality terms of reference and corporate identity."},"ru":{"title":"Как создать эффективный фирменный стиль и логотип: опыт разработки","og_image":"/uploads/projects/radioplayer-stage1/placeholder-mobile.png","og_title":"Как создать эффективный фирменный стиль и логотип: опыт разработки","description":"Ключевые шаги в создании уникального бренда: разработка ТЗ и фирменного стиля. Проект студии Piplos Media.","og_description":"В этой статье вы найдете подробную информацию о том, как разработать техническое задание и фирменный стиль для вашего проекта. Мы рассмотрим каждый этап процесса: от определения целей и задач до создания логотипа и установки бренд-бук. Вы узнаете, как сделать свой проект уникальным и запоминающимся, а также как сформулировать требования к функциональности и дизайну. В конце статьи вы получите полезные советы по созданию качественного технического задания и фирменного стиля."}}$row_139$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/radioplayer-stage2', $row_140${"en":{"title":"RadioPlayer Stage 2 — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/radioplayer-stage2/placeholder-mobile-1.png","og_title":"Development of website and API system with Personal Area for radio stations","description":"From idea to implementation: the stages of development of a Personal Office for radio station flow management with an API system","og_description":"Learn about the process of developing a website with Personal Area to manage radio station streams, as well as developing an API system for data collection and analysis. Learn how to set up Google Analytics to track user counts, listen times and other important metrics."},"ru":{"title":"Разработка веб-сайта и API системы с Личным Кабинетом для радиостанций","og_image":"/uploads/projects/radioplayer-stage2/placeholder-mobile-1.png","og_title":"Разработка веб-сайта и API системы с Личным Кабинетом для радиостанций","description":"От идеи до реализации: этапы разработки Личного Кабинета для управления потоками радиостанций с API системой. Проект студии Piplos Media.","og_description":"Узнайте о процессе разработки веб-сайта с Личным Кабинетом для управления потоками радиостанций, а также о разработке API системы для сбора и анализа данных. Узнайте, как настроить Google Analytics, чтобы отслеживать количество пользователей, время прослушивания и другие важные метрики."}}$row_140$::jsonb)
