INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/shkodovody-belarusi', $row_159${"en":{"title":"Skoda fans Belarus: new SMM app from Piplos Media for car enthusiasts","og_image":"/uploads/projects/shkodovody-belarusi/71-setetk6-al-ac-sx-679.jpg","og_title":"Skoda fans Belarus: new SMM app from Piplos Media for car enthusiasts","description":"Skoda fans Belarus: new SMM app from Piplos Media for car enthusiasts","og_description":"This article explores the development of the SMM application \"Skoda Belarus fans\" by Piplos Media. The article delves into the features of the application, including its ability to gather feedback, conduct market research, and increase brand loyalty. It also discusses the challenges faced during the development process and how they were overcome. Additionally, the article highlights the benefits of using SMM applications for businesses looking to establish a strong social media presence."},"ru":{"title":"Шкодоводы Беларуси — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/shkodovody-belarusi/71-setetk6-al-ac-sx-679.jpg","og_title":"Шкодоводы Беларуси: новое SMM приложение от Piplos Media для любителей автомобилей","description":"Шкодоводы Беларуси: новое SMM приложение от Piplos Media для любителей автомобилей","og_description":"В данной статье рассматривается разработка SMM-приложения \"Шкодоводы Беларуси\" компанией Piplos Media. В статье рассматриваются особенности приложения, в том числе его способность собирать отзывы, проводить маркетинговые исследования и повышать лояльность к бренду. В ней также обсуждаются проблемы, с которыми пришлось столкнуться в процессе разработки, и способы их преодоления. Кроме того, в статье подчеркиваются преимущества использования SMM-приложений для компаний, стремящихся создать сильное присутствие в социальных сетях."}}$row_159$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
