INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/soberi-devushku-na-vecherinku', $row_164${"en":{"title":"SMM Facebook app: how we created 'Get the girl to the party","og_image":"/uploads/projects/soberi-devushku-na-vecherinku/frame-65.png","og_title":"SMM Facebook app: how we created 'Get the girl to the party","description":"SMM Facebook app: how we created 'Get the girl to the party. These days, social media is a powerful tool for promoting a brand and attracting new customers…","og_description":"This article looks at the development of an SMM application for Facebook called 'Get a Girl at a Party'. Through the use of Facebook API and careful development of the app, users can create their own parties and invite friends, as well as select and invite girls to the party. The stages of development, the functionality of the app and its effectiveness in promoting the brand and attracting new customers are discussed in detail."},"ru":{"title":"Собери девушку на вечеринку — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/soberi-devushku-na-vecherinku/frame-65.png","og_title":"SMM приложение для Facebook: как мы создали \"Собери девушку на вечеринку","description":"SMM приложение для Facebook: как мы создали \"Собери девушку на вечеринку. Проект студии Piplos Media.","og_description":"В данной статье рассмотрена разработка SMM-приложения для Facebook под названием \"Собери девушку на вечеринку\". Благодаря использованию Facebook API и тщательной разработке приложения, пользователи могут создавать собственные вечеринки и приглашать друзей, а также выбирать и приглашать девушек на вечеринку. Подробно рассмотрены этапы разработки, функциональные возможности приложения и его эффективность в продвижении бренда и привлечении новых клиентов."}}$row_164$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

