INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/sportevent', $row_168${"en":{"title":"Sports Event Landing Page — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/sportevent/3924690-12590-1.png","og_title":"Sports Event Landing Page — Web Development Case Study | Piplos Media","description":"Case study: developing a landing page and admin panel for the SPORTFEST 2024 sports event. A project by Piplos Media.","og_description":"Case study: developing a landing page and admin panel for the SPORTFEST 2024 sports event. A project by Piplos Media."},"ru":{"title":"Лендинг Спортивного События — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/sportevent/3924690-12590-1.png","og_title":"Разработка лендинга спортивного мероприятия - адаптивный веб-проект от Piplos Media","description":"Кейс. Разработка лендинга и админ-панели для спортивного мероприятия «СПОРТФЕСТ 2024». Проект студии Piplos Media.","og_description":"Кейс разработки современного лендинга для спортивного мероприятия. Команда Piplos Media создала адаптивный сайт с удобной структурой, динамичным интерфейсом и функциональностью для регистрации участников, расписания событий и интеграции с CRM. Реализация заняла 3 недели и включала работу трёх специалистов."}}$row_168$::jsonb)
