INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/tehnobankblog', $row_173${"en":{"title":"Developing a Blog for Technobank | Piplos Media","og_image":"/uploads/projects/tehnobankblog/tehnobank-placeholder.png","og_title":"Developing a Blog for Technobank: creating a space for sharing knowledge and experience in the banking sector","description":"Developing a Blog for Technobank: creating a space for sharing knowledge and experience in the banking sector. A project by Piplos Media.","og_description":"This article describes the development of a blog for Tekhnobank OJSC. It describes the challenges the team faced in creating this project, such as adaptive design, differentiation of articles into headings, mandatory subscription form, and the ability to comment on articles. It also describes how the blog helps to increase customer engagement and brand promotion in the banking sector."},"ru":{"title":"Разработка Блога для ОАО \"Технобанк\" | Piplos Media","og_image":"/uploads/projects/tehnobankblog/tehnobank-placeholder.png","og_title":"Разработка Блога для ОАО \"Технобанк\": создание пространства для обмена знаниями и опытом в банковской сфере","description":"Разработка Блога для ОАО \"Технобанк\": создание пространства для обмена знаниями и опытом в банковской сфере. Проект студии Piplos Media.","og_description":"В данной статье рассказывается о разработке блога для ОАО \"Технобанк\". Описываются задачи, которые перед командой стояли при создании данного проекта, такие как адаптивный дизайн, разграничение статей на рубрики, обязательная форма подписки и возможность комментирования статей. Также рассказывается о том, как блог помогает увеличить вовлеченность клиентов и продвижении бренда в банковской сфере."}}$row_173$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
