VALUES ('/portfolio/tikoo-market', $row_181${"en":{"title":"TiKoo Marketplace — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/tikoo-market/frame-4-1.png","og_title":"TiKoo: Israel's B2B2C Trade Shop and Tech Innovation in TiKoo Marketplace","description":"TiKoo: Israel's B2B2C Trade Shop and Tech Innovation in TiKoo Marketplace. A project by Piplos Media.","og_description":"Explore the technical innovations in TiKoo Marketplace and learn how this Israeli B2B2C marketplace improves the experience of buyers and sellers. From flexible infrastructure to a rating system, all the information you need is here."},"ru":{"title":"TiKoo Marketplace — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/tikoo-market/frame-4-1.png","og_title":"TiKoo: Израильский B2B2C Торговый Магазин и Технические Инновации в TiKoo Marketplace","description":"TiKoo: Израильский B2B2C Торговый Магазин и Технические Инновации в TiKoo Marketplace. Проект студии Piplos Media.","og_description":"Изучите технические инновации в TiKoo Marketplace и узнайте, как этот израильский B2B2C маркетплейс улучшает опыт покупателей и продавцов. От гибкой инфраструктуры до системы рейтингов - вся необходимая информация здесь."}}$row_181$::jsonb)
