INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/unistar', $row_194${"en":{"title":"Unistar: Development of an Android and iOS mobile app","og_image":"/uploads/projects/unistar/v1.png","og_title":"Unistar: Development of an Android and iOS mobile app","description":"The Unistar mobile app: a convenient way to listen to a radio station. A project by Piplos Media.","og_description":"We developed a mobile app for radio station Unistar, allowing you to listen to icecast and HLS streams with adaptive quality on Android and iOS. The app was developed based on the cross-platform Flutter solution and uses Firebase functionality such as Remote Config, Cloud Firestore, Cloud Functions, Crashlytics and Google Analytics. All app management is done on the side of the Firebase service, allowing you to easily configure your channel list and modify app content. Find out more about our mobile app development project for radio station Unistar."},"ru":{"title":"Unistar: Разработка мобильного приложения для Android и iOS","og_image":"/uploads/projects/unistar/v1.png","og_title":"Unistar: Разработка мобильного приложения для Android и iOS","description":"Мобильное приложение Unistar: удобный способ прослушивания радиостанции. Проект студии Piplos Media.","og_description":"Мы разработали мобильное приложение для радиостанции Unistar, позволяющее слушать потоки в формате icecast и HLS с адаптивным качеством на Android и iOS. Приложение было разработано на базе кроссплатформенного решения Flutter и использует функционал Firebase, такой как Remote Config, Cloud Firestore, Cloud Functions, Crashlytics и Google Analytics. Вся управление приложением осуществляется на стороне сервиса Firebase, позволяя легко настраивать список каналов и изменять контент приложения. Узнайте больше о нашем проекте разработки мобильного приложения для радиостанции Unistar."}}$row_194$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

