INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/versusports-app', $row_204${"en":{"title":"VERSUSPORTS - The Ultimate Sports Enthusiast's Social Network","og_image":"/uploads/projects/versusports-app/93448613abd4423c80b2e094cbc2f3a8.jpeg","og_title":"VERSUSPORTS: Transforming Sports Enthusiasm into a Thriving Social Network","description":"VERSUSPORTS: Transforming Sports Enthusiasm into a Thriving Social Network. A project by Piplos Media.","og_description":"Explore how Piplos Media's expertise shaped VERSUSPORTS, a revolutionary mobile platform and social network for sports lovers. Discover how this dynamic app enhances sports engagement, offers personalized experiences, and brings communities together through the love of sports."},"ru":{"title":"VERSUSPORTS - социальная сеть для энтузиастов спорта | Piplos Media","og_image":"/uploads/projects/versusports-app/93448613abd4423c80b2e094cbc2f3a8.jpeg","og_title":"Революционная социальная сеть энтузиастов спорта: История успеха VERSUSPORTS","description":"Революционная социальная сеть энтузиастов спорта: История успеха VERSUSPORTS. Проект студии Piplos Media.","og_description":"Узнайте, как компания Piplos Media изменила ландшафт спортивных сетей с помощью VERSUSPORTS - мобильной платформы, которая объединяет спортсменов, организует игры и способствует укреплению духа сообщества."}}$row_204$::jsonb)
