    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/viberi-svoi-auto', $row_205${"en":{"title":"applications for FAVORIT MOTORS | Piplos Media","og_image":"/uploads/projects/viberi-svoi-auto/a609a2dbe30e452a8e1b12b60a5c0aa7.png","og_title":"Driving Social Engagement: Piplos Media's Success Story with FAVORIT MOTORS SMM App","description":"How Piplos Media created an SMM app for FAVORIT MOTORS. Social media is becoming increasingly popular amongst marketers and business people, and no wonder, as…","og_description":"In this article we look at the process of developing an SMM application for FAVORIT MOTORS by Piplos Media. You'll learn what tools we used to create an app that helps the client attract more leads and improve their online reputation. We will also share our experience of working with the client and discuss the key points of the project."},"ru":{"title":"приложения для FAVORIT MOTORS — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/viberi-svoi-auto/a609a2dbe30e452a8e1b12b60a5c0aa7.png","og_title":"Обеспечение социальной вовлеченности: История успеха Piplos Media с SMM-приложением FAVORIT MOTORS","description":"Как Piplos Media создало SMM-приложение для FAVORIT MOTORS. Социальные сети становятся все более популярными среди маркетологов и бизнесменов, и это…","og_description":"В этой статье мы рассмотрим процесс разработки SMM-приложения для FAVORIT MOTORS компанией Piplos Media. Вы узнаете, какими инструментами мы пользовались, чтобы создать приложение, которое помогает клиенту привлечь больше потенциальных покупателей и улучшить свою онлайн-репутацию. Мы также поделимся нашим опытом работы с заказчиком и обсудим ключевые моменты проекта."}}$row_205$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/viberi-svoi-ford', $row_206${"en":{"title":"SMM apps for Facebook — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/viberi-svoi-ford/865ba30be60d47cbadf75fa8fa377507.jpeg","og_title":"Boosting Company Recognition with Functional Facebook Applications: Our Team's Success Story","description":"Developing functional SMM apps for Facebook: how to increase a company's visibility. A project by Piplos Media.","og_description":"This article looks at the development of functional Facebook apps that help companies increase their visibility and market research. We'll look at different types of SMM apps, their benefits and ways to increase brand loyalty."},"ru":{"title":"SMM приложений для Facebook — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/viberi-svoi-ford/865ba30be60d47cbadf75fa8fa377507.jpeg","og_title":"Повышение узнаваемости компании с помощью функциональных приложений Facebook: История успеха нашей команды","description":"Разработка функциональных SMM приложений для Facebook: как повысить узнаваемость компании. Проект студии Piplos Media.","og_description":"В данной статье рассматривается разработка функциональных приложений для Facebook, которые помогают компаниям повышать свою узнаваемость и проводить маркетинговые исследования. Мы рассмотрим различные виды SMM приложений, их преимущества и способы повышения лояльности к брендам."}}$row_206$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/viberi-svoi-opel', $row_207${"en":{"title":"Choose Your Opel: Developing an SMM App to Increase Brand Loyalty","og_image":"/uploads/projects/viberi-svoi-opel/c12626a9d048471c9ce9ef486f98fd19.jpeg","og_title":"Choose Your Opel: Developing an SMM App to Increase Brand Loyalty","description":"Choose Your Opel: Developing an SMM App to Increase Brand Loyalty. A project by Piplos Media.","og_description":"Opel is one of the most popular car brands in the world, and its loyal fans are always looking for new ways to learn more about the brand. That's why Piplos Media has developed a new SMM application, \"Choose Your Opel,\" designed to increase recognition and loyalty to the brand. The Facebook-based app includes a variety of features to help potential buyers choose their ideal Opel car. Users can view photos, descriptions, and technical specifications of each Opel model, as well as access a range of interesting features to help them choose their perfect vehicle. The app's key feature is a virtual test drive of each Opel model. Users can take the test drive on their computer using the built-in tools and get a realistic idea of how they will feel behind the wheel of each car. Additionally, \"Choose Your Opel\" allows users to customize their ideal car with a built-in configurator, including the body color, engine type, and transmission type, among others. For those who have already purchased an Opel car, the app provides a variety of useful features. They can find the nearest Opel service center, access exclusive promotions and offers, and much more. Thanks to the \"Choose Your Opel\" SMM app, Piplos Media has helped increase recognition and loyalty to the Opel brand by providing potential and current customers with a convenient way to learn about Opel cars, take a virtual test drive, and customize their ideal vehicle."},"ru":{"title":"Выбери свой Opel — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/viberi-svoi-opel/c12626a9d048471c9ce9ef486f98fd19.jpeg","og_title":"Выбери свой Opel — Кейс веб-разработки | Piplos Media","description":"Выбери свой Opel: разработка SMM-приложения для повышения лояльности к бренду. Проект студии Piplos Media.","og_description":"Выбери свой Opel: разработка SMM-приложения для повышения лояльности к бренду. Проект студии Piplos Media."}}$row_207$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

