INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/zakatki-ren', $row_213${"en":{"title":"Zakatki Ren: Building an SMM Application | Piplos Media","og_image":"/uploads/projects/zakatki-ren/84f6e578272d4ff0b1506b6b79c74ac1.jpeg","og_title":"Zakatki Ren: Building an SMM Application | Piplos Media","description":"The art of promotion: how to build an SMM application for VKontakte — the Zakatki Ren case. A project by Piplos Media.","og_description":"The art of promotion: how to build an SMM application for VKontakte — the Zakatki Ren case. A project by Piplos Media."},"ru":{"title":"Закатки Рень: создание SMM-приложения | Piplos Media","og_image":"/uploads/projects/zakatki-ren/84f6e578272d4ff0b1506b6b79c74ac1.jpeg","og_title":"Закатки Рень","description":"Искусство продвижения: Как разработать SMM приложение для Вконтакте на примере Закатки Рень. Проект студии Piplos Media.","og_description":"Статья о разработке SMM-приложения \"Закатки Рень\" для социальной сети Вконтакте. В ней рассматриваются основные этапы создания приложения, его функциональность и возможности, а также преимущества его использования для продвижения бренда в социальных сетях. Эта статья будет полезна тем, кто хочет узнать больше о создании эффективного инструмента для управления аккаунтом в социальной сети Вконтакте."}}$row_213$::jsonb)
