INSERT INTO seo_pages (path, translations)
VALUES ('/portfolio/zero23', $row_214${"en":{"title":"ZERO23 — Web Development Case Study | Piplos Media","og_image":"/uploads/projects/zero23/image-1-1-1.png","og_title":"Engaging Your Audience: How to Create a Landing Page with a Voting System","description":"A competition landing page with voting: how to create an immersive experience for your audience. A project by Piplos Media.","og_description":"This article explores the development of a landing page with a voting system for a contest's participants. The website includes a list of contestants and a screen for broadcasting real-time voting results. The project utilizes a technology stack consisting of HTML, CSS, Sass, SCSS, JS, PHP, ReactJS, and Bootstrap 4.x. Creating a landing page with a voting system can be an excellent way to engage an audience and generate buzz around an event. By using modern web development tools like ReactJS and Bootstrap, you can create an attractive and user-friendly website with a robust and secure voting system."},"ru":{"title":"ZERO23 — Кейс веб-разработки | Piplos Media","og_image":"/uploads/projects/zero23/image-1-1-1.png","og_title":"Как разработать лендинг-страницу с голосованием: технологии и возможности","description":"Конкурсная лендинг-страница с голосованием: как создать захватывающий опыт для вашей аудитории. Проект студии Piplos Media.","og_description":"Эта статья рассказывает о создании лендинга с системой голосования для участников конкурса. Вы узнаете, как использовать фронтенд-технологии, такие как HTML, CSS, JS, Sass и SCSS, а также бэкенд-технологии PHP, ReactJS и Bootstrap 4.x, чтобы создать привлекательный и удобный в использовании сайт с возможностью голосования в режиме реального времени. Этот метод прекрасно подходит для привлечения аудитории и создания ажиотажа вокруг вашего мероприятия или конкурса."}}$row_214$::jsonb)
ON CONFLICT (path) DO UPDATE SET
    translations = EXCLUDED.translations,
    updated_at = now();

